    ('SQL-R22', 113, 'update TransX set Flex1 = ''non-FX'' from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-R22', 121, 'insert into TransX (KeyID, Ledger, Co, GL, TP,PC,BusCat, Flex1, Amt1,Amt2,RefKey2) (Select KeyID, Ledger, Co, GL, TP,PC,BusCat, Flex1, round(sum(Amt1),2) as Amt1, round(sum(Amt1)-sum(Amt2),2) as Amt2, ''pass2'' as RefKey2 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Co, GL, TP,PC,BusCat, Flex1)'),
    ('SQL-R22', 122, 'delete from TransX where KeyID = ''[batchID]'' and RefKey2 is NULL'),
    ('SQL-R22', 201, 'update TransX set RefKey2 = ''1. Gross'', Flex3 = ''Balance Sheet'', Flex4 = ''Paid'', Flex5 = ''ULAE'', Flex6 = ''Americas'', RefKey3 = ''US Branch'', RefKey1 = ''no'', BusCatDesc = '''', Tpname = '''' from TransX where KeyID = ''[batchID]'''),
    ('SQL-R22', 202, 'update TransX set RefKey2 = ''2. Ceded'' from TransX where KeyID = ''[batchID]'' and (substring(GL,1,2) = ''14'' or BusCat like ''3%'')'),
    ('SQL-R22', 203, 'update TransX set Flex3 = ''Income Statement'' from TransX where KeyID = ''[batchID]'' and GL >= ''4000000'''),
    ('SQL-R22', 204, 'update TransX set Flex4 = ''IBNR'' from TransX where KeyID = ''[batchID]'' and (substring(GL,1,3) in (''143'',''145'',''203'',''205'') or GL = ''2040001'')'),
    ('SQL-R22', 205, 'update TransX set Flex4 = ''Case'' from TransX where KeyID = ''[batchID]'' and GL < ''3000000'' and Flex4 = ''Paid'''),
    ('SQL-R22', 207, 'update TransX set Flex4 = ''Change in Case'' from TransX where KeyID = ''[batchID]'' and substring(GL,1,2) = ''53'' and Flex4 = ''Paid'''),
    ('SQL-R22', 220, 'update TransX set RefKey1 = ''yes'' from TransX where KeyID = ''[batchID]'' and substring(PC,1,1) = ''6'''),
    ('SQL-R22', 221, 'update TransX set CCdesc = c.Name from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'''),
    ('SQL-R22', 222, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R22', 223, 'update TransX set PCdesc = p.Descr, Division = p.Division, Region = p.Region, Location = p.Location, Zone = p.Zone, Hierarchy = p.Hierarchy from TransX t inner join PCTRS p on t.PC = p.PCTR where KeyID = ''[batchID]'''),
    ('SQL-G80', 402, 'insert into TransX (KeyID, GL, PC, CC, Contract, ProdCode, TP,Amt1, Amt2, Amt3,PK) (Select KeyID,GL, PC, CC, Contract, ProdCode, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and not PK = ''40'')'),
    ('SQL-G80', 403, 'delete from TransX where KeyID = ''[batchID]'' and not PK in (''40'',''50'')'),
    ('SQL-G80', 404, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G80', 501, 'update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID like ''[batchID]%'''),
    ('SQL-G80', 502, 'update TransX set Txt = ''FFX LatAm Chargeback for [Yr]/[Mo]'' where KeyID = ''[batchID]'''),
    ('SQL-R08', 225, 'update TransX set FSitem = f.FSitem, FSitemDesc = f.FSitemDesc from TransX t inner join Fsitems f on t.GL >= f.FromGL and t.GL <= ThruGL where KeyID = ''[batchID]'''),
    ('SQL-R08', 226, 'update TransX set BusCatDesc = m.Descr from TransX t inner join Misc_Tables m on t.BusCat = m.ID where KeyID = ''[batchID]'' and BusCat <> '''' and Table_ID = ''BusCat'''),
    ('SQL-R08', 231, 'update TransX set Flex6 = ''US Insurance Ops'', RefKey3 = ''US Insurance Ops'' from TransX where KeyID = ''[batchID]'' and Division = ''US_INS_OPS'''),
    ('SQL-R08', 232, 'update TransX set Flex6 = ''EuroAsia'', RefKey3 = ''Europe'' from TransX where KeyID = ''[batchID]'' and ((Division = ''EUROASIA'' and Region =  ''EUROPE'') or (Division = ''FIRV'' and Region =  ''EUR_FIRV''))'),
    ('SQL-R08', 233, 'update TransX set Flex6 = ''EuroAsia'', RefKey3 = ''Asia'' from TransX where KeyID = ''[batchID]'' and ((Division = ''EUROASIA'' and Region =  ''ASIA'') or (Division = ''FIRV'' and Region =  ''SNG_FIRV''))'),
    ('SQL-M13', 420, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data11'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC where source = ''R64'' and YearPeriod > ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control x left join IR17_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join IR17_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD ) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) AND NOT GL_Grp IN (''DAC'',''UPR'') and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-G59', 250, 'update TransX set Broker = ''UNKNOWN'' from TransX t inner join [GFS].dbo.FSGValidation v on GL = GLAccount where KeyID = ''[batchID]'' and v.Broker = 1'),
    ('SQL-G59', 251, 'update TransX set ReinName = ''UNKNOWN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and Cedant = 1'),
    ('SQL-G59', 252, 'update TransX set TransCode = ''T9999'' from TransX inner join [GFS].dbo.FSGValidation v on GL = GLAccount where KeyID = ''[batchID]'' and v.TransCode = 1'),
    ('SQL-R75', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
