    ('SQL-R75', 301, 'Update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID = ''[batchID]'''),
    ('SQL-R75', 302, 'Update x set x.CCdesc = y.Descr from TransX x inner join CCtrs y on x.Contract = y.CCtr where KeyID = ''[batchID]'''),
    ('SQL-R70', 208, 'update TransX set Flex1 = ''3030'', Flex2 = ''FIRV 2001'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2001'' and PC like ''6%'' and Contract like ''%3030%'''),
    ('SQL-R03', 122, 'insert into TransX (KeyID, Ledger, Co, PC, GL, TP, Contract, UWYR, BusCat, Amt1, Flex2) (Select KeyID, Ledger, Co, PC, GL, TP, Contract, UWYR, BusCat, round(Amt1*.7,2) as Amt1, ''3 Calc'' as Flex2 from TransX where KeyID = ''[batchID]'' and Flex2 = ''1 Non-QS'' and not ((Region = ''USO_CROP'' and Hierarchy <> ''USO_MPCI'') or Hierarchy in (''USO_AH_EX'',''USOTRG_MAR'',''USONWGNLIA'')))'),
    ('SQL-M43', 452, 'delete from TransX where KeyID = ''[batchID]'' and not Flex1 is NULL'),
    ('SQL-M43', 453, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0'),
    ('SQL-G51', 105, 'delete from TransX where KeyID = ''[batchID]'' and substring(GL,1,3) in (''162'',''242'')'),
    ('SQL-G51', 106, 'insert into TransX (KeyID,GL,Amt1) (select KeyID + ''-data2'',GL,Amt1 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G89', 367, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-M15', 131, 'Update TransX set Flex1 = (case when Co like ''599%'' then ''(2) Back-out'' else ''(1) IFRS 4'' end) where KeyID = ''[batchID]'''),
    ('SQL-G31', 449, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G31', 453, 'delete from TransX where KeyID = ''[batchID]'' and PK = ''1'''),
    ('SQL-R49', 111, 'delete from TransX where KeyID = ''[batchID]'' and amt2 = 0 and amt4 = 0 and amt5 = 0'),
    ('SQL-G31', 454, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G51', 201, 'update TransX set GL = substring(GL,1,5) + ''01'' from TransX where KeyID = ''[batchID]'' and not substring(GL,6,2) in (''96'',''98'')'),
    ('SQL-G71', 235, 'Update TransX set TP = ''F0018'' where KeyID = ''[batchID]'' and GL = ''1998900'' and Contract = ''5USA000084'''),
    ('SQL-G87', 202, 'delete from TransX where KeyID = ''[batchID]'' and ProdCode = ''CHGBACK'' and not Contract in (''1OSS000034'',''5OSS000001'',''5USA000087'')'),
    ('SQL-G46', 206, 'delete from TransX where KeyID = ''[batchID]'' and GL = ''3545502'''),
    ('SQL-T01', 101, 'insert into TransX (KeyID,Co,Flex1,Flex2,Flex3,Crcy,Flex4,PC,CC,PCdesc,CCdesc,Flex5,Flex6,FSitemDesc,Txt) (select ''[batchID]'',Co,Name,FullName,SAPName,Crcy,LC3Crcy,DefaultPC,DefaultCC,DefaultPCPrefix,DefaultCCPrefix,POPC,Division,ExposureLoc,Notes from Companies)'),
    ('SQL-G71', 104, 'Update TransX set Txt = ''FFX Reimburse @[Yr]/[Mo] from '' + Contract + '' '' + GL, Amt1 = round(-Amt1,2) where KeyID = ''[batchID]'' and CC = ''5USA000032'''),
    ('SQL-G71', 201, 'Update TransX set Txt = ''FFX Reimburse @[Yr]/[Mo] from '' + CC + '' '' + GL, Contract = CC, CC = ''5USA000032'', ProdCode = ''CHGBACK'', Amt1 = round(-Amt1,2) where KeyID = ''[batchID]'' and not CC = ''5USA000032'''),
    ('SQL-G71', 202, 'Update x set x.GL = y.Field1 from TransX x inner join Misc_Tables y on x.GL = y.Descr where KeyID = ''[batchID]'' and Table_ID = ''Reimburse'' and ID = ''GL'''),
    ('SQL-G71', 211, 'insert into TransX (KeyID,GL,CC,Txt,Contract,ProdCode,Amt1,Flex1) (select KeyID,GL,CC,Txt,Contract,ProdCode,round(sum(Amt1),2) as Amt1,''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,GL,CC,Txt,Contract,ProdCode)'),
    ('SQL-G71', 212, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 or FLex1 is NULL)'),
    ('SQL-G71', 221, 'insert into TransX (KeyID,GL,PC,Txt,Contract,ProdCode,TP,Amt1) (select KeyID,''1998900'' as GL,''5200000000'' as PC,substring(Txt,1,len(Txt)-8),Contract,'''' as ProdCode,''F0046'' as TP,round(-sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' group by KeyID,substring(Txt,1,len(Txt)-8),Contract)'),
    ('SQL-G71', 222, 'insert into TransX (KeyID,GL,PC,Txt,Contract,ProdCode,TP,Amt1) (select KeyID,''2898900'' as GL,''5200000000'' as PC,Txt,Contract,'''' as ProdCode,''F0046'' as TP,ROUND((-SUM(Amt1)),2) from TransX where KeyID = ''[batchID]'' and GL = ''1998900'' and Contract = ''5USA000086'' group by KeyID,Txt,Contract)'),
    ('SQL-G71', 224, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-G71', 234, 'Update TransX set TP = ''F0037'' where KeyID = ''[batchID]'' and GL = ''1998900'' and Contract = ''5USA000065'''),
    ('SQL-R59', 702, 'update TransX set RefKey1 = ''M7-3-06-02'' from TransX where KeyID = ''[batchID]'' and RefKey1 = ''M7-3-06-01'' and BusCatDesc = ''Ceded'''),
    ('SQL-S08', 510, 'update TransX set Amt2 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, GL, UWYR, Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.GL = f2.GL and f1.UWYR = f2.UWYR and f1.Amt1 = f2.Amt1'),
    ('SQL-S08', 511, 'update TransX set Amt3 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, GL, UWYR, Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'') f2 on f1.KeyID = f2.KeyID and f1.GL = f2.GL and f1.UWYR = f2.UWYR and f1.Amt1 = f2.Amt1'),
    ('SQL-R27', 214, 'update TransX set Flex1 = ''Gross Hedge-Futures'' from TransX where KeyID = ''[batchID]''  and GL like ''503%'' and not (GL = ''5030000'' and Ledger = ''IF'')'),
    ('SQL-S08', 513, 'update TransX set Ledger = ''Z000'' from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' and Amt1 = Amt3'),
    ('SQL-S08', 530, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R49', 112, 'update TransX set Amt4 = Amt2, Amt5 = Amt2 where KeyID = ''[batchID]'' and GL like ''3%'' and (TTY = ''100'' or not GL like ''%2'') and not GL = ''3584005'' and not PC in (''141CPW0000'',''141SCP0000'',''141QUE0000'',''141SAB0000'',''141SBG0000'')'),
    ('SQL-G12', 222, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-sum(coalesce(Amt1,0)),2) as Amt1,  ''40'' as PK from TransX where KeyID = ''[batchID]'' and Amt1 < 0 and PK is NULL group by KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF)'),
    ('SQL-G12', 241, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '''' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and substring(GL,4,2) = ''89'' and TP <> '''' )'),
    ('SQL-G12', 242, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '''' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''50'' and substring(GL,4,2) = ''89'' and TP <> '''')'),
    ('SQL-G12', 243, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, '''' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and substring(GL,4,2) <> ''89'' and TP <> '''')'),
    ('SQL-G29', 512, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL like m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID = ''[batchID]'' and not GL in (''4419900'') and ProdCode is NULL'),
    ('SQL-G29', 541, 'Update t set Co = m.Field1 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Co'' and m.Descr = t.Co where t.KeyID = ''[batchID]'''),
    ('SQL-G29', 551, 'update TransX set  TTY = ''822'' where KeyID = ''[batchID]''  and TTY = ''821'''),
    ('SQL-G29', 582, 'update TransX set TTY = '''' from TransX where KeyID = ''[batchID]'' and GL in (''2853500'',''3870003'')'),
    ('SQL-G29', 603, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data3'' as KeyID, ''9999'' as Co, ''filler'' as GL, '''' as Crcy, '''' as PC, '''' as TTY, '''' as TP, '''' as  Assgnmt, '''' as ProdCode, '''' as PTF, 0 as Amt1, 0 as  Amt2 , 0 as  Amt3)'),
    ('SQL-R63', 550, 'insert into TransX (KeyID, Co, GL, CCcat, TP, BusCat, TTY, ProdCode, PTF, TransCode, Flex1, Flex2, Flex3, Flex4, Flex5, Flex6, Flex7, Flex8, FSitem, ExpNode, Txt, RefKey1, RefKey2, RefKey3, ReinLoc, RiskTerr, Flex9, Amt1, Amt2, Amt3, Amt4) 
		(select ''[batchID]-save'',Co, GL, CCcat, TP, BusCat, TTY, ProdCode, PTF, TransCode, Flex1, Flex2, Flex3, Flex4, Flex5, Flex6, Flex7, Flex8, FSitem, ExpNode, Txt, RefKey1, RefKey2, RefKey3, ReinLoc, RiskTerr, Flex9, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, round(sum(Amt4),2) as Amt4 
		from TransX where KeyID = ''[batchID]''  group by KeyID, Co, GL, CCcat, TP, BusCat, TTY, ProdCode, PTF, TransCode, Flex1, Flex2, Flex3, Flex4, Flex5, Flex6, Flex7, Flex8, FSitem, ExpNode, Txt, RefKey1, RefKey2, RefKey3, ReinLoc, RiskTerr, Flex9)'),
    ('SQL-R63', 551, 'delete from TransX where KeyID = ''[batchID]'''),
    ('SQL-S22', 472, 'update CedingCoByQtr set Flex3 = replace(replace(replace(replace(Flex3,''general'',''gen''),''genl'',''gen''),''assr'',''asr''),''seguros'',''se'') where Yr = ''[Yr]'' and Per = ''[Mo]'' and Flex2 is NULL'),
    ('SQL-S22', 479, 'update c1 set Name = c1.SAP_Name,Flex2 = ''found'', SP_Name = (case when c2.SP_Rating = '''' then '''' else c2.Name end), AM_Name = (case when c2.AMBest_Rating = '''' then '''' else c2.Name end), c1.SP_Rating = c2.SP_Rating, c1.AMBest_Rating = c2.AMBest_Rating, c1.Flex1 = c2.CedingCo from CedingCoByQtr c1 inner join CedingCoByQtr c2 on (substring(c1.Flex3,1,17) = substring(c2.Flex3,1,17) or substring(c1.Flex3,1,len(c2.Flex3)) = c2.Flex3 or c1.Flex3 = substring(c2.Flex3,1,len(c1.Flex3))) and c1.Yr = c2.Yr and c1.Per = c2.Per where c1.Yr = ''[Yr]'' and c1.Per = ''[Mo]'' and c1.Name is NULL and not c1.SAP_Name is NULL and c2.SAP_Name is NULL');



			ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt3,0)),2) as Amt3, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, 
			''pass2'' as Flex5  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, GLdesc, TP, TPname, Flex2, Hierarchy, Flex1, PC, TTY)'),
    ('SQL-G23', 261, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Amt1, Amt2, Amt3,Assgnmt) (Select ''[batchID]-data3'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, (case when Co like ''599%'' then '''' else ''x'' + Flex1 + ''x'' + Flex2 + ''x'' + Flex3 end) as Assgnmt from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Flex1, Flex2, Flex3)'),
    ('SQL-G23', 262, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, BusCat, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1099917'' as GL, Crcy, ''900'' as TTY, '''' as TP, PC, '''' as BusCat, Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]-data3'' and Assgnmt in (''x4419901x20x'',''x6829900xx'',''x6829901xx'') and ''[yyyy-mm-dd]'' in (''2022-12-31'') group by KeyID, Co, Crcy, PC, Assgnmt)'),
    ('SQL-G23', 315, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select ''[batchID]'' as KeyID, m.Field1 as Co, t.GL, t.Crcy, t.PC,t.TTY, t.TP, t.BusCat, coalesce(t.Assgnmt,''''), t.ProdCode, t.Amt1, t.Amt2 , t.Amt3 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Co'' and m.Descr = t.Co where t.KeyID = ''[batchID]-data3'')'),
    ('SQL-G23', 421, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, BusCat, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, ''4398600'' as GL, Crcy, '''' as TTY, '''' as TP, ''5500000000'' as PC, '''' as BusCat, '''' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' group by KeyID, Co, Crcy)'),
