    ('SQL-G23', 259, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, BusCat, Assgnmt, Flex1, Flex2, Flex3, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1099917'' as GL, Crcy, '''' as TTY, TP, PC, '''' as BusCat, Assgnmt, Flex1, '''' as Flex2, '''' as Flex3, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and Flex1 in (''4410000'',''4419900'',''4410001'',''4419901'') group by KeyID, Co, Crcy, TP, PC,Assgnmt, Flex1)'),
