    ('SQL-R21', 112, 'update TransX set Hierarchy = p.Region, Flex2 = m.Field1, Flex3 = m.Field2 from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Table_ID = ''DACanalysis'' and m.ID = ''Hierarchy'' and m.Descr = p.Region where KeyID = ''[batchID]'''),
    ('SQL-R21', 113, 'update TransX set Hierarchy = p.Location, Flex2 = m.Field1, Flex3 = m.Field2 from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Table_ID = ''DACanalysis'' and m.ID = ''Hierarchy'' and m.Descr = p.Location where KeyID = ''[batchID]'''),
    ('SQL-R21', 114, 'update TransX set Hierarchy = p.Zone, Flex2 = m.Field1, Flex3 = m.Field2 from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Table_ID = ''DACanalysis'' and m.ID = ''Hierarchy'' and m.Descr = p.Zone where KeyID = ''[batchID]'''),
    ('SQL-R21', 115, 'update TransX set Hierarchy = p.Hierarchy, Flex2 = m.Field1, Flex3 = m.Field2 from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Table_ID = ''DACanalysis'' and m.ID = ''Hierarchy'' and m.Descr = p.Hierarchy where KeyID = ''[batchID]'''),
