    ('SQL-G24', 251, 'update TransX set ProdCode = '''' where KeyID = ''[batchID]'''),
    ('SQL-G24', 261, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''FFH TP'' and t.GL = m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID = ''[batchID]'''),
    ('SQL-R49', 695, 'update TransX set Flex8 = (case when (substring(GL,4,4) in (''9900'',''9901'') or GL in (''1320000'',''1320500'',''1321500'',''2025001'',''2035001'')) and GL < ''4000000'' then ''reg/est'' else ''other'' end) where KeyID = ''[batchID]'''),
    ('SQL-G24', 281, 'Update t set Amt2 = round(Amt2*r1.Rate/r2.Rate,2) from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.Field3 = ''convert'' and m.ID = ''Co'' and m.Descr = t.Co inner join CrcyRates r1 on r1.Crcy = m.Field2 and r1.Typ = ''S'' and r1.EffDate = (select max(EffDate) from (select EffDate from CrcyRates where Typ = ''S'' and Crcy = ''GBP'' and EffDate <= ''[yyyy-mm-dd]'') a) inner join CrcyRates r2 on r2.Crcy = m.Field4 and r2.Typ = ''S'' and r2.EffDate = r1.EffDate where t.KeyID = ''[batchID]'''),
    ('SQL-G24', 291, 'Update t set Co = m.Field1 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Co'' and m.Descr = t.Co where t.KeyID = ''[batchID]'''),
