    ('SQL-G27', 221, 'insert into TransX (KeyID, Co, GL, Crcy, TP, PC, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TP, PC, ProdCode, PTF, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2 , round(sum(coalesce(Amt3,0)),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TP, PC,ProdCode,PTF)'),
