    ('SQL-G27', 243, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Amt1, Amt2, Amt3,Assgnmt) (Select KeyID, Co, Assgnmt, Crcy, TTY, TP, PC, ProdCode, PTF, round(-Amt1,2), round(-Amt2,2), round(-Amt3,2),Assgnmt from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G27', 331, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
    ('SQL-G27', 332, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
