    ('SQL-G23', 220, 'Update x set Amt1 = round(Amt1*c.Rate,2), Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy inner join CrcyRates c on c.Crcy = x.Crcy and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-G65', 106, 'insert into TransX (KeyID,GL,Amt1) (select KeyID + ''-data2'',GL,Amt1 from TransX where KeyID = ''[batchID]'')'),
