    ('SQL-G70', 601, 'update TransX set ProdCode = ''CHGBACK'' where KeyID = ''[batchID]'' and GL like ''6%'''),
    ('SQL-G70', 304, 'insert into TransX (KeyID, GL, Crcy,Amt1, Amt2, Amt3,Co,PC,TP) (Select KeyID, ''2899901'' as GL, Crcy, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2,  round(-sum(Amt3),2) as Amt3, Co,''3990000000'' as PC, ''2006'' as TP from TransX where KeyID = ''[batchID]'' and Co = ''3060'' group by KeyID,Co, Crcy)'),
    ('SQL-T05', 104, 'update TransX set Flex8 = substring(''GL: '' + c3.COA,1,254) from TransX inner join (select distinct c2.GL, (select c1.OS_GL + '','' as [text()] from (select GL,OS_GL from COA inner join (select distinct GL_From, GL_Thru, OS_GL from osAccountMap3 where Co_Thru = ''9999'') os on GL >= GL_From and GL <= GL_Thru) c1 where c1.GL = c2.GL order by c1.OS_GL for XML Path ('''') ) [COA] from COA c2) c3 on TransX.GL = c3.GL where KeyID = ''[batchID]'''),
    ('SQL-T05', 125, 'update TransX set Flex9 = x.OS_GL_Desc from TransX t inner join osAccountMap3 x on substring(t.Flex8,5,4) = x.OS_GL where KeyID = ''[batchID]'' and len(t.Flex8) > 4'),
    ('SQL-W13', 221, 'Update TransX set Flex2 = ''05-CASH'' where KeyID = ''[batchID]'' and TTY in (''805'',''811'',''812'') and TransCode = '''''),
    ('SQL-W13', 231, 'Update x set x.Flex4 = y.Descr from TransX x inner join Misc_Tables y on Flex2 = y.ID and y.Table_ID = ''W13 Grp2''  where KeyID = ''[batchID]'' and not Flex2 = '''''),
    ('SQL-R07', 311, 'Update x set x.Flex2 = y.Field1 from TransX x inner join Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex2 is NULL'),
    ('SQL-R07', 312, 'Update x set x.Flex2 = y.Field1 from TransX x inner join Misc_Tables y on substring(GL,1,3) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex2 is NULL'),
    ('SQL-G24', 214, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = ''any'' and m.Field1 = ''any'' and m.Field2 = x.TTY and m.Field6 = ''1'' where KeyID = ''[batchID]'')'),
    ('SQL-R59', 411, 'insert into TransX (KeyID, GL, BusCatDesc, Co, Ledger,Flex4, Amt1,Amt2,Flex8) (select ''[batchID]'',(case when Yr < [Yr] and GL >= ''4000000'' then ''3610000'' else (case when Yr < [Yr] and GL = ''3810001'' then ''3810000'' else GL end) end) as GL, '''' as BusCatDesc,Co,Ledger,JE,Amt, (case when Yr = [Yr] then Amt else 0 end) as Amt2,''pass6'' from GAAP2Stat where Yr <= [Yr] and (CarryFwd = ''Y'' or Yr = ''[Yr]'') and (Period <= [Mo] or Yr < [Yr]) and not JE like ''%-H%'')'),
    ('SQL-R59', 605, 'insert into TransX (KeyID, GL, BusCatDesc, Co, Ledger,Flex4, Amt1,Amt2,Flex8) (select KeyID, ''1999901'', '''', Co, Ledger,Flex4,round(-sum(Amt1),2),round(-sum(Amt2),2),''pass7'' from TransX where KeyID = ''[batchID]'' and Flex4 = ''0010-050'' and Co = ''2008'' group by KeyID,Co,Ledger,Flex4)'),
    ('SQL-R28', 232, 'insert into TransX (KeyID, GL, Gldesc, Co, Flex1, Flex4, Flex9, Qtr, Amt2, Amt3) (select KeyID, ''1000000'' as GL, ''Colm 13'' as GLdesc, Co, SchedYname, Flex4, ''n'' as Flex9, 13 as Qtr,round(-sum(Amt2),2) as Amt2,round(-sum(Amt3),2) as Amt3 from TransX t inner join TPs p on t.Co = p.TP where KeyID = ''[batchID]'' and Qtr = 13 group by KeyID,Co,SchedYname,Flex4)'),
    ('SQL-R28', 242, 'insert into TransX (KeyID, Yr,Flex1,Flex5,Flex6,Period,Flex2,Flex9,Qtr,Amt1) (select ''[batchID]'' as KeyID,Descr,Field1,Field2,Field3,Descr,Field1,''y'' as Flex9, 9 as Qtr, 0 as Amt1 from Misc_Tables where Table_ID = ''Sched Y'' and ID = ''Names'')'),
    ('SQL-R16', 236, 'update TransX set Flex6 = coalesce(m.SchedFname,'''') from TransX t inner join TPs m on t.TP = m.TP where KeyID = ''[batchID]'' and Flex6 = '''''),
    ('SQL-E08', 1004, 'delete from TransX where KeyID = ''[batchID]'' and GL = ''1480002'''),
    ('SQL-R24', 223, 'update TransX set Flex6 = ''A'' from TransX t inner join Misc_Tables m on substring(t.GL,1,5) = m.ID where KeyID = ''[batchID]'' and m.Table_ID = ''Tax GL'' and m.Descr = ''9999999'''),
    ('SQL-G63', 231, 'insert into TransX (KeyID, GL, TP, Contract, ReinName, TTY, Amt1) (Select KeyID,Descr as GL, TP, Contract, ReinName, Field2 as TTY, Amt1 * cast(Field3 as int) as Amt1 from TransX inner join Misc_Tables on GL = ID where KeyID = ''[batchID]'' and Table_ID = ''ElimGLmap7'' )'),
    ('SQL-R25', 211, 'update TransX set GLdesc = c.Name from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-M25', 601, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''1) RI'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and SubProd = ''G26'' and (GL = ''1099917'' or GL = ''2851017'' or substring(GL,1,4) in (''3572'',''3590'',''3591'',''3592'',''4398'')) and Flex5 = ''4) Other'')'),
    ('SQL-M25', 602, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G26'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''4) Other'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and SubProd = ''G26'' and (GL = ''1099917'' or GL = ''2851017'' or substring(GL,1,4) in (''3572'',''3590'',''3591'',''3592'',''4398'')) and Flex5 = ''4) Other'')'),
    ('SQL-M25', 712, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY = c.TTY and c.BC_From = '''' and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL'),
    ('SQL-M25', 713, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY like c.TTY and c.BC_From = '''' and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL'),
    ('SQL-M25', 721, 'update TransX set  BusCat = '''' where KeyID = ''[batchID]'' and not substring(GL,1,1) in (''4'',''5'') and not substring(GL,1,3) in (''283'',''284'')'),
    ('SQL-M25', 722, 'update TransX set  BusCat = '''' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''46'',''56'')'),
    ('SQL-M25', 731, 'update t set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-G27', 231, 'insert into TransX (KeyID, GL, PC, Amt3, Flex1) (Select ''[batchID]'' as KeyID, substring(GL,3,1), substring(PC,1,6), round(sum(Amt3),2) as Amt3, ''pass1'' from TransX where KeyID = ''[batchID]-data2'' group by substring(GL,3,1),substring(PC,1,6))'),
    ('SQL-G27', 232, 'update TransX set Amt3 = 1 where KeyID = ''[batchID]'' and PC = ''550000'' and GL = ''6'''),
    ('SQL-G27', 233, 'update TransX set Amt3 = -1 where KeyID = ''[batchID]'' and PC = ''550000'' and GL = ''5'''),
    ('SQL-P00', 1052, 'update TransX set Amt1 = round(-Amt1,2), Amt3 = round(-Amt3,2) where KeyID = ''[batchID]'' and TP <> '''''),
    ('SQL-G28', 399, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G28', 801, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-G23', 222, 'delete from TransX where KeyID = ''[batchID]'''),
    ('SQL-G23', 223, 'delete from TransX where KeyID = ''[batchID]-data2'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G23', 231, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Amt1, Amt2, Amt3) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]-data2'')'),
    ('SQL-G23', 237, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, BusCat, TTY, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, ''3870002'' as GL, Crcy, PC, TP, '''' as BusCat, ''640'' as TTY, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' and ''[yyyy-mm-dd]'' = ''2022-01-31'' group by KeyID, Co,  Crcy, PC, TP)'),
    ('SQL-G23', 243, 'Update t set Flex1 = m.Field3, Flex2 = m.Field4, Flex3 = m.Field5, Flex4 = m.Field6 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Rev Offset'' and t.GL = m.Descr and t.BusCat = m.Field1 where t.KeyID = ''[batchID]'' and t.Flex1 is NULL and m.Field2 = '''' and not ''[yyyy-mm-dd]'' = ''2022-01-31'''),
    ('SQL-T05', 101, 'insert into TransX (KeyID,GL,GLdesc,Flex1,FSitem,FSitemDesc,CC,Zone,Flex2,Flex3,Flex4,Flex5,Flex6,RefKey1,RefKey2,RefKey3,Broker) (Select ''[batchID]'',GL, Name, Descr,f.FSitem, FSitemDesc, Blocked, BSorPL, FXCaption, FXCaptionRecon, Grp, CreatedBy, convert(varchar,CreatedOn,101) as CreatedOn, ''yes'' as RefKey1, ''yes'' as RefKey2, ''yes'' as RefKey3,Restricted from COA c left join FSitems F on GL >= FromGL and GL <= ThruGL and len(f.FSitem)=7)'),
    ('SQL-T05', 110, 'update TransX set PC = FSG from TransX t inner join COAxCo c on t.GL = c.GL where KeyID = ''[batchID]'' and t.PC is NULL'),
    ('SQL-T05', 111, 'update TransX set PCdesc = f.Descr from TransX t inner join FSG f on t.PC = f.FSG where KeyID = ''[batchID]'''),
    ('SQL-T05', 121, 'update TransX set Flex8 = ''GL: '' + substring(Flex8,6,999) from TransX where KeyID = ''[batchID]'' and Flex8 like ''GL: ,%'''),
    ('SQL-T05', 122, 'update TransX set Flex8 = ''GL: '' + substring(Flex8,10,999) from TransX where KeyID = ''[batchID]'' and substring(Flex8,5,4) = substring(Flex8,10,4)'),
    ('SQL-T05', 123, 'update TransX set Flex8 = ''GL: '' + substring(Flex8,10,999) from TransX where KeyID = ''[batchID]'' and substring(Flex8,5,4) = substring(Flex8,10,4)'),
    ('SQL-T05', 124, 'update TransX set Flex8 = substring(Flex8,1,9) + substring(Flex8,15,999) from TransX where KeyID = ''[batchID]'' and substring(Flex8,10,4) = substring(Flex8,15,4)'),
    ('SQL-T05', 126, 'update TransX set Flex8 = '''' from TransX where KeyID = ''[batchID]'' and Flex8 = ''GL: '''),
    ('SQL-T05', 128, 'update TransX set RefKey2 = ''no'' from TransX t inner join Sets s on t.GL >= s.FromVal and t.GL <= s.ThruVal where KeyID = ''[batchID]'' and s.ID in (''ZGL017'',''ZGL018'',''ZGL056'',''ZGL062'')'),
    ('SQL-T05', 129, 'update TransX set RefKey3 = ''no'' from TransX t inner join Sets s on t.GL >= s.FromVal and t.GL <= s.ThruVal where KeyID = ''[batchID]'' and s.ID in (''ZGL017'',''ZGL018'',''ZGL027'')'),
    ('SQL-M17', 561, 'update TransX set Flex4 = Flex4 + '' (Alex Start)'' where KeyID = ''[batchID]'' and Flex4 like ''01 %'' and TP = '''' and not Co in (''2999'',''3999'') and not PC in (''4020200070'',''5702999000'') and (substring(GL,1,2) in (''18'',''20'',''21'',''23'') or substring(GL,1,3) in (''131'',''141'',''142'',''143'',''144'',''145'',''151'',''159'',''283'',''284'',''287'') or (substring(GL,1,3) in (''148'',''282'') and PC = ''4020100070''))'),
    ('SQL-M17', 581, 'update TransX set Flex4 = Flex4 + '' (Alex ADJ)'' where KeyID = ''[batchID]'' and Flex4 like ''02 % clear%'' and TP = '''' and not Co in (''2999'',''3999'') and not PC in (''4020200070'',''5702999000'') and (substring(GL,1,2) in (''18'',''20'',''21'',''23'') or substring(GL,1,3) in (''131'',''141'',''142'',''143'',''144'',''145'',''151'',''159'',''283'',''284'',''287'') or (substring(GL,1,3) in (''148'',''282'') and PC = ''4020100070''))'),
    ('SQL-M17', 611, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, ''Topside JE17'' as Txt, Amt1, ''2052'' as FSitem, '' Other taxes payable (including sales tax, VAT, capital and payroll tax) '' as Flex1, ''01. Accounts Payable and Accrued Liabilities'' as Flex2, Flex3, ''02 Other clear'' as Flex4, ''29. Accounts Payable and Accrued Liabilities'' as Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and GL in (''2550001'',''2550002'')) a )'),
    ('SQL-M17', 412, 'update t set Flex2 = m.Descr from TransX t inner join Misc_Tables m on t.Flex3 = m.Field1 and m.Table_ID = ''M17 FS'' and m.Descr like (case when t.Flex3 = ''3-Equity'' then ''%Retained Earnings%'' else ''%Accounts Payable%'' end) where KeyID = ''[batchID]'' and Co = ''fill'''),
    ('SQL-S20', 501, 'Insert into TransX (KeyID,Ledger,Co,GL,GLdesc,Flex1) (select distinct ''[batchID]-data3'' as KeyID,x.Ledger,x.Co,x.GL,x.GLdesc,''Please extend GL# to Co#'' as Flex1 from TransX x left join COAxCo c on x.Co = c.Co and x.GL = c.GL where KeyID = ''[batchID]'' and c.Co is NULL)'),
    ('SQL-S20', 502, 'Insert into TransX (KeyID,Ledger,Co,GL,GLdesc,Flex1) (select distinct ''[batchID]-data3'' as KeyID,x.Ledger,x.Co,x.GL,x.GLdesc,''Please unblock GL# on Co#'' as Flex1 from TransX x inner join COAxCo c on x.Co = c.Co and x.GL = c.GL where KeyID = ''[batchID]'' and c.Blocked in (''Yes'',''Del''))'),
    ('SQL-S20', 599, 'Insert into TransX (KeyID,Ledger,Co,GL,GLdesc,Flex1) (select ''[batchID]-data3'' as KeyID, '''' as Ledger,'''' as Co,'''' as GL, '''' as GLdesc,''no errors'' as Flex1 from (Select count(*) as cnt from TransX where KeyID = ''[batchID]-data3'' ) a where cnt = 0)'),
    ('SQL-S20', 611, 'Insert into TransX (KeyID,Flex1,Flex2,Division,Region,Location,Zone) (select ''[batchID]-data4'' as KeyID, x.ID as Flex1, y.ID as Flex2, y.Field_Name as Division, y.From_ID as Region, y.Thru_ID as  Location, y.Incl_Excl as Zone from FX_Variant_Detail x inner join FX_Select_Detail y on x.FX_Select_ID = y.ID where x.ID = ''[version]'')'),
    ('SQL-G28', 802, 'update TransX set SubProd = ''G28'', Flex1 = '''' from TransX where KeyID = ''[batchID]'''),
    ('SQL-G28', 803, 'update TransX set Flex2 = p.Descr from TransX t inner join PTFs p on t.PTF = p.PTF where KeyID in (''[batchID]'',''[batchID]-data8'')'),
    ('SQL-S07', 212, 'update TransX set Flex3 = Descr, TPname = ID from TransX inner join (select min(Descr) as Descr, min(ID) as ID, Field2 from Misc_Tables where Table_ID = ''HUD_STM_Contracts'' group by Field2) a on Contract = Field2 where KeyID = ''[batchID]''  and Co = ''2008'''),
    ('SQL-S07', 213, 'update TransX set TPname = Contract from TransX where KeyID = ''[batchID]'' and Co = ''2008'''),
