    ('SQL-S07', 301, 'update TransX set Flex4 = Field2, Flex2 = Field3 from TransX inner join Misc_Tables on Contract = ID where KeyID = ''[batchID]'' and Table_ID = ''HUD_STM_Contracts'' and Co in (''2300'',''2400'',''2450'')'),
    ('SQL-S07', 302, 'update TransX set Flex4 = Contract from TransX where Co = ''2008'''),
    ('SQL-S07', 401, 'insert into TransX (KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWyr,TTY,Flex1,Flex2,Flex4, Amt1) (select KeyID, Ledger, Co, GL, PC, isnull(CC,''''), TP, BusCat, Contract, UWyr,TTY, ''pass1'', Flex2,Flex4, Amt1 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-S07', 501, 'update TransX set Amt1 = round(0-Amt1,2), Flex1 = ''pass2'' from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-S07', 503, 'update TransX set GL = m.Descr, GLdesc = c.Descr, Contract = t.Flex4, TP = Co, Co = ''2008'', Flex1 = ''pass3'', BusCat = ''21'' from TransX t inner join Misc_Tables m on GL = ID inner join COA c on t.GL = c.GL where Table_ID = ''ElimGLmap3'' and KeyID = ''[batchID]'' and t.Flex1 = ''pass2'' and Co <> ''2008'''),
    ('SQL-S07', 505, 'update TransX set GL = substring(GL,1,3) + ''9901'' from TransX where KeyID = ''[batchID]'' and Flex1 <> ''pass1'' and GL like ''%9900'''),
    ('SQL-S07', 508, 'insert into TransX (KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1) (Select KeyID, Ledger, Co, GL, '''' as PC, '''' as CC, '''' as TP, '''' as BusCat, Contract, isnull(UWYR,'''') as UWYR, '''' as TTY, round(sum(Amt1),2) as Amt1, ''pass4'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1 <> ''pass1'' and GL > ''4000000'' group by KeyID, Ledger, Co, GL,  Contract, isnull(UWYR,''''))'),
    ('SQL-S07', 509, 'delete from TransX where KeyID = ''[batchID]'' and (Flex1 in (''pass2'',''pass3'') or Amt1 = 0)'),
    ('SQL-S07', 510, 'update TransX set Amt2 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
    ('SQL-S07', 513, 'update TransX set Ledger = ''Z000'' from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' and Amt1 = Amt3 and Amt1 = Amt4'),
