    ('SQL-E00', 1020, 'update TransX set BusCat = '''' where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-E00', 1025, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, PC, TP, BusCat, Contract, TTY, UWyr, Amt1) (select (KeyID + ''-save'') as KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, PC, TP, BusCat,Contract, TTY, UWyr, Amt1 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G64', 257, 'update TransX set Broker = ''UNKNOWN'' from TransX t inner join [GFS].dbo.FSGValidation v on GL = GLAccount where KeyID = ''[batchID]'' and v.Broker = 1'),
    ('SQL-E00', 1070, 'insert into TransX (KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1) (Select KeyID, Ledger, Co, GL, PC, isnull(CC,'''') as CC, TP, BusCat, Contract, isnull(UWYR,'''') as UWYR, TTY, round(sum(Amt1),2) as Amt1, ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Co, GL, PC, isnull(CC,''''), TP, BusCat, Contract, isnull(UWYR,''''), TTY)'),
    ('SQL-E00', 1080, 'delete from TransX where KeyID = ''[batchID]'' and (Flex1 is null or Amt1 = 0)'),
