    ('SQL-S43', 202, 'delete from TransX where KeyID = ''[batchID]'' and GL in (''1439900x'',''1439901x'',''2039900x'',''2039901x'',''5339900x'',''5339901x'',''1819900'',''2879900'',''5519900'',''1819901'',''2879901'',''5519901'')'),
    ('SQL-S43', 203, 'update TransX set Amt1 = round(0-Amt2,2), UWYR = coalesce(UWYR,'''') from TransX where KeyID = ''[batchID]'''),
    ('SQL-S43', 503, 'update TransX set GL = m.Descr, GLdesc = c.Descr from TransX t inner join Misc_Tables m on GL = ID inner join COA c on t.GL = c.GL where Table_ID = ''ElimGLmap3'' and KeyID = ''[batchID]''  and Co <> ''2008'''),
    ('SQL-S43', 505, 'update TransX set GL = substring(GL,1,3) + ''9901'' from TransX where KeyID = ''[batchID]'' and GL like ''%9900'''),
    ('SQL-S43', 508, 'insert into TransX (KeyID, Ledger, GL, UWYR, Amt1, Flex1) (Select KeyID, Ledger,GL, UWYR, round(sum(Amt1),2) as Amt1, ''pass4'' as Flex1 from TransX where KeyID = ''[batchID]'' and GL > ''4000000'' group by KeyID, Ledger, GL, UWYR)'),
    ('SQL-S43', 509, 'delete from TransX where KeyID = ''[batchID]'' and (Flex1 is NULL or Amt1 = 0)'),
    ('SQL-S43', 510, 'update TransX set Amt2 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, GL, UWYR, Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.GL = f2.GL and f1.UWYR = f2.UWYR and f1.Amt1 = f2.Amt1'),
    ('SQL-M17', 411, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex5, Flex3) (Select ''[batchID]'' as KeyID, ''fill'' as Co, ''fill'' as GL, '''' as TTY, '''' as TP, '''' as BusCat, '''' as CC, '''' as PC, ''4-IFRS'' as Txt, 0 as Amt1, ''fill'' as FSitem, ''fill'' as Flex1, Descr as Flex5, Field1 as Flex3 from Misc_Tables where Table_ID = ''M17 QIS'' and not Descr in (select distinct Flex5 from TransX where  KeyID = ''[batchID]''))'),
    ('SQL-M17', 513, 'update TransX set Flex4 = Flex4 + ''LIC Assumed E49'' where KeyID = ''[batchID]'' and substring(GL,1,3) in (''283'',''284'')'),
