    ('SQL-M17', 541, 'update TransX set Flex4 = Flex4 + ''LRC Ceded H47'' where KeyID = ''[batchID]'' and substring(GL,1,3) in (''151'',''159'')'),
    ('SQL-M17', 572, 'update TransX set Flex4 = Flex4 + '' clear'' where KeyID = ''[batchID]'' and Flex4 like ''02 %'' and not Txt = ''RI'' and not substring(GL,1,3) in (''155'',''156'',''157'',''215'',''216'',''217'') and not Co = ''JE'''),
