    ('SQL-R16f', 112, 'update TransX set Amt4 = Round(Amt1*r.rate/rc.rate,2) from TransX t inner join CrcyRates r on t.Crcy = r.Crcy inner join Companies c on t.Co = c.Co inner join CrcyRates rc on c.Crcy = rc.Crcy where KeyID = ''[batchID]'' and r.EffDate = ''[yyyy-mm-dd]'' and rc.EffDate = ''[yyyy-mm-dd]'' and r.Typ = ''S'' and rc.Typ = ''S''  and GL < ''2870000'' and not GL like ''%96'' and not GL like ''%98'' and not SUBSTRING(GL,1,4) in (''1320'') and not SUBSTRING(GL,1,3) in (''151'',''162'',''211'',''242'') and not t.PC in (''220CSIC000'',''221CSIC000'',''341CSIC000'') and Flex1 = ''pass3'' and not t.crcy = rc.crcy'),
