    ('SQL-G41', 222, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-sum(coalesce(Amt1,0)),2) as Amt1, round(-sum(coalesce(Amt2,0)),2) as Amt2,  round(-sum(coalesce(Amt3,0)),2) as Amt3,  ''40'' as PK from TransX where KeyID = ''[batchID]'' and (Amt1 < 0 or Amt2 < 0 or Amt3 < 0) and PK is NULL group by KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF)'),
