    ('SQL-G41', 242, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '''' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2, round(-Amt3,2) as Amt3,''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''50'' and substring(GL,4,2) = ''89'' and TP <> '''')'),
