    ('SQL-M26', 311, 'update x set Flex1 = y.Descr, Flex3 = y.Field1 from TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''IC Validations'' and y.Field2 = x.GL where x.KeyID = ''[batchID]'' and x.Flex1 is NULL and y.Field3 = '''' and y.Field4 = '''''),
    ('SQL-M26', 312, 'update x set Flex1 = y.Descr, Flex3 = y.Field1 from TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''IC Validations'' and y.Field2 <= x.GL and y.Field3 >= x.GL and y.Field4 <= x.BusCat and y.Field5 >= x.BusCat where x.KeyID = ''[batchID]'' and x.Flex1 is NULL and y.Field5 <> '''''),
