    ('SQL-R15', 217, 'update TransX set Amt2 = -Amt1 from TransX where KeyID = ''[batchID]'' and substring(GL,1,1) = ''2'' and not (Flex1 = ''Ceded'' and substring(GL,1,2) = ''28'') and not GL = ''2854600'''),
    ('SQL-R57', 111, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
