    ('SQL-R57', 122, 'update TransX set Flex1 = c.SAPname from TransX t inner join Companies c on t.CO = c.CO where KeyID = ''[batchID]'''),
    ('SQL-R57', 123, 'update TransX set Hierarchy = p.Hierarchy, PCdesc = p.Descr from TransX t inner join PCTRS p on t.PC = p.PCTR  where KeyID = ''[batchID]'''),
    ('SQL-M42', 224, 'update TransX set Flex6 = Mapkey from TransX t inner join mapkeyranges m on t.GL >= m.fromGL and t.GL <=m.thruGL where keyID = ''[batchID]'' and mapkey like ''M1-_-%-%-%'' and not mapkey like ''M1-_-%-%-%-%'''),
    ('SQL-M42', 225, 'update TransX set Flex7 = m.Name from TransX t inner join mapkeys m on t.flex6 = m.mapkey where keyID = ''[batchID]'''),
    ('SQL-M42', 302, 'Update x set Flex8 = x.Flex2 + ''-'' + m1.field3 + ''-'' + x.Flex5, Division = m1.field2 from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' where KeyID = ''[batchID]'''),
    ('SQL-M42', 303, 'Update x set Flex5 = m2.field2 from TransX x inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-M42', 304, 'Update TransX set TPname = CASE WHEN TP = '''' THEN ''3rd'' WHEN SUBSTRING(TP,1,1) = ''F'' THEN ''FFH'' ELSE ''ODY'' END where KeyID = ''[batchID]'''),
    ('SQL-M42', 305, 'Update TransX set Flex4 = CASE WHEN TTY IN ('''',''821'',''822'') THEN ''Incurred'' ELSE ''Other'' END where KeyID = ''[batchID]'''),
