    ('SQL-G39', 305, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''4060200317'' as PC, ''4HE''+SUBSTRING(CC,4,1)+''200317'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''1406000362'')'),
    ('SQL-G39', 306, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''1406000363'' as PC, ''1US''+SUBSTRING(CC,4,1)+''600363'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode,ROUND(0-ROUND(Amt1/3,2)*2,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''1406000362'')'),
    ('SQL-G39', 307, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''1406000364'' as PC, ''1US''+SUBSTRING(CC,4,1)+''600364'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''3991061407'')'),
    ('SQL-G39', 308, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''4060200317'' as PC, ''4HE''+SUBSTRING(CC,4,1)+''200317'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''3991061407'')'),
    ('SQL-G39', 309, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''3991061408'' as PC, ''3NS''+SUBSTRING(CC,4,1)+''101408'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode,ROUND(0-ROUND(Amt1/3,2)*2,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''3991061407'')'),
    ('SQL-R22', 304, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Ledger,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2) (select KeyID + ''-data2'', ''4. FX Impact'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Ledger,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2 from TransX where KeyID = ''[batchID]'' and Flex1 = ''FX-Adj'')'),
    ('SQL-R22', 305, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Ledger,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2) (select KeyID + ''-data2'', ''5. Acq/Divest'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Ledger,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2 from TransX where KeyID = ''[batchID]'' and Flex1 = ''Purch/Sale'')'),
