    ('SQL-S32', 311, 'insert into TransX (KeyID, YearPeriod,Yr,Period,Ledger, Co, GL, PC, CC, BusCat, Amt1, Flex1) (Select KeyID, YearPeriod,Yr,Period, Ledger, Co, Descr as GL,PC, '''' as CC,BusCat,0-Amt1 as Amt1, ''pass2'' as Flex1 from TransX inner join Misc_Tables on GL = ID and BusCat = Field1 where KeyID = ''[batchID]'' and Table_ID = ''ElimGLmap5'' and GL >= ''4000000'' and GL < ''6000000'' and GL <> ''4498000'' and BusCat = ''30'')'),
    ('SQL-S32', 312, 'insert into TransX (KeyID, YearPeriod,Yr,Period,Ledger, Co, GL, PC, CC, BusCat, Amt1, Flex1) (Select KeyID, YearPeriod,Yr,Period, Ledger, Co, Descr as GL,PC, '''' as CC,BusCat,0-Amt1 as Amt1, ''pass2'' as Flex1 from TransX inner join Misc_Tables on GL = ID and Field1 = '''' where KeyID = ''[batchID]'' and Table_ID = ''ElimGLmap5'' and GL >= ''4000000'' and GL < ''6000000'' and GL <> ''4498000'' and BusCat <> ''30'')'),
    ('SQL-S32', 313, 'insert into TransX (KeyID, YearPeriod,Yr,Period,Ledger, Co, GL, PC, CC, BusCat, Amt1, Flex1) (Select KeyID, YearPeriod,Yr,t.Period, Ledger, t.Co, Descr as GL,DefaultPC as PC,'''' as CC,BusCat,0-Amt1 as Amt1, ''pass2'' as Flex1 from TransX t inner join Misc_Tables on ID = ''default'' inner join companies c on t.co = c.co where KeyID = ''[batchID]'' and Table_ID = ''ElimGLmap5'' and( GL >= ''6000000'' or GL = ''4498000''))'),
