    ('SQL-M42', 404, 'delete from TransX where KeyID = ''[batchID]'' and GL >= ''5210000'' and GL <= ''5299999'''),
    ('SQL-M42', 423, 'insert into TransX (KeyID,Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt3) (select KeyID,''pass2'' as Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Yr <> [Yr] and Flex1 is NULL)'),
    ('SQL-M42', 424, 'insert into TransX (KeyID,Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt2,Amt4) (select KeyID,''pass2'' as Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Flex1 is NULL)'),
    ('SQL-M42', 425, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-M42', 426, 'insert into TransX (KeyID,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2,Amt3,Amt4) (select KeyID,UWYr,Crcy,Flex2,Division,Flex5,Flex8,ROUND(SUM(COALESCE(Amt1,0)),2),ROUND(SUM(COALESCE(Amt2,0)),2),ROUND(SUM(COALESCE(Amt3,0)),2),ROUND(SUM(COALESCE(Amt4,0)),2) from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass2'' group by KeyID,UWYr,Crcy,Flex2,Division,Flex5,Flex8)'),
