    ('SQL-S22', 471, 'update CedingCoByQtr set Flex3 = replace(replace(replace(replace(Flex3,''american'',''am''),''america'',''am''),''north amer'',''n am''),''amer '',''am '') where Yr = ''[Yr]'' and Per = ''[Mo]'' and Flex2 is NULL'),
