    ('SQL-R16c', 120, 'insert into TransX (KeyID, Co, Crcy, GL, TP, ReinName, BusCat,Contract,uwyr,PC, Amt1, Amt2, Amt3, Flex1) (Select KeyID, Co, Crcy, GL, TP, '''' as ReinName, BusCat,'''' as Contract,'''' as uwyr,PC, 0 as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, ''pass4'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass3'' group by KeyID, Co, Crcy, GL, TP, BusCat,PC)'),
    ('SQL-R16c', 121, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass3'''),
    ('SQL-R16c', 111, 'update TransX set Amt4 = Round(Amt1*r.rate/rc.rate,2) from TransX t inner join CrcyRates r on t.Crcy = r.Crcy inner join Companies c on t.Co = c.Co inner join CrcyRates rc on c.Crcy = rc.Crcy where KeyID = ''[batchID]'' and r.EffDate = ''[yyyy-mm-dd]'' and rc.EffDate = ''[yyyy-mm-dd]'' and r.Typ = ''S'' and rc.Typ = ''S''  and GL < ''2870000'' and not GL like ''%96'' and not GL like ''%98'' and not SUBSTRING(GL,1,4) in (''1320'') and not SUBSTRING(GL,1,3) in (''151'',''162'',''211'',''242'') and not t.PC in (''220CSIC000'',''221CSIC000'',''341CSIC000'') and not t.crcy = rc.crcy'),
    ('SQL-R16c', 118, 'insert into TransX (KeyID, Co, Crcy, GL, TP, ReinName, BusCat,Contract,uwyr,PC, Amt1, Amt2, Amt3, Flex1) (Select KeyID, Co, Crcy, Flex1 as GL, TP, ReinName, BusCat,Contract,uwyr,PC, 0 as Amt1, round(sum(Amt4),2) as Amt2, round(sum(Amt1),2) as Amt3, ''pass2'' as Flex1 from TransX where KeyID = ''[batchID]'' and not Flex1 in (''pass1'',''pass3'') and not Amt4 is NULL group by KeyID, Co, Crcy, Flex1, TP, ReinName, BusCat,Contract,uwyr,PC)'),
    ('SQL-S02', 320, 'insert into TransX (KeyID, Contract, yearperiod, Flex1, UWYR, Co, Amt1, GL, PC, Flex2, Ledger, TP, BusCat, TTY) SELECT ''[batchID]'',policy, substring(yearperiod,1,6), sub_contract,UWYR,company,round(cast(amt1 as money),2),gl,orc_pc,hud_pc,ledger,tp,buscat,tty from CorpAcct_Apps.dbo.S02_FRS_Entries'),
    ('SQL-R16c', 119, 'insert into TransX (KeyID, Co, Crcy, GL, TP, ReinName, BusCat,Contract,uwyr,PC, Amt1, Amt2, Amt3, Flex1) (Select KeyID, Co, Crcy, GL, TP, '''' as ReinName, BusCat,'''' as Contract,'''' as uwyr,PC, 0 as Amt1, round(-sum(Amt2),2) as Amt2, round(-sum(Amt3),2) as Amt3, ''pass3'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1  =''pass2'' group by KeyID, Co, Crcy, GL, TP, BusCat,PC)'),
