    ('SQL-R28', 241, 'insert into TransX (KeyID, Amt4,Flex1,Yr,Qtr,Flex2,Period,Flex7,Flex8,Flex9) (select KeyID,round(0-Amt4,2) as Amt4,Flex2,Period,Qtr,Flex1,Yr,Flex8,Flex7, ''z'' as Flex9 from TransX where KeyID = ''[batchID]'' and not GL in (''1000000'',''4000000'') )'),
    ('SQL-S22', 421, 'insert into CedingCoByQtr (CedingCo,Yr,Per,SAP_CedingCo,SAP_Name,NAIC,FedID,RSG_CedingCo,RSG_Name,FFH_Aff,ORH_Aff) (select c.CedingCo, c.Yr, c.Per, c.CedingCo, b.Name, b.NAIC, B.FedID ,c.Flex1, c.Flex2,c.ReinType1,c.ReinType2 from (select CedingCo,Yr,Per,max(Flex1) as Flex1,max(Flex2) as Flex2, max(ReinType1) as ReinType1, max(ReinType2) as ReinType2, count(*) as cnt from CedingCoByQtrContractUWYR  where Yr = ''2021'' and Per = ''6'' group by CedingCo,Yr,Per) c left join Brokers b on c.CedingCo = b.Broker where c.Yr = ''[Yr]'' and c.Per = ''[Mo]'')'),
    ('SQL-R70', 210, 'update TransX set Flex1 = ''3075'', Flex2 = ''FIRV 2001'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2001'' and PC like ''6%'' and Contract like ''%3075%'''),
    ('SQL-R70', 211, 'update TransX set Flex1 = ''3030'', Flex2 = ''FIRV 2001'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2001'' and PC like ''6%'' and Flex1 = '''''),
    ('SQL-R70', 212, 'update TransX set Flex1 = ''2001'', Flex2 = ''FIRV 3030'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''3030'' and PC like ''6%'''),
    ('SQL-R70', 213, 'update TransX set Flex1 = ''2008'', Flex2 = ''HUD ST 2300'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2300'' and Contract like ''% 2008'' and Flex1 = '''''),
    ('SQL-R70', 214, 'update TransX set Flex1 = ''2008'', Flex2 = ''HUD ST 2400'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2400'' and Contract like ''% 2008'' and Flex1 = '''''),
