    ('SQL-G24', 415, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, PTF, Assgnmt, ProdCode, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, PTF, Assgnmt, ProdCode, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' group by KeyID, Co, GL, Crcy, PC, TTY, TP, PTF, Assgnmt, ProdCode)'),
    ('SQL-G71', 102, 'delete from TransX where KeyID = ''[batchID]'' and CC = ''5USA000032'' and Contract  = '''''),
