    ('SQL-M41', 421, 'insert into TransX (KeyID,Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt3) (select KeyID,''pass2'' as Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Yr <> [Yr] and SUBSTRING(GL,1,1) = ''4'' and Flex1 is NULL)'),
