    ('SQL-G24', 302, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, ''607'' as TTY, '''' as TP, PC, ''U1804'' as ProdCode, '''' as PTF, Assgnmt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and ''[yyyy-mm-dd]'' <> ''2022-01-31'' and GL in (''4630000'',''5630000'') group by KeyID, Co, Crcy, PC, Assgnmt)'),
    ('SQL-G29', 202, 'delete from TransX where KeyID = ''[batchID]'' and contract like ''BULK%'' and (substring(GL,1,2) in (''15'',''18'',''21'',''40'',''41'',''50'',''51'',''54'',''55'') or substring(GL,1,3) in (''131'',''231'',''287'') or GL in (''1480000'',''1480001'',''1480002'',''1480003'',''2210000'',''2210001'',''2820000'') or (GL >= ''5211000'' and GL <= ''5299999''))'),
