    ('SQL-G31', 447, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, coalesce(ProdCode,''''), coalesce(PTF,''''), round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''2'' group by KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, coalesce(ProdCode,''''), coalesce(PTF,''''))'),
    ('SQL-G31', 451, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-G31', 452, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-R82', 202, 'insert into TransX (KeyID,Flex1,Crcy,Flex2,Flex3,Date1,Period,Rate1,Flex4,Amt2,Amt3,Flex5,Flex6,Flex7) (select ''[batchID]'',''''''01'',r.Crcy,''USD'',''MAVG'',''[yyyy-mm-dd]'',0,round(avg(round(1/r.rate/c.xfactor,5)),5) as rate,'''',c.xfactor,1,'''','''','''' from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where r.Typ = ''M'' and year(r.EffDate) = ''[Yr]'' and month(r.EffDate) = ''[Mo]'' and r.Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by r.Crcy,c.xfactor)'),
    ('SQL-R82', 401, 'delete from CrcyRates where Typ = ''MAVG'' and EffDate = ''[yyyy-mm-dd]'''),
    ('SQL-R82', 402, 'insert into CrcyRates (Typ,EffDate,Crcy,Rate) (select ''MAVG'',''[yyyy-mm-dd]'',r.Crcy,1/round(avg(round(1/r.rate,5)),5) from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where r.Typ = ''M'' and year(r.EffDate) = ''[Yr]'' and month(r.EffDate) = ''[Mo]'' and r.Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by r.Crcy)'),
    ('SQL-R82', 403, 'insert into CrcyRates (Typ,EffDate,Crcy,Rate) (select ''MAVG'',''[yyyy-mm-dd]'',Crcy,avg(rate) from CrcyRates where Typ = ''M'' and year(EffDate) = ''[Yr]'' and month(EffDate) = ''[Mo]'' and not Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by Crcy)'),
    ('SQL-R82', 702, 'delete from CrcyRates where Typ = ''Y'' and EffDate = ''[yyyy-mm-dd]'''),
    ('SQL-R82', 703, 'insert into CrcyRates (Typ,EffDate,Crcy,Rate) (select ''Y'',''[yyyy-mm-dd]'',r.Crcy,1/round(avg(round(1/r.rate,5)),5) from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where r.Typ = ''M'' and year(r.EffDate) = ''[Yr]'' and r.Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by r.Crcy)'),
