    ('SQL-G38', 231, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, BusCat, TTY, Contract, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1999901'' as GL, Crcy, ''3990000000'' as PC, ''3030'' as TP, '''' as BusCat, '''' as TTY, '''' as Contract, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, Crcy)'),
