    ('SQL-S06', 503, 'update TransX set GL = m.Descr, GLdesc = c.Descr, Contract = t.Flex4, TP = Co, Co = ''2200'', Flex1 = ''pass3'', BusCat = ''21'' from TransX t inner join Misc_Tables m on GL = ID inner join COA c on t.GL = c.GL where Table_ID = ''ElimGLmap3'' and KeyID = ''[batchID]'' and t.Flex1 = ''pass2'' and Co <> ''2200'''),
