    ('SQL-R33', 206, 'insert into TransX (KeyID, Co, GL, Amt1, Amt2, Amt3, Amt4, Amt5, Flex1) (select KeyID, Co, GL, Amt1, Amt2, Amt3, Amt4, Amt5, ''M2-3-6-06-04-01'' as Flex1 from TransX inner join MapKeyRanges on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and MapKey = ''M2-3-6-06-04-01'' )'),
    ('SQL-R51', 107, 'update TransX set Flex3 = ''(2) Elim'' from TransX where KeyID = ''[batchID]'' and Co = ''2999'''),
    ('SQL-R25', 257, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, '''' as BusCat, '''' as Contract, ''AW'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''287%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 inner join (Select Crcy,PC,GL,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''189%'' and Flex1 = ''FX'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and substring(f1.GL,4,4) = substring(f2.GL,4,4) where f2.Amt1 <> 0 or f2.Amt2 <> 0)'),
    ('SQL-R25', 258, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '''' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''287%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 left join (Select Crcy,PC,GL,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''287%'' and Flex1 = ''FX'' and UWYR = ''AW'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)'),
    ('SQL-R50', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R50', 102, 'delete from TransX where KeyID = ''[batchID]'' and TTY in (''810'',''815'')'),
