    ('SQL-S02', 323, 'update TransX set Flex3 = ''m - Treaty'', Flex4 = orc_contract, TPname = orc_contract from TransX t inner join CorpAcct_Apps.dbo.S02_Contract_Map m on contract = policy_no  where KeyID = ''[batchID]'''),
    ('SQL-R50', 211, 'insert into TransX (KeyID, Co, Amt1, Flex1) (select KeyID + ''-save'', ''2xxx'' as Co, round(sum(Amt1),2) as Amt1, ''5001'' as Flex1 from TransX where KeyID = ''[batchID]'' and GL in (''1480001'',''2310001'')  and TTY = ''807'' and Co > ''2000'' and Co < ''3000'' group by KeyID)'),
    ('SQL-R03', 201, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R03', 202, 'update TransX set PCdesc = p.Descr, Region = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR where KeyID = ''[batchID]'''),
