    ('SQL-S38', 201, 'update TransX set Flex2 = ''Expenses - Pre-Allocation'' from TransX where KeyID = ''[batchID]'' and (GL like ''6%'' or GL like ''7%'') and BusCat <> ''99'' and BusCat <> ''98'''),
    ('SQL-E00', 1060, 'delete from TransX where KeyID = ''[batchID]'' and Co <> ''[ElimCo]'''),
    ('SQL-E00', 1171, 'insert into TransX (KeyID, Ledger, Co, GL, TP, PC, Contract, TTY, Amt1,Flex1) (select KeyID, Ledger, ''[ElimCo]'', ''1320000'','''' as TP, ''5000000000'' as PC, ''[ContractPrefix]'' as Contract, ''806'', round(0-sum(Amt1),2) as Amt1, ''pass2'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger)'),
    ('SQL-R51', 111, 'update TransX set Flex1 = Descr, Flex4 = Field1 from TransX t inner join Misc_Tables m on substring(t.GL,1,2) = m.ID where KeyID = ''[batchID]'' and Table_ID = ''GL Grp 4'''),
    ('SQL-S04', 505, 'update TransX set GL = substring(GL,1,3) + ''9901'' from TransX where KeyID = ''[batchID]'' and substring(GL, len(GL)-3,4) = ''9900'''),
    ('SQL-R25', 241, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '''' as Contract, ''AW'' as UWYR, ''FX'' as Flex1,''3590099'' as GL,''CTA FX'' as GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''359%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname) f1 inner join (Select Crcy,PC,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''359%'' and Flex1 = ''FX'' group by Crcy,PC) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC where f2.Amt1 <> 0 or f2.Amt2 <> 0)'),
    ('SQL-R25', 242, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '''' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1,''3590099'' as GL,''CTA FX'' as GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''359%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname) f1 left join (Select Crcy,PC,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL = ''3590099'' and UWYR = ''AW'' group by Crcy,PC) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)'),
    ('SQL-R49', 609, 'update TransX set Flex5 = ''7a'', Flex6 = ''NICL QS'' from TransX where KeyID = ''[batchID]'' and coalesce(Flex5,'''') <> ''7'' and Co = ''2999'' and Contract like ''NICL LB%'''),
    ('SQL-R49', 608, 'update TransX set Flex5 = ''103'', Flex6 = ''Tax'' from TransX where KeyID = ''[batchID]'' and Flex5 is Null and substring(GL,1,3) in (''172'',''261'')'),
    ('SQL-R49', 607, 'update TransX set Flex5 = ''4a'', Flex6 = ''ORH Loan'' from TransX where KeyID = ''[batchID]'' and Flex5 is Null and (Co = ''2999'' and GL = ''1320000'' and Contract = ''R/E'') or Contract like ''67612%'' or GL in (''1290500'',''3584000'',''3584000'')'),
    ('SQL-R49', 645, 'update TransX set Flex5 = ''132'', Flex6 = ''Retained Earnings'' where KeyID = ''[batchID]'' and GL like ''361%'' and Flex5 is NULL'),
