    ('SQL-R16c', 146, 'insert into TransX (KeyID, Co, Crcy, GL, TP, BusCat,PC, Amt1, Amt2, Amt3, Flex1) (Select KeyID, Co, Crcy, GL, TP, BusCat,PC, 0 as Amt1, 0 as Amt2, round(-sum(Amt3),2) as Amt3, ''pass3'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1  =''pass2'' group by KeyID, Co, Crcy, GL, TP, BusCat,PC)'),
    ('SQL-R16c', 147, 'insert into TransX (KeyID, Co, Crcy, GL, TP, ReinName, BusCat,Contract,uwyr,PC, Amt1, Amt2, Amt3, Flex1) (Select KeyID, Co, Crcy, GL, TP, '''' as ReinName, BusCat,'''' as Contract,'''' as uwyr,PC, 0 as Amt1, 0 as Amt2, round(sum(Amt3),2) as Amt3, ''pass4'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass3'' group by KeyID, Co, Crcy, GL, TP, BusCat,PC)'),
