    ('SQL-G69', 201, 'insert into TransX (KeyID,GL,TP,PC,Amt1) (select KeyID,GL,TP,''4059000000'' as PC,round(sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' group by KeyID,GL,TP)'),
    ('SQL-G69', 202, 'insert into TransX (KeyID,GL,TP,PC,Amt1) (select KeyID,GL,TP,PC,round(-sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' and not PC = ''4059000000'' group by KeyID,GL,TP,PC)'),
    ('SQL-E00', 1062, 'update TransX set UWyr = year(getdate()) from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and UWYear = 1 and isnull(UWyr,'''') = '''''),
    ('SQL-E00', 1210, 'update TransX set ProdCode = ''UNKNOWN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and Product = 1'),
