    ('SQL-M14', 114, 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and (substring(GL,1,2) in (''14'',''15'',''23'') or GL like ''287%'') and not BusCat in (''A'',''D'',''C'')'),
    ('SQL-G31', 243, 'Update t set Flex1 = m.Field3, Flex2 = m.Field4, Flex3 = m.Field5, Flex4 = m.Field6 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Rev Offset'' and t.GL = m.Descr and t.BusCat = m.Field1 where t.KeyID = ''[batchID]'' and t.Flex1 is NULL and m.Field2 = '''' and not ''[yyyy-mm-dd]'' = ''2022-01-31'''),
    ('SQL-G31', 244, 'Update TransX set Flex1 = ''2851017'', Flex2 = '''', Flex3 = '''', Flex4 = ''1''  where KeyID = ''[batchID]'' and Flex1 is NULL and (GL like ''449%'' or (GL like ''6%'' and not GL like ''682%'')) and not ''[yyyy-mm-dd]'' = ''2022-01-31'''),
    ('SQL-G31', 251, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, PC, TP, BusCat, Amt1, Amt2, Amt3,Flex1,Flex2,Flex3) (Select KeyID, Co, Flex1 as GL, Crcy, Flex3 as TTY, PC, TP, Flex2 as BusCat, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3, Flex1,Flex2,Flex3 from TransX where KeyID = ''[batchID]'' and Flex4 in (''1'',''2''))'),
    ('SQL-G31', 266, 'delete from TransX where KeyID = ''[batchID]'''),
    ('SQL-S01', 212, 'update TransX set Flex3 = Descr, TPname = ID from TransX inner join (select min(Descr) as Descr, min(ID) as ID, Field2 from Misc_Tables where Table_ID = ''HUD_STM_Contracts'' group by Field2) a on Contract = Field2 where KeyID = ''[batchID]''  and Co = ''2008'''),
