    ('SQL-M27', 101, 'delete from TransX where KeyID = ''[batchID]'' and not (substring(GL,1,1) in (''5'',''6'') or substring(GL,1,2) in (''13'',''14'',''15'',''18'',''20'',''21'',''22'',''23'',''40'',''41'') or substring(GL,1,3) in (''282'',''287'',''441''))'),
