    ('SQL-G39', 251, 'update TransX set Amt1 = round(-Amt1,2), flex1 = ''pass1'' where KeyID = ''[batchID]'' and not PC in (''1406000362'',''3991061407'',''4060100317'')'),
    ('SQL-G39', 301, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''1406000364'' as PC, ''1US''+SUBSTRING(CC,4,1)+''600364'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''4060100317'')'),
    ('SQL-G39', 302, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''3991061409'' as PC, ''3NS''+SUBSTRING(CC,4,1)+''101409'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''4060100317'')'),
    ('SQL-G39', 303, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''4060300317'' as PC, ''4HE''+SUBSTRING(CC,4,1)+''300317'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode,ROUND(0-ROUND(Amt1/3,2)*2,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''4060100317'')'),
    ('SQL-G39', 304, 'insert into TransX (KeyID, Co, GL, BusCat, PC, CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, Amt1,flex1) (Select KeyID, Co, GL, BusCat, ''3991061409'' as PC, ''3NS''+SUBSTRING(CC,4,1)+''101409'' as CC, Contract, UWYr,AccYr,Reinloc,Riskterr,Broker,ProdCode,Transcode, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''10406000362'')'),
    ('SQL-G39', 321, 'update TransX set CC = '''' where KeyID = ''[batchID]'' and not GL like ''6%'''),
