    ('SQL-R02', 108, 'update TransX set Flex3 = ''Assumed'' from TransX where KeyID = ''[batchID]'' and (BusCat in (''20'',''21'',''22'',''23'',''24'') or (GL like ''13%'' and BusCat <> ''10''))'),
    ('SQL-R02', 109, 'update TransX set Flex3 = ''Direct'' from TransX where KeyID = ''[batchID]'' and BusCat = ''10'''),
    ('SQL-R02', 110, 'update TransX set Flex4 = m.Descr, Amt3 = cast(m.Field2 as int) * Amt1, Amt4 = cast(m.Field2 as int) * Amt2 from TransX t inner join Misc_Tables m on t.GL >= m.ID and t.GL <= m.Field1 where KeyID = ''[batchID]'' and m.Table_ID = ''GLmap1'' and Flex3 = ''Assumed'''),
    ('SQL-R02', 111, 'update TransX set Flex4 = m.Descr, Amt3 = cast(m.Field3 as int) * Amt1, Amt4 = cast(m.Field3 as int) * Amt2 from TransX t inner join Misc_Tables m on t.GL >= m.ID and t.GL <= m.Field1 where KeyID = ''[batchID]'' and m.Table_ID = ''GLmap1'' and Flex3 = ''Ceded'''),
    ('SQL-R02', 112, 'delete from TransX where KeyID = ''[batchID]'' and Flex4 is NULL'),
    ('SQL-R02', 113, 'insert into TransX (KeyID,Co, GL, TP, BusCat, Amt1, Amt2, Amt3, Amt4, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, Co, GL, TP, BusCat, 0 as Amt1, 0 as Amt2, Amt3, Amt4, Flex1, Flex2, Flex3, ''b. Premiums Earned (40xxx & 41xxx)'' as Flex4, Flex5 from TransX where KeyID = ''[batchID]'' and Flex4 = ''a. Premiums written'')'),
    ('SQL-R16c', 145, 'insert into TransX (KeyID, Co, Crcy, GL, TP, ReinName, BusCat,Contract,uwyr,PC, Amt1, Amt2, Amt3, Flex1) (Select KeyID, Co, Crcy, Flex1 as GL, TP, ReinName, BusCat,Contract,uwyr,PC, 0 as Amt1, 0 as Amt2, round(sum(coalesce(Amt4,0)),2) as Amt3, ''pass2'' as Flex1 from TransX where KeyID = ''[batchID]'' and not Flex1 in (''pass1'',''pass3'') group by KeyID, Co, Crcy, Flex1, TP, ReinName, BusCat,Contract,uwyr,PC)'),
    ('SQL-S05', 201, 'delete from TransX where KeyID = ''[batchID]'' and amt2 = 0'),
    ('SQL-G29', 421, 'Update x set x.Flex5 = y.Product from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]'''),
    ('SQL-G29', 484, 'Update TransX set PC =(case when BusCat = ''20'' then ''7URCAA'' else ''7UICAC'' end) + ''NTP0'' where KeyID = ''[batchID]'''),
    ('SQL-G29', 485, 'Update x set x.Flex5 = y.Product from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]'''),
    ('SQL-G29', 501, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and not GL in (''2853500'',''2851017'')'),
    ('SQL-M18', 191, 'insert into TransX (KeyID, Zone, Co, GL, BusCat,TP,PC,SubProd, Flex1, Amt1,Amt2) (Select KeyID, Zone, Co, substring(GL,1,5) + '' 0'' as GL, '''' as BusCat, TP, PC,SubProd, Flex1, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2  from TransX where KeyID = ''[batchID]'' and GL = ''2855100'')'),
    ('SQL-M18', 515, 'update TransX set Flex3 = ''1585'' where KeyID = ''[batchID]'' and (GL = ''1560002'' or substring(GL,1,3) in (''148'',''149''))'),
