    ('SQL-G29', 571, 'Update TransX set GL = ''4398005'', TTY = ''991'' where KeyID = ''[batchID]'' and GL = ''4398008'''),
    ('SQL-G29', 581, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''4398600'' as GL, Crcy, '''' as TTY, '''' as TP, ''5500000000'' as PC, '''' as ProdCode, '''' as PTF, '''' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, Crcy)');



