    ('SQL-G24', 248, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and (t.BusCat = m.Field1 or m.Field1 = '''') and (t.TTY = m.Field2 or m.Field2 = '''') where t.KeyID = ''[batchID]'' and Flex7 is NULL and not TTY = ''815'''),
