    ('SQL-G28', 261, 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,Amt1,Amt2,Amt3) (select ''[batchID]-data5'' as KeyID, ''5990'' as Co,''USD'' as Crcy,GL,''7URCAANTP0'' as PC,PTF,round(sum(Amt3),2) as Amt1, round(sum(Amt3),2) as Amt2, round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and GL in (''5600000'',''5600001'') and not PTF in (''U3025'',''U3030'',''U3035'',''U3040'',''U3145'',''U3146'',''U3170'')  group by GL,PTF)'),
