    ('SQL-G26', 432, 'update TransX set TTY = ''900'' from TransX where KeyID = ''[batchID]'' and not ''[yyyy-mm-dd]'' = ''2022-01-31'' and GL in (''1570000'',''2170000'',''2851017'') and not TTY = ''815'''),
    ('SQL-G26', 213, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''1099917'' as GL, substring(GL,1,3) + ''% 804'' as Assgnmt, Crcy, '''' as TTY, TP, '''' as BusCat, PC, Flex5, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and (substring(GL,1,3) in (''161'',''162'',''241'',''242'',''441'',''682'') or TTY = ''804'') and not GL in (''1610002'',''2421002'') and not TTY = ''815'' group by KeyID,Co,Crcy,TP,PC,Flex5,substring(GL,1,3))'),
    ('SQL-M25', 535, 'update TransX set Flex5 = ''05 Other''  where KeyID = ''[batchID]'' and Flex5 = ''02 RI'' and TTY = ''815'' and SubProd in (''G23'',''G26'')'),
    ('SQL-G32', 341, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''3870003'' as GL, Crcy, ''640'' as TTY, TP, PC, '''' as ProdCode, '''' as PTF, '''' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and ''[yyyy-mm-dd]'' = ''2022-01-31'' group by KeyID, Co, Crcy, TP, PC)'),
    ('SQL-G32', 342, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''4398600'' as GL, Crcy, '''' as TTY, '''' as TP, ''5500000000'' as PC, '''' as ProdCode, '''' as PTF, '''' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID in (''[batchID]'',''[batchID]-data8'') group by KeyID, Co, Crcy)'),
    ('SQL-G32', 361, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID in (''[batchID]'',''[batchID]-data8'') group by KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt)'),
