    ('SQL-G68', 111, 'update TransX set Flex2 = m.Mapkey, Flex3 = x.Field1 from TransX t inner join mapkeyranges m on t.GL >= m.fromGL and t.GL <=m.thruGL inner join Misc_Tables x on m.MapKey = x.Descr and x.Table_ID = ''G68'' and x.ID = ''Mapkeys'' where keyID = ''[batchID]'' and x.Field3 = ''[version]'''),
