    ('SQL-G68', 141, 'insert into TransX (KeyID,Co,GL,Flex2,Flex3,Flex5,Amt1) (select KeyID,''2999'' as Co,GL,Flex2,GL,''pass1'',round(-sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' and GL < ''2000000'' and Amt2 < 0 and ''[version]'' = ''UG'' group by KeyID,GL,Flex2)'),
    ('SQL-G90', 221, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-sum(coalesce(Amt1,0)),2) as Amt1,  ''50'' as PK from TransX where KeyID = ''[batchID]'' and Amt1 > 0 and PK is NULL group by KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF)'),
    ('SQL-G90', 222, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-sum(coalesce(Amt1,0)),2) as Amt1,  ''40'' as PK from TransX where KeyID = ''[batchID]'' and Amt1 < 0 and PK is NULL group by KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF)'),
    ('SQL-G90', 223, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G90', 241, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '''' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and substring(GL,4,2) = ''99'' and TP <> '''' )'),
    ('SQL-G68', 303, 'Update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID like ''[batchID]%'''),
    ('SQL-G90', 242, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, (substring(GL,1,3) + ''00'' + substring(GL,6,2)) as GL, Crcy, '''' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''50'' and substring(GL,4,2) = ''99'' and TP <> '''')'),
    ('SQL-G90', 251, 'update TransX set Flex6 = '''' from TransX where KeyID = ''[batchID]'''),
