    ('SQL-G51', 262, 'update TransX set ReinName = '''' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and Cedant = 0'),
    ('SQL-G59', 244, 'update TransX set BusCat = '''' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and ReinsType = 0'),
    ('SQL-G59', 246, 'update TransX set UWYR = ''[year]'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and UWYear = 1'),
