    ('SQL-S06', 210, 'update TransX set TPname = ''TR911'',Flex4 = ''TR911'', Flex2 = ''1002000000'' where KeyID = ''[batchID]'''),
    ('SQL-S06', 401, 'insert into TransX (KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWyr,TTY,Flex1,Flex2,Flex4, Amt1) (select KeyID, Ledger, Co, GL, PC, isnull(CC,''''), TP, BusCat, Contract, UWyr,TTY, ''pass1'', Flex2,Flex4, Amt1 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-R08', 234, 'update TransX set Flex6 = ''London Market'', RefKey3 = ''London Branch'' from TransX where KeyID = ''[batchID]'' and ((Division = ''LONDON_MKT'' and Region =  ''LONBRANCH'') or (Division = ''FIRV'' and Region =  ''LB_FIRV''))'),
    ('SQL-R08', 235, 'update TransX set Flex6 = ''London Market'', RefKey3 = ''Newline'' from TransX where KeyID = ''[batchID]'' and Division = ''LONDON_MKT'' and Region =  ''NEWLN'''),
    ('SQL-R08', 236, 'update TransX set Flex6 = ''Americas'', RefKey3 = ''Canada Branch'' from TransX where KeyID = ''[batchID]'' and ((Division = ''Americas'' and Location =  ''CAN'') or (Division = ''FIRV'' and Region =  ''CA_FIRV''))'),
    ('SQL-R08', 237, 'update TransX set Flex6 = ''Americas'', RefKey3 = ''Latin America'' from TransX where KeyID = ''[batchID]'' and (Division = ''LATAMER'' or (Division = ''FIRV'' and Region =  ''LAFIRV''))'),
    ('SQL-R08', 238, 'update TransX set Flex6 = ''Americas'', RefKey3 = ''US Branch'' from TransX where KeyID = ''[batchID]'' and ((Division = ''Americas'' and Location =  ''USA'') or (Division = ''FIRV'' and Region =  ''USR_FIRV''))'),
    ('SQL-R08', 239, 'update TransX set Flex6 = ''Americas'', RefKey3 = ''Miscellaneous'' from TransX where KeyID = ''[batchID]'' and Division = ''Americas'' and Region = ''AMER_MISC'''),
