    ('SQL-R08', 250, 'update TransX set Flex2 = m.Field1 + '' '' + m.Field2 from TransX t inner join Misc_Tables m on t.Hierarchy = m.Descr where KeyID = ''[batchID]'' and Table_ID = ''DACanalysis'' and ID = ''Hierarchy'''),
    ('SQL-M13', 439, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data10'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,'''' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Canada where source = ''R66'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'''' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source union all select Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Canada where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,PC,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_CAD '')'),
    ('SQL-G30', 211, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''3572002'' as GL, Crcy, PC, TP, ProdCode, 0 as Amt1, round(-Amt2,2) as Amt2, round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G30', 331, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, TP, ProdCode, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
    ('SQL-G30', 332, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, TP, ProdCode, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
    ('SQL-G30', 333, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G30', 334, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G30', 401, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-R28', 242, 'insert into TransX (KeyID, Yr,Flex1,Flex5,Flex6,Period,Flex2,Flex9,Qtr,Amt1) (select ''[batchID]'' as KeyID,Descr,Field1,Field2,Field3,Descr,Field1,''y'' as Flex9,13 as Qtr,0 as Amt1 from Misc_Tables where Table_ID = ''Sched Y'' and ID = ''Names'')'),
    ('SQL-S10d', 101, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-S10d', 102, 'delete from TransX where KeyID = ''[batchID]'' and amt2 = 0 and amt4 = 0'),
    ('SQL-G52', 205, 'insert into TransX (KeyID,Co, GL, TP, PC, BusCat, Amt3) (Select KeyID + ''-data2'', Co, GL,TP, PC, BusCat, Amt3 from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-G52', 206, 'update TransX set Flex1 = Field1, Flex2 = Field2, Flex3 = PC from TransX inner join Misc_Tables on substring(GL,1,3) = Descr where keyID = ''[batchID]-data2'' and Table_ID = ''StatFXmove'' and ID = ''GL'''),
    ('SQL-M44a', 102, 'delete from TransX where KeyID = ''[batchID]'' and Flex2 = ''1'' and Amt1 = 0'),
