    ('SQL-R08', 122, 'delete from TransX where KeyID = ''[batchID]'' and RefKey2 is NULL'),
    ('SQL-R08', 201, 'update TransX set RefKey2 = ''1. Gross'', Flex3 = ''Balance Sheet'', Flex4 = ''Paid'', Flex5 = ''ULAE'', Flex6 = ''Americas'', RefKey3 = ''US Branch'', RefKey1 = ''no'', BusCatDesc = '''', Tpname = '''' from TransX where KeyID = ''[batchID]'''),
    ('SQL-R08', 202, 'update TransX set RefKey2 = ''2. Ceded'' from TransX where KeyID = ''[batchID]'' and (substring(GL,1,2) = ''14'' or BusCat like ''3%'')'),
