    ('SQL-S22', 489, 'update c1 set Name = c1.SAP_Name,Flex2 = ''found'', SP_Name = (case when c2.SP_Rating = '''' then '''' else c2.Name end), AM_Name = (case when c2.AMBest_Rating = '''' then '''' else c2.Name end), c1.SP_Rating = c2.SP_Rating, c1.AMBest_Rating = c2.AMBest_Rating, c1.Flex1 = c2.CedingCo from CedingCoByQtr c1 inner join CedingCoByQtr c2 on (substring(c1.Flex3,1,17) = substring(c2.Flex3,1,17) or substring(c1.Flex3,1,len(c2.Flex3)) = c2.Flex3 or c1.Flex3 = substring(c2.Flex3,1,len(c1.Flex3))) and c1.Yr = c2.Yr and c1.Per = c2.Per where c1.Yr = ''[Yr]'' and c1.Per = ''[Mo]'' and c1.Name is NULL and not c1.SAP_Name is NULL and c2.SAP_Name is NULL'),
