    ('SQL-G55', 201, 'insert into TransX (KeyID, Ledger, Co, GL, Crcy, TP, PC, BusCat, Contract, UWYR, ProdCode, AccYr, ReinName, ReinLoc, CatCode, Broker, RiskTerr, PTF,Stat,TransCode,Amt1, Amt2, Amt3, Flex6) (Select KeyID, Ledger, Co, GL, Crcy, TP, PC, BusCat, Contract, UWYR, ProdCode, AccYr, ReinName, ReinLoc, CatCode, Broker, RiskTerr, PTF,Stat,TransCode, round(-sum(coalesce(Amt1,0)),2) as Amt1, round(-sum(coalesce(Amt2,0)),2) as Amt2,  round(-sum(coalesce(Amt3,0)),2) as Amt3, ''pass1'' as Flex6 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Co, GL, Crcy, TP, PC, BusCat, Contract, UWYR, ProdCode, AccYr, ReinName, ReinLoc, CatCode, Broker, RiskTerr, PTF,Stat,TransCode)'),
