    ('SQL-G55', 203, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G55', 204, 'delete t from TransX t inner join (select * from (Select Ledger, GL, TP, Contract, UWYR, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by Ledger, Co, GL, TP, Contract, UWYR) f1 where Amt2 <> 0 or Amt3 = 0) f2 on t.Ledger = f2.Ledger and t.GL = f2.GL and t.TP = f2.TP and t.Contract = f2.Contract and t.UWYR = f2.UWYR'),
    ('SQL-G55', 211, 'update t set t.Ledger = ''Z004'' from TransX t inner join (select * from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') x on x.Crcy = t.Crcy and x.GL = t.GL and x.PC = t.PC and x.TP = t.TP and x.BusCat = t.BusCat and x.Contract = t.Contract and x.UWYR = t.UWYR and x.ProdCode = t.ProdCode and x.Accyr = t.AccYr and x.ReinName = t.ReinName and x.ReinLoc = t.ReinLoc and x.CatCode = t.CatCode and x.Broker = t.Broker and x.RiskTerr = t.RiskTerr and x.PTF = t.PTF and x.Stat = t.Stat and x.TransCode = t.TransCode and x.Amt1 = t.Amt1 and x.Amt2 = t.Amt2 and x.Amt3 = t.Amt3 Where t.KeyID = ''[batchID]'' and t.Ledger = ''UG'''),
    ('SQL-G55', 212, 'delete t from TransX t inner join (select * from TransX where KeyID = ''[batchID]'' and Ledger = ''Z004'') x on x.Crcy = t.Crcy and x.GL = t.GL and x.PC = t.PC and x.TP = t.TP and x.BusCat = t.BusCat and x.Contract = t.Contract and x.UWYR = t.UWYR and x.ProdCode = t.ProdCode and x.Accyr = t.AccYr and x.ReinName = t.ReinName and x.ReinLoc = t.ReinLoc and x.CatCode = t.CatCode and x.Broker = t.Broker and x.RiskTerr = t.RiskTerr and x.PTF = t.PTF and x.Stat = t.Stat and x.TransCode = t.TransCode and x.Amt1 = t.Amt1 and x.Amt2 = t.Amt2 and x.Amt3 = t.Amt3 Where t.KeyID = ''[batchID]'' and t.Ledger = ''IF'''),
    ('SQL-G55', 213, 'update t set t.Ledger = ''Z003'' from TransX t inner join (select * from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') x on x.Crcy = t.Crcy and x.GL = t.GL and x.PC = t.PC and x.TP = t.TP and x.BusCat = t.BusCat and x.Contract = t.Contract and x.UWYR = t.UWYR and x.ProdCode = t.ProdCode and x.Accyr = t.AccYr and x.ReinName = t.ReinName and x.ReinLoc = t.ReinLoc and x.CatCode = t.CatCode and x.Broker = t.Broker and x.RiskTerr = t.RiskTerr and x.PTF = t.PTF and x.Stat = t.Stat and x.TransCode = t.TransCode and x.Amt1 = t.Amt1 and x.Amt2 = t.Amt2 and x.Amt3 = t.Amt3 Where t.KeyID = ''[batchID]'' and t.Ledger = ''Z004'''),
    ('SQL-G55', 214, 'delete t from TransX t inner join (select * from TransX where KeyID = ''[batchID]'' and Ledger = ''Z003'') x on x.Crcy = t.Crcy and x.GL = t.GL and x.PC = t.PC and x.TP = t.TP and x.BusCat = t.BusCat and x.Contract = t.Contract and x.UWYR = t.UWYR and x.ProdCode = t.ProdCode and x.Accyr = t.AccYr and x.ReinName = t.ReinName and x.ReinLoc = t.ReinLoc and x.CatCode = t.CatCode and x.Broker = t.Broker and x.RiskTerr = t.RiskTerr and x.PTF = t.PTF and x.Stat = t.Stat and x.TransCode = t.TransCode and x.Amt1 = t.Amt1 and x.Amt2 = t.Amt2 and x.Amt3 = t.Amt3 Where t.KeyID = ''[batchID]'' and t.Ledger = ''US'''),
