    ('SQL-R70', 251, 'update TransX set Flex1 = ''3030'', Flex2 = ''SYND HSC 2400'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2400'' and Contract like ''% 3030'' and Flex1 = '''''),
    ('SQL-R70', 252, 'update TransX set Flex1 = ''2400'', Flex2 = ''SYND HSC 3030'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''3030'' and Contract like ''% 2400'' and Flex1 = '''''),
    ('SQL-R07', 401, 'update TransX set Flex1 = ''01 GIC QS'' from TransX where KeyID = ''[batchID]'' and Co in (''2001'',''2002'',''2003'',''2200'',''2999'') and TP in (''2001'',''2002'',''2003'',''2200'',''2999'') and PC in (''220CSIC000'',''221CSIC000'',''341CSIC000'') and Flex1 is NULL'),
    ('SQL-S60', 210, 'update TransX set Flex8 = Field1 from TransX inner join Misc_Tables on substring(cc,11-len(ID),99) = ID and Yr = Descr where KeyID = ''[batchID]'' and Table_ID = ''ChangeDoc'''),
    ('SQL-R42', 101, 'update TransX set GLdesc = c.Descr,Flex6 = c.FXCaption,Flex7 = c.FXCaptionRecon from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R40', 201, 'update TransX set GLdesc = c.Descr,Flex7 = c.FXCaption,Flex8 = c.FXCaptionRecon from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-M17', 424, 'update TransX set Txt = ''G26-Misc'' where KeyID = ''[batchID]'' and Txt = ''G26'''),
    ('SQL-M17', 501, 'update TransX set Flex4 = (case when Co < ''5990'' then ''01 '' else ''02 '' end) where KeyID = ''[batchID]'' and Flex4 = '''''),
    ('SQL-M17', 512, 'update TransX set Flex4 = Flex4 + ''LIC Assumed D15'' where KeyID = ''[batchID]'' and (GL like ''22%'' or GL like ''282%'' or GL in (''2550001'',''2550002'',''2853500''))'),
    ('SQL-M17', 514, 'update TransX set Flex4 = Flex4 + ''LIC Assumed'' where KeyID = ''[batchID]'' and substring(GL,1,3) in (''155'',''215'') and GL like ''%01'''),
    ('SQL-T26', 101, 'insert into TransX (KeyID,Flex1,Flex2) (Select ''[batchID]'',ReinLoc,Descr from ReinLocs)'),
    ('SQL-T27', 101, 'insert into TransX (KeyID,Flex1,Flex2) (Select ''[batchID]'',RiskTerr,Descr from RiskTerrs)'),
    ('SQL-T28', 101, 'insert into TransX (KeyID,Flex1,Flex2) (Select ''[batchID]'',Stat,Descr from StatusRSG)'),
    ('SQL-T29', 101, 'insert into TransX (KeyID,Flex1,Flex2) (Select ''[batchID]'',SubProd,Descr from SubProds)'),
    ('SQL-R08', 301, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR) (select KeyID + ''-data2'', ''1. Beginning Balance'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt2,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR from TransX where KeyID = ''[batchID]'' and Amt2 <> 0)'),
    ('SQL-R08', 302, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR) (select KeyID + ''-data2'', ''2. Incurred Losses'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,round(-Amt1,2) as Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR from TransX where KeyID = ''[batchID]'' and (Flex4 like ''Change in %'' or Flex4 = ''Paid''))'),
    ('SQL-R08', 303, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR) (select KeyID + ''-data2'', ''3. Paid Losses'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR from TransX where KeyID = ''[batchID]'' and Flex4 = ''Paid'')'),
    ('SQL-R08', 304, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR) (select KeyID + ''-data2'', ''4. FX Impact'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR from TransX where KeyID = ''[batchID]'' and Flex1 = ''FX-Adj'')'),
    ('SQL-R08', 305, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR) (select KeyID + ''-data2'', ''5. Acq/Divest'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR from TransX where KeyID = ''[batchID]'' and Flex1 = ''Purch/Sale'')'),
    ('SQL-R08', 306, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR) (select KeyID + ''-data2'', ''6. Ending Balance'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2,Contract,UWYR from TransX where KeyID = ''[batchID]'' and Flex3 = ''Balance Sheet'')'),
    ('SQL-S06', 508, 'insert into TransX (KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1) (Select KeyID, Ledger, Co, GL, '''' as PC, '''' as CC, '''' as TP, '''' as BusCat, Contract, isnull(UWYR,'''') as UWYR, '''' as TTY, round(sum(Amt1),2) as Amt1, ''pass4'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1 <> ''pass1'' and (GL > ''4000000'' or GL = ''1619901'') group by KeyID, Ledger, Co, GL,  Contract, isnull(UWYR,''''))'),
    ('SQL-R32', 101, 'delete from TransX where KeyID = ''[batchID]'' and CC <> '''' and not substring(CC,4,1) = ''I'' and not Co like ''45%'''),
    ('SQL-R32', 103, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-R32', 104, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0 and Amt5 = 0'),
    ('SQL-R32', 201, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R32', 202, 'update TransX set Flex1 = MapKey from TransX inner join MapKeyRanges on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and MapKey like ''M1-3-6-06-03-%'''),
    ('SQL-R32', 203, 'update TransX set Flex1 = MapKey from TransX inner join MapKeyRanges on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and MapKey = ''M1-3-6-06-14-01'' and not Co like ''45%'''),
    ('SQL-G70', 307, 'delete from TransX where KeyID = ''[batchID]'' and Co is NULL'),
    ('SQL-G70', 308, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G70', 309, 'delete from TransX where KeyID = ''[batchID]'' and Co = ''2008'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-R70', 228, 'update TransX set Flex1 = ''4110'', Flex2 = ''ORESA ST 2008'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2008'' and Contract like ''67612%'' and Flex1 = '''''),
    ('SQL-G26', 211, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, x.GL + '' '' + TTY as Assgnmt, Crcy, m.Field5 as TTY, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = ''any'' and m.Field1 = ''any'' and m.Field2 = x.TTY and m.Field6 = ''1'' where KeyID in (''[batchID]'',''[batchID]-data8''))'),
    ('SQL-G25', 221, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, ProdCode, PTF, Flex5, Amt1, Amt2, Amt3) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, ProdCode, PTF, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC,ProdCode,PTF,Flex5)'),
    ('SQL-G26', 235, 'Update x set PC = ''7'' + m1.field2 + m2.field2 + (case when x.BusCat = ''20'' then ''A'' else ''C'' end) + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID in (''[batchID]'',''[batchID]-data8'')'),
    ('SQL-G26', 314, 'Update t set Amt2 = round(Amt2*r1.Rate/r2.Rate,2) from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.Field3 = ''convert'' and m.ID = ''Co'' and m.Descr = t.Co inner join CrcyRates r1 on r1.Crcy = m.Field2 and r1.Typ = ''S'' and r1.EffDate = (select max(EffDate) from (select EffDate from CrcyRates where Typ = ''S'' and Crcy = ''GBP'' and EffDate <= ''[yyyy-mm-dd]'') a) inner join CrcyRates r2 on r2.Crcy = m.Field4 and r2.Typ = ''S'' and r2.EffDate = r1.EffDate where t.KeyID in (''[batchID]'',''[batchID]-data8'')'),
    ('SQL-G26', 221, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt, Flex5, Amt1, Amt2, Amt3,Zone) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3,Zone from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC,ProdCode,PTF,Assgnmt,Flex5,Zone)'),
    ('SQL-G26', 243, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and not GL in (''2853500'',''2851017'')'),
    ('SQL-M19', 211, 'insert into TransX (KeyID, Co, GL, PC, ProdCode, Amt1,Flex1) (select KeyID, Co, GL, PC, ProdCode, round(sum(Amt1),2), ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]''  group by KeyID, Co, GL, PC, ProdCode)'),
    ('SQL-M17', 617, 'update TransX set Flex4 = Flex4 + '' to IFRS9'' where KeyID = ''[batchID]'' and Txt = ''G23-Rev'' and GL in (''2822000'',''2822500'',''2853500'')'),
    ('SQL-M17', 618, 'update TransX set Flex4 = ''02 Other clear'' where KeyID = ''[batchID]'' and Txt = ''G26-Misc'' and GL in (''2853500'')'),
    ('SQL-G23', 269, 'update TransX set Assgnmt = replace(Assgnmt,''x10x'',''x20x'') where KeyID = ''[batchID]-data3'' and (Assgnmt like ''x551%x10x'' or Assgnmt like ''x501%x10x'')'),
    ('SQL-G26', 224, 'delete from TransX where KeyID = ''[batchID]-data2''  and ''[yyyy-mm-dd]'' = ''2022-01-31'' and (GL = ''1099917'' or GL > ''3000000'')'),
    ('SQL-G26', 231, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt,Flex5, Amt1, Amt2, Amt3) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt,Flex5,Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]-data2'')'),
    ('SQL-G31', 323, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, BusCat, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, ''4398600'' as GL, Crcy, '''' as TTY, '''' as TP, ''5500000000'' as PC, '''' as BusCat, '''' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' group by KeyID, Co, Crcy)'),
    ('SQL-S20', 162, 'update x set Rate2 = y.Rate from TransX x inner join Companies c on x.Co = c.Co inner join (select Crcy,Rate from CrcyRates where Typ = substring(''[GL]'',5,99) and EffDate = (select max(EffDate) from CrcyRates where Typ = substring(''[GL]'',5,99) and Crcy = ''EUR'' and EffDate <= ''[yyyy-mm-dd]'')) y on c.Crcy = y.Crcy where KeyID = ''[batchID]'''),
    ('SQL-G24', 244, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and m.Field1 = '''' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL and not GL in (''2853500'',''2851017'')'),
    ('SQL-R19b', 102, 'delete from TransX where KeyID = ''[batchID]'' and Amt4 = 0'),
    ('SQL-S60', 215, 'update TransX set Flex8 = ''Posted to Local Ledger only'' from TransX where KeyID = ''[batchID]'' and Flex8 is NULL and Ledger in (''LS'',''LG'',''MA'',''TL'',''Z006'',''Z016'')'),
    ('SQL-R24', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-R24', 201, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R24', 202, 'update TransX set Flex1 = MapKey from TransX inner join MapKeyRanges on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and (MapKey like ''M2-3-5-A-%-1'' or MapKey like ''M2-3-5-A-%-2'')'),
    ('SQL-R24', 203, 'update TransX set Flex2 = m.Name from TransX t inner join MapKeys m on t.Flex1 = m.MapKey where KeyID = ''[batchID]'''),
    ('SQL-R24', 204, 'update TransX set Flex3 = MapKey from TransX inner join MapKeyRanges on Co >= FromGL and Co <= ThruGL where KeyID = ''[batchID]'' and MapKey like ''C2-%'''),
    ('SQL-R24', 205, 'update TransX set Flex4 = m.Name from TransX t inner join MapKeys m on t.Flex3 = m.MapKey where KeyID = ''[batchID]'''),
    ('SQL-R24', 206, 'update TransX set Ledger = ''IFRS'' from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'''),
    ('SQL-R24', 207, 'update TransX set Ledger = ''GAAP'' from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'''),
    ('SQL-R24', 208, 'update TransX set Ledger = ''STAT'' from TransX where KeyID = ''[batchID]'' and Ledger = ''US'''),
    ('SQL-R24', 209, 'update TransX set Amt3 = round(Amt2-Amt3,2) from TransX where KeyID = ''[batchID]'''),
    ('SQL-R24', 221, 'insert into TransX (KeyID, Ledger,Flex1,Flex2,GL,GLdesc,Flex3,Flex4,Co,Amt1,Amt2,Amt3) (select KeyID, Ledger,Flex1,Flex2,GL,GLdesc,''C2'' as Flex3,''Odyssey Re Holding Corp.'' as Flex4,''all'' as Co,round(sum(Amt1),2) as Amt1,round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID,Ledger,Flex1,Flex2,GL,GLdesc)'),
    ('SQL-R23', 204, 'update TransX set Flex3 = MapKey from TransX inner join MapKeyRanges on Co >= FromGL and Co <= ThruGL where KeyID = ''[batchID]'' and MapKey like ''C2-%'''),
    ('SQL-R23', 205, 'update TransX set Flex4 = m.Name from TransX t inner join MapKeys m on t.Flex3 = m.MapKey where KeyID = ''[batchID]'''),
    ('SQL-R23', 206, 'update TransX set Ledger = ''IFRS'' from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'''),
    ('SQL-R23', 207, 'update TransX set Ledger = ''GAAP'' from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'''),
    ('SQL-R23', 208, 'update TransX set Ledger = ''STAT'' from TransX where KeyID = ''[batchID]'' and Ledger = ''US'''),
    ('SQL-R23', 209, 'update TransX set Amt3 = round(Amt2-Amt3,2) from TransX where KeyID = ''[batchID]'''),
    ('SQL-R23', 221, 'insert into TransX (KeyID, Ledger,Flex1,Flex2,GL,GLdesc,Flex3,Flex4,Co,Amt1,Amt2,Amt3) (select KeyID, Ledger,Flex1,Flex2,GL,GLdesc,''C2'' as Flex3,''Odyssey Re Holding Corp.'' as Flex4,''all'' as Co,round(sum(Amt1),2) as Amt1,round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID,Ledger,Flex1,Flex2,GL,GLdesc)'),
    ('SQL-R23', 222, 'update TransX set Flex5 = substring(GL,7,1) from TransX where KeyID = ''[batchID]'''),
    ('SQL-R20', 122, 'update TransX set Hierarchy = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Region like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R20', 123, 'update TransX set Hierarchy = p.Location from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Location like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R20', 124, 'update TransX set Hierarchy = p.Zone from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Zone like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-M15', 541, 'update TransX set Flex3 = ''FX Equity'' where KeyID = ''[batchID]'' and GL like ''35%'''),
    ('SQL-M15', 542, 'update TransX set Flex3 = ''FX P&L'' where KeyID = ''[batchID]'' and GL like ''4398%'' and coalesce(Flex3,'''') = '''''),
    ('SQL-M15', 543, 'update TransX set Flex3 = ''FH P&L'' where KeyID = ''[batchID]'' and (GL like ''4415%'' or GL in (''4418900'',''6828900'')) and coalesce(Flex3,'''') = '''''),
    ('SQL-M15', 544, 'update TransX set Flex3 = ''Other'' where KeyID = ''[batchID]'' and coalesce(Flex3,'''') = '''''),
    ('SQL-G32', 451, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-G32', 452, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-R28', 203, 'update TransX set Amt4 = (case when GL < ''4000000'' then round(-Amt1,2) else Amt1 end) from TransX where KeyID = ''[batchID]'' and not (Co >= ''2001'' and Co <= ''2008'' and TP >= ''2200'' and TP <= ''2450'' and not TP = ''2210'')'),
    ('SQL-G28', 164, 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Flex3,Flex4,Flex1,Flex2,Location) (select ''[batchID]-data4'' as KeyID, Co,Crcy,GL,PC,CC,Amt1 * (Rate1 - Rate2) * Rate3,Amt2 * (Rate1 - Rate2) * Rate3,Amt3 * (Rate1 - Rate2) * Rate3,CCcat, ''Y'' as Deferrable_Flag, ''N'' as Attributable_Flag, Flex1, Flex2,Location from TransX where KeyID = ''[batchID]-data3'' and Rate1 > Rate2)'),
    ('SQL-G31', 438, 'update TransX set TP = '''' from TransX where KeyID = ''[batchID]'' and GL in (''1099917'',''2851017'')'),
    ('SQL-G28', 362, 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt,Amt1,Amt2,Amt3) (select ''[batchID]'' as KeyID, Co,Crcy,''2150000'' as GL,PC,'''' as PTF,''U1804'' as ProdCode,''602'' as TTY,''Exp reclass [yyyy-mm-dd] 5600000 roll'' as Txt,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2, round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600000'' group by Co,Crcy,PC)'),
    ('SQL-M41', 426, 'insert into TransX (KeyID,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6,Amt7,Amt8) (select KeyID,UWYr,Crcy,Flex2,Division,Flex5,Flex8,ROUND(SUM(COALESCE(Amt1,0)),2),ROUND(SUM(COALESCE(Amt2,0)),2),ROUND(SUM(COALESCE(Amt3,0)),2),ROUND(SUM(COALESCE(Amt4,0)),2),ROUND(SUM(COALESCE(Amt5,0)),2),ROUND(SUM(COALESCE(Amt6,0)),2),ROUND(SUM(COALESCE(Amt7,0)),2),ROUND(SUM(COALESCE(Amt8,0)),2) from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass2'' group by KeyID,UWYr,Crcy,Flex2,Division,Flex5,Flex8)'),
    ('SQL-G28', 317, 'update TransX set Amt1 = round(Amt1,0) from TransX t inner join Crcy c on t.Crcy = c.Crcy where KeyID = ''[batchID]'' and c.DecimalPlaces = 0'),
    ('SQL-M18', 551, 'update TransX set Flex3 = ''2056'' where KeyID = ''[batchID]'' and (GL like ''% %'' or GL in (''1099917'',''2851017'',''2310003''))'),
    ('SQL-R50', 215, 'insert into TransX (KeyID, Co, Amt1, Flex1,Flex2) (select ''[batchID]-save'', ''HudG'' as Co, round(sum(lc2_amt),2) as Amt1, ''5005'' as Flex1, ''The balance should net to zero for GLs starting with "992" for the Hudson companies and CCAT I/E'' as Flex2 from CorpAcct_Apps.dbo.SAP_Ledger_Data where fiscal_year = ''[Yr]'' and period <= ''[Mo]'' and GL like ''992%'' and substring(cost_centre,4,1) in (''I'',''E''))'),
    ('SQL-R19', 161, 'update TransX set Flex4 = p.hierarchy, PCDesc = p.Descr from TransX t inner join PCTRS p on t.PC = p.PCTR where KeyID = ''[batchID]'''),
    ('SQL-R08', 251, 'update TransX set Flex2 = m.Field1 + '' '' + m.Field2 from TransX t inner join Misc_Tables m on t.Zone = m.Descr where KeyID = ''[batchID]'' and Table_ID = ''DACanalysis'' and ID = ''Hierarchy'' and Flex2 is NULL and t.Zone <> '''''),
    ('SQL-R08', 252, 'update TransX set Flex2 = m.Field1 + '' '' + m.Field2 from TransX t inner join Misc_Tables m on t.Location = m.Descr where KeyID = ''[batchID]'' and Table_ID = ''DACanalysis'' and ID = ''Hierarchy'' and Flex2 is NULL and t.Location <> '''''),
    ('SQL-R08', 253, 'update TransX set Flex2 = m.Field1 + '' '' + m.Field2 from TransX t inner join Misc_Tables m on t.Region = m.Descr where KeyID = ''[batchID]'' and Table_ID = ''DACanalysis'' and ID = ''Hierarchy'' and Flex2 is NULL and t.Region <> '''''),
    ('SQL-R08', 254, 'update TransX set Flex2 = Division + '' '' + Hierarchy from TransX where KeyID = ''[batchID]'' and Flex2 is NULL'),
    ('SQL-R08', 255, 'update TransX set Flex2 = Flex2 + '' FIRV'' from TransX where KeyID = ''[batchID]'' and Hierarchy like ''%FIRV'''),
