    ('SQL-R71', 302, 'Update x set x.CCdesc = y.Descr from TransX x inner join CCtrs y on x.Contract = y.CCtr where KeyID = ''[batchID]'''),
    ('SQL-R72', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R72', 103, 'Update TransX set Amt1 = -Amt1 where KeyID = ''[batchID]'''),
    ('SQL-R72', 301, 'Update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID = ''[batchID]'''),
    ('SQL-R72', 302, 'Update x set x.CCdesc = y.Descr from TransX x inner join CCtrs y on x.Contract = y.CCtr where KeyID = ''[batchID]'''),
