    ('SQL-R73', 301, 'Update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID = ''[batchID]'''),
    ('SQL-M41', 321, 'insert into TransX (KeyID, Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4,Amt1,Amt2) (select KeyID + ''-data2'', Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4,ROUND(SUM(Amt1),2),ROUND(SUM(Amt2),2) from TransX where KeyID = ''[batchID]'' group by KeyID, Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4)'),
    ('SQL-M41', 403, 'delete from TransX where KeyID = ''[batchID]'' and Co like ''_999'''),
    ('SQL-G23', 402, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-M41', 404, 'delete from TransX where KeyID = ''[batchID]'' and GL >= ''5010000'' and GL <= ''5349999'''),
    ('SQL-R17', 121, 'insert into TransX (KeyID, Period, Ledger, Co, GL, TP, Division, Region, Amt1, Amt2, Amt4, Amt6, Flex6) (select KeyID, Period, Ledger, Co, GL, TP, Division, Region, ROUND(SUM(COALESCE(Amt1,0)),2) as Amt1, ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, ROUND(SUM(COALESCE(Amt6,0)),2) as Amt6, ''pass1'' as Flex6  from TransX where KeyID = ''[batchID]'' group by KeyID, Period, Ledger, Co, GL, TP, Division, Region)'),
    ('SQL-R17', 131, 'update TransX set Amt3 = Amt1 - Amt2, Amt5 = Amt1 - Amt4, Amt7 = Amt1 - Amt6 where KeyID = ''[batchID]'''),
    ('SQL-R17', 132, 'delete from TransX where KeyID = ''[batchID]'' and (Flex6 is null or (Amt1 = 0 and Amt2 = 0 and Amt4 = 0 and Amt6 = 0))'),
    ('SQL-R17', 133, 'update TransX set Flex1 = Mapkey from TransX t inner join mapkeyranges m on t.GL >= m.fromGL and t.GL <=m.thruGL where keyID = ''[batchID]'' and mapkey like ''M1-1-10-__'''),
    ('SQL-R17', 134, 'update TransX set Flex2 = m.Name from TransX t inner join mapkeys m on t.flex1 = m.mapkey where keyID = ''[batchID]'''),
    ('SQL-R60', 213, 'update TransX set Flex2 = ''Assumed'' from TransX where KeyID = ''[batchID]'' and GL like ''13%'''),
    ('SQL-R60', 214, 'update TransX set Flex2 = ''Direct'' from TransX where KeyID = ''[batchID]'' and BusCat = ''10'''),
    ('SQL-R60', 215, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R60', 221, 'update t set ReinName = c.CedingCo from TransX t inner join CedingCoByQtrContractUWYR c on t.Co = c.Co and t.Contract = c.Contract and t.UWYR = c.UWYR where t.KeyID = ''[batchID]'' and c.Yr = ''[Yr]'' and c.Per = ''[Mo]'''),
    ('SQL-R17', 135, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is null'),
    ('SQL-R17', 136, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R17', 137, 'update TransX set TPname = m.Name from TransX t inner join TPs m on t.TP = m.TP where KeyID = ''[batchID]'''),
    ('SQL-R17', 141, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data2'', Ledger, Flex1, Flex2, ''1. [CQ1] vs. [PQ1]'' as Flex3, round(sum(Amt3)/1000,0) as Amt3 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R49', 650, 'update TransX set Flex5 = ''136'', Flex6 = ''check if any arrangement between 3270 and 3075 - else clear'' where KeyID = ''[batchID]'' and ((Co = ''3075'' and TP = ''3270'') or (Co = ''3270'' and TP = ''3075'')) and Flex5 is NULL'),
    ('SQL-R49', 651, 'update TransX set Flex5 = ''100'', Flex6 = ''ORB QS'' where KeyID = ''[batchID]'' and TP = ''2210'' and PC like ''%CSIC000'' and Flex5 is NULL'),
    ('SQL-R49', 723, 'delete from TransX where KeyID = ''[batchID]'' and amt1 = 0 and amt2 = 0 and amt3 = 0'),
    ('SQL-R49', 396, 'update TransX set Flex5 = 41 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2008'' and TP >= ''2300'' and TP <= ''2450'' and PC = ''1402000101'''),
    ('SQL-E00', 1050, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, PC, TP, BusCat, Contract, TTY, UWyr, Flex2, Amt1,Flex8) (select KeyID, YearPeriod, Yr, Period, Ledger, ''[ElimCo]'', Descr, [OffsetPC], [ForceTP2], ''[OffsetBC]'', (''[ContractPrefix] '' + TP) as Contract, TTY, UWyr, ''offset'', Amt1,Contract from TransX inner join Misc_Tables on GL = ID where Table_ID = ''ElimGLmap[ElimMapNbr]'' and KeyID = ''[batchID]'' and Co <> ''[ElimCo]'' and ''[ContractPrefix]'' <> ''[keep]'')'),
    ('SQL-E00', 1051, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, PC, TP, BusCat, Contract, TTY, UWyr, Flex2, Amt1,Flex8) (select KeyID, YearPeriod, Yr, Period, Ledger, ''[ElimCo]'', Descr, [OffsetPC], [ForceTP2], ''[OffsetBC]'', Contract, TTY, UWyr, ''offset'', Amt1,Contract from TransX inner join Misc_Tables on GL = ID where Table_ID = ''ElimGLmap[ElimMapNbr]'' and KeyID = ''[batchID]'' and Co <> ''[ElimCo]'' and ''[ContractPrefix]'' = ''[keep]'')'),
    ('SQL-R49', 397, 'update TransX set Flex5 = 41 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co >= ''2300'' and Co <= ''2450'' and TP = ''2008'' and PC = ''4050100250'''),
    ('SQL-M13', 412, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data3'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC where  source = ''R64'' and YearPeriod > ''202112'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''202112'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-G49', 213, 'update TransX set Flex6 = ''30'', Amt1 = Amt3 from TransX where KeyID = ''[batchID]'' and Amt3 is not null'),
    ('SQL-R42', 300, 'update TransX set Flex5 = (case when Flex2 is NULL then ''no'' else ''yes'' end) from TransX where KeyID = ''[batchID]'''),
    ('SQL-R31', 201, 'insert into TransX (KeyID, Yr,Period,Co, GL, PC, UWYR, Amt1, Amt2, Flex1) (select KeyID, Yr, Period, Co, GL, PC, UWYR, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,Yr,Period,Co,GL,PC,UWYR)'),
    ('SQL-R08', 203, 'update TransX set Flex3 = ''Income Statement'' from TransX where KeyID = ''[batchID]'' and GL >= ''4000000'''),
    ('SQL-R74', 302, 'Update x set x.CCdesc = y.Descr from TransX x inner join CCtrs y on x.Contract = y.CCtr where KeyID = ''[batchID]'''),
    ('SQL-R49', 494, 'update TransX set Flex5 = 34 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and TP in (''2008'',''2201'') and (contract like ''CSIC ST%'' or Contract like ''GIC ST%'' or Contract like ''GICD ST%'' or Contract = ''HUD 2101'' or Contract = ''OPUS 2200'')'),
    ('SQL-S39', 332, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass1'''),
    ('SQL-M18', 212, 'delete from TransX where KeyID = ''[batchID]''  and Flex4 is NULL'),
    ('SQL-M13', 413, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt3) (select ''[batchID]-data4'',Co,GL,Crcy,ACD,Doc_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-M13', 414, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data5'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-S08', 546, 'update t set UWYR = s.UWYR from TransX t join CorpAcct_Apps.dbo.SAP_Ledger_Data s on t.co = s.co and t.pc = s.profit_centre and t.tp = s.trade_ptr and t.contract = s.contract and t.gl = s.gl and t.buscat = s.bus_cat where KeyID = ''[batchID]'' and t.UWYR = '''''),
    ('SQL-G49', 214, 'update TransX set Amt2 = 0, Amt3 = 0, Amt4 = 0 from TransX where KeyID = ''[batchID]'''),
    ('SQL-G49', 224, 'update TransX set Ledger = ''Z003'' from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' and Amt1 = Amt3 and Amt1 = Amt4'),
    ('SQL-G49', 225, 'delete from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and Amt1 = Amt2 and Amt1 = Amt4'),
    ('SQL-G49', 226, 'delete from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' and Amt1 = Amt2 and Amt1 = Amt3'),
