    ('SQL-G49', 228, 'delete from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and Amt1 = Amt2'),
    ('SQL-G49', 231, 'update TransX set Amt2 = 0, Amt3 = 0, Amt4 = 0 from TransX where KeyID = ''[batchID]'' and Flex6 = ''00'''),
    ('SQL-G49', 232, 'update TransX set Amt2 = Amt1, Amt1 = 0, Amt3 = 0, Amt4 = 0 from TransX where KeyID = ''[batchID]'' and Flex6 = ''10'''),
    ('SQL-G49', 233, 'update TransX set Amt3 = Amt1, Amt1 = 0, Amt2 = 0, Amt4 = 0 from TransX where KeyID = ''[batchID]'' and Flex6 = ''30'''),
    ('SQL-G49', 236, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G49', 221, 'update TransX set Amt2 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, Crcy, GL, PC, TP, BusCat, TTY, Flex6, Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.Crcy = f2.Crcy and f1.GL = f2.GL and f1.PC = f2.PC and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.TTY = f2.TTY and f1.Flex6 = f2.Flex6 and f1.Amt1 = f2.Amt1'),
    ('SQL-G61', 230, 'insert into TransX (KeyID,Co,Ledger,Crcy,Flex6,PK,GL,GLdesc,Amt1,Amt2,Amt3,Flex5,PC,CC,TP,BusCat,TTY,Amt4,Amt5,Amt6) (Select KeyID, Co,Ledger,Crcy,Flex6,(case when PK = ''40'' then ''50'' else ''40'' end) as PK,GL,GLdesc, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2,  round(-Amt3,2) as Amt3, ''NLS_MISC CCtr reclass (new cctr)'' as Flex5,PC,CC,TP,BusCat,TTY,Amt4,Amt5,Amt6 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-R70', 282, 'update TransX set Flex1 = ''2001'', Flex2 = ''LB NICL-G 3075'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''3075'' and Contract like ''% 2001'' and Flex1 = '''''),
    ('SQL-R70', 283, 'update TransX set Flex1 = ''3075'', Flex2 = ''LB NICL-G 2001'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2001'' and Contract like ''% 3075'' and Flex1 = '''''),
    ('SQL-R70', 284, 'update TransX set Flex1 = ''3070'', Flex2 = ''LB NICL 2001'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2001'' and PC like ''399%'' and Flex1 = '''''),
    ('SQL-R70', 285, 'update TransX set Flex1 = ''2001'', Flex2 = ''LB NICL 3070'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''3070'' and PC = ''34142701EL'' and Flex1 = '''''),
    ('SQL-R70', 286, 'update TransX set Flex1 = ''2001'', Flex2 = ''LB NICL-G 3075'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''3075'' and PC = ''34142701EL'' and Flex1 = '''''),
    ('SQL-R70', 287, 'update TransX set Flex1 = ''4110'', Flex2 = ''ORESA GIC 2200'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2200'' and PC = ''2202EU0721'' and Flex1 = '''''),
    ('SQL-R70', 288, 'update TransX set Flex1 = ''2300'', Flex2 = ''HIC CIC 2101'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2101'' and PC like ''4%'' and Flex1 = '''''),
    ('SQL-R70', 289, 'update TransX set Flex1 = ''2008'', Flex2 = ''ST CIC 2101'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2101'' and Flex1 = '''''),
    ('SQL-R70', 290, 'update TransX set Flex1 = ''2008'', Flex2 = ''GIC ST 2200'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2200'' and Flex1 = '''''),
