    ('SQL-R70', 302, 'update TransX set Flex1 = ''2400'', Flex2 = ''Investments'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and GL in (''114730'',''1147301'') and Flex1 = '''''),
    ('SQL-R70', 303, 'update TransX set Flex1 = ''2600'', Flex2 = ''Investments'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and GL in (''114870'',''1148701'') and Flex1 = '''''),
    ('SQL-R70', 304, 'update TransX set Flex1 = ''4000'', Flex2 = ''Investments'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and GL in (''1147700'') and Flex1 = '''''),
    ('SQL-R70', 305, 'update TransX set Flex1 = ''4100'', Flex2 = ''Investments'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and GL in (''1144800'') and Flex1 = '''''),
