    ('SQL-M25', 414, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''07 Payables'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and not substring(GL,1,3) in (''132'',''221'') and Flex9 = ''4'')'),
