    ('SQL-G81', 311, 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,UWYR,Txt,Amt1,Amt2,Amt3,Amt4,PK) (select KeyID,Ledger,Co,Crcy,GL,PC,UWYR,Txt,(case when Amt1 > 0 then Amt1 else 0 end),(case when Amt2 > 0 then Amt2 else 0 end),(case when Amt3 > 0 then Amt3 else 0 end),(case when Amt4 > 0 then Amt4 else 0 end),''40'' from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
