    ('SQL-M25', 701, 'update TransX set TTY = ''100'' where KeyID = ''[batchID]'' and coalesce(TTY,'''') = '''' and substring(GL,1,3) in (''155'',''156'',''215'',''216'')'),
    ('SQL-M25', 702, 'update TransX set TTY = ''100'' where KeyID = ''[batchID]'' and TTY = ''805'' and GL = ''1560002'''),
    ('SQL-G23', 292, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560002'' as GL, Crcy, PC,''803'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''1560001'' and TTY = ''627'')'),
    ('SQL-M25', 711, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY = c.TTY and t.BusCat = c.BC_From and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'''),
    ('SQL-M32', 121, 'update TransX set Date1 = '''' where 1 = 0'),
    ('SQL-M41', 428, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0 and Amt5 = 0 and Amt6 = 0 and Amt7 = 0 and Amt8 = 0'),
    ('SQL-T05', 102, 'update TransX set Flex5 = substring(Flex5,11,99) from TransX where KeyID = ''[batchID]'' and substring(Flex5,1,10) = ''ODYSSEYRE\'''),
    ('SQL-T05', 103, 'update TransX set Flex7 = substring(''Co: '' + c3.COAxCo,1,254) from TransX inner join (select distinct c2.GL, (select c1.Co + '','' as [text()] from COAxCo c1 where c1.GL = c2.GL and not c1.Co in (''2103'',''2350'',''2500'',''3080'',''3090'',''4000'',''4025'',''4030'') order by c1.Co for XML Path ('''') ) [COAxCo] from COAxCo c2) c3 on TransX.GL = c3.GL where KeyID = ''[batchID]'''),
    ('SQL-T05', 105, 'update TransX set Flex7 = substring(Flex7,1,len(Flex7)-1) from TransX where KeyID = ''[batchID]'' and not Flex7 is NULL'),
    ('SQL-T05', 106, 'update TransX set Flex8 = substring(Flex8,1,len(Flex8)-1) from TransX where KeyID = ''[batchID]'' and not Flex8 is NULL'),
    ('SQL-R48', 121, 'insert into TransX (KeyID, BusCatDesc, Amt1) (select ''[batchID]-data3'', (case when substring(GL,1,3) = ''460'' then ''Insurance(gross)'' else ''Reinsurance(ceded)'' end), round(-sum(Amt1),2)  from TransX  where KeyID = ''[batchID]'' and Co like ''599%'' group by substring(GL,1,3))'),
    ('SQL-R27', 213, 'update TransX set Flex2 = m.Descr from TransX t inner join Misc_Tables m on t.GL >= m.Field1 and t.GL <= m.Field2 where KeyID = ''[batchID]''  and m.Table_ID = ''ClaimLiabRollFwd'' and m.ID = ''GL'''),
    ('SQL-M15', 211, 'insert into TransX (KeyID, Flex1, Co, GL, BusCat, TP, Amt1,Flex4) (select KeyID, Flex1, Co, GL, BusCat, TP, round(sum(Amt1),2), ''pass1'' as Flex4 from TransX where KeyID = ''[batchID]''  group by KeyID, Flex1, Co, GL, BusCat, TP)'),
    ('SQL-M15', 212, 'delete from TransX where KeyID = ''[batchID]''  and Flex4 is NULL'),
