    ('SQL-M15', 322, 'update x set Flex3 = cast(m.Field2 as varchar) from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''FFH TP'' and x.GL like m.Descr where KeyID = ''[batchID]'''),
    ('SQL-M15', 323, 'update x set Flex3 = cast(m.Field2 as varchar) from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''FFH TP'' and x.GL = m.Field3 where KeyID = ''[batchID]'' and Flex1 = ''(4) Re-entry'''),
    ('SQL-M25', 566, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''02 RI'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and SubProd = ''G23'' and Flex5 = ''07 Payables'' and GL in (''3590702'',''3590802'',''3592502'',''4398004'',''4398005''))'),
    ('SQL-M25', 567, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G26'' as SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''07 Payables'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and SubProd = ''G23'' and Flex5 = ''07 Payables'' and GL in (''3590702'',''3590802'',''3592502'',''4398004'',''4398005''))'),
    ('SQL-G23', 257, 'Update t set Amt2 = round(Amt2*r1.Rate/r2.Rate,2) from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.Field3 = ''convert'' and m.ID = ''Co'' and m.Descr = t.Co inner join CrcyRates r1 on r1.Crcy = m.Field2 and r1.Typ = ''S'' and r1.EffDate = (select max(EffDate) from (select EffDate from CrcyRates where Typ = ''S'' and Crcy = ''GBP'' and EffDate <= ''[yyyy-mm-dd]'') a) inner join CrcyRates r2 on r2.Crcy = m.Field4 and r2.Typ = ''S'' and r2.EffDate = r1.EffDate where t.KeyID = ''[batchID]'''),
    ('SQL-M25', 422, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''07 Payables'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and Flex9 = ''5'')'),
    ('SQL-M25', 431, 'update TransX set Flex5 = ''01 IFRS-4''  where KeyID = ''[batchID]'' and Co < ''5990'' and Flex5 = '''''),
    ('SQL-G31', 223, 'delete from TransX where KeyID = ''[batchID]-data2'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G31', 231, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Amt1, Amt2, Amt3) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]-data2'')'),
    ('SQL-G31', 237, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, BusCat, TTY, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, ''3870002'' as GL, Crcy, PC, TP, '''' as BusCat, ''640'' as TTY, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' and ''[yyyy-mm-dd]'' = ''2022-01-31'' group by KeyID, Co,  Crcy, PC, TP)'),
    ('SQL-G31', 241, 'Update TransX set Flex1 = PC, Flex2 = '''', Flex3 = '''', Flex4 = '''' where KeyID = ''[batchID]'' and Co like ''9%'''),
    ('SQL-S07', 512, 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
    ('SQL-R70', 262, 'update TransX set Flex1 = ''2200'', Flex2 = ''GIC PB 2002'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2002'' and PC = ''220CSIC000'' and Flex1 = '''''),
    ('SQL-R70', 263, 'update TransX set Flex1 = ''2002'', Flex2 = ''GIC PB 2200'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2200'' and PC = ''220CSIC000'' and Flex1 = '''''),
    ('SQL-R70', 264, 'update TransX set Flex1 = ''2200'', Flex2 = ''GIC STK 2003'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2003'' and PC = ''221CSIC000'' and Flex1 = '''''),
    ('SQL-M28', 201, 'update TransX set  BusCat = '''' where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-T05', 130, 'update x set Flex8 = Flex8 + '' '' + m.UD3 from TransX x inner join (Select distinct GL_From,GL_Thru,UD3 from osAccountMap3 where GL_From like ''6%'' and Co_Thru = ''9999'') m on x.GL >= m.GL_From and x.GL <= m.GL_Thru where KeyID = ''[batchID]'' and GL like ''6%'''),
    ('SQL-R70', 265, 'update TransX set Flex1 = ''2003'', Flex2 = ''GIC STK 2200'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2200'' and PC = ''221CSIC000'' and Flex1 = '''''),
    ('SQL-G85', 102, 'Delete from TransX where KeyID = ''[batchID]'' and coalesce(Flex1,'''') = '''''),
