    ('SQL-G85', 104, 'update TransX set Amt4 = 0, Amt5 = 0, Txt = cast(GL as varchar(10)) + '' - Translation Using [yyyy-mm-dd]'', Flex1 = '''' from TransX where KeyID = ''[batchID]'''),
    ('SQL-G85', 112, 'update TransX set Amt3 = round(Amt1 * Rate1,2) where KeyID = ''[batchID]'''),
