    ('SQL-G85', 131, 'update TransX set Ledger = ''Z000''  from TransX where KeyID = ''[batchID]'' and Amt7 = Amt8 and Amt7 = Rate2 and Ledger = ''IF'''),
    ('SQL-G32', 217, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, x.GL + '' '' + TTY as Assgnmt, Crcy, m.Field5 as TTY, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = ''any'' and m.Field1 = ''any'' and m.Field2 = x.TTY and m.Field6 = ''1'' where KeyID in (''[batchID]'',''[batchID]-data8''))'),
    ('SQL-G46', 101, 'delete from TransX where KeyID = ''[batchID]'' and  ''[version]'' = ''ODY IFRS 4'' and not (Ledger in (''IF'',''UG'') and Co < ''5001'')'),
    ('SQL-G46', 102, 'delete from TransX where KeyID = ''[batchID]'' and  ''[version]'' = ''ODY IFRS 17'' and not (Ledger = ''IF'' and Co like ''599%'')'),
