    ('SQL-G44', 253, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-G44', 254, 'update TransX set Amt3 = NULL, Amt4 = NULL, Flex3 = '''', Flex5 = '''' from TransX where KeyID = ''[batchID]'' and Co = ''2006'''),
    ('SQL-G44', 222, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3,Amt4, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, substring(GL,1,5) + ''00'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  -Amt4 as Amt4,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and ((GL >= ''3000000'' and GL < ''3330000'') or GL >= ''3640000''))'),
    ('SQL-G44', 223, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3,Amt4, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, substring(GL,1,5) + ''00'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  -Amt4 as Amt4,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and GL >= ''3330000'' and GL < ''3600000'' and substring(GL,6,2) in (''01'',''02''))'),
    ('SQL-G44', 224, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3,Amt4, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, ''3610000'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  -Amt4 as Amt4,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and GL >= ''3600000'' and GL < ''3640000'' )'),
    ('SQL-G44', 231, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3,Amt4, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3,  round(sum(Amt4),2) as Amt4,  ''99'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY,PTF)'),
    ('SQL-G44', 241, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3,Amt4, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, case when Amt1>0 then Amt1 else 0 end as Amt1, case when Amt2>0 then Amt2 else 0 end as Amt2,  case when Amt3>0 then Amt3 else 0 end as Amt3,  case when Amt4>0 then Amt4 else 0 end as Amt4,  ''40'' as PK from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-G44', 242, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3,Amt4, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, case when Amt1<0 then Amt1 else 0 end as Amt1, case when Amt2<0 then Amt2 else 0 end as Amt2,  case when Amt3<0 then Amt3 else 0 end as Amt3,  case when Amt4<0 then Amt4 else 0 end as Amt4,  ''50'' as PK from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-G46', 201, 'delete from TransX where KeyID = ''[batchID]'' and (Amt3 = 0 or Amt4 = 0)'),
    ('SQL-G46', 202, 'delete from TransX where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and not substring(GL,6,2) in (''01'',''02'',''04'',''05'')'),
    ('SQL-G46', 203, 'update TransX set GL = ''9999999'' from TransX inner join Misc_Tables on substring(GL,1,5) = ID where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and Table_ID = ''Tax GL'' and Descr = ''9999999'''),
    ('SQL-G46', 204, 'delete from TransX where KeyID = ''[batchID]'' and GL = ''9999999'''),
    ('SQL-G46', 205, 'update TransX set TP = '''', Contract = '''' from TransX where KeyID = ''[batchID]'' and substring(GL,1,5) <> ''35840'''),
    ('SQL-G46', 211, 'update TransX set Amt3 = -Amt3 where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and substring(GL,6,2) in (''04'',''05'') and not Amt3 is NULL'),
    ('SQL-G46', 212, 'update TransX set Amt4 = -Amt4 where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and substring(GL,6,2) in (''04'',''05'') and not Amt4 is NULL'),
    ('SQL-G46', 221, 'update TransX set Amt3 = -Amt3*0.21 from TransX where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and substring(GL,6,2) in (''01'',''02'') and not Amt3 is NULL'),
    ('SQL-G46', 222, 'update TransX set Amt4 = -Amt4*0.21 from TransX where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and substring(GL,6,2) in (''01'',''02'') and not Amt4 is NULL'),
    ('SQL-G46', 223, 'update TransX set GL = substring(GL,1,5) + ''04'' from TransX where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and GL like ''%01'''),
    ('SQL-G46', 224, 'update TransX set GL = substring(GL,1,5) + ''05'' from TransX where KeyID = ''[batchID]'' and GL >= ''3400000'' and GL < ''3600000'' and GL like ''%02'''),
    ('SQL-G46', 225, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3, Flex6) (Select KeyID, Ledger, Co, GL,TP, Contract, round(sum(Amt3),0) as Amt3, ''consolidate'' from TransX where KeyID = ''[batchID]'' and not Amt3 is NULL group by KeyID, Ledger, Co, GL, TP, Contract)'),
    ('SQL-G46', 226, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt4, Flex6) (Select KeyID, Ledger, Co, GL,TP, Contract, round(sum(Amt4),0) as Amt4, ''consolidate'' from TransX where KeyID = ''[batchID]'' and not Amt4 is NULL group by KeyID, Ledger, Co, GL, TP, Contract)'),
    ('SQL-G46', 103, 'delete from TransX where KeyID = ''[batchID]'' and  ''[version]'' = ''ORB IFRS 4 LG'' and not (Ledger = ''LG'' and Co = ''2210'')'),
    ('SQL-G46', 104, 'delete from TransX where KeyID = ''[batchID]'' and  ''[version]'' = ''CAD IFRS 17 LG'' and not (Ledger = ''LG'' and Co in (''2006'',''9006''))'),
    ('SQL-R16', 237, 'update TransX set PC = substring(cast(f2.ceding_co_id as varchar(255)),1,10), PCdesc = substring(f3.name,1,50) from TransX f1 inner join [stm-dwhse-01].[ORION].dbo.[Contracts] f2 on f1.contract = f2.contract_no and f1.uwyr = f2.uw_year inner join [stm-dwhse-01].[ORION].dbo.[Companies] f3 on f2.ceding_co_id = f3.company_id'),
    ('SQL-G46', 106, 'delete from TransX where KeyID = ''[batchID]'' and  ''[version]'' = ''HUDCAD IFRS 17 LG'' and not (Ledger = ''LG'' and Co in (''2310'',''9231''))'),
    ('SQL-G85', 122, 'update x set Amt7 = y.Amt6 from TransX x inner join (Select KeyID,Crcy,GL,PC,UWYR,TP,Contract,ReinName,BusCat,round(sum(Amt6),2) as Amt6 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' group by KeyID,Crcy,GL,PC,UWYR,TP,Contract,ReinName,BusCat) y on x.KeyID = y.KeyID and x.Crcy = y.Crcy and x.GL = y.GL and x.PC = y.PC and x.UWYR = y.UWYR and x.TP = y.TP and x.Contract = y.Contract and x.ReinName = y.ReinName and x.BusCat = y.BusCat'),
    ('SQL-G85', 123, 'update x set Amt8 = y.Amt6 from TransX x inner join (Select KeyID,Crcy,GL,PC,UWYR,TP,Contract,ReinName,BusCat,round(sum(Amt6),2) as Amt6 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' group by KeyID,Crcy,GL,PC,UWYR,TP,Contract,ReinName,BusCat) y on x.KeyID = y.KeyID and x.Crcy = y.Crcy and x.GL = y.GL and x.PC = y.PC and x.UWYR = y.UWYR and x.TP = y.TP and x.Contract = y.Contract and x.ReinName = y.ReinName and x.BusCat = y.BusCat'),
    ('SQL-G85', 124, 'update x set Rate2 = y.Amt6 from TransX x inner join (Select KeyID,Crcy,GL,PC,UWYR,TP,Contract,ReinName,BusCat,round(sum(Amt6),2) as Amt6 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' group by KeyID,Crcy,GL,PC,UWYR,TP,Contract,ReinName,BusCat) y on x.KeyID = y.KeyID and x.Crcy = y.Crcy and x.GL = y.GL and x.PC = y.PC and x.UWYR = y.UWYR and x.TP = y.TP and x.Contract = y.Contract and x.ReinName = y.ReinName and x.BusCat = y.BusCat'),
    ('SQL-R16', 101, 'update TransX set Contract = ''UNKNOWN'', ReinName = ''UNKNOWN'' from TransX where KeyID = ''[batchID]'' and Co in (''2002'',''2003'') and Contract like ''AR%'' and GL like ''13%'''),
    ('SQL-R16', 201, 'insert into TransX (KeyID, Co, GL, TP, ReinName, BusCat,Contract,uwyr,Amt1, Amt2, Amt3, Flex1) (Select KeyID, Co, GL, TP, ReinName, BusCat,Contract,uwyr,0 as Amt1, 0 as Amt2, round(sum(Amt3),2) as Amt3, ''pass9'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, TP, ReinName, BusCat,Contract,uwyr)'),
    ('SQL-R16', 224, 'update TransX set Flex4 = coalesce(m.Name,''''), Flex6 = coalesce(m.SchedFname,''''), Division = m.NAIC, Location = m.FedID from TransX t inner join Brokers m on t.ReinName = m.Broker where KeyID = ''[batchID]'''),
    ('SQL-R16', 202, 'delete from TransX where KeyID = ''[batchID]'' and (Amt3 = 0 or Flex1 <> ''pass9'')'),
    ('SQL-R16', 211, 'update TransX set Flex1 = ''Ceded'', Flex2 = ''no'', Flex5 = ''non-affiliate'', Flex6 = '''', Amt4 = Amt3 from TransX where KeyID = ''[batchID]'''),
    ('SQL-R16', 212, 'update TransX set Flex1 = ''Assumed'' from TransX where KeyID = ''[batchID]'' and BusCat >= ''20'' and BusCat <= ''29'''),
    ('SQL-R16', 213, 'update TransX set Flex1 = ''Assumed'' from TransX where KeyID = ''[batchID]'' and GL like ''13%'''),
    ('SQL-R16', 214, 'update TransX set Flex1 = ''Direct'' from TransX where KeyID = ''[batchID]'' and BusCat = ''10'''),
    ('SQL-R16', 215, 'update TransX set Flex2 = ''yes'' from TransX where KeyID = ''[batchID]'' and (GL like ''%96'' or GL like ''%97'' or GL like ''%98'')'),
    ('SQL-R16', 216, 'update TransX set Flex3 = m.Descr from TransX t inner join Misc_Tables m on substring(t.GL,1,3) = m.ID and t.Flex1 = m.Field1 where KeyID = ''[batchID]'' and m.Table_ID = ''GL Sched F'''),
    ('SQL-R16', 217, 'update TransX set Amt4 = -Amt3 from TransX where KeyID = ''[batchID]'' and substring(GL,1,1) = ''2'' and not (Flex1 = ''Ceded'' and substring(GL,1,2) = ''28'')'),
    ('SQL-R16', 218, 'update TransX set Amt4 = -Amt3 from TransX where KeyID = ''[batchID]'' and ((substring(GL,1,1) = ''4'' and Flex1 <> ''Ceded'') or (substring(GL,1,1) = ''5'' and Flex1 = ''Ceded''))'),
    ('SQL-R16', 222, 'update TransX set TP = Field1 from TransX inner join Misc_Tables on ReinName = Descr where  KeyID = ''[batchID]'' and Table_ID = ''TP Sched F'' and TP is NULL'),
    ('SQL-R16', 225, 'update TransX set Flex6 = coalesce(Field2,'''') from TransX inner join Misc_Tables on ReinName = Descr and Co = Field1 where  KeyID = ''[batchID]'' and Table_ID = ''Reins Sched F'''),
    ('SQL-G34', 275, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, TTY, ProdCode, Amt1, Amt2, PK) (Select KeyID, Co, ''2150001'' as GL, Crcy, PC, Assgnmt + '' roll 2'' as Assgnmt, ''824'' as TTY, ''U1801'' as ProdCode,Amt1, Amt2 , ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' and GL = ''5600062'')'),
    ('SQL-G34', 277, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, PTF, Amt1, Amt2, PK) (Select KeyID, Co, ''5600000'' as GL, Crcy, PC, Assgnmt + '' roll 3'' as Assgnmt, PTF, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' and GL = ''5600062'' and not Assgnmt = ''6917000'')'),
    ('SQL-R49', 110, 'delete from TransX where KeyID = ''[batchID]'' and Flex6 is NULL'),
    ('SQL-R49', 618, 'update TransX set Flex5 = ''112'', Flex6 = ''cash accounts should not have TP'' where KeyID = ''[batchID]'' and GL = ''4398002'' and Flex5 is NULL'),
    ('SQL-G39', 310, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-G39', 332, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass1'''),
    ('SQL-G29', 461, 'Update x set Amt1 = round(Amt1*c.Rate,2), Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy inner join CrcyRates c on c.Crcy = x.Crcy and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-G29', 591, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt)'),
    ('SQL-R49', 696, 'update TransX set Flex7 = (case when Co = ''2999'' or Co = ''3999'' then ''Yes'' else ''No'' end) where KeyID = ''[batchID]'''),
    ('SQL-R49', 697, 'update t set FSitemDesc = f.FSitemDesc from TransX t inner join COA c on t.GL = c.GL inner join Fsitems f on c.Fsitem = f.fsitem where KeyID = ''[batchID]'''),
    ('SQL-G32', 246, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL'),
    ('SQL-G32', 247, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and m.Field1 = '''' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL'),
    ('SQL-G32', 248, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and (t.BusCat = m.Field1 or m.Field1 = '''') and (t.TTY = m.Field2 or m.Field2 = '''') where t.KeyID = ''[batchID]'' and Flex7 is NULL'),
    ('SQL-M41', 401, 'delete from TransX where KeyID = ''[batchID]'' and TTY <> ''822'' and not GL like ''4%'''),
    ('SQL-M41', 402, 'delete from TransX where KeyID = ''[batchID]'' and not TP = '''''),
    ('SQL-G34', 141, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3, Amt1, Amt2) (Select KeyID, Co, GL, Crcy, PC, ''2150001'' as Flex1, Flex2, Flex3, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 from TransX where KeyID = ''[batchID]'' and GL Like ''6917%'' and Flex1 = ''5600000'')'),
    ('SQL-G34', 142, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3, Amt1, Amt2) (Select KeyID, Co, GL, Crcy, PC, ''2150001'' as Flex1, ''U3010'' as Flex2, Flex3, Amt1, Amt2 from TransX where KeyID = ''[batchID]'' and GL Like ''6917%'' and Flex1 = ''5600000'')'),
    ('SQL-R16', 301, 'insert into TransX (KeyID,Flex1,Flex2,Flex3,Flex5,ReinName,Flex6,Amt3,Amt4) select ''[batchID]'',x.Flex1,''prorate'',x.Flex3,''non-affiliate'',x.ReinName,x.Flex6,round(x.Amt3/z.Amt3*y.Amt3,2),round(x.Amt4/z.Amt4*y.Amt4,2) from (select Flex1,Flex3,ReinName,Flex6,round(sum(Amt3),2) as Amt3,round(sum(Amt4),2) as Amt4 from TransX where KeyID = ''[batchID]'' and Flex5 = ''non-affiliate'' and Flex6 <> '''' group by Flex1,Flex3,ReinName,Flex6) x inner join (select Flex1,Flex3,Amt3,Amt4 from (select Flex1,Flex3,sum(Amt3) as Amt3,sum(Amt4) as Amt4 from TransX where KeyID = ''[batchID]'' and Flex6 = '''' group by Flex1, Flex3) a where Amt3 <> 0 or Amt4 <> 0) y on y.Flex1 = x.Flex1 and y.Flex3 = x.Flex3 inner join (select Flex1,Flex3,Amt3,Amt4 from (select Flex1,Flex3,sum(Amt3) as Amt3,sum(Amt4) as Amt4 from TransX where KeyID = ''[batchID]'' and Flex5 = ''non-affiliate'' and Flex6 <> '''' group by Flex1,Flex3) b where Amt3 <> 0 or Amt4 <> 0) z on z.Flex1 = x.Flex1 and z.Flex3 = x.Flex3'),
    ('SQL-R16', 200, 'update TransX set ReinName = m.CEDANT_REINSURER_CODE from TransX t inner join [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] m on t.Co = m.LEGAL_ENTITY and t.Contract = m.CONTRACT_NO and t.UWYR = m.UW_YEAR where KeyID = ''[batchID]'' and not t.Contract in ('''',''UNKNOWN'') and not ReinName in (select z.CEDANT_REINSURER_CODE from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] z where z.CONTRACT_NO = t.Contract and z.UW_YEAR = t.UWYR and z.LEGAL_ENTITY = t.Co)'),
    ('SQL-T03', 101, 'insert into TransX (KeyID,PC,Flex1,PCdesc,Hierarchy,Division,Region,Location,Zone,Flex6,Flex7,Flex8,Flex2,Flex3,Flex4,Flex5) (select ''[batchID]'',PCTR,Name,Descr,Hierarchy,Division,Region,Location,Zone,MajorClass,Product,Program,Blocked,ValidThru,UpdatedOn,UpdatedBy from PCTRS)'),
    ('SQL-G26', 413, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data3'' as KeyID, ''9999'' as Co, ''filler'' as GL, '''' as Crcy, '''' as PC, '''' as TTY, '''' as TP, '''' as  Assgnmt, '''' as ProdCode, '''' as PTF, 0 as Amt1, 0 as  Amt2 , 0 as  Amt3)'),
    ('SQL-G32', 226, 'delete from TransX where KeyID = ''[batchID]-data2''  and ''[yyyy-mm-dd]'' = ''2022-01-31'' and (GL = ''1099917'' or GL > ''3000000'')'),
    ('SQL-G26', 431, 'update TransX set TTY = '''' from TransX where KeyID = ''[batchID]'' and GL in (''2853500'',''3870003'') and not ''[yyyy-mm-dd]'' = ''2022-01-31'''),
    ('SQL-G26', 433, 'update TransX set ProdCode = ''U1892'', PTF = ''U3650'' from TransX where KeyID = ''[batchID]'' and GL = ''4600000'' and coalesce(ProdCode,'''') = '''''),
    ('SQL-G77', 404, 'update TransX set Amt2 = 0 where KeyID = ''[batchID]'' and PK = ''40'' and Amt2 < 0'),
    ('SQL-G77', 405, 'update TransX set Amt3 = 0 where KeyID = ''[batchID]'' and PK = ''40'' and Amt3 < 0'),
    ('SQL-G77', 421, 'update TransX set GL = ''2899901'' where KeyID = ''[batchID]'' and PK = ''50'' and GL = ''1999901'''),
    ('SQL-G77', 501, 'update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID like ''[batchID]%'''),
    ('SQL-G77', 502, 'update TransX set Txt = ''Mexico-Newline Chargeback for [Yr]/[Mo]'' where KeyID = ''[batchID]'''),
    ('SQL-S32', 302, 'delete from TransX where KeyID = ''[batchID]'' and GL < ''6000000'' and GL <> ''4498000'' and Flex1 is NULL'),
    ('SQL-G34', 221, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3, Amt1, Amt2) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, Flex1, Flex2, Flex3)'),
    ('SQL-G34', 222, 'delete from TransX where KeyID = ''[batchID]'''),
    ('SQL-S32', 321, 'insert into TransX (KeyID, YearPeriod,Yr,Period,Ledger, Co, GL, PC, CC, BusCat, Amt1, Flex1) (Select KeyID, YearPeriod,Yr,Period, Ledger, Co, GL,PC,CC,BusCat,round(sum(Amt1),2) as Amt1, ''pass3'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, YearPeriod,Yr,Period, Ledger, Co, GL,  PC, CC, BusCat)'),
    ('SQL-R25', 251, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, '''' as BusCat, '''' as Contract, ''AW'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''143%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 inner join (Select Crcy,PC,GL,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''203%'' and Flex1 = ''FX'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and substring(f1.GL,4,4) = substring(f2.GL,4,4) where f2.Amt1 <> 0 or f2.Amt2 <> 0)'),
    ('SQL-G87', 402, 'insert into TransX (KeyID, Co,GL, Crcy,PC, CC, Contract, ProdCode,TP,Amt1, Amt2, Amt3,PK) (Select KeyID, Co,GL, Crcy,PC,CC, Contract, ProdCode,TP,(case when Amt1 < 0 then Amt1 else 0 end) as Amt1,(case when Amt2 < 0 then Amt2 else 0 end) as Amt2,  (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and (Amt1 < 0 or Amt2 < 0 or Amt3 < 0))'),
    ('SQL-R16f', 111, 'update TransX set Amt4 = Round(Amt1*r.rate/rc.rate,2) from TransX t inner join CrcyRates r on t.Crcy = r.Crcy inner join Companies c on t.Co = c.Co inner join CrcyRates rc on c.Crcy = rc.Crcy where KeyID = ''[batchID]'' and r.EffDate = ''[PY]-12-31'' and rc.EffDate = ''[PY]-12-31'' and r.Typ = ''S'' and rc.Typ = ''S''  and GL < ''2870000'' and not GL like ''%96'' and not GL like ''%98'' and not SUBSTRING(GL,1,4) in (''1320'') and not SUBSTRING(GL,1,3) in (''151'',''162'',''211'',''242'') and not t.PC in (''220CSIC000'',''221CSIC000'',''341CSIC000'') and Flex1 = ''pass2'' and not t.crcy = rc.crcy'),
    ('SQL-G29', 513, 'update TransX set ProdCode = '''' where KeyID = ''[batchID]'' and ProdCode is null'),
    ('SQL-R49', 421, 'update TransX set Flex5 = 6 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and TP in (''2300'',''2400'',''2450'',''2008'') and substring(PC,1,1) =''6'' and not (substring(Contract,1,7) = ''FIRV ST'' or substring(Contract,1,3) =  ''FV-'')'),
    ('SQL-G26', 198, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''401'' + substring(GL,4,4) as GL, Assgnmt, Crcy, '''' as TTY, TP, BusCat, PC, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and Zone = ''7'' and GL like ''131%'' and TTY = ''809'')'),
    ('SQL-G29', 301, 'insert into TransX (KeyID,Co,Yr,Period,GL,Ledger,Division,Region,Location,Zone,PCdesc,TPname,CCdesc,Crcy,PK,Amt1,Amt2,Amt3,Amt4,Amt5,RefKey1,RefKey2,RefKey3,Assgnmt,Txt,PC,CC,BusCat,TTY,UWYR,Broker,TP,PTF,Contract,ProdCode,BusCatDesc,ExpNode,Flex1,FSitem,RiskTerr,ReinLoc,CatCode,AccYr,ReinName,SubProd,TransCode,Stat) (select ''[batchID]-data2'',Co,Yr,Period,GL,Ledger,Division,Region,Location,Zone,PCdesc,TPname,CCdesc,Crcy,PK,Amt1,Amt2,Amt3,Amt4,Amt5,RefKey1,RefKey2,RefKey3,Assgnmt,Txt,PC,CC,BusCat,TTY,UWYR,Broker,TP,PTF,Contract,ProdCode,BusCatDesc,ExpNode,Flex1,FSitem,RiskTerr,ReinLoc,CatCode,AccYr,ReinName,SubProd,TransCode,Stat from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G29', 462, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'') then '''' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' then '''' else x.TTY end) and m.Field6 = ''1'' where KeyID = ''[batchID]'')'),
    ('SQL-R27', 201, 'insert into TransX (KeyID, Ledger,GL,Co, TP, TTY, Amt1, Amt2, Flex3) (select KeyID, Ledger,GL,Co, TP, TTY, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, ''pass1'' as Flex3 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger,GL,Co, TP, TTY)'),
    ('SQL-R27', 202, 'delete from TransX where KeyID = ''[batchID]'' and (Flex3 is NULL or (Amt1 = 0 and Amt2 = 0))'),
    ('SQL-R27', 211, 'update TransX set Flex1 = ''Gross Unpaid Claim Liabilities'' from TransX where KeyID = ''[batchID]''  and GL like ''20%'''),
    ('SQL-R27', 212, 'update TransX set Flex1 = ''Ceded Unpaid Claim Liabilities'' from TransX where KeyID = ''[batchID]''  and GL like ''14%'''),
    ('SQL-R16c', 122, 'delete from TransX where KeyID = ''[batchID]'' and Amt2 = 0 and Amt3 = 0'),
    ('SQL-R16c', 149, 'update TransX set Amt4 = NULL, Flex1 = ''pass1'' from TransX where KeyID = ''[batchID]'''),
    ('SQL-R16', 223, 'update TransX set TPname = m.Name from TransX t inner join TPs m on t.TP = m.TP where KeyID = ''[batchID]'''),
    ('SQL-R03', 203, 'update TransX set TPname = p.Name from TransX t inner join TPs p on t.TP = p.TP where KeyID = ''[batchID]'''),
    ('SQL-E00', 1105, 'update TransX set Amt3 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1 from TransX where KeyID = ''[batchID]-save'' and Ledger = ''UG'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1'),
    ('SQL-E00', 1110, 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1'),
    ('SQL-E00', 1115, 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1 from TransX where KeyID = ''[batchID]-save'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1'),
    ('SQL-E12', 2001, 'update TransX set CC = ''5EOI000000'', PC = '''' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and CostCenter = 1'),
    ('SQL-G88', 401, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP, Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, (case when Amt4 > 0 then Amt4 else 0 end) as Amt4, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2008'')'),
    ('SQL-G88', 402, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, (case when Amt4 < 0 then Amt4 else 0 end) as Amt4, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2008'')'),
    ('SQL-S03', 512, 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
    ('SQL-R18', 131, 'update TransX set Amt3 = Amt1 - Amt2, Amt5 = Amt1 - Amt4, Amt7 = Amt1 - Amt6 where KeyID = ''[batchID]'''),
    ('SQL-G88', 403, 'delete from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2008'''),
    ('SQL-R18', 132, 'delete from TransX where KeyID = ''[batchID]'' and (Flex6 is null or (Amt1 = 0 and Amt2 = 0 and Amt4 = 0 and Amt6 = 0))'),
    ('SQL-R18', 133, 'update TransX set Flex1 = Mapkey from TransX t inner join mapkeyranges m on t.GL >= m.fromGL and t.GL <=m.thruGL where keyID = ''[batchID]'' and mapkey like ''M1-2-7-%'''),
