    ('SQL-R18', 136, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R18', 137, 'update TransX set TPname = m.Name from TransX t inner join TPs m on t.TP = m.TP where KeyID = ''[batchID]'''),
    ('SQL-R18', 141, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data2'', Ledger, Flex1, Flex2, ''1. [CQ1] vs. [PQ1]'' as Flex3, round(sum(Amt3)/1000,0) as Amt3 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R18', 142, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data2'', Ledger, Flex1, Flex2, ''2. [CQ1] vs. [PYE1]'' as Flex3, round(sum(Amt5)/1000,0) as Amt5 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and Period > 3 group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R18', 143, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data2'', Ledger, Flex1, Flex2, ''3. [CQ1] vs. [PYCQ1]'' as Flex3, round(sum(Amt7)/1000,0) as Amt7 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R18', 144, 'delete from TransX where KeyID = ''[batchID]-data2'' and Abs(Amt1) < 500'),
    ('SQL-R18', 151, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data3'', Ledger, Flex1, Flex2, ''1. [CQ1] vs. [PQ1]'' as Flex3, round(sum(Amt3)/1000,0) as Amt3 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R18', 152, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data3'', Ledger, Flex1, Flex2, ''2. [CQ1] vs. [PYE1]'' as Flex3, round(sum(Amt5)/1000,0) as Amt5 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' and Period > 3 group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R18', 153, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data3'', Ledger, Flex1, Flex2, ''3. [CQ1] vs. [PYCQ1]'' as Flex3, round(sum(Amt7)/1000,0) as Amt7 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-G67', 241, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select KeyID,Ledger,Co,GL,TP,round(sum(Amt1),2) as Amt1,''pass6'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,Ledger,Co,GL,TP'),
