    ('SQL-G31', 431, 'update TransX set TP = ''2008'' from TransX where KeyID = ''[batchID]'' and GL = ''1999901'' and PC like ''5702%'''),
    ('SQL-G31', 432, 'update TransX set ProdCode = ''U1892'', PTF = ''U3650'' from TransX where KeyID = ''[batchID]'' and GL = ''4600000'''),
    ('SQL-G32', 218, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, x.GL + '' '' + TTY as Assgnmt, Crcy, m.Field5 as TTY, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'',''232'') then '''' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' then '''' else x.TTY end) and m.Field6 = ''1'' where KeyID in (''[batchID]'',''[batchID]-data8''))'),
    ('SQL-G32', 286, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''602'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Flex5, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600000'')'),
    ('SQL-G86', 211, 'insert into TransX (KeyID, GL,Contract,ProdCode,CC, Crcy,Amt1, Amt2, Amt3,PK) (Select KeyID, GL,Contract,ProdCode,CC, Crcy, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,  round(sum(coalesce(Amt3,0)),2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, GL,Contract,ProdCode,CC, Crcy)'),
    ('SQL-G32', 289, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560001'' as GL, Crcy, PC,''627'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600067'')'),
    ('SQL-G25', 104, 'delete from TransX where KeyID = ''[batchID]''  and ''[version]'' = ''First'' and Co like ''599%'''),
    ('SQL-G25', 111, 'Update TransX set Amt1 = coalesce(Amt4,0), Amt2 = coalesce(Amt5,0), Amt3 =coalesce(Amt6,0) where KeyID = ''[batchID]'' and ''[yyyy-mm-dd]'' = ''2022-01-31'' and not Co like ''599%'''),
    ('SQL-M25', 436, 'update TransX set Flex5 = ''04 ODY TP''  where KeyID = ''[batchID]'' and GL like ''44155%'' and SubProd= ''G23'' and Flex5 = '''''),
    ('SQL-M25', 437, 'update TransX set Flex5 = ''04 ODY TP''  where KeyID = ''[batchID]'' and SubProd = ''G25'' and Flex5 = '''''),
    ('SQL-M25', 441, 'update TransX set Flex5 = ''06 FH''  where KeyID = ''[batchID]'' and SubProd in (''G23'',''G26'') and substring(GL,1,3) in (''441'',''x682'') and Flex5 = '''''),
    ('SQL-M25', 442, 'update TransX set Flex5 = ''06 FH''  where KeyID = ''[batchID]'' and SubProd = ''G23'' and substring(GL,1,2) in (''16'',''24'') and Flex5 = '''''),
    ('SQL-M25', 445, 'update TransX set Flex5 = ''06 FH''  where KeyID = ''[batchID]'' and SubProd = ''G26'' and GL in (''1550003'',''1558903'',''1560003'',''1568903'',''2150003'',''2158903'',''2160003'',''2168903'') and Flex5 = '''''),
    ('SQL-M25', 451, 'update TransX set Flex5 = ''10 WH/Other''  where KeyID = ''[batchID]'' and SubProd = ''G23'' and GL in (''1935002'',''2550001'',''2550002'',''2810029'',''2810033'',''2810034'',''2810037'',''2810038'',''2855100'') and Flex5 = '''''),
    ('SQL-G32', 290, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560001'' as GL, Crcy, PC,''615'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, Flex5, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600067'')'),
    ('SQL-M17', 403, 'update TransX set Txt = ''G23'' where KeyID = ''[batchID]'' and Txt = '''' and Co like ''599%'''),
    ('SQL-G85', 101, 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,TP,UWYR,Contract,ReinName,BusCat,Amt1,Amt2,Flex1) (select KeyID,Ledger,Co,Crcy,GL,PC,(case when TP like ''F%'' then TP else '''' end) as TP,UWYR,Contract,ReinName,BusCat,round(sum(Amt1),2),round(sum(Amt2),2),''pass1'' from TransX where KeyID = ''[batchID]'' group by KeyID,Ledger,Co,Crcy,GL,PC,TP,UWYR,Contract,ReinName,BusCat)'),
    ('SQL-G81', 111, 'Delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 '),
    ('SQL-G81', 112, 'Delete from TransX where KeyID = ''[batchID]'' and cast(GL as varchar(7)) + cast(Co as varchar(4)) in (Select cast(x.GL as varchar(7)) + cast(x.Co as varchar(4)) from COAxCo x inner join Companies y on x.Co = y.Co where GL >= ''1050000'' and GL <= ''1099800'' and not x.Crcy = y.Crcy)'),
    ('SQL-G81', 113, 'Delete from TransX where KeyID = ''[batchID]'' and cast(Co as varchar(4)) + Crcy in (Select cast(Co as varchar(4)) + Crcy from Companies)'),
    ('SQL-G81', 121, 'update TransX set Amt2 = 0, Amt3 = 0, Amt4 = 0, Amt5 = 0 from TransX where KeyID = ''[batchID]'''),
    ('SQL-G81', 122, 'update x set Amt2 = y.Amt1 from TransX x inner join (Select KeyID,Flex3,Crcy,Co,GL,PC,UWYR,round(sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''0L'' group by KeyID,Flex3,Crcy,Co,GL,PC,UWYR) y on x.KeyID = y.KeyID and x.Flex3 = y.Flex3 and x.Crcy = y.Crcy and x.Co = y.Co and x.GL = y.GL and x.PC = y.PC and x.UWYR = y.UWYR'),
    ('SQL-G81', 123, 'update x set Amt3 = y.Amt1 from TransX x inner join (Select KeyID,Flex3,Crcy,Co,GL,PC,UWYR,round(sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' group by KeyID,Flex3,Crcy,Co,GL,PC,UWYR) y on x.KeyID = y.KeyID and x.Flex3 = y.Flex3 and x.Crcy = y.Crcy and x.Co = y.Co and x.GL = y.GL and x.PC = y.PC and x.UWYR = y.UWYR'),
