    ('SQL-G85', 232, 'insert into TransX (KeyID, RefKey3, Ledger, Crcy, Co, PC, TP, Contract, UWYR, BusCat, ReinName, Assgnmt, Txt, Amt4, Amt5, GL, TTY, Amt6) (Select KeyID, RefKey3, Ledger, Crcy, Co, PC, TP, Contract, UWYR, BusCat, ReinName, Assgnmt, Txt, 0 as Amt4, 0 as Amt5,Descr as GL, Field2 as TTY, Amt6 * cast(Field3 as int) as Amt6 from TransX inner join Misc_Tables on GL = ID where KeyID = ''[batchID]'' and Table_ID = ''ElimGLmap8'' and BusCat >= 30 )'),
