    ('SQL-S03', 508, 'insert into TransX (KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1) (Select KeyID, Ledger, Co, GL, '''' as PC, '''' as CC, '''' as TP, '''' as BusCat, Contract, isnull(UWYR,'''') as UWYR, '''' as TTY, round(sum(Amt1),2) as Amt1, ''pass4'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1 <> ''pass1'' and GL > ''4000000'' group by KeyID, Ledger, Co, GL,  Contract, isnull(UWYR,''''))'),
    ('SQL-S03', 509, 'delete from TransX where KeyID = ''[batchID]'' and (Flex1 in (''pass2'',''pass3'') or Amt1 = 0)'),
    ('SQL-S03', 510, 'update TransX set Amt2 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
    ('SQL-S03', 511, 'update TransX set Amt3 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
