    ('SQL-R58', 143, 'Update TransX set Flex4 = c.Region,Flex5 = c.Region from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'' and coalesce(Flex5,'''') = '''''),
    ('SQL-R58', 101, 'insert into TransX (KeyID, Co, GL, PC, BusCat,ProdCode, RiskTerr,ReinLoc,Amt1) (select ''[batchID]-data2'', Co, GL, PC, BusCat,ProdCode, RiskTerr,ReinLoc,Amt1  from TransX  where KeyID = ''[batchID]'' and Amt1 <>0)'),
    ('SQL-S22', 433, 'update c set NAIC = x.NAIC_COMPANY, FedID = x.FEIN_NUM, RSG_CedingCo = x.COMPANY_ID, Name = x.NAME from CedingCoByQtr c inner join [stm-dwhse-01].[ORION].dbo.[Companies] x on c.CedingCo = cast(x.BART_MAP_TO as varchar(20)) where coalesce(c.RSG_CedingCo,'''') = '''' and coalesce(x.NAIC_COMPANY,'''') <> '''' and c.Yr = ''[Yr]'' and c.Per = ''[Mo]'' and c.SAP_CedingCo is not NULL'),
