    ('SQL-S22', 435, 'update c set RSG_CedingCo = x.COMPANY_ID, Name = x.NAME from CedingCoByQtr c inner join [stm-dwhse-01].[ORION].dbo.[Companies] x on c.CedingCo = cast(x.BART_MAP_TO as varchar(20)) where coalesce(c.RSG_CedingCo,'''') = '''' and c.Yr = ''[Yr]'' and c.Per = ''[Mo]'' and c.SAP_CedingCo is not NULL'),
