    ('SQL-G24', 210, 'Update x set Amt1 = round(Amt1*c.Rate,2), Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy inner join CrcyRates c on c.Crcy = x.Crcy and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-G24', 212, 'delete from TransX where KeyID = ''[batchID]''  and ''[yyyy-mm-dd]'' = ''2022-01-31'' and (GL = ''1099917'' or GL > ''3000000'')'),
    ('SQL-G24', 213, 'update TransX set  TP = '''' where KeyID = ''[batchID]'' and substring(GL,1,3) in (''282'',''283'',''284'',''563'')'),
    ('SQL-G24', 222, 'delete from TransX where KeyID = ''[batchID]'''),
    ('SQL-G24', 223, 'delete from TransX where KeyID = ''[batchID]-data2'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G24', 231, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, PTF,Flex5, Amt1, Amt2, Amt3) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, PTF,Flex5,Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]-data2'')'),
    ('SQL-G24', 236, 'Update TransX set PC = ''5500000000'' where KeyID = ''[batchID]'' and Flex5 = ''Investment'''),
    ('SQL-G24', 243, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and not GL in (''2853500'',''2851017'')'),
    ('SQL-G86', 302, 'delete from TransX where KeyID = ''[batchID]'' and PK = '''''),
    ('SQL-G87', 303, 'insert into TransX (KeyID, Co,GL, Crcy,PC,CC,Contract,ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, ''2008'' as Co,''6911000'' as GL, Crcy, '''' as PC, ''5USA000087'' as CC, ''5OSS000001'' as Contract, ''CHGBACK'' as ProdCode, round(-Amt1,2) as Amt1, 0 as Amt2, round(-Amt3,2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' and GL = ''6910501'' and Co = ''4010'')'),
    ('SQL-R33', 103, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-S32', 201, 'update TransX set BusCat = '''' from TransX where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-S32', 202, 'update TransX set BusCat = ''20'' from TransX where KeyID = ''[batchID]'' and BusCat in (''21'',''22'',''23'',''24'')'),
    ('SQL-S32', 203, 'update TransX set BusCat = ''30'' from TransX where KeyID = ''[batchID]'' and BusCat in (''31'',''32'',''33'',''34'')'),
    ('SQL-S32', 204, 'update TransX set GL = substring(GL,1,2) + ''10000'' from TransX where KeyID = ''[batchID]'' and GL > = ''4000000'' and GL <= ''5999999'' and GL like ''%99998'''),
    ('SQL-S32', 314, 'update TransX set GL = substring(GL,1,3) + ''9900'' from TransX where KeyID = ''[batchID]'' and GL < ''6000000'' and GL <> ''4498000'' and GL <> ''2850500'' and Co in (''2999'',''3999'')'),
    ('SQL-S32', 205, 'update TransX set GL = substring(GL,1,3) + ''0000'' from TransX where KeyID = ''[batchID]'' and GL > = ''4000000'' and GL <= ''5999999'' and GL <> ''4498000'''),
    ('SQL-S32', 301, 'insert into TransX (KeyID, YearPeriod,Yr,Period,Ledger, Co, GL, PC, CC, BusCat, Amt1, Flex1) (Select KeyID, YearPeriod,Yr,Period, Ledger, Co, GL,PC, '''' as CC,BusCat,round(sum(Amt1),2) as Amt1, ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' and GL < ''6000000'' and GL <> ''4498000'' group by KeyID, YearPeriod,Yr,Period, Ledger, Co, GL,  PC, BusCat)'),
    ('SQL-M41', 225, 'update TransX set Flex7 = REPLACE(m.Name,'' & ULAE'','''') from TransX t inner join mapkeys m on t.flex6 = m.mapkey where keyID = ''[batchID]'''),
    ('SQL-M41', 302, 'Update x set Flex8 = x.Flex2 + ''-'' + m1.field3 + ''-'' + x.Flex5, Division = m1.field2 from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' where KeyID = ''[batchID]'''),
    ('SQL-M41', 303, 'Update x set Flex5 = m2.field2 from TransX x inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-M41', 304, 'Update TransX set TPname = CASE WHEN TP = '''' THEN ''3rd'' WHEN SUBSTRING(TP,1,1) = ''F'' THEN ''FFH'' ELSE ''ODY'' END where KeyID = ''[batchID]'''),
    ('SQL-S38', 203, 'update TransX set Flex2 = ''Expenses - After Allocation'' from TransX where KeyID = ''[batchID]'' and BusCat = ''98'' or (GL in (''6998000'',''4498000'',''6997000'') and BusCat = '''')'),
    ('SQL-S38', 204, 'update TransX set Flex2 = ''Prophecy - Prem Wr'' from TransX where KeyID = ''[batchID]'' and GL like ''40%'''),
    ('SQL-S38', 205, 'update TransX set Flex2 = ''Prophecy - UPR'' from TransX where KeyID = ''[batchID]'' and GL like ''41%'''),
    ('SQL-S38', 206, 'update TransX set Flex2 = ''Prophecy - Paid Loss'' from TransX where KeyID = ''[batchID]'' and (GL like ''50%'' or GL like ''51%'' or GL like ''52%'')'),
    ('SQL-S38', 207, 'update TransX set Flex2 = ''Prophecy - Case'' from TransX where KeyID = ''[batchID]'' and GL like ''53%'''),
    ('SQL-S38', 208, 'update TransX set Flex2 = ''Prophecy - Comm'' from TransX where KeyID = ''[batchID]'' and GL like ''54%'''),
    ('SQL-S38', 209, 'update TransX set Flex2 = ''Prophecy - DAC'' from TransX where KeyID = ''[batchID]'' and GL like ''55%'''),
    ('SQL-S38', 210, 'update TransX set Flex2 = ''Other P&L'' from TransX where KeyID = ''[batchID]'' and GL > ''4000000'' and Flex2 is NULL'),
    ('SQL-S38', 211, 'update TransX set Flex1 = ''[Yr] [version] '' + (case when ''[version]'' = ''P'' then ''Budget'' else ''Outlook'' end) from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-R98', 201, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R15', 201, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R19', 162, 'update TransX set Flex3 = c.Descr from TransX t inner join TTYs c on t.TTY = c.TTY where KeyID = ''[batchID]'''),
    ('SQL-R15', 211, 'update TransX set Flex1 = ''Ceded'', Flex2 = ''no'', Flex5 = ''non-affiliate'', Amt2 = Amt1 from TransX where KeyID = ''[batchID]'''),
    ('SQL-R15', 212, 'update TransX set Flex1 = ''Assumed'' from TransX where KeyID = ''[batchID]'' and BusCat >= ''20'' and BusCat <= ''29'''),
    ('SQL-R15', 214, 'update TransX set Flex1 = ''Direct'' from TransX where KeyID = ''[batchID]'' and BusCat = ''10'''),
    ('SQL-R15', 215, 'update TransX set Flex2 = ''yes'' from TransX where KeyID = ''[batchID]'' and (GL like ''%96'' or GL like ''%98'')'),
    ('SQL-R15', 216, 'update TransX set Flex3 = m.Descr from TransX t inner join Misc_Tables m on substring(t.GL,1,3) = m.ID and t.Flex1 = m.Field1 where KeyID = ''[batchID]'' and m.Table_ID = ''GL Sched F'''),
    ('SQL-R15', 218, 'update TransX set Amt2 = -Amt1 from TransX where KeyID = ''[batchID]'' and ((substring(GL,1,1) = ''4'' and Flex1 <> ''Ceded'') or (substring(GL,1,1) = ''5'' and Flex1 = ''Ceded''))'),
    ('SQL-R15', 220, 'update TransX set TP = Field1 from TransX inner join Misc_Tables on ReinName = Descr where  KeyID = ''[batchID]'' and Table_ID = ''TP Sched F'' and TP is NULL'),
    ('SQL-G33', 221, 'insert into TransX (KeyID, Co, GL, Crcy, TP, PC, ProdCode, PTF, Amt1, Amt2) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TP, PC, ProdCode, PTF, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TP, PC,ProdCode,PTF)'),
    ('SQL-G33', 222, 'delete from TransX where KeyID = ''[batchID]'''),
    ('SQL-G33', 223, 'delete from TransX where KeyID = ''[batchID]-data2'' and Amt1 = 0 and Amt2 = 0'),
    ('SQL-G33', 231, 'insert into TransX (KeyID, GL, PC, Amt2, Flex1) (Select ''[batchID]'' as KeyID, substring(GL,3,1), substring(PC,1,6), round(sum(Amt2),2) as Amt2, ''pass1'' from TransX where KeyID = ''[batchID]-data2'' group by substring(GL,3,1),substring(PC,1,6))'),
    ('SQL-G33', 232, 'update TransX set Amt2 = 1 where KeyID = ''[batchID]'' and PC = ''550000'' and GL = ''6'''),
    ('SQL-G33', 233, 'update TransX set Amt2 = -1 where KeyID = ''[batchID]'' and PC = ''550000'' and GL = ''5'''),
    ('SQL-G33', 234, 'update TransX set GLdesc = (case when Amt2 >= 0 then 150 else 210 end) + GL where KeyID = ''[batchID]'''),
    ('SQL-G33', 241, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Amt1, Amt2,Assgnmt) (Select y.KeyID, x.Co, y.GLdesc + substring(x.GL,4,4), x.Crcy, ''877'' as TTY, x.TP, x.PC, x.ProdCode, x.PTF, x.Amt1, x.Amt2,x.GL from TransX x inner join TransX y on substring(x.PC,1,6) = y.PC and substring(x.GL,3,1) = y.GL and x.KeyID = ''[batchID]-data2'' and y.KeyID = ''[batchID]'' where substring(x.GL,1,3) <> y.GLdesc)'),
    ('SQL-G33', 242, 'delete from TransX where KeyID = ''[batchID]'' and Crcy is NULL'),
    ('SQL-G33', 243, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Amt1, Amt2,Assgnmt) (Select KeyID, Co, Assgnmt, Crcy, TTY, TP, PC, ProdCode, PTF, round(-Amt1,2), round(-Amt2,2),Assgnmt from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G33', 331, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, Amt1, Amt2, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
    ('SQL-G33', 332, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, Amt1, Amt2, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, TTY, TP, Assgnmt, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
    ('SQL-G33', 333, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G33', 334, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0'),
    ('SQL-G33', 401, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-G33', 402, 'update TransX set Txt = ''IFRS-17 asset-liab reclass'', SubProd = ''G27'' from TransX where KeyID = ''[batchID]'''),
    ('SQL-P00', 1204, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt3 = 0'),
    ('SQL-P00', 1006, 'delete from TransX where KeyID = ''[batchID]'' and (GL < ''4000000'' or GL like ''43%'') and not GL in (select Descr from Misc_Tables where Table_ID = ''True-up FX'' and ID = ''GL'')'),
    ('SQL-P00', 1036, 'update x set GL = m.Descr from TransX x inner join Misc_Tables m on x.GL = m.ID and m.Table_ID = ''ElimGLmap3'' and m.field1 = ''CtoA'' inner join Eliminations e on e.ID = ''[ElimID]'' where x.KeyID = ''[batchID]'' and substring(x.GL,6,2) in (''96'',''98'') and e.TrueUpAorC = ''A'' and not e.TrueUpCo in (''2201'',''2300'',''2400'',''2450'')'),
    ('SQL-P00', 1037, 'update x set GL = ''441'' + substring(x.GL,4,4) from TransX x  inner join Eliminations e on e.ID = ''[ElimID]'' where x.KeyID = ''[batchID]'' and x.GL like ''682%'' and e.TrueUpAorC = ''A'''),
    ('SQL-P00', 1038, 'update x set GL = ''682'' + substring(x.GL,4,4) from TransX x  inner join Eliminations e on e.ID = ''[ElimID]'' where x.KeyID = ''[batchID]'' and x.GL like ''441%'' and e.TrueUpAorC = ''C'''),
    ('SQL-P00', 1040, 'update x set Contract = e.TrueUpContract from TransX  x inner join Eliminations e on e.ID = ''[ElimID]'' where KeyID = ''[batchID]'''),
    ('SQL-M25', 104, 'insert into TransX (KeyID, Flex9, Co, GL, FSitem, TTY, TP, BusCat, SubProd, Amt1, Flex5) (Select KeyID, Flex9, Co, GL, FSitem, TTY, TP, BusCat, SubProd, Amt2, '''' as Flex5 from TransX where KeyID = ''[batchID]'' and Co <> ''JE'')'),
    ('SQL-M42', 301, 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.Flex2 + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-M42', 321, 'insert into TransX (KeyID, Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4,Amt1,Amt2) (select KeyID + ''-data2'', Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4,ROUND(SUM(Amt1),2),ROUND(SUM(Amt2),2) from TransX where KeyID = ''[batchID]'' group by KeyID, Yr,Co,Crcy,Flex6,Flex7,GL,GLdesc,Flex2,TP,TPname,PC,Flex5,Flex9,Flex8,TTY,Flex4)'),
    ('SQL-G43', 242, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, case when Amt1<0 then Amt1 else 0 end as Amt1, case when Amt2<0 then Amt2 else 0 end as Amt2,  case when Amt3<0 then Amt3 else 0 end as Amt3,  ''50'' as PK from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-R82', 232, 'insert into TransX (KeyID,Flex1,Crcy,Flex2,Flex3,Date1,Period,Rate1,Flex4,Amt2,Amt3,Flex5,Flex6,Flex7) (select ''[batchID]'',''''''01'',r.Crcy,''USD'',''Y'',''[yyyy-mm-dd]'',0,round(avg(round(1/r.rate/c.xfactor,5)),5) as rate,'''',c.xfactor,1,'''','''','''' from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where r.Typ = ''M'' and year(r.EffDate) = ''[Yr]'' and r.Crcy in (''AUD'',''BBD'',''BRL'',''CAD'',''EUR'',''GBP'',''MXN'',''SEK'',''SGD'') group by r.Crcy,c.xfactor)'),
    ('SQL-S20', 321, 'update TransX set PC = '''', CC = c.CCtr From TransX x inner join (Select Co,PCtr,max(CCtr) as CCtr from CCtrs group by Co,Pctr) c on x.Co = c.Co and x.PC = c.PCtr where KeyID = ''[batchID]'' and x.Co < ''5001'' and x.GL > ''6000000'' and x.GL < ''7100000'''),
    ('SQL-G35', 101, 'update TransX set Amt1 = coalesce(Amt1,0), Amt2 = coalesce(Amt2,0), Amt3 = coalesce(Amt3,0) where KeyID = ''[batchID]'''),
    ('SQL-G35', 102, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 and Amt2 = 0 and Amt3 = 0)'),
    ('SQL-R17', 142, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data2'', Ledger, Flex1, Flex2, ''2. [CQ1] vs. [PYE1]'' as Flex3, round(sum(Amt5)/1000,0) as Amt5 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and Period > 3 group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R51', 309, 'update TransX set Flex3 = ''i - D&H 267'' where KeyID = ''[batchID]'' and PC in (''4050100267'',''1402000755'') and Flex3 = ''i - D&H'''),
    ('SQL-R54', 301, 'delete from TransX where KeyID = ''[batchID]'' and Flex3 <> '''''),
    ('SQL-G54', 401, 'update TransX set PK = ''40'', CC = ''5USI000001'', Flex6 = '''', Txt = ''IFRS Inv Exp Reclass'' from TransX where KeyID = ''[batchID]'''),
    ('SQL-G54', 402, 'update TransX set PK = ''50'' from TransX where KeyID = ''[batchID]'' and Amt1 < 0'),
    ('SQL-G54', 403, 'update TransX set CC = ''5OHI000000'' from TransX where KeyID = ''[batchID]'' and Co = ''1000'''),
    ('SQL-G54', 411, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-G54', 421, 'update TransX set Flex1 = cast(ABS(Amt1) as varchar(255)) from TransX where KeyID = ''[batchID]'''),
    ('SQL-G54', 431, 'update TransX set Ledger = ''IF'',PC = '''',TP = '''',TTY='''',ProdCode = '''',UWYR = '''',AccYr = '''',ReinName = '''',ReinLoc = '''',BusCat = '''',Contract = '''',CatCode = '''',RiskTerr = '''',Broker = '''',PTF = '''',Stat = '''',TransCode = '''' from TransX where KeyID = ''[batchID]'''),
    ('SQL-R51', 109, 'update TransX set Flex2 = ''Co'' + Co + '' Tp'' + TP from TransX where KeyID = ''[batchID]'''),
    ('SQL-R56', 209, 'update TransX set Flex2 = ''Ceded IBNR'' from TransX where KeyID = ''[batchID]'' and (GL like ''143%'' or GL like ''145%'' or GL like ''146%'' or GL like ''147%'')'),
    ('SQL-R56', 211, 'update TransX set Flex2 = ''Gross IBNR'' from TransX where KeyID = ''[batchID]'' and (GL like ''203%'' or GL like ''205%'' or GL like ''206%'' or GL like ''207%'')'),
    ('SQL-R56', 226, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, GLdesc, PC, PCdesc, Hierarchy, TP, TPname, TTY, Flex1, Flex2, Flex3, Flex4, Amt1) (select KeyID, YearPeriod, Yr, Period, Ledger, ''adj'' as Co,'' adj'' as GL, ''Gulf RBP'' as GLdesc, ''adj'' as PC, ''adj'' as PCdesc, ''adj'' as Hierarchy, ''adj'' as TP, ''adj'' as TPname, ''824'' as TTY, ''Gross Unpaid Claim Liabilities'' as Flex1, ''adj'' as Flex2, ''5 Paid - curr year'' as Flex3, ''3rd Party'' as Flex4, round(sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and TP in (''F0075'',''F0080'') and Flex1 = ''RBP'' group by KeyID, YearPeriod, Yr, Period, Ledger)'),
    ('SQL-R56', 227, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, GLdesc, PC, PCdesc, Hierarchy, TP, TPname, TTY, Flex1, Flex2, Flex3, Flex4, Amt1) (select KeyID, YearPeriod, Yr, Period, Ledger, Co,GL, GLdesc, PC, PCdesc, Hierarchy, TP, TPname, TTY, Flex1, Flex2, Flex3, ''I/C'' as Flex4, round(-Amt1,2) as Amt1 from TransX where KeyID = ''[batchID]'' and GLdesc = ''Gulf RBP'')'),
    ('SQL-R41', 100, 'delete from TransX where KeyID = ''[batchID]'' and amt1 = 0'),
    ('SQL-R41', 101, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R41', 201, 'update TransX set Flex3 = substring(m2.MapKey,4,1) + '' '' + m2.Name from TransX inner join MapKeyRanges m1 on Co >= FromGL and Co <= ThruGL inner join MapKeys m2 on m1.MapKey = m2.MapKey where KeyID = ''[batchID]'' and m1.MapKey like ''C2%'''),
    ('SQL-G72', 202, 'Update x set x.GL = y.Field1 from TransX x inner join Misc_Tables y on x.GL = y.Descr where KeyID = ''[batchID]'' and Table_ID = ''Reimburse'' and ID = ''GL'''),
    ('SQL-G69', 301, 'update TransX set ProdCode = ''UNKNOWN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and Product = 1'),
    ('SQL-G69', 302, 'update TransX set AccYr = ''9999'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and AccidentYear = 1'),
    ('SQL-G69', 303, 'update TransX set ReinLoc = ''UNKN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and InsurerLocation = 1'),
    ('SQL-G69', 304, 'update TransX set RiskTerr = ''UNKN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and RiskLocation = 1'),
    ('SQL-G69', 305, 'update TransX set Broker = ''UNKNOWN'' from TransX t inner join [GFS].dbo.FSGValidation v on GL = GLAccount where KeyID = ''[batchID]'' and v.Broker = 1'),
    ('SQL-G69', 306, 'update TransX set ReinName = ''UNKNOWN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and Cedant = 1'),
    ('SQL-G69', 307, 'update TransX set TransCode = ''T9999'' from TransX inner join [GFS].dbo.FSGValidation v on GL = GLAccount where KeyID = ''[batchID]'' and v.TransCode = 1'),
    ('SQL-G83', 251, 'update TransX set BusCat = '''' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and ReinsType = 0'),
    ('SQL-G83', 252, 'update TransX set ProdCode = ''UNKNOWN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and Product = 1'),
    ('SQL-G47', 262, 'update TransX set Flex1 = cast(ABS(Amt1) as varchar(255)) from TransX where KeyID = ''[batchID]'''),
    ('SQL-G47', 263, 'update TransX set PK = ''40'' from TransX where KeyID = ''[batchID]'' and Amt1 > 0'),
    ('SQL-G47', 264, 'update TransX set PK = ''50'' from TransX where KeyID = ''[batchID]'' and Amt1 < 0'),
