    ('SQL-R33', 212, 'update TransX set Flex2 = m.Name from TransX t inner join MapKeys m on t.Flex1 = m.MapKey where KeyID = ''[batchID]'''),
    ('SQL-G43', 222, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, substring(GL,1,5) + ''00'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and ((GL >= ''3000000'' and GL < ''3330000'') or GL >= ''3640000''))'),
    ('SQL-G43', 223, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, substring(GL,1,5) + ''00'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and GL >= ''3330000'' and GL < ''3600000'' and substring(GL,6,2) in (''01'',''02''))'),
    ('SQL-G43', 231, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3,  ''99'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY,PTF)'),
    ('SQL-M25', 531, 'update TransX set Flex5 = ''06 FH''  where KeyID = ''[batchID]'' and Flex5 in (''02 RI'',''05 Other'') and GL in (''3572102'',''3572202'',''3591002'',''4397002'',''4398007'',''4398010'')'),
    ('SQL-M25', 533, 'update TransX set Flex5 = ''05 Other''  where KeyID = ''[batchID]'' and Flex5 = ''02 RI'' and TTY = ''809'''),
    ('SQL-P00', 1081, 'insert into TransX (KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat, TTY, Amt1, Amt3) (Select x.KeyID, x.Ledger, x.Crcy, x.Co, y.Descr as GL, x.PC, x.Contract, x.TP, x.BusCat, y.Field2 as TTY, round(x.Amt1 * y.Field3,2) as Amt1, round(x.Amt3 * y.Field3,2) as Amt3 from TransX x inner join Misc_Tables y on x.GL = y.ID and (substring(x.BusCat,1,1) = substring(y.Field1,1,1) or (substring(x.BusCat,1,1) = '''' and substring(y.Field1,1,1) = ''3''))and y.Table_ID in (''ElimGLmap7'',''ElimGLmap8'') where KeyID = ''[batchID]'')'),
    ('SQL-P00', 1101, 'update TransX set Amt2 = f2.Amt1, Amt4 = f2.Amt3 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, Contract, TP, BusCat, TTY, Amt1, Amt3 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and f1.Contract = f2.Contract and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1 and f1.Amt3 = f2.Amt3'),
    ('SQL-P00', 1102, 'update TransX set Amt5 = f2.Amt1, Amt6 = f2.Amt3 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, Contract, TP, BusCat, TTY, Amt1, Amt3 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and f1.Contract = f2.Contract and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1 and f1.Amt3 = f2.Amt3'),
    ('SQL-P00', 1103, 'update TransX set Amt7 = f2.Amt1, Amt8 = f2.Amt3 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, Contract, TP, BusCat, TTY, Amt1, Amt3 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and f1.Contract = f2.Contract and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.TTY = f2.TTY and f1.Amt1 = f2.Amt1 and f1.Amt3 = f2.Amt3'),
    ('SQL-P00', 1122, 'delete from TransX where KeyID like ''[batchID]%'' and Ledger = ''UG'' and Amt1 = coalesce(Amt5,0) and Amt3 = coalesce(Amt6,0)'),
