    ('SQL-R51', 307, 'update TransX set Flex3 = ''e - Healthcare'' where KeyID = ''[batchID]'' and  Flex3 = ''a - 70% QS'' and Co = ''2008'' and TP in (''2300'',''2400'') and UWYR = ''9999'''),
    ('SQL-G60', 102, 'insert into TransX (KeyID, Co,Flex1,Flex2,Flex3,Date1,Date2,Crcy,GL,GLdesc,Amt1,PC,CC) (Select KeyID + ''-data2'', Co,Flex1,Flex2,Flex3,Date1,Date2,Crcy,GL,GLdesc,Amt1,PC,CC from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-R08', 204, 'update TransX set Flex4 = ''IBNR'' from TransX where KeyID = ''[batchID]'' and (substring(GL,1,3) in (''143'',''145'',''203'',''205'') or GL = ''2040001'')'),
