    ('SQL-R08', 209, 'update TransX set Flex5 = ''Loss'' from TransX where KeyID = ''[batchID]'' and (substring(GL,1,3) in (''141'',''142'',''143'',''201'',''202'',''203'',''531'',''532'',''533'') or GL like ''50%'' or GL = ''2040001'')'),
