    ('SQL-M13', 417, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6) (select ''[batchID]-data8'',Co,GL,Crcy,PC,CC,ACD,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(-Doc_QTD),2) as Doc_QTD,round(sum(-Doc_ITD),2) as Doc_ITD,round(sum(-LC_QTD),2) as LC_QTD,round(sum(-LC_ITD),2) as LC_ITD,round(sum(-LC2_QTD),2) as LC2_QTD,round(sum(-LC2_ITD),2) as LC2_ITD from IR17_Other where source = ''R69'' GROUP BY Co,GL,Crcy,PC,CC,ACD,Source union all select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from IR17_Control where source = ''R63'' and GL in (''nothing'') GROUP BY Co,GL,Crcy,PC,CC,ACD,Source) a GROUP BY Co,GL,Crcy,PC,CC,ACD) b where (abs(Doc_QTD) > 1 or abs(Doc_ITD) > 1 or abs(LC_QTD) > 1 or abs(LC_ITD) > 1 or abs(LC2_QTD) > 1 or abs(LC2_ITD) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-G88', 303, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Amt1) (select KeyID,GL,''USD'' as Crcy,''3080'' as Co,''3GSA100004'' as CC,Amt3 from TransX where KeyID = ''[batchID]'' and Co is NULL)'),
    ('SQL-G88', 304, 'insert into TransX (KeyID, GL, Crcy,Amt1,Co,PC,TP) (Select KeyID, ''2899901'' as GL, ''USD'' as Crcy, round(sum(-Amt3),2) as Amt1, ''3080'' as Co,''3990000000'' as PC, ''2008'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)'),
    ('SQL-G88', 337, 'delete from TransX where KeyID = ''[batchID]'' and Co is NULL'),
