    ('SQL-G82', 401, 'Update x set CC = y.CCTR from TransX x inner join (Select t.CC,c3.CCTR from TransX t left join CCtrs c1 on t.CC = c1.CCTR and c1.BlockAct <> ''X'' and t.Flex1 is not NULL inner join CCtrs c2 on t.Flex1 = c2.CCTR left join (Select Co,Hierarchy,max(CCTR) as CCTR from CCtrs where Cat in (''U'',''S'',''A'') and BlockAct <> ''X'' group by Co,Hierarchy) c3 on t.Co = c3.Co and c2.Hierarchy = c3.Hierarchy where KeyID = ''[batchID]'' and c1.CCTR is NULL and c3.CCTR is not NULL) y on x.CC = y.CC where KeyID = ''[batchID]'''),
