    ('SQL-G70', 211, 'insert into TransX (KeyID, GL, Crcy,CC,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, GL, Crcy, CC, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,  round(sum(coalesce(Amt3,0)),2) as Amt3,round(sum(coalesce(Amt4,0)),2) as Amt4, '''' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, GL, Crcy,CC)'),
    ('SQL-G70', 212, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G70', 221, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Amt1,Amt2,Amt3,Amt4) (select KeyID + ''-data2'',GL,Crcy,''2006'' as Co,CC,Amt1,Amt2,Amt3,Amt4 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G70', 301, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2006'' as Co,''1CBA000009'' as CC,''1CBA000008'' as Contract,-Amt1,-Amt2,-Amt3,-Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL)'),
    ('SQL-G70', 302, 'insert into TransX (KeyID, GL, Crcy,Amt1, Amt2, Amt3, Amt4,Co,PC,TP) (Select KeyID, ''1999901'' as GL, Crcy, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3,round(sum(Amt4),2) as Amt4, ''2006'' as Co,''1600000000'' as PC, ''3060'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)'),
    ('SQL-G70', 303, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Amt1,Amt2,Amt3) (select KeyID,GL,Crcy,''3060'' as Co,''3NBS100001'' as CC,Amt1,Amt2,Amt3 from TransX where KeyID = ''[batchID]'' and Co is NULL)'),
