    ('SQL-G65', 212, 'Update x set x.Crcy = y.Crcy, x.PC = (case when GL = ''2510001'' then y.DefaultPC else '''' end) from TransX x inner join Companies y on x.Co = y.Co where KeyID = ''[batchID]'''),
