    ('SQL-G87', 302, 'insert into TransX (KeyID, Co,GL, Crcy,PC,CC,Contract,ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, ''4010'' as Co, ''6910501'' as GL, Crcy, '''' as PC, ''5OSS000001'' as CC, ''5USA000087'' as Contract, ''CHGBACK'' as ProdCode, round(sum(-Amt1*.1),2) as Amt1, round(sum(-Amt2*.1),2) as Amt2,  round(sum(-Amt3*.1),2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' and Co = ''2008'' group by KeyID,Crcy)'),
