    ('SQL-S20', 121, 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,TP,BusCat,SubProd,UWYR,Contract,ReinName,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6,Stat) (select KeyID,Ledger,Co,Crcy,GL,PC,TP,BusCat,SubProd,UWYR,Contract,ReinName,round(sum(case when Flex1 = ''1'' then Amt1 else 0 end),2) as Amt1,round(sum(case when Flex1 = ''2'' then Amt1 else 0 end),2) as Amt2, 0 as Amt3, 0 as Amt4, 0 as Amt5, 0 as Amt6, ''1'' as Stat from TransX where KeyID = ''[batchID]'' group by KeyID,Ledger,Co,Crcy,GL,PC,TP,BusCat,SubProd,UWYR,Contract,ReinName)'),
