    ('SQL-S20', 142, 'update x set Amt7 = y.Amt1, Amt8 = y.Amt2 from TransX x inner join (Select KeyID,Co,Crcy,GL,PC,TP,BusCat,SubProd,UWYR,Contract,ReinName,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') y on x.KeyID = y.KeyID and x.Co = y.Co and x.Crcy = y.Crcy and x.GL = y.GL and x.PC = y.PC and x.TP = y.TP and x.BusCat = y.BusCat and x.SubProd = y.SubProd and x.UWYR = y.UWYR and x.Contract = y.Contract and x.ReinName = y.ReinName'),
