    ('SQL-S20', 164, 'update TransX set Rate4 = (case when substring(''[GL]'',3,2) = ''10'' then Rate1/Rate2 else (case when substring(''[GL]'',3,2) = ''60'' then Rate1/Rate3 else Rate1 end) end) where KeyID = ''[batchID]'' and substring(''[GL]'',1,2) = ''00'''),
