    ('SQL-M10', 530, '[ReplaceConnString][LockDownConnString]'),
    ('SQL-M10', 531, 'insert into [FX_Recon].dbo.TransX (KeyID,Flex1,Co,Flex3,Crcy,Flex2,PC,PCdesc,Flex4,Flex5,Flex6,UWYR,TP,Flex7,Amt1,Amt2,Amt3) (select ''[batchID]'',''IR17_LIC'',Co,GL_Grp,Crcy,Co_Crcy,PC,PC_Desc,Portfolio_PC,Program,ACD,UWYR,TP,Incl_Excl,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from IR17_LIC where  YearPeriod >= ''[Yr]01'' and YearPeriod <= ''[Yr][Mo]'' GROUP BY Co,GL_Grp,Crcy,Co_Crcy,PC,PC_Desc,Portfolio_PC,Program,ACD,UWYR,TP,Incl_Excl)'),
