    ('SQL-G75', 301, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2008'' as Co,''1USS6005HO'' as CC,''1USS6004HO'' as Contract,-Amt1,-Amt2,-Amt3,-Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL)'),
    ('SQL-G75', 302, 'insert into TransX (KeyID, GL, Crcy,Amt1, Amt2, Amt3, Amt4,Co,PC,TP) (Select KeyID, ''1999901'' as GL, Crcy, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3,round(sum(Amt4),2) as Amt4, ''2008'' as Co,''1400000000'' as PC, ''3010'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)'),
    ('SQL-G25', 102, 'delete from TransX where KeyID = ''[batchID]''  and ''[yyyy-mm-dd]'' = ''2022-03-31'' and Co like ''599%'''),
