    ('SQL-G69', 211, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 or not Co is NULL)'),
    ('SQL-R59', 162, 'delete from TransX where KeyID = ''[batchID]'' and (amt1 = 0 and amt2 = 0)'),
    ('SQL-R59', 606, 'insert into TransX (KeyID, GL, BusCatDesc, Co, Ledger,Flex4, Amt1,Amt2,Flex8) (select KeyID, ''2899901'', '''', Co, Ledger,Flex4,round(-sum(Amt1),2),round(-sum(Amt2),2),''pass7'' from TransX where KeyID = ''[batchID]'' and Flex4 = ''0010-050'' and Co <> ''2008'' group by KeyID,Co,Ledger,Flex4)'),
    ('SQL-R59', 164, 'delete from TransX where KeyID = ''[batchID]'' and Flex8 is NULL'),
