    ('SQL-G29', 120, 'delete from TransX where KeyID = ''[batchID]''  and ''[version]'' = ''First'' and Zone = ''1'''),
    ('SQL-G29', 121, 'update TransX set KeyID = ''[batchID]-data3'', Amt1 = coalesce(Amt1,0), Amt2 = coalesce(Amt2,0), Amt3 = coalesce(Amt3,0) where KeyID = ''[batchID]''  and Zone = ''1'''),
    ('SQL-G29', 122, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Amt1, Amt2, Amt3,Zone) (Select KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3,''2'' as Zone from TransX where KeyID = ''[batchID]-data3'' group by KeyID, Co, GL, Crcy, TTY, TP,  PC,ProdCode,PTF)'),
    ('SQL-G29', 123, 'delete from TransX where KeyID = ''[batchID]-data3'' and Zone = ''1'''),
    ('SQL-G29', 124, 'delete from TransX where KeyID = ''[batchID]-data3'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-R41', 202, 'update TransX set Flex1 = ''CTA'' from TransX where KeyID = ''[batchID]'' and GL < ''4000000'''),
    ('SQL-R41', 203, 'update TransX set Flex1 = ''P&L'' from TransX where KeyID = ''[batchID]'' and GL > ''4000000'''),
    ('SQL-R41', 204, 'update TransX set Flex2 = ''4 FX Hedge'', Flex4 = ''M3-3-6-06-B-2'' from TransX inner join MapKeyRanges m1 on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and m1.MapKey = ''M3-3-6-06-B-2'''),
    ('SQL-R41', 205, 'update TransX set Flex2 = ''3 Other Expense'', Flex4 = ''M3-3-6-06-C'' from TransX inner join MapKeyRanges m1 on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and m1.MapKey = ''M3-3-6-06-C'''),
    ('SQL-R41', 206, 'update TransX set Flex2 = ''2 Realized Gains/Losses'', Flex4 = ''M3-3-6-06-B'' from TransX inner join MapKeyRanges m1 on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and m1.MapKey = ''M3-3-6-06-B'' and TTY >= ''990'' and Flex2 is NULL'),
    ('SQL-R41', 207, 'update TransX set Flex2 = ''1 Investment Income'', Flex4 = ''M3-3-6-06-A'' from TransX inner join MapKeyRanges m1 on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and m1.MapKey = ''M3-3-6-06-A'' and TTY >= ''990'''),
    ('SQL-T35', 241, 'insert into TransX (KeyID,GL,Flex1,Flex2,Flex3,Date1,Flex4,Date2) (Select ''[batchID]-data5'',ID,From_Co,Thru_Co,Created_By,Created_On,Updated_By,Updated_On from FX_Variant_Co)'),
    ('SQL-R59', 801, 'insert into TransX (KeyID, Co,GL, BusCatDesc,GLDesc,Amt1,Amt2,Flex1,Flex2,Flex4,Ledger,Flex3) (select KeyID, Co,GL, BusCatDesc,GLDesc,round(sum(Amt1),2),round(sum(Amt2),2),Flex1,Flex2,Flex4,Ledger,''pass1'' as Flex3 from TransX where KeyID = ''[batchID]''  group by KeyID, Co,GL, BusCatDesc,GLDesc,Flex1,Flex2,Flex4,Ledger)'),
    ('SQL-R59', 802, 'delete from TransX where KeyID = ''[batchID]''  and Flex3 is null'),
