    ('SQL-R59', 810, 'update x set Flex5 = y.Short From TransX x inner join GAAP2Stat_Descr y on x.Flex4 = y.JE where KeyID = ''[batchID]'''),
    ('SQL-R59', 811, 'update TransX set Flex8 = ''1'' where KeyID = ''[batchID]'' and Flex4 = ''0000-UG'''),
    ('SQL-R59', 812, 'update TransX set Flex8 = ''3'' where KeyID = ''[batchID]'' and Flex4 = ''9999-001'''),
    ('SQL-R59', 813, 'update TransX set Flex8 = ''2'' where KeyID = ''[batchID]'' and Flex8 is NULL'),
    ('SQL-R59', 814, 'update TransX set Flex9 = substring(Flex4,1,4) where KeyID = ''[batchID]'''),
    ('SQL-R59', 815, 'update x set Flex7 = c.SAPname from TransX x inner join Companies c on x.Co = c.Co where KeyID = ''[batchID]'''),
    ('SQL-G23', 501, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-G23', 502, 'update TransX set Txt = ''IFRS-17 Reversal'', SubProd = ''G23'' from TransX where KeyID = ''[batchID]'''),
    ('SQL-G23', 126, 'update TransX set  BusCat = '''' where KeyID = ''[batchID]-data4'' and BusCat = ''XX'''),
    ('SQL-G25', 244, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and m.Field1 = '''' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL and not GL in (''2853500'',''2851017'')'),
    ('SQL-G23', 446, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, coalesce(ProdCode,''''), coalesce(PTF,''''), round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''2'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, coalesce(ProdCode,''''), coalesce(PTF,''''))'),
    ('SQL-G23', 447, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, coalesce(ProdCode,''''), coalesce(PTF,''''), round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''2'' group by KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, coalesce(ProdCode,''''), coalesce(PTF,''''))'),
    ('SQL-G23', 451, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, PTF, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-G92', 455, 'Update x set x.GL = y.Field1 from TransX x inner join Misc_Tables y on x.GL = y.Descr where KeyID = ''[batchID]'' and Table_ID = ''Reimburse'' and ID = ''GL'''),
    ('SQL-T35', 109, 'Update t Set Flex6 = f1.ID from TransX t inner join FX_Variant_Co f1 on t.Co >= f1.From_Co and t.Co <= f1.Thru_Co inner join FX_Variant f2 on f1.ID = f2.ID and f2.Descr like ''%GAAP Trans PL Inv%'''),
    ('SQL-R50', 202, 'Insert into TransX (KeyID,Co,Flex1,Amt1) (select KeyID + ''-save'' as KeyID,''599x'' as Co,m.ID as Flex1,round(sum(Amt1 * m.Field5),2) as Amt1 from TransX t inner join Misc_Tables m on m.Table_ID = ''Val GL offset'' and t.GL = m.Descr and t.BusCat like m.Field1 and t.TTY like m.Field2 and t.Co >= ''5990'' and t.Co <= ''5999''  where KeyID = ''[batchID]'' and m.Field6 = ''IFRS17'' group by t.KeyID,m.ID)'),
    ('SQL-G26', 196, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, GL, Assgnmt, Crcy, ''806'' as TTY, TP, BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and Zone = ''7'' and GL like ''231%'' and TTY = ''809'')'),
    ('SQL-G26', 181, 'update TransX set KeyID = ''[batchID]-data3'' where KeyID = ''[batchID]''  and Co like ''599%'''),
    ('SQL-G26', 289, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560001'' as GL, Crcy, PC,''627'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600067'')'),
    ('SQL-G24', 412, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3, PK) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, -Amt1,- Amt2 ,- Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]-data3'')'),
    ('SQL-G26', 301, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, ProdCode, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150001'' as GL, ''2880000 803'' as Assgnmt, Crcy, ''822'' as TTY, ''U1801'' as ProdCode, TP, '''' as BusCat, PC, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''2880000'')'),
    ('SQL-G24', 413, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data3'' as KeyID, ''9999'' as Co, ''filler'' as GL, '''' as Crcy, '''' as PC, '''' as TTY, '''' as TP, '''' as  Assgnmt, '''' as ProdCode, '''' as PTF, 0 as Amt1, 0 as  Amt2 , 0 as  Amt3)'),
    ('SQL-S39', 202, 'delete from TransX where KeyID = ''[batchID]'' and ''[version]'' = ''P2'' and Period < 4'),
