    ('SQL-S39', 205, 'delete from TransX where KeyID = ''[batchID]'' and SUBSTRING(GL,6,2) in (''96'',''98'')'),
    ('SQL-S39', 221, 'insert into TransX (KeyID,Yr, Period,Co,GL,BusCat,PC,CC,Amt1, flex1) (Select ''[batchID]-data2'' as KeyID,Yr, Period,Co,GL,BusCat,PC,CC,Amt1, ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-S39', 305, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, ''4060200317'' as PC, ''4HE''+SUBSTRING(CC,4,1)+''200317'' as CC, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''1406000362'')'),
    ('SQL-S39', 306, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, ''1406000363'' as PC, ''1US''+SUBSTRING(CC,4,1)+''600363'' as CC,ROUND(0-ROUND(Amt1/3,2)*2,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''1406000362'')'),
    ('SQL-S39', 307, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, ''1406000364'' as PC, ''1US''+SUBSTRING(CC,4,1)+''600364'' as CC, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''3991061407'')'),
    ('SQL-S39', 308, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, ''4060200317'' as PC, ''4HE''+SUBSTRING(CC,4,1)+''200317'' as CC, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''3991061407'')'),
    ('SQL-S39', 310, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-S39', 321, 'update TransX set CC = '''' where KeyID = ''[batchID]'' and not GL like ''6%'''),
    ('SQL-S39', 331, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,Flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, PC, CC,ROUND(SUM(Amt1),2) as Amt1, ''pass2'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1 = ''pass1'' group by KeyID,Yr, Period, Co, GL, BusCat, PC, CC)'),
    ('SQL-R15', 221, 'update TransX set Flex5 = ''affiliate'' from TransX where KeyID = ''[batchID]'' and TP <> '''''),
    ('SQL-R15', 222, 'update TransX set Flex4 = m.Name, Flex6 = m.SchedFname, Division = m.NAIC, Location = m.FedID from TransX t inner join Brokers m on t.ReinName = m.Broker where KeyID = ''[batchID]'''),
    ('SQL-R15', 223, 'update TransX set TPname = m.Name, Flex6 = m.SchedFname, Division = coalesce(m.NAIC,Division,''''), Location = coalesce(m.FedID,Location,'''') from TransX t inner join TPs m on t.TP = m.TP where KeyID = ''[batchID]'''),
    ('SQL-R15', 224, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R51', 231, 'update TransX set Amt1 = round(Amt2-Amt5,2), Amt3 = round(Amt2-Amt4,2) where KeyID = ''[batchID]'''),
    ('SQL-R51', 232, 'update TransX set Amt2 = 0 from TransX where KeyID = ''[batchID]'' and GL >= ''4000000'''),
    ('SQL-R51', 233, 'delete from TransX where KeyID = ''[batchID]'' and amt1 = 0 and amt2 = 0 and amt3 = 0'),
    ('SQL-R25', 201, 'insert into TransX (KeyID, Yr, Crcy, Co, GL, TP, PC, BusCat, Contract, UWYR, Amt1, Amt2, Flex1) (select KeyID, Yr, Crcy, Co, GL, TP, PC, BusCat, Contract, UWYR, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, ''Reg'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Yr, Crcy, Co, GL, TP, PC, BusCat, Contract, UWYR)'),
    ('SQL-R25', 202, 'delete from TransX where KeyID = ''[batchID]'' and (Flex1 is NULL or (Amt1 = 0 and Amt2 = 0))'),
    ('SQL-R25', 212, 'update TransX set TPname = p.Name from TransX t inner join TPs p on t.TP = p.TP where KeyID = ''[batchID]'''),
    ('SQL-R25', 221, 'update TransX set Flex1 = ''FX'' from TransX where KeyID = ''[batchID]'' and (substring(GL,6,2) in (''96'',''97'',''98'') or GL like ''3%'' or GL like ''71%'' or GL in (''2421001'',''2421002''))'),
    ('SQL-R25', 222, 'update TransX set Flex1 = ''FX'' from TransX where KeyID = ''[batchID]'' and GLdesc like ''%Fx%'''),
    ('SQL-R25', 223, 'update TransX set Flex1 = ''Est'' from TransX where KeyID = ''[batchID]'' and (substring(GL,6,2) = ''01'' or GL = ''1310002'')'),
    ('SQL-R25', 203, 'update TransX set BusCat = '''' from TransX where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-R26', 201, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R26', 202, 'update TransX set BusCat = '''' from TransX where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-R26', 211, 'update TransX set GLdesc = c.Name from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R26', 212, 'update TransX set TPname = p.Name from TransX t inner join TPs p on t.TP = p.TP where KeyID = ''[batchID]'''),
    ('SQL-R26', 213, 'update TransX set BusCatDesc = m.Descr from TransX t inner join Misc_Tables m on t.BusCat = m.ID where KeyID = ''[batchID]'' and BusCat <> '''' and Table_ID = ''BusCat'''),
    ('SQL-R26', 214, 'update TransX set Flex1 = c.SAPname from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'''),
    ('SQL-R26', 215, 'update TransX set Flex2 = m.Descr from TransX t inner join Misc_Tables m on t.TTY = m.ID where KeyID = ''[batchID]'' and t.TTY <> '''' and m.Table_ID = ''TTY'''),
    ('SQL-R26', 216, 'update TransX set Flex3 = m.Descr from TransX t inner join Misc_Tables m on t.GL >= m.Field1 and t.GL <= m.Field2 where KeyID = ''[batchID]''  and m.Table_ID = ''AffBalRollFwd'' and m.ID = ''GL'''),
    ('SQL-R26', 217, 'update TransX set Flex4 = case when TTY = 100 then ''BBal'' else ''YTD'' end from TransX where KeyID = ''[batchID]'''),
    ('SQL-R26', 218, 'update TransX set Flex5 = case when BusCat >= 10 and BusCat <= 29 then ''Assumed'' else ''Ceded'' end from TransX where KeyID = ''[batchID]'''),
    ('SQL-R26', 219, 'update TransX set Flex6 = case when TTY >= 990 then ''yes'' else ''no'' end from TransX where KeyID = ''[batchID]'''),
    ('SQL-S39', 502, 'update TransX set Ledger = ''UG'', Flex1 = ''[version]'' where KeyID = ''[batchID]'''),
    ('SQL-G59', 151, 'update TransX set GL = substring(GL,1,5) + ''02'' from TransX where KeyID = ''[batchID]'' and GL like ''359%00'''),
    ('SQL-R08', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0'),
    ('SQL-G72', 211, 'insert into TransX (KeyID,GL,CC,Txt,Contract,ProdCode,Amt1,Flex1) (select KeyID,GL,CC,Txt,Contract,ProdCode,round(sum(Amt1),2) as Amt1,''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,GL,CC,Txt,Contract,ProdCode)'),
    ('SQL-G72', 212, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 or FLex1 is NULL)'),
    ('SQL-G72', 221, 'insert into TransX (KeyID,GL,PC,Txt,Contract,ProdCode,TP,Amt1) (select KeyID,''1998900'' as GL,''1400000000'' as PC,substring(Txt,1,len(Txt)-8),Contract,'''' as ProdCode,''F0007'' as TP,round(-sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' group by KeyID,substring(Txt,1,len(Txt)-8),Contract)'),
    ('SQL-G72', 222, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-G72', 301, 'Update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID like ''[batchID]%'''),
    ('SQL-G72', 302, 'Update TransX set PK = (case when Amt1 > 0 then ''40'' else ''50'' end) where KeyID = ''[batchID]'''),
    ('SQL-G25', 301, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''3870003'' as GL, Crcy, ''640'' as TTY, TP, PC, '''' as ProdCode, '''' as PTF, '''' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and ''[yyyy-mm-dd]'' = ''2022-01-31'' group by KeyID, Co, Crcy, TP, PC)'),
    ('SQL-G25', 451, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-G25', 452, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-G25', 453, 'delete from TransX where KeyID = ''[batchID]'' and (not PK in (''40'',''50'') or PK is NULL)'),
    ('SQL-G25', 454, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
