    ('SQL-R06b', 209, 'update TransX set Flex2 = ''2 Realized Gains/Losses'', Flex4 = ''M3-3-6-06-B-1'' from TransX inner join MapKeyRanges m1 on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and m1.MapKey = ''M3-3-6-06-B-1'' and Flex2 is NULL'),
