    ('SQL-R06b', 212, 'update TransX set Flex2 = ''Non-Investment'', Flex4 = m1.MapKey from TransX inner join MapKeyRanges m1 on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and m1.MapKey like ''M2-3-5-B-%-1'' and SUBSTRING(m1.Mapkey,10,3) in (''710'',''720'',''721'',''760'',''820'')'),
