    ('SQL-T14', 101, 'insert into TransX (KeyID,Flex1,Flex2,Crcy,Flex3,Rate1,Yr,Period,Flex5,Flex6) (select ''[batchID]'',EffDate,Typ,r.Crcy,Name,Rate,xfactor,DecimalPlaces,RSG,Notes from CrcyRates r inner join Crcy c on r.Crcy = c.Crcy where EffDate >= ''[FROMyyyy-mm-dd]'' and EffDate <= ''[THRUyyyy-mm-dd]'' and Typ like ''[version]'' and r.Crcy like ''[GL]'')'),
