    ('SQL-R25', 224, 'update TransX set Flex1 = ''OC'' from TransX where KeyID = ''[batchID]'' and (substring(PC,1,2) = ''16'')'),
    ('SQL-G31', 261, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Amt1, Amt2, Amt3,Assgnmt) (Select ''[batchID]-data3'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, (case when Co like ''9%'' then '''' else ''x'' + Flex1 + ''x'' + Flex2 + ''x'' + Flex3 end) as Assgnmt from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, Flex1, Flex2, Flex3)'),
    ('SQL-G31', 315, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select ''[batchID]'' as KeyID, m.Field1 as Co, t.GL, t.Crcy, t.PC,t.TTY, t.TP, t.BusCat, coalesce(t.Assgnmt,''''), t.ProdCode, t.Amt1, t.Amt2 , t.Amt3 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Co9'' and m.Descr = t.Co where t.KeyID = ''[batchID]-data3'')'),
    ('SQL-G75', 454, 'update TransX set GL = ''6314000'' where KeyID = ''[batchID]'' and Co = ''3030'' and GL in (''6314005'')'),
    ('SQL-M25', 582, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL = m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID = ''[batchID]'' and not GL in (''4419900'') and Assgnmt is NULL and Flex9 = ''translate'''),
    ('SQL-M25', 583, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL like m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID = ''[batchID]'' and not GL in (''4419900'') and Assgnmt is NULL and Flex9 = ''translate'''),
    ('SQL-M25', 434, 'update TransX set Flex5 = ''04 ODY TP''  where KeyID = ''[batchID]'' and Co in (''2999'',''3999'') and SubProd= ''G23'' and Flex5 = '''''),
    ('SQL-M25', 435, 'update TransX set Flex5 = ''04 ODY TP''  where KeyID = ''[batchID]'' and TP = ''ODY'' and SubProd= ''G23'' and Flex5 = '''''),
    ('SQL-G31', 291, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560002'' as GL, Crcy, PC,''806'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''1560001'' and TTY = ''627'')'),
    ('SQL-G31', 292, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560002'' as GL, Crcy, PC,''803'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''1560001'' and TTY = ''627'')'),
    ('SQL-G31', 321, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode)'),
    ('SQL-G26', 212, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, x.GL + '' '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'',''232'') then '''' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' and substring(x.TTY,1,1) = ''9'' then '''' else x.TTY end) and m.Field6 = ''1'' and not x.TTY = ''815'' where KeyID = ''[batchID]'')'),
    ('SQL-G32', 190, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data3'', Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Amt1, Amt2, Amt3 from Trans3 where KeyID = ''LS-SING-data3'' and substring(''[BudAct]'',1,7) = ''LS-SING'' and ''[yyyy-mm-dd]'' like ''2022%'' and not ''[yyyy-mm-dd]'' = ''2022-01-31'' and not ''[version]'' = ''First'' )'),
    ('SQL-S43', 535, 'Update t set t.YearPeriod = s.fiscal_year + s.period , t.Yr = s.fiscal_year , t.Period = s.period , t.Co = s.co , t.Crcy = s.crcy , t.PC = s.profit_centre , t.CC = s.cost_centre , t.TP = s.trade_ptr , t.BusCat = s.bus_cat , t.Contract = coalesce(s.contract, '''') , t.UWYR = s.uwyr , t.TTY = s.trans_type from TransX t join CorpAcct_Apps.dbo.SAP_ledger_data s on t.GL = s.gl and t.Amt1 = s.doc_amt where KeyID = ''[batchID]'' and (t.Contract is null or t.Contract = '''')'),
    ('SQL-G80', 361, 'insert into TransX (KeyID, GL, Amt1, Amt2, Amt3,CC,PC,TP,Contract,ProdCode,PK) (Select KeyID, ''1998900'' as GL, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2,  round(-sum(Amt3),2) as Amt3,'''' as CC,''1600000000'' as PC, ''F0085'' as TP,''1CBA000006'' as Contract,'''' as ProdCode, ''99'' as PK from TransX where KeyID = ''[batchID]'' and ProdCode = ''CHGBACK'' group by KeyID)'),
    ('SQL-E24', 1066, 'update TransX set PC = ''3992080000'' where KeyID = ''[batchID]'' and Co = ''3999'' and Contract = ''QS'''),
    ('SQL-S01', 509, 'delete from TransX where KeyID = ''[batchID]'' and (Flex1 in (''pass2'',''pass3'') or Amt1 = 0)'),
    ('SQL-S01', 513, 'update TransX set Ledger = ''Z000'' from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'' and Amt1 = Amt3 and Amt1 = Amt4'),
    ('SQL-S01', 514, 'delete from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and Amt1 = Amt2 and Amt1 = Amt4'),
    ('SQL-R49', 484, 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co in (''2300'',''2400'',''2450'')  and not Contract like ''FV-%'''),
    ('SQL-R49', 485, 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and (TP = ''2008'' or (TP in (''2300'',''2400'',''2450'') ) and tp <> ''2310'') and (PC in (''1002000000'',''5380000000'',''1000000000'',''1426720828'') or PC like ''140%'' or PC like ''4%'') and not Contract in (''CSIC 2008'',''GIC 2008'',''HUD 2101'',''HUD 2102'',''2300-2101'',''CSIC SC 2200'',''CB HIC 2006'',''GIC SC 2200'') and  not substring(Contract,1,7) in (''CSIC ST'' ,''CAD HIC'',''GICD ST'',''ST SYND'',''PSI HIC'',''HCN CAD'',''ORESA S'',''HCN CAF'') and not Contract like ''OPUS%'''),
    ('SQL-R49', 486, 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and tp <> ''2310'' and upper(substring(Contract,1,5)) = ''HUD ST'''),
    ('SQL-R49', 487, 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and tp <> ''2310'' and substring(PC,1,1) = ''4'' and Contract = ''PC RECLASS'''),
    ('SQL-R49', 624, 'update TransX set Flex5 = ''100'', Flex6 = ''clearing ITD balance in current year'' where KeyID = ''[batchID]'' and Amt2 = 0 and Flex5 is NULL and upper(substring(contract,1,7)) not in (''FV-EUCL'',''HCN CAF'')'),
    ('SQL-R49', 652, 'update TransX set Flex5 = ''138'', Flex6 = ''need to investigate small non-2999 FX balances and clear'' where KeyID = ''[batchID]'' and not Co = ''2999'' and Flex1 like ''9%'' and upper(substring(contract,1,7)) not in (''FV-EUCL'',''HCN CAF'') and Flex5 is NULL'),
    ('SQL-M13', 211, 'insert into TransX (KeyID, Co, GL, BusCat, PC,Amt1,Amt2,Amt3,Amt4,Amt7,Amt8,Flex1) (select KeyID, Co, GL, BusCat, PC, round(sum(coalesce(Amt1,0)),2), round(sum(coalesce(Amt1+Amt2,0)),2), round(sum(coalesce(Amt3,0)),2), round(sum(coalesce(Amt4,0)),2),round(sum(coalesce(Amt7,0)),2), round(sum(coalesce(Amt8,0)),2),''pass1'' from TransX where KeyID = ''[batchID]''  group by KeyID, Co, GL, BusCat, PC)'),
    ('SQL-M13', 411, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,PC,BusCat,Amt3) (select ''[batchID]-data2'',Co,GL,PC,ACD,LC2_Amt from (select Co,GL,PC,ACD, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,PC,ACD,Source,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''M12'' and YearPeriod = ''201012'' GROUP BY Co,GL,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,PC,ACD,Source,round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod = ''201012'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'' or GL like ''148%'' or GL like ''23%'') and not GL like ''2822%'' GROUP BY Co,GL,PC,ACD,Source) a GROUP BY Co,GL,PC,ACD) b where abs(LC2_Amt) > 1 and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-R07', 420, 'update TransX set Flex1 = ''20 ORESA Paris'' from TransX where KeyID = ''[batchID]'' and Co = ''2999'' and TP in (''2002'',''4110'') and Contract like ''ORESA P%'' and Flex1 is NULL'),
    ('SQL-R07', 424, 'update TransX set Flex1 = ''24 NEVAG QS'' from TransX where KeyID = ''[batchID]'' and Co in (''3070'',''3999'') and TP = ''3270'' and Flex1 is NULL'),
    ('SQL-R07', 424, 'update TransX set Flex1 = ''24 NEVAG QS'' from TransX where KeyID = ''[batchID]'' and Co in (''3270'',''3999'') and TP = ''3070'' and Flex1 is NULL'),
    ('SQL-R07', 425, 'update TransX set Flex1 = ''25 ORESA GIC'' from TransX where KeyID = ''[batchID]'' and Co = ''2200'' and TP = ''4110'' and Flex1 is NULL'),
    ('SQL-R07', 425, 'update TransX set Flex1 = ''25 ORESA GIC'' from TransX where KeyID = ''[batchID]'' and Co = ''4110'' and TP = ''2200'' and Flex1 is NULL'),
    ('SQL-R07', 425, 'update TransX set Flex1 = ''25 ORESA GIC'' from TransX where KeyID = ''[batchID]'' and Co = ''2999'' and TP in (''2200'',''4110'') and Contract like ''ORESA G%'' and Flex1 is NULL'),
    ('SQL-G24', 452, 'insert into TransX (KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, PC, ProdCode, PTF, Assgnmt, TTY, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-G24', 321, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, coalesce(PTF,''''), Assgnmt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, coalesce(PTF,''''), Assgnmt)'),
    ('SQL-S06', 510, 'update TransX set Amt2 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''IF'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
    ('SQL-S06', 511, 'update TransX set Amt3 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
    ('SQL-S06', 512, 'update TransX set Amt4 = f2.Amt1 from TransX f1 inner join (Select KeyID, Ledger, Co, GL, PC, CC, TP, BusCat, Contract, UWYR, TTY, Amt1, Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'') f2 on f1.KeyID = f2.KeyID and f1.Co = f2.Co and f1.GL = f2.GL and f1.PC = f2.PC and isnull(f1.CC,'''') = isnull(f2.CC,'''') and f1.TP = f2.TP and f1.BusCat = f2.BusCat and f1.Contract = f2.Contract and isnull(f1.UWYR,'''') = isnull(f2.UWYR,'''') and f1.TTY = f2.TTY and f1.Flex1 = f2.Flex1 and f1.Amt1 = f2.Amt1'),
    ('SQL-M16', 212, 'delete from TransX where KeyID = ''[batchID]''  and Flex4 is NULL'),
    ('SQL-G25', 421, 'Update TransX set ProdCode =  ''U1806'' where KeyID = ''[batchID]'' and Co like ''599%'' and GL = ''1560000'''),
    ('SQL-R49', 901, 'insert into TransX (KeyID,YearPeriod,FSitemDesc,GLdesc,Period,Date1,Flex1,Qtr,Date2,Flex2,Yr,Flex3) (select ''[batchID]-data3'',e.ID, e.ShortName, e.Def, max(p1.VerNbr), max(p1.Finished), substring(max(right(''00''+convert(varchar,p1.VerNbr),2) + p1.RunBy),3,99), max(p2.VerNbr), max(p2.Finished), substring(max(right(''00''+convert(varchar,p2.VerNbr),2) + p2.RunBy),3,99), max(coalesce(p4.VerNbr,0)), max(p3.Comments) from Eliminations e left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Recon'') p1 on p1.ID = e.ID left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Elim'' and len(ID) < 3) p2 on p2.ID = e.ID left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Comments'') p3 on p3.ID = e.ID left join (select ID, VerNbr, Finished, RunBy, Comments from ProcessTracker where SubID = ''[Yr][Mo]'' and RunMode = ''Elim'' and Comments = ''y'') p4 on p4.ID = e.ID where right(''000''+convert(varchar,e.ID),3) < ''050'' group by e.ID, e.ShortName, e.Def)'),
    ('SQL-M13', 457, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6) (select ''[batchID]-data8'',Co,GL,Crcy,PC,CC,ACD,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(-Doc_QTD),2) as Doc_QTD,round(sum(-Doc_ITD),2) as Doc_ITD,round(sum(-LC_QTD),2) as LC_QTD,round(sum(-LC_ITD),2) as LC_ITD,round(sum(-LC2_QTD),2) as LC2_QTD,round(sum(-LC2_ITD),2) as LC2_ITD from IR17_Other_Singapore where source = ''R69'' GROUP BY Co,GL,Crcy,PC,CC,ACD,Source union all select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from IR17_Control_Singapore where source = ''R63'' and GL in (''nothing'') GROUP BY Co,GL,Crcy,PC,CC,ACD,Source) a GROUP BY Co,GL,Crcy,PC,CC,ACD) b where (abs(Doc_QTD) > 1 or abs(Doc_ITD) > 1 or abs(LC_QTD) > 1 or abs(LC_ITD) > 1 or abs(LC2_QTD) > 1 or abs(LC2_ITD) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-R49', 619, 'update TransX set Flex5 = ''Sched F'', Flex6 = ''Adj for Sched F (OK)'' from TransX where KeyID = ''[batchID]'' and Flex5 is Null and Contract = ''SCHED F'''),
    ('SQL-W15', 505, 'Delete from IR17_Other_Singapore where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R67'' and substring(''[BudAct]'',1,7) = ''IF-SING'' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-M10', 104, 'delete from TransX where KeyID = ''[batchID]'' and Zone = ''2'' and not TP like ''F%'' and not (TP = '''' and contract in ('''',''RRP RECLASS''))'),
    ('SQL-G92', 211, 'insert into TransX (KeyID, GL, Crcy, CC, Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, GL, Crcy, CC, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,  round(sum(coalesce(Amt3,0)),2) as Amt3,round(sum(coalesce(Amt4,0)),2) as Amt4, ''1'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, GL, CC, Crcy)'),
    ('SQL-G92', 221, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Amt1,Amt2,Amt3,Amt4) (select KeyID + ''-data2'',GL,Crcy,''2005'' as Co,CC,Amt1,Amt2,Amt3,Amt4 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G92', 222, 'insert into TransX (KeyID, GL, Crcy,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, GL, Crcy, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,  round(sum(coalesce(Amt3,0)),2) as Amt3,round(sum(coalesce(Amt4,0)),2) as Amt4, '''' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, GL, Crcy)'),
    ('SQL-G30', 101, 'delete from TransX where KeyID = ''[batchID]'' and GL = ''2850500'''),
    ('SQL-G30', 102, 'Delete from TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LS-SING'' and not GL in (''1099917'',''2851017'')'),
    ('SQL-G30', 103, 'update TransX set Amt1 = coalesce(Amt1,0), Amt2 = coalesce(Amt2,0), Amt3 = coalesce(Amt3,0) where KeyID = ''[batchID]'''),
    ('SQL-G30', 104, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 and Amt2 = 0 and Amt3 = 0)'),
    ('SQL-R40', 213, 'update TransX set Amt4 = round(-Amt1 * cast(Flex3 as float),2), Amt5 = round(-Amt2 * (cast(Flex2 as float)-cast(Flex4 as float)),2) where KeyID = ''[batchID]'''),
    ('SQL-G30', 105, 'Delete from TransX where KeyID = ''[batchID]'' and Co = ''9005'' and not substring(''[BudAct]'',1,7) = ''LS-SING'''),
    ('SQL-G30', 106, 'Delete from TransX where KeyID = ''[batchID]'' and Co = ''9006'' and not substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-S38', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and not Flex3 is NULL'),
    ('SQL-E16', 1015, 'update TransX set GL = ''3593102'', TTY = ''990'' from TransX where KeyID = ''[batchID]'' and GL = ''4399898'''),
    ('SQL-R54', 250, 'update TransX set Flex1 = ''02 RCR & ALAE'' where KeyID = ''[batchID]'' and Flex1 in (''02 RCR'',''04 ALAE'')'),
    ('SQL-R54', 251, 'update TransX set Flex1 = ''26 Chg RCR & ALAE'' where KeyID = ''[batchID]'' and Flex1 in (''26 Chg RCR'',''28 Chg ALAE'')'),
    ('SQL-G30', 107, 'Delete from TransX where KeyID = ''[batchID]'' and Co = ''9231'' and not substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
    ('SQL-S60', 205, 'update TransX set Amt7 = round(Amt4-Amt3,2), Amt8 = 100 from TransX where KeyID = ''[batchID]'' and not Amt3 is NULL'),
    ('SQL-G30', 108, 'Delete from TransX where KeyID = ''[batchID]'' and Co like ''599%'' and not substring(''[BudAct]'',1,7) = ''IF-ODY '''),
    ('SQL-G30', 121, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3,Flex1) (Select KeyID, Co, GL, Crcy, PC, TP, ProdCode, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, '''' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, TP, ProdCode)'),
    ('SQL-G30', 122, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-G30', 131, 'Update x set Rate1 = r.Rate From TransX x inner join CrcyRates r on r.Crcy = x.Crcy and r.Typ = ''S'' and r.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-G30', 132, 'Update x set Rate2 = r.Rate From TransX x inner join Companies c on c.Co = x.Co inner join CrcyRates r on r.Crcy = c.Crcy and r.Typ = ''S'' and r.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-R70', 217, 'update TransX set Flex1 = ''2400'', Flex2 = ''HUD ST 2008'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2008'' and Contract like ''% 2400'' and Flex1 = '''''),
    ('SQL-R59', 156, 'update TransX set BusCatDesc = ''Executive'' from TransX  where KeyID = ''[batchID]'' and substring(CC,4,1) in (''E'')'),
    ('SQL-R59', 161, 'insert into TransX (KeyID, GL, Co, Ledger,BusCatDesc, Amt1,Amt2,Flex8) (select KeyID, GL, Co, Ledger,BusCatDesc, round(sum(Amt1),2) as Amt1,round(sum(Amt2),2) as Amt2,''pass0'' as Flex8 from TransX where KeyID = ''[batchID]'' group by KeyID, GL, Co, Ledger,BusCatDesc)'),
    ('SQL-G34', 234, 'Update x set x.Flex5 = y.Product from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]'''),
    ('SQL-G34', 235, 'Update x set PC = ''7'' + m1.field2 + m2.field2 + ''ANTP0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'' and not Co like ''9%'''),
    ('SQL-G34', 236, 'Update TransX set PC = ''5500000000'' where KeyID = ''[batchID]'' and not Co like ''9%'' and Flex5 = ''Investment'''),
    ('SQL-G34', 237, 'Update TransX set PC =''7CACAANTP0'' where KeyID = ''[batchID]'' and not Co like ''9%'''),
    ('SQL-G34', 241, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, PTF, Amt1, Amt2) (Select ''[batchID]'' as KeyID, Co, ''5600000'' as GL, Crcy, PC, GL + '' U3010'' as Assgnmt, ''U3455'' as PTF,Amt1, Amt2  from TransX where KeyID = ''[batchID]-data2'' and GL in (''5600001'',''5620000''))'),
    ('SQL-G34', 242, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, PTF, Amt1, Amt2) (Select ''[batchID]'' as KeyID, Co, ''5600000'' as GL, Crcy, PC, GL + '' U3010'' as Assgnmt, ''U3010'' as PTF, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2  from TransX where KeyID = ''[batchID]-data2'' and GL in (''5600001'',''5620000''))'),
    ('SQL-G34', 245, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, PTF, Amt1, Amt2) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, PC, ''prior runs'' as Assgnmt, PTF, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2  from TransX where KeyID = ''[batchID]-data2'' and Flex3 = ''2'')'),
    ('SQL-G34', 251, 'Update TransX set Co = ''9005''  where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LS-SING'''),
    ('SQL-G34', 252, 'Update TransX set Co = ''9006''  where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-G34', 253, 'Update TransX set Co = ''9231''  where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
    ('SQL-G34', 261, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, PTF, Amt1, Amt2,PK) (Select KeyID, Co, GL, Crcy, PC, Assgnmt, PTF, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , ''0'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, Assgnmt, PTF)'),
    ('SQL-G34', 262, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G34', 263, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0'),
    ('SQL-G34', 271, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, TTY, ProdCode, Amt1, Amt2, PK) (Select KeyID, Co, ''2150001'' as GL, Crcy, PC, Assgnmt + '' roll 1'' as Assgnmt, ''603'' as TTY, ''U1801'' as ProdCode, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' and GL = ''5600062'')'),
    ('SQL-G34', 272, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, TTY, ProdCode, Amt1, Amt2, PK) (Select KeyID, Co, ''2150001'' as GL, Crcy, PC, Assgnmt + '' roll 1'' as Assgnmt, ''610'' as TTY, ''U1801'' as ProdCode,Amt1, Amt2 , ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' and GL = ''5600062'')'),
    ('SQL-G34', 274, 'insert into TransX (KeyID, Co, GL, Crcy, PC, Assgnmt, TTY, ProdCode, Amt1, Amt2, PK) (Select KeyID, Co, ''2150001'' as GL, Crcy, PC, Assgnmt + '' roll 2'' as Assgnmt, ''612'' as TTY, ''U1801'' as ProdCode, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' and GL = ''5600062'')'),
    ('SQL-G38', 242, 'update TransX set GL = ''2899901'' from TransX where KeyID = ''[batchID]'' and GL = ''1999901'' and Amt3 < 0'),
    ('SQL-G30', 151, 'Update TransX set Amt4 = round(Amt1*Rate1/Rate2,2), Amt5 = round(Amt1*Rate1,2) where KeyID = ''[batchID]'''),
    ('SQL-G30', 152, 'Update TransX set Amt6 = round(Amt4 - Amt2,2), Amt7 = round(Amt5 - Amt3,2) where KeyID = ''[batchID]'''),
    ('SQL-G30', 191, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3,Rate1,Rate2,Amt4,Amt5,Amt6,Amt7) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3,Rate1,Rate2,Amt4,Amt5,Amt6,Amt7 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G30', 201, 'Update TransX set Amt1 = 0, Amt2 = Amt6, Amt3 = Amt7 where KeyID = ''[batchID]'''),
    ('SQL-R54', 211, 'update TransX set Flex3 = Descr, TPname = Field2 from TransX inner join Misc_Tables on Contract = ID where KeyID = ''[batchID]'' and Table_ID = ''HUD_STM_Contracts'' and Co <> ''2008'''),
    ('SQL-R54', 212, 'update TransX set Flex3 = Descr, TPname = ID from TransX inner join (select min(Descr) as Descr, min(ID) as ID, Field2 from Misc_Tables where Table_ID = ''HUD_STM_Contracts'' group by Field2) a on Contract = Field2 where KeyID = ''[batchID]''  and Co = ''2008'''),
    ('SQL-G53', 212, 'update TransX set Flex1 = Field2, Flex2 = Field3  from TransX inner join Misc_Tables on GL > = Descr and GL < = Field1 where keyID = ''[batchID]'' and Table_ID = ''ULAEexpReclass'' and ID = ''GL Override'''),
    ('SQL-R43', 202, 'update TransX set Flex1 = ''3 Other Expense'' from TransX inner join MapKeyRanges m1 on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and m1.MapKey = ''M3-3-6-06-C'''),
    ('SQL-M14', 107, 'delete from TransX where KeyID = ''[batchID]''  and GL in (''1550000'',''1560000'',''2150000'',''2160000'',''2851017'',''2868901'',''4430000'')'),
    ('SQL-G79', 372, 'insert into TransX (KeyID, GL, Amt1, Amt2, Amt3,Co,PC,TP,CC,ProdCode,Flex3) (Select KeyID, ''1999901'' as GL, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2,  round(-sum(Amt3),2) as Amt3, ''3010'' as Co,''3990000000'' as PC, ''2008'' as TP, '''' as CC, '''' as ProdCode, '''' as Flex3 from TransX where KeyID = ''[batchID]'' and Co = ''3010'' group by KeyID)'),
    ('SQL-M17', 113, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-M17', 131, 'Update TransX set PC = '''' where KeyID = ''[batchID]'' and not PC in (''4020100070'',''4020200070'',''5702999000'')'),
    ('SQL-M17', 543, 'update TransX set Flex4 = Flex4 + ''LRC Ceded 28100xx'' where KeyID = ''[batchID]'' and GL in (''2810029'',''2810033'',''2810034'',''2810037'',''2810038'') and Flex4 in (''01 '',''02 '')'),
    ('SQL-T06', 101, 'insert into TransX (KeyID,Co,GL,GLdesc,Flex1,FSitem,FSitemDesc,Crcy,PC,Flex2,Flex3,Flex4,Flex5,Flex6) (Select ''[batchID]'',Co,x.GL, Name, c.Descr,F.FSitem, FSitemDesc,x.Crcy,FSG, Case when x.Blocked = ''No'' then c.Blocked else x.Blocked End as Blocked, BSorPL, Grp, x.CreatedBy, convert(varchar,x.CreatedOn,101) as CreatedOn from COAxCo x left join FSitems F on x.GL >= FromGL and x.GL <= ThruGL inner join COA c on c.GL = x.GL inner join Misc_Tables m on Table_ID = ''CoSelect'' and (substring(m.Descr,1,4) = ''[CoSelect]'' or m.Descr = ''[CoSelect]'') inner join ElimSelect e on ElimID = ''Co:'' + m.ID where (e.Oper = ''EQ'' and x.Co = e.FromVal) or (e.Oper = ''BT'' and x.Co >= e.FromVal and x.Co <= e.ThruVal))'),
    ('SQL-M17', 544, 'update TransX set Flex4 = Flex4 + ''LRC Ceded'' where KeyID = ''[batchID]'' and substring(GL,1,3) in (''156'',''216'') and GL like ''%00'''),
    ('SQL-M17', 551, 'update TransX set Flex4 = Flex4 + ''Other'' where KeyID = ''[batchID]'' and Flex4 in (''01 '',''02 '')'),
    ('SQL-M17', 571, 'update TransX set Flex4 = Flex4 + '' (Alex ADJ RI)'' where KeyID = ''[batchID]'' and Flex4 like ''02 %'' and Txt = ''RI'''),
    ('SQL-M17', 612, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, ''Topside JE17'' as Txt, -Amt1, FSitem, Flex1, Flex2, Flex3, ''02 LIC Assumed D15 clear to IFRS9'' as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and GL in (''2550001'',''2550002'') and FSitem = ''2000'') a )'),
    ('SQL-M17', 613, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '''' as PC, ''G23-Rev'' as Txt, Amt1, FSitem, Flex1, Flex2, Flex3, replace(replace(Flex4,''01 '',''02 ''),''(Alex Start)'',''clear'') as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020100070'' and GL in (''1480000'',''2820000'') and not Flex4 like ''%clear'') a )'),
    ('SQL-M17', 614, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '''' as PC, ''G23-Rev'' as Txt, -Amt1, FSitem, Flex1, Flex2, Flex3, replace(replace(Flex4,''01 '',''02 ''),''(Alex Start)'',''clear (Alex ADJ)'') as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020100070'' and GL in (''1480000'',''2820000'') and not Flex4 like ''% clear'') a )'),
    ('SQL-M17', 615, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '''' as PC, ''G23-Rev'' as Txt, Amt1, FSitem, Flex1, Flex2, Flex3, ''02 '' + substring(Flex4,4,99) + '' clear (Alex ADJ)'' as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020200070'' and not GL in (''1480000'',''2820000'')) a )'),
    ('SQL-M17', 616, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select KeyID, ''5990'' as Co, GL, TTY, TP, BusCat, CC, '''' as PC, ''G23-Rev'' as Txt, -Amt1, FSitem, Flex1, Flex2, Flex3, ''02 '' + substring(Flex4,4,99) + '' clear'' as Flex4, Flex5 from (select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5 from TransX where  KeyID = ''[batchID]'' and PC = ''4020200070'' and not GL in (''1480000'',''2820000'')) a )'),
    ('SQL-G26', 285, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''607'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600000'')'),
    ('SQL-G26', 286, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''602'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Flex5, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600000'')'),
    ('SQL-G26', 313, 'update TransX set  TTY = ''607'' where KeyID = ''[batchID]''  and not ''[yyyy-mm-dd]'' = ''2022-01-31'' and TTY = '''' and GL in (''2150000'')'),
    ('SQL-G26', 315, 'update TransX set  TTY = ''612'' where KeyID = ''[batchID]''  and TTY = ''607'' and GL in (''2150001'')'),
    ('SQL-G26', 421, 'Update TransX set ProdCode =  ''U1806'' where KeyID = ''[batchID]'' and Co like ''599%'' and GL = ''1560000'''),
    ('SQL-G23', 314, 'update TransX set GL = ''1560000'', TTY = ''626'', ProdCode = ''U1806'' where KeyID in (''[batchID]'',''[batchID]-data3'') and GL = ''2860000'''),
    ('SQL-G99', 222, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, substring(GL,1,5) + ''00'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and ((GL >= ''3000000'' and GL < ''3330000'') or GL >= ''3640000''))'),
    ('SQL-G99', 223, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, substring(GL,1,5) + ''00'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and GL >= ''3330000'' and GL < ''3600000'' and substring(GL,6,2) in (''01'',''02''))'),
    ('SQL-G99', 231, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3,  ''99'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY,PTF)'),
    ('SQL-G99', 241, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, case when Amt1>0 then Amt1 else 0 end as Amt1, case when Amt2>0 then Amt2 else 0 end as Amt2,  case when Amt3>0 then Amt3 else 0 end as Amt3,  ''40'' as PK from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-G99', 242, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, case when Amt1<0 then Amt1 else 0 end as Amt1, case when Amt2<0 then Amt2 else 0 end as Amt2,  case when Amt3<0 then Amt3 else 0 end as Amt3,  ''50'' as PK from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-S20', 301, 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,TP,BusCat,SubProd,TTY,UWYR,Contract,ReinName,Amt1,Amt2,Amt3,Amt4,Txt,Assgnmt,RefKey1,RefKey2,PK,Flex3) (select ''[batchID]'' as KeyID,Ledger,Co,Crcy,RefKey1 as GL,PC,TP,BusCat,(case when substring(''[GL]'',3,2) = ''30'' then ''S20 FB'' else ''S20 FA'' end) as SubProd,(case when substring(''[GL]'',3,2) = ''30'' then ''990'' else ''991'' end) as TTY,UWYR,Contract,ReinName,0 as Amt1,(case when substring(''[GL]'',3,2) = ''10'' then Amt4 else 0 end) as Amt2,(case when substring(''[GL]'',3,2) = ''10'' then Amt5 else (case when substring(''[GL]'',3,2) = ''30'' then Amt4 else 0 end) end) as Amt3,(case when substring(''[GL]'',3,2) = ''60'' then Amt4 else 0 end) as Amt4,Txt,Assgnmt,RefKey1,RefKey2, (case when Amt4 > 0 then ''40'' else ''50'' end) as PK, ''FX calc [Yr]-[Mo]'' as Flex3 from TransX where KeyID = ''[batchID]-data2'')'),
    ('SQL-R49', 602, 'update TransX set Flex5 = ''RRP'', Flex6 = ''RRP and CLRF reclasses'' from TransX where KeyID = ''[batchID]'' and Flex5 is Null and Contract in (''RRP Reclass'',''CLRF'')'),
    ('SQL-T11', 101, 'insert into TransX (KeyID,Flex1,Flex2,Flex3,Flex4,Flex5) (Select ''[batchID]'',TTY,Descr,Active,BalFwd,Sgn from TTYS)'),
    ('SQL-M19', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-M19', 401, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-M19', 402, 'update TransX set Flex5 = p.Descr from TransX t inner join ProdCodes p on t.ProdCode = p.ProdCode where KeyID like ''[batchID]%'''),
    ('SQL-M10', 105, 'Update TransX set Flex1 = ''SAP late'', Amt1 = -Amt1, Amt2 = -Amt2, Amt3 = -Amt3, PK = NULL where KeyID = ''[batchID]'' and Flex1 in (''S'',''H'')'),
    ('SQL-M10', 106, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 = ''SAP late'' and not (substring(GL,1,2) in (''15'',''20'',''21'',''22'',''23'',''40'') or substring(GL,1,3) in (''131'',''141'',''142'',''143'',''144'',''145'',''146'',''147'',''148'',''181'',''282'',''283'',''284'',''287'',''541'',''542'',''543'',''544'',''545''))'),
    ('SQL-M10', 107, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 = ''SAP late'' and not Ledger in (select LedgerGroup from LedgerGroups where Ledger = ''IF'') and not Ledger = '''''),
    ('SQL-M16', 101, 'delete from TransX where KeyID = ''[batchID]''  and ''[version]'' = ''B'' and GL > ''4000000'''),
    ('SQL-M16', 111, 'Update TransX set BusCat = ''30'' where KeyID = ''[batchID]'' and BusCat like ''3%'''),
    ('SQL-M16', 113, 'Update TransX set BusCat = ''20'' where KeyID = ''[batchID]'' and BusCat like ''2%'''),
    ('SQL-M16', 114, 'Update TransX set BusCat = ''30'' where KeyID = ''[batchID]'' and (substring(GL,1,2) in (''14'',''15'',''23'') or substring(GL,1,3) in (''287'',''216'',''461'') or GL in (''5600065'',''5600067'',''5600068'')) and  not GL like ''155%'' and not BusCat in (''10'',''20'',''30'')'),
    ('SQL-M16', 115, 'Update TransX set BusCat = ''20'' where KeyID = ''[batchID]'' and (GL like ''6%'' or GL = ''4498000'')'),
    ('SQL-M16', 119, 'Update TransX set BusCat = ''20'' where KeyID = ''[batchID]'' and not BusCat in (''10'',''20'',''30'')'),
    ('SQL-M16', 131, 'Update TransX set Flex1 = (case when Co like ''599%'' then ''(2) Back-out'' else ''(1) IFRS 4'' end) where KeyID = ''[batchID]'''),
    ('SQL-M16', 132, 'Update TransX set Amt1 = Amt2 where KeyID = ''[batchID]'' and ''[version]'' = ''B'' and Flex1 = ''(1) IFRS 4'''),
    ('SQL-M16', 135, 'Update TransX set Flex1 = ''(4) Re-entry'' where KeyID = ''[batchID]'' and SubProd = ''G25'''),
    ('SQL-M16', 211, 'insert into TransX (KeyID, Flex1, Co, GL, BusCat, TP, Amt1,Flex4) (select KeyID, Flex1, Co, GL, BusCat, TP, round(sum(Amt1),2), ''pass1'' as Flex4 from TransX where KeyID = ''[batchID]''  group by KeyID, Flex1, Co, GL, BusCat, TP)'),
    ('SQL-M10', 111, 'Update TransX set Flex6 = ''C'' where KeyID = ''[batchID]'' and BusCat like ''3%'''),
    ('SQL-M10', 112, 'Update TransX set Flex6 = ''D'' where KeyID = ''[batchID]'' and BusCat = ''10'''),
    ('SQL-M10', 113, 'Update TransX set Flex6 = ''A'' where KeyID = ''[batchID]'' and BusCat like ''2%'''),
    ('SQL-M10', 114, 'Update TransX set Flex6 = ''C'' where KeyID = ''[batchID]'' and (GL like ''14%'' or GL like ''15%'' or GL like ''23%'' or GL like ''287%'') and Flex6 is null'),
    ('SQL-M10', 115, 'Update TransX set Flex6 = ''A'' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''18'',''20'',''21'') and Flex6 is null'),
    ('SQL-M10', 116, 'Update TransX set Flex6 = ''A'' where KeyID = ''[batchID]'' and Flex6 is null'),
    ('SQL-M10', 153, 'Update TransX set BusCat = '''' where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-M10', 202, 'Update x set Flex3 = y.Field1, Flex1 = Flex1 + '' LIC'' from TransX x inner join Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex3 is NULL'),
