    ('SQL-M26', 701, 'update t set TPname = tp.Name,Flex5 = tp.OneStreamID from TransX t inner join TPs tp on t.TP = tp.TP where KeyID like ''[batchID]%'''),
    ('SQL-R19a', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-M17', 211, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY = c.TTY and t.BusCat = c.BC_From and (t.TP = c.TP_From or (len(t.TP) = 4 and c.TP_From = ''O'') or (t.TP like ''F%'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'''),
    ('SQL-M17', 212, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY = c.TTY and c.BC_From = '''' and (t.TP = c.TP_From or (len(t.TP) = 4 and c.TP_From = ''O'') or (t.TP like ''F%'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL'),
    ('SQL-M17', 213, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and t.TTY like c.TTY and c.BC_From = '''' and (t.TP = c.TP_From or (len(t.TP) = 4 and c.TP_From = ''O'') or (t.TP like ''F%'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL'),
    ('SQL-M17', 291, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, CC, PC, Txt, Amt1, FSitem, Flex1,Flex4) (Select KeyID, Co, GL, TTY, TP, BusCat, CC, PC, ''4-JE-Rev'' as Txt, round(-Amt1,2) as Amt1, FSitem, Flex1,(case when Flex4 = '''' then '''' else replace(Flex4,''01 '',''02 '') + '' clear'' end) as Flex4 from TransX where KeyID = ''[batchID]'' and Co = ''JE'' and Txt = ''4-IFRS'')'),
    ('SQL-M25', 608, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''02 RI'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and Flex5 = ''02 RI'' and GL = ''4099998''  and not TP = ''FFH'')'),
    ('SQL-G23', 291, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560002'' as GL, Crcy, PC,''806'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''1560001'' and TTY = ''627'')'),
    ('SQL-E00', 1280, 'update TransX set TransCode = ''T9999'' from TransX inner join [GFS].dbo.FSGValidation v on GL = GLAccount where KeyID = ''[batchID]'' and v.TransCode = 1'),
    ('SQL-S20', 503, 'Insert into TransX (KeyID,Ledger,Co,GL,GLdesc,Flex1) (select distinct ''[batchID]-data3'' as KeyID,max(v.Ledger) as Ledger,v.Co,v.GL,v.GLdesc,''Please open period for Ledger/Co/GL combination'' as Flex1 from (Select x.Co,x.GL,x.GLdesc,y.Ledger from TransX x inner join LedgerGroups y on x.Ledger = y.LedgerGroup and y.Ledger in (''IF'',''UG'') inner join Companies z on x.Co = z.Co inner join PeriodStatus p on z.Period = p.Variant and x.GL >= p.FromAcct and x.GL <= p.ThruAcct and p.AccType = ''S'' where (''[Yr]-[Mo]'' < cast(p.FromYr as varchar(4)) + ''-'' + (case when p.FromPer < 10 then ''0'' else '''' end) + cast(p.FromPer as varchar(2)) or ''[Yr]-[Mo]'' > cast(p.ThruYr as varchar(4)) + ''-'' + (case when p.ThruPer < 10 then ''0'' else '''' end) + cast(p.ThruPer as varchar(2))) and x.KeyID = ''[batchID]'') v group by v.Co, v.GL,v.GLdesc)'),
    ('SQL-S20', 621, 'Insert into TransX (KeyID,Flex1,Flex2,Division,Region,Location,Zone) (select ''[batchID]-data5'' as KeyID, x.ID as Flex1, y.ID as Flex2, y.From_GL as Division, y.Thru_GL as Region, y.Post_GL as  Location, y.Offset_GL as Zone from FX_Variant_Detail x inner join FX_Map_Detail y on x.FX_Map_ID = y.ID where x.ID = ''[version]'')'),
    ('SQL-G86', 344, 'insert into TransX (KeyID,GL,Co,Crcy,CC,Contract,ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, ''6911000'' as GL,''3270'' as Co,Crcy,''3GIA000011'' as CC, Contract, ProdCode, round(sum(Amt1)*0.05,2) as Amt1, round(sum(Amt2)*0.05,2) as Amt2, round(sum(Amt3)*0.05,2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' group by KeyID,Crcy,Contract,ProdCode )'),
    ('SQL-G23', 101, 'delete from TransX where KeyID = ''[batchID]''  and ''[yyyy-mm-dd]'' = ''2022-01-31'' and GL > ''3000000'''),
    ('SQL-M11', 206, 'Update x set Flex5 = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex9 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-G23', 102, 'Update TransX set Amt1 = coalesce(Amt4,0), Amt2 = coalesce(Amt5,0), Amt3 =coalesce(Amt6,0) where KeyID = ''[batchID]'' and ''[yyyy-mm-dd]'' = ''2022-01-31'' and not Co like ''599%'''),
    ('SQL-E00', 1030, 'update TransX set Amt1 = round(0-Amt1,2), Flex2 = Co where KeyID = ''[batchID]'' and Co = ''[ElimCo]'''),
    ('SQL-T15', 101, 'insert into TransX (KeyID,TransCode,Flex1) (Select ''[batchID]'',ID,Descr from Misc_Tables where Table_ID = ''TransCode'')'),
    ('SQL-R19', 132, 'update TransX set Hierarchy = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''[CoSelect]'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Region like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R19', 133, 'update TransX set Hierarchy = p.Location from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''[CoSelect]'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Location like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R19', 134, 'update TransX set Hierarchy = p.Zone from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''[CoSelect]'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Zone like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R19', 135, 'update TransX set Hierarchy = p.Hierarchy from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''[CoSelect]'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Hierarchy like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-S60', 213, 'update TransX set Flex8 = ''Doc not changed by Posted-By'' from TransX where KeyID = ''[batchID]'' and Flex8 is NULL and Flex1 <> Flex4'),
    ('SQL-R23', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-R23', 201, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R23', 202, 'update TransX set Flex1 = MapKey from TransX inner join MapKeyRanges on GL >= FromGL and GL <= ThruGL where KeyID = ''[batchID]'' and (MapKey like ''M2-3-5-B-%-1'' or MapKey like ''M2-3-5-B-%-2'')'),
    ('SQL-R10', 217, 'update TransX set Amt2 = -Amt1 from TransX where KeyID = ''[batchID]'' and substring(GL,1,1) = ''2'' and not (Flex1 = ''Ceded'' and substring(GL,1,2) = ''28'')'),
    ('SQL-R16', 235, 'update TransX set Flex6 = '''' from TransX where KeyID = ''[batchID]'' and coalesce(Flex6,'''') in ('''',''UNKNOWN'')'),
    ('SQL-R28', 201, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R28', 211, 'update TransX set BusCat = '''' from TransX where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-R28', 212, 'update TransX set GLdesc = c.Name from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R28', 213, 'update TransX set TPname = p.Name, Flex1 = p.SchedYname, Yr = p.SchedYrow, Flex5 = p.NAIC, Flex6 = p.FedID, Flex7 = p.OneStreamID from TransX t inner join TPs p on t.TP = p.TP where KeyID = ''[batchID]'''),
    ('SQL-R28', 214, 'update TransX set Flex2 = p.SchedYname, Period = p.SchedYrow, Flex8 = p.OneStreamID from TransX t inner join TPs p on t.Co = p.TP where KeyID = ''[batchID]'''),
    ('SQL-R28', 215, 'update TransX set Flex4 = (case when BusCat >= ''10'' and BusCat <= ''29'' then ''A'' else ''C'' end) from TransX where KeyID = ''[batchID]'''),
    ('SQL-M18', 514, 'update TransX set Flex3 = ''4603'' where KeyID = ''[batchID]'' and (substring(GL,1,2) in (''54'',''55'') or GL = ''4600003'') and BusCat in (''A'',''D'')'),
    ('SQL-R28', 216, 'update TransX set Flex3 = m.Field1, Qtr = m.Field2 from TransX t inner join Misc_Tables m on substring(t.GL,1,3) = m.Descr where KeyID = ''[batchID]'' and Table_ID = ''Sched Y'' and ID = ''GL'''),
    ('SQL-R28', 218, 'update TransX set Amt3 = round(0-Amt2,2) from TransX where KeyID = ''[batchID]'''),
    ('SQL-R28', 231, 'insert into TransX (KeyID, GL, Gldesc, Co, Flex1, Flex4, Flex9, Qtr, Amt2, Amt3) (select KeyID, ''4000000'' as GL, ''Colm 9'' as GLdesc, Co, SchedYname, Flex4, ''n'' as Flex9, 9 as Qtr, round(-sum(Amt2),2) as Amt2, round(-sum(Amt3),2) as Amt3 from TransX t inner join TPs p on t.Co = p.TP where KeyID = ''[batchID]'' and Qtr = 9 group by KeyID,Co,SchedYname,Flex4)'),
    ('SQL-R29', 221, 'update TransX set Flex1 = ''ASSETS'' from TransX where KeyID = ''[batchID]'' and Flex5 like ''M1-1-%'''),
    ('SQL-R29', 222, 'update TransX set Flex2 = ''('' + substring(Flex5,6,2) + '') '' + m.name from TransX t inner join MapKeys m on m.MapKey = substring(Flex5,1,7) where KeyID = ''[batchID]'' and Flex5 like ''M1-1-%'''),
    ('SQL-R29', 223, 'update TransX set Flex3 = ''('' + substring(Flex5,9,2) + '') '' + m.name from TransX t inner join MapKeys m on m.MapKey = substring(Flex5,1,10) where KeyID = ''[batchID]'' and Flex5 like ''M1-1-01-%'''),
    ('SQL-R29', 224, 'update TransX set Flex4 = ''('' + substring(Flex5,12,1) + '') '' + m.name from TransX t inner join MapKeys m on m.MapKey = Flex5 where KeyID = ''[batchID]'' and Flex5 like ''M1-1-01-06-%'''),
    ('SQL-R29', 231, 'update TransX set Flex2 = ''('' + substring(Flex5,4,1) + '') '' + upper(m.name) from TransX t inner join MapKeys m on m.MapKey = substring(Flex5,1,4) where KeyID = ''[batchID]'' and not Flex5 like ''M1-1-%'''),
    ('SQL-R29', 232, 'update TransX set Flex3 = ''('' + substring(Flex5,6,1) + '') '' + m.name from TransX t inner join MapKeys m on m.MapKey = Flex5 where KeyID = ''[batchID]'' and not Flex5 like ''M1-1-%'''),
    ('SQL-R29', 241, 'update TransX set Amt3 = round(Amt1-Amt2,2) from TransX where KeyID = ''[batchID]'''),
    ('SQL-M18', 199, 'insert into TransX (KeyID, Zone, Co, GL, BusCat,TP,PC,SubProd, Flex1, Amt1,Amt2) (Select KeyID, Zone, Co, substring(GL,1,3) + '' '' + TTY as GL, '''' as BusCat, TP, PC,SubProd, Flex1, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2  from TransX where KeyID = ''[batchID]'' and substring(GL,1,3) in (''148'') and TTY in (''804''))'),
    ('SQL-G59', 249, 'update TransX set RiskTerr = ''UNKN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and RiskLocation = 1'),
    ('SQL-R20', 125, 'update TransX set Hierarchy = p.Hierarchy from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Hierarchy like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R20', 131, 'update TransX set Flex1 = m.Field1 from TransX t inner join Misc_Tables m on m.Field2 = t.Hierarchy or m.Field2 = '''' where KeyID = ''[batchID]'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and m.Descr = ''All Divisions'' and Flex1 is NULL'),
    ('SQL-T30', 101, 'insert into TransX (KeyID,Flex1,Flex2) (Select ''[batchID]'',PymtTerm,Descr from PymtTerms)'),
    ('SQL-R20a', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-R20b', 102, 'delete from TransX where KeyID = ''[batchID]'' and Amt4 = 0'),
    ('SQL-R20', 104, 'delete from TransX where KeyID = ''[batchID]'' and Flex6 is NULL'),
    ('SQL-R20', 110, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R20', 142, 'delete from TransX where KeyID = ''[batchID]'' and Flex5 is NULL'),
    ('SQL-R20', 143, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0'),
    ('SQL-R20', 135, 'update TransX set Flex2 = m.Descr from TransX t inner join Misc_Tables m on t.GL >= m.Field1 and t.GL <= m.Field2 where KeyID = ''[batchID]'' and m.Table_ID = ''Flux'' and m.ID = ''GLgrp'''),
    ('SQL-T06', 102, 'update TransX set Flex5 = substring(Flex2,11,99) from TransX where KeyID = ''[batchID]'' and substring(Flex5,1,10) = ''ODYSSEYRE\'''),
    ('SQL-T06', 103, 'update TransX set PCdesc = f.Descr from TransX t inner join FSG f on t.PC = f.FSG where KeyID = ''[batchID]'''),
    ('SQL-T07', 101, 'insert into TransX (KeyID,PC,FSitemDesc,GL,GLdesc,Flex1,Flex2,Flex3,Flex4,Flex5) (select ''[batchID]'',FSitem,FSitemDesc,FromGL,ThruGL,Cast(ID as varchar), Cast(ParentID as varchar), Cast(FirstChildID as varchar), Cast(SiblingID as varchar), Cast(Lvl as varchar) from FSitems)'),
    ('SQL-G26', 261, 'Update TransX set TTY = ''900'' where KeyID = ''[batchID]'' and GL = ''1099917'' and not TTY = ''815'''),
    ('SQL-G26', 238, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1099917'' as GL, Crcy, ''900'' as TTY, TP, PC, '''' as ProdCode, '''' as PTF, ''FH'' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and (TTY = ''804'' or substring(GL,1,5) in (''16100'',''24100'',''44100'',''68200'')) and not TTY = ''815'' and ''[yyyy-mm-dd]'' = ''2022-12-31'' group by KeyID, Co, Crcy, TP, PC)'),
    ('SQL-E31', 1181, 'insert into TransX (KeyID,Ledger,Co,GL,PC,TP,BusCat,Contract,UWYR,TTY,Amt1,Flex1) (select ''[batchID]'' as KeyID,Ledger,Co,GL,''4050500010'' as PC,''2300'' as TP,BusCat,''DAH'' as Contract,UWYR,TTY,round(sum(Amt1),2),''pass4'' as Flex1 from TransX where KeyID = ''[batchID]'' group by Ledger,Co,GL,BusCat,UWYR,TTY)'),
    ('SQL-G47', 236, 'insert into TransX (KeyID, GL, PC, Amt1, TTY,BusCat) (Select KeyID, ''202'' + substring(GL,4,4) as GL, PC, -Amt1, ''822'' as TTY,BusCat from TransX where KeyID = ''[batchID]'' and substring(GL,1,2) in (''50'',''51'',''52'') and BusCat = '''')'),
    ('SQL-G47', 237, 'insert into TransX (KeyID, GL, PC, Amt1, TTY, BusCat) (Select KeyID, ''151'' + substring(GL,4,4) as GL, PC, Amt1, ''831'' as TTY, BusCat from TransX where KeyID = ''[batchID]'' and GL like ''401%'' and BusCat = ''30'')'),
    ('SQL-G47', 238, 'insert into TransX (KeyID, GL, PC, Amt1, TTY,BusCat) (Select KeyID, ''151'' + substring(GL,4,4) as GL, PC, -Amt1 as Amt1, ''832'' as TTY,BusCat from TransX where KeyID = ''[batchID]'' and GL like ''401%'' and BusCat = ''30'')'),
    ('SQL-G47', 239, 'insert into TransX (KeyID, GL, PC, Amt1, TTY,BusCat) (Select KeyID, ''142'' + substring(GL,4,4) as GL, PC, Amt1, ''824'' as TTY,BusCat from TransX where KeyID = ''[batchID]'' and substring(GL,1,2) in (''50'',''51'',''52'') and BusCat = ''30'')'),
    ('SQL-G47', 240, 'insert into TransX (KeyID, GL, PC, Amt1, TTY,BusCat) (Select KeyID, ''142'' + substring(GL,4,4) as GL, PC, -Amt1, ''822'' as TTY,BusCat from TransX where KeyID = ''[batchID]'' and substring(GL,1,2) in (''50'',''51'',''52'') and BusCat = ''30'')'),
    ('SQL-G47', 251, 'update TransX set BusCat = ''21'', TP = ''2300'' from TransX where KeyID = ''[batchID]'' and BusCat = '''''),
    ('SQL-G47', 252, 'update TransX set TP = ''FF001'' from TransX where KeyID = ''[batchID]'' and BusCat = ''30'''),
    ('SQL-F00', 106, 'update TransX set TPname = p.Name from TransX t inner join TPs p on t.TP = p.TP where KeyID = ''[batchID]'''),
    ('SQL-F00', 108, 'update TransX set Flex3 = ''(1) Co2Co'' from TransX where KeyID = ''[batchID]'' and Flex3 is NULL'),
    ('SQL-F00', 109, 'update TransX set Flex2 = ''Co'' + Co + '' Tp'' + TP from TransX where KeyID = ''[batchID]'''),
    ('SQL-F00', 110, 'update TransX set Flex1 = Descr, Flex4 = Field1 from TransX t inner join Misc_Tables m on t.GL = m.ID where KeyID = ''[batchID]'' and Table_ID = ''GL Grp 4'''),
    ('SQL-F00', 111, 'update TransX set Flex1 = Descr, Flex4 = Field1 from TransX t inner join Misc_Tables m on substring(t.GL,1,2) = m.ID where KeyID = ''[batchID]'' and Table_ID = ''GL Grp 4'''),
    ('SQL-R51', 210, 'update TransX set TPname = '''', Flex3 = '''' where KeyID = ''[batchID]'''),
    ('SQL-R51', 211, 'update TransX set Flex3 = Descr, TPname = Field2 from TransX inner join Misc_Tables on Contract = ID where KeyID = ''[batchID]'' and Table_ID = ''HUD_STM_Contracts'' and Co <> ''2008'''),
    ('SQL-R51', 212, 'update TransX set Flex3 = Descr, TPname = ID from TransX inner join (select min(Descr) as Descr, min(ID) as ID, Field2 from Misc_Tables where Table_ID = ''HUD_STM_Contracts'' group by Field2) a on Contract = Field2 where KeyID = ''[batchID]''  and Co = ''2008'''),
    ('SQL-R51', 250, 'update TransX set Flex1 = ''02 RCR & ALAE'' where KeyID = ''[batchID]'' and Flex1 in (''02 RCR'',''04 ALAE'')'),
    ('SQL-R51', 251, 'update TransX set Flex1 = ''26 Chg RCR & ALAE'' where KeyID = ''[batchID]'' and Flex1 in (''26 Chg RCR'',''28 Chg ALAE'')'),
    ('SQL-R51', 304, 'update TransX set TPname = Field2 from TransX inner join Misc_Tables on Contract = ID and Co = Field1 where KeyID = ''[batchID]'' and Table_ID = ''HUD_STM_Contracts'' and Co <> ''2008'' and Flex3 = ''a - 70% QS'' and Contract like ''P%-QS%'''),
    ('SQL-R18', 161, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data4'', Ledger, Flex1, Flex2, ''1. [CQ1] vs. [PQ1]'' as Flex3, round(sum(Amt3)/1000,0) as Amt3 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R18', 162, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data4'', Ledger, Flex1, Flex2, ''2. [CQ1] vs. [PYE1]'' as Flex3, round(sum(Amt5)/1000,0) as Amt5 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' and Period > 3 group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R18', 163, 'insert into TransX (KeyID, Ledger, Flex1, Flex2, Flex3, Amt1) (select KeyID + ''-data4'', Ledger, Flex1, Flex2, ''3. [CQ1] vs. [PYCQ1]'' as Flex3, round(sum(Amt7)/1000,0) as Amt7 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' group by KeyID, Ledger, Flex1, Flex2)'),
    ('SQL-R70', 229, 'update TransX set Flex1 = ''2300'', Flex2 = ''HUD ST 2008'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2008'' and Flex1 = '''''),
    ('SQL-R18', 164, 'delete from TransX where KeyID = ''[batchID]-data4'' and Abs(Amt1) < 500'),
    ('SQL-R20', 103, 'insert into TransX (KeyID, Co, GL, PC, TP, Amt1, Amt2, Amt3, Amt4, Flex6) (select KeyID, Co, GL, PC, TP, ROUND(SUM(COALESCE(Amt1,0)),2) as Amt1, ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt3,0)),2) as Amt3, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, ''pass1'' as Flex6  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, PC,TP)'),
    ('SQL-G29', 209, 'delete from TransX where KeyID = ''[batchID]'' and TPname in (''FA'',''FB'')'),
    ('SQL-G29', 506, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and (t.BusCat = m.Field1 or m.Field1 = '''') and (t.TTY = m.Field2 or m.Field2 = '''') where t.KeyID = ''[batchID]'' and Flex7 is NULL'),
