    ('SQL-G55', 222, 'insert into TransX (KeyID, Ledger, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, ProdCode, AccYr, ReinName, ReinLoc, CatCode, Broker, RiskTerr, PTF,Stat,TransCode,Amt1, Amt2, Amt3, Flex6) (Select KeyID, Ledger, Co, ''6914000'' as GL, Crcy, '''' as TP, '''' as PC, ''1CBU000100'' as CC, '''' as BusCat, '''' as Contract, '''' as UWYR, '''' as ProdCode, '''' as AccYr, '''' as ReinName, '''' as ReinLoc, '''' as CatCode, '''' as Broker, '''' as RiskTerr, '''' as PTF,'''' as Stat,'''' as TransCode, round(-sum(coalesce(Amt1,0)),2) as Amt1, round(-sum(coalesce(Amt2,0)),2) as Amt2, round(-sum(coalesce(Amt3,0)),2) as Amt3, '''' as Flex6 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Co, Crcy)'),
