    ('SQL-R59', 281, 'insert into TransX (KeyID, GL, BusCatDesc, Co, Ledger,Flex4,Flex5, Amt1,Amt2,Flex8) (select ''[batchID]'',(case when Yr < [Yr] and GL >= ''4000000'' then ''3610000'' else (case when Yr < [Yr] and GL = ''3810001'' then ''3810000'' else GL end) end) as GL, '''' as BusCatDesc,Co,Ledger,JE,Ref,Amt as Amt1, (case when Yr = [Yr] then Amt else 0 end) as Amt2,''pass4'' from GAAP2Stat where Yr <= [Yr] and (CarryFwd = ''Y'' or Yr = ''[Yr]'') and (Period <= [Mo] or Yr < [Yr]) and JE like ''%-H%'')'),
