    ('SQL-G78', 361, 'insert into TransX (KeyID, GL, Amt1, Amt2, Amt3,CC,PC,TP,Contract,ProdCode,PK) (Select KeyID, ''1998900'' as GL, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2,  round(-sum(Amt3),2) as Amt3,'''' as CC,''3990000000'' as PC, ''F0037'' as TP,''3NMA100014'' as Contract,'''' as ProdCode, ''99'' as PK from TransX where KeyID = ''[batchID]'' and ProdCode = ''CHGBACK'' group by KeyID)'),
    ('SQL-P00', 1061, 'insert into TransX (KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat, TTY, Amt1, Amt3, Flex1) (Select KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat, TTY, round(sum(Amt1),2) as Amt1, round(sum(Amt3),2) as Amt3, ''pass 1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat, TTY)'),
