    ('SQL-R59', 631, 'Update TransX set Flex4 = ''0010-031'' where KeyID = ''[batchID]'' and Flex4 = ''9999-001'' and cast(Co as varchar(10)) + cast(GL as varchar(10)) in (select CoGL from (select cast(Co as varchar(10)) + cast(GL as varchar(10)) as CoGL,sum(Amt1) as Amt1 from TransX where KeyID = ''[batchID]'' and Flex4 = ''9999-001'' group by Co,GL) x where abs(x.amt1)<1)'),
