    ('SQL-R32', 102, 'insert into TransX (KeyID, Co, GL, CC, Amt1, Amt2, Amt3, Amt4, Amt5, Flex1) (select KeyID, Co, GL, CC, round(sum(coalesce(Amt2,0))-sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, round(sum(coalesce(Amt4,0))-sum(coalesce(Amt3,0)),2) as Amt3, round(sum(coalesce(Amt4,0)),2) as Amt4, round(sum(coalesce(Amt5,0)),2) as Amt5, ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,Co,GL,CC)'),
    ('SQL-G31', 122, 'update TransX set ProdCode = ''U1801'' where KeyID = ''[batchID]-data4''  and GL in (''1560001'',''1560002'',''2150001'')'),
