    ('SQL-G77', 402, 'insert into TransX (KeyID, Co,GL, Crcy,PC, CC, Contract, ProdCode,TP,Amt1, Amt2, Amt3,PK) (Select KeyID, Co,GL, Crcy,PC,CC, Contract, ProdCode,TP,(case when Amt1 < 0 then Amt1 else 0 end) as Amt1,(case when Amt2 < 0 then Amt2 else 0 end) as Amt2,  (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and (Amt1 < 0 or Amt2 < 0 or Amt3 < 0))'),
