    ('SQL-G77', 301, 'insert into TransX (KeyID, Co,GL, Crcy,PC,CC,Contract,ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, ''4010'' as Co, ''6910000'' as GL, Crcy, '''' as PC, ''1OSS000032'' as CC, ''3NSU100113'' as Contract, ''CHGBACK'' as ProdCode, round(sum(-Amt1),2) as Amt1, round(sum(-Amt2),2) as Amt2,  round(sum(-Amt3),2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' group by KeyID,Crcy)'),
    ('SQL-G77', 302, 'insert into TransX (KeyID, Co,GL, Crcy,PC,CC,Contract,ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, ''4010'' as Co, ''6910501'' as GL, Crcy, '''' as PC, ''5OSS000001'' as CC, ''3NSU100113'' as Contract, ''CHGBACK'' as ProdCode, round(sum(-Amt1*.1),2) as Amt1, round(sum(-Amt2*.1),2) as Amt2,  round(sum(-Amt3*.1),2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' and GL >= ''6000000'' and GL <= ''61999999'' and Co = ''3030'' group by KeyID,Crcy)'),
    ('SQL-G77', 303, 'insert into TransX (KeyID, Co,GL, Crcy,PC,CC,Contract,ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, ''3030'' as Co, GL, Crcy, '''' as PC, ''3NSU100113'' as CC, ''5OSS000001'' as Contract, ''CHGBACK'' as ProdCode, round(-Amt1,2) as Amt1, 0 as Amt2, round(-Amt3,2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' and GL = ''6910501'' and Co = ''4010'')'),
