    ('SQL-G77', 365, 'insert into TransX (KeyID,Co,GL,Crcy,PC,CC,Contract,ProdCode,TP,Amt1, Amt2, Amt3,PK,Flex9) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, ProdCode, TP, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, '''' as PK, ''pass1'' as Flex9 from TransX where KeyID = ''[batchID]'' group by KeyID,Co,GL,Crcy,PC,CC,Contract,ProdCode,TP )'),
