    ('SQL-G61', 212, 'insert into TransX (KeyID,Co, GL, Crcy, CC,BusCat,Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, CC,BusCat, round(-sum(coalesce(Amt1,0)),2) as Amt1, round(-sum(coalesce(Amt2,0)),2) as Amt2,  round(-sum(coalesce(Amt3,0)),2) as Amt3,  ''40'' as PK from TransX where KeyID = ''[batchID]'' and (Amt1 < 0 or Amt2 < 0 or Amt3 < 0) and PK is NULL group by KeyID, Co, GL, Crcy, CC,BusCat)'),
