    ('SQL-R49', 630, 'update TransX set Flex5 = ''116'', Flex6 = ''co 2007 tp 2400/2450 only has Pontus - others should have TP removed'' where KeyID = ''[batchID]'' and Co = ''2007'' and TP in (''2400'',''2450'') and Flex5 is NULL'),
