    ('SQL-M45', 121, 'insert into TransX (KeyID, Yr, Co, Crcy, GL, TP,PC,Flex2, TTY,Contract,UWYr,Amt1,Amt2,Flex3) (Select KeyID, Yr, Co, Crcy, GL, TP,PC,Flex2, TTY,Contract,UWYr, round(sum(COALESCE(Amt1,0)),2) as Amt1, round(sum(COALESCE(Amt2,0)),2) as Amt2, ''pass2'' as Flex3 from TransX where KeyID = ''[batchID]'' group by KeyID, Yr, Co, Crcy, GL, TP, PC, Flex2, TTY,Contract,UWYr)'),
    ('SQL-M45', 122, 'delete from TransX where KeyID = ''[batchID]'' and Flex3 is NULL'),
