    ('SQL-G74', 311, 'insert into TransX (KeyID, Co,TP,GL, Crcy,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID,''2008'' as Co,''F0018'' as TP, ''2898900'' as GL, Crcy, Amt1, Amt2,  Amt3, Amt4, PK from TransX where KeyID = ''[batchID]'' and GL = ''1999901'')'),
