    ('SQL-M45', 224, 'update TransX set Flex6 = Mapkey from TransX t inner join mapkeyranges m on t.GL >= m.fromGL and t.GL <=m.thruGL where keyID = ''[batchID]'' and mapkey like ''M1-_-%-%-%'' and not mapkey like ''M1-_-%-%-%-%'''),
    ('SQL-M45', 225, 'update TransX set Flex7 = REPLACE(m.Name,'' & ULAE'','''') from TransX t inner join mapkeys m on t.flex6 = m.mapkey where keyID = ''[batchID]'''),
    ('SQL-M45', 302, 'Update x set Flex8 = x.Flex2 + ''-'' + m1.field3 + ''-'' + x.Flex5, Division = m1.field2 from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' where KeyID = ''[batchID]'''),
    ('SQL-M45', 303, 'Update x set Flex5 = m2.field2 from TransX x inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
