    ('SQL-S22', 312, 'update TransX set ReinName = f4.CEDANT_REINSURER_CODE, TP = F4.TRADING_PARTNER, BusCat = F4.BUSINESS_CATEGORY_REINS_TYPE from TransX f1 inner join (select f3.contract_no, f3.cedant_reinsurer_code,f3.trading_partner,f3.business_category_reins_type from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] f3 inner join (select CONTRACT_NO, max(UW_YEAR) as UW_YEAR from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] group by COntract_no) f2 on f2.contract_no = f3.contract_no and f2.uw_year = f3.uw_year group by f3.contract_no, f3.cedant_reinsurer_code,f3.trading_partner,f3.business_category_reins_type) f4 on f1.contract = f4.contract_no where KeyID = ''[batchID]'' and not f1.Contract in ('''',''UNKNOWN'') and not ReinName in (select z.CEDANT_REINSURER_CODE from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] z where z.CONTRACT_NO = f1.Contract and z.UW_YEAR = f1.UWYR and z.LEGAL_ENTITY = f1.Co)'),
    ('SQL-S22', 411, 'insert into CedingCoByQtrContractUWYR (Co,Contract,UWYR,Yr,Per,CedingCo,ReinType1,ReinType2,BusCat,Flex1,Flex2) (Select Co,Contract,UWYR,Yr,Period,ReinName,Flex2,Flex3,BusCat,PC,PCdesc from TransX  where KeyID = ''[batchID]'' )'),
    ('SQL-S22', 422, 'delete from CedingCoByQtr where CedingCo = '''''),
    ('SQL-S22', 436, 'update c set NAIC = x.NAIC_COMPANY, FedID = x.FEIN_NUM from CedingCoByQtr c inner join [stm-dwhse-01].[ORION].dbo.[Companies] x on c.CedingCo = cast(x.BART_MAP_TO as varchar(20)) where coalesce(c.NAIC,'''') = '''' and coalesce(x.NAIC_COMPANY,'''') <> '''' and c.Yr = ''[Yr]'' and c.Per = ''[Mo]'' and c.SAP_CedingCo is not NULL'),
    ('SQL-S22', 701, 'insert into TransX (KeyID,ReinName,Flex1,PC,CC,Flex3,Flex4,Flex5,Flex6) (Select ''[batchID]-data3'',CedingCo,Name,AMBest_Rating,SP_Rating,AM_Name,SP_Name,NAIC,FedID from CedingCoByQtr where Yr = ''[Yr]'' and Per = ''[Mo]'' and Flex1 = ''[batchID]'')'),
    ('SQL-G81', 124, 'update x set Amt4 = y.Amt1 from TransX x inner join (Select KeyID,Flex3,Crcy,Co,GL,PC,UWYR,round(sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' group by KeyID,Flex3,Crcy,Co,GL,PC,UWYR) y on x.KeyID = y.KeyID and x.Flex3 = y.Flex3 and x.Crcy = y.Crcy and x.Co = y.Co and x.GL = y.GL and x.PC = y.PC and x.UWYR = y.UWYR'),
    ('SQL-R19', 145, 'update TransX set Flex2 = m.Descr from TransX t inner join Misc_Tables m on t.GL >= m.Field1 and t.GL <= m.Field2 where KeyID = ''[batchID]'' and m.Table_ID = ''Flux'' and m.ID = ''GLgrp'''),
    ('SQL-R20', 121, 'update TransX set Hierarchy = p.Division from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Division like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
