    ('SQL-M10', 305, 'Update x set Flex4 = ''7'' + m1.field2 + m2.field2 + x.Flex6 + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex8 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-M10', 532, 'insert into [FX_Recon].dbo.TransX (KeyID,Flex1,Co,GL,Crcy,Flex2,PC,PCdesc,Flex4,Flex5,Flex6,UWYR,TP,Flex7,Amt1,Amt2,Amt3) (select ''[batchID]'',''IR17_CF'',Co,GL,Crcy,Co_Crcy,PC,PC_Desc,Portfolio_PC,Program,ACD,UWYR,TP,Incl_Excl,round(-sum(Doc_Amt),2) as Doc_Amt,round(-sum(LC_Amt),2) as LC_Amt,round(-sum(LC2_Amt),2) as LC2_Amt from IR17_CF where  YearPeriod >= ''[Yr]01'' and YearPeriod <= ''[Yr][Mo]'' GROUP BY Co,GL,Crcy,Co_Crcy,PC,PC_Desc,Portfolio_PC,Program,ACD,UWYR,TP,Incl_Excl)'),
    ('SQL-M10', 533, 'insert into [FX_Recon].dbo.TransX (KeyID,Flex1,Co,GL,Crcy,Flex2,PC,PCdesc,Flex4,Flex5,Flex6,UWYR,TP,Flex7,Amt1,Amt2,Amt3,Flex3) (select ''[batchID]'',''IR17_RIP'',Co,GL,Crcy,Co_Crcy,PC,PC_Desc,Portfolio_PC,Program,ACD,UWYR,TP,Incl_Excl,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt, ''RIP'' as Flex3 from IR17_CF where  YearPeriod >= ''[Yr]01'' and YearPeriod <= ''[Yr][Mo]'' and GL = ''1310001'' and Group2_Desc = ''Claims'' and Source = ''R65'' GROUP BY Co,GL,Crcy,Co_Crcy,PC,PC_Desc,Portfolio_PC,Program,ACD,UWYR,TP,Incl_Excl)'),
    ('SQL-G29', 525, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''607'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600000'')'),
    ('SQL-G29', 526, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''602'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Flex5, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600000'')'),
