    ('SQL-R59', 313, 'update TransX set Flex4 = ''0010-024'' from TransX where KeyID = ''[batchID]'' and Co in (''2300'',''2310'',''2400'',''2450'') and GL in (''9920001'',''9920002'',''6915000'') and Flex4 = ''9999-001'''),
    ('SQL-R49', 432, 'update TransX set Flex5 = (case when TP = '''' then ''777'' else ''7'' end), Flex6 = ''NICL QS'' from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and PC in (''3992070000'',''39990000EL'',''34142701EL'') and not Contract like ''N-LB AF%'''),
