    ('SQL-S39', 301, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, ''1406000364'' as PC, ''1US''+SUBSTRING(CC,4,1)+''600364'' as CC, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''4060100317'')'),
    ('SQL-S39', 302, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, ''3991061409'' as PC, ''3NS''+SUBSTRING(CC,4,1)+''101409'' as CC, ROUND(Amt1/3,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''4060100317'')'),
