    ('SQL-G26', 247, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and m.Field1 = '''' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL'),
    ('SQL-M25', 771, 'insert into TransX (KeyID, Co, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5) (Select ''[batchID]'', ''5990'' as Co, ''777'' as TTY, '''' as TP, '''' as BusCat, ''G26'' as SubProd, round(-sum(Amt1),2) as Amt1, ''2056'' as FSitem, ''2056 A/P - other (over $ must be explained)'' as Flex1, ''01) Accounts Payable and Accrued Liabilities'' as Flex2, ''1099917 Suspense Cash - IFRS17'' as Flex3, ''2) Liabilities'' as Flex4, ''02 RI'' as Flex5 from TransX where KeyID = ''[batchID]'' and Flex5 = ''02 RI'')'),
    ('SQL-M25', 716, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and c.TTY = ''990'' and substring(t.GL,4,3) = ''999'' and t.BusCat = c.BC_From and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL'),
    ('SQL-G23', 288, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150001'' as GL, Crcy, PC,''603'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''5600052'')'),
    ('SQL-G23', 289, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560001'' as GL, Crcy, PC,''627'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''5600067'')'),
    ('SQL-G28', 105, 'delete from TransX where KeyID = ''[batchID]'' and co = ''2999x'''),
    ('SQL-G25', 277, 'Update t set Amt2 = round(Amt2*r1.Rate/r2.Rate,2) from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.Field3 = ''convert'' and m.ID = ''Co'' and m.Descr = t.Co inner join CrcyRates r1 on r1.Crcy = m.Field2 and r1.Typ = ''S'' and r1.EffDate = (select max(EffDate) from (select EffDate from CrcyRates where Typ = ''S'' and Crcy = ''GBP'' and EffDate <= ''[yyyy-mm-dd]'') a) inner join CrcyRates r2 on r2.Crcy = m.Field4 and r2.Typ = ''S'' and r2.EffDate = r1.EffDate where t.KeyID = ''[batchID]'''),
    ('SQL-M15', 601, 'insert into TransX (KeyID, Flex3,Flex1, Co, GL, GLdesc, BusCat, TP, Amt1) (select KeyID, Flex3,''(3) variance'' as Flex1, Co, GL, GLdesc, BusCat, TP, round(sum(Amt1),2) from TransX where KeyID = ''[batchID]'' and Flex1 in (''(1) IFRS 4'',''(2) Back-out'')  group by KeyID, Flex3, Co, GL, GLdesc, BusCat, TP)'),
    ('SQL-M15', 602, 'insert into TransX (KeyID, Flex3,Flex1, Co, GL, GLdesc, BusCat, TP, Amt1) (select KeyID, Flex3,''(5) variance'' as Flex1, Co, GL, GLdesc, BusCat, TP, round(sum(Amt1),2) from TransX where KeyID = ''[batchID]'' and Flex1 in (''(2) Back-out'',''(4) Re-entry'')  group by KeyID, Flex3, Co, GL, GLdesc, BusCat, TP)'),
    ('SQL-W13', 220, 'Update TransX set Flex2 = ''05-CASH'' where KeyID = ''[batchID]'' and TTY in (''805'',''808'') and TransCode in (''T0008'',''T0014'',''T0048'')'),
    ('SQL-G47', 235, 'insert into TransX (KeyID, GL, PC, Amt1, TTY,BusCat) (Select KeyID, ''202'' + substring(GL,4,4) as GL, PC, Amt1, ''824'' as TTY,BusCat from TransX where KeyID = ''[batchID]'' and substring(GL,1,2) in (''50'',''51'',''52'') and BusCat = '''')'),
    ('SQL-G81', 125, 'update x set Amt5 = y.Amt1 from TransX x inner join (Select KeyID,Flex3,Crcy,Co,GL,PC,UWYR,round(sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' group by KeyID,Flex3,Crcy,Co,GL,PC,UWYR) y on x.KeyID = y.KeyID and x.Flex3 = y.Flex3 and x.Crcy = y.Crcy and x.Co = y.Co and x.GL = y.GL and x.PC = y.PC and x.UWYR = y.UWYR'),
    ('SQL-G81', 131, 'update TransX set Ledger = ''Z000''  from TransX where KeyID = ''[batchID]'' and Flex3 = ''60'' and Ledger = ''0L'''),
    ('SQL-G81', 132, 'update TransX set Ledger = ''Z000''  from TransX where KeyID = ''[batchID]'' and Amt2 = Amt3 and Amt2 = Amt4 and Amt2 = Amt5 and Ledger = ''0L'''),
    ('SQL-G81', 133, 'delete from TransX where KeyID = ''[batchID]'' and Amt2 = Amt3 and Amt2 = Amt4 and Amt2 = Amt5 and Ledger <> ''0L'' and Ledger <> ''Z000'''),
    ('SQL-G81', 134, 'update TransX set Ledger = ''Z000''  from TransX where KeyID = ''[batchID]'' and Amt2 = Amt3 and Amt2 = Amt4 and Ledger = ''0L'' and (Co like ''1%'' or Co like ''26%'' or Co like ''41%'')'),
    ('SQL-G81', 192, 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,UWYR,Amt1,Amt2,Amt3,Amt4,Txt,Flex3) (select KeyID,Ledger,Co,Crcy,GL,PC,UWYR,round(sum(Amt1),2),round(sum(Amt2),2),round(sum(amt3),2),round(sum(Amt4),2),''Bank Crcy Adj for '' + cast(GL as varchar(7)) + '' '' + Crcy as Txt,''pass2'' from TransX where KeyID = ''[batchID]'' and Flex3 = ''pass1'' group by KeyID,Ledger,Co,Crcy,GL,PC,UWYR)'),
    ('SQL-G81', 136, 'update TransX set Ledger = ''Z003''  from TransX where KeyID = ''[batchID]'' and Amt3 = Amt4 and Amt3 = Amt5 and Ledger = ''IF'''),
    ('SQL-G81', 137, 'delete  from TransX where KeyID = ''[batchID]'' and Amt3 = Amt4 and Amt3 = Amt5 and Ledger in (''UG'',''US'')'),
