    ('SQL-R20', 141, 'insert into TransX (KeyID, Co, GL, GLdesc, TP, TPname, Flex2,Hierarchy, Flex1, Amt1, Amt2, Amt3, Amt4, Flex5) (select KeyID, Co, GL, GLdesc, TP, TPname, Flex2, Hierarchy, Flex1, ROUND(SUM(COALESCE(Amt1,0)),2) as Amt1, ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt3,0)),2) as Amt3, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, ''pass2'' as Flex5  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, GLdesc, TP, TPname, Flex2, Hierarchy, Flex1)'),
    ('SQL-R21', 131, 'insert into TransX (KeyID, Co, GL, GLdesc, Flex1, PC,Hierarchy, Flex2,Flex3, Amt1, Amt2, Amt3, Amt4, Flex5) (select KeyID, Co, GL, GLdesc, Flex1, PC,Hierarchy, Flex2,Flex3, ROUND(SUM(COALESCE(Amt1,0)),2) as Amt1, ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt3,0)),2) as Amt3, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, ''pass2'' as Flex5  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, GLdesc, Flex1, PC,Hierarchy, Flex2,Flex3)'),
