    ('SQL-G31', 285, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''607'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''5600000'')'),
    ('SQL-G31', 286, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''602'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]-data3'' and GL = ''5600000'')'),
    ('SQL-G31', 314, 'update TransX set GL = ''1560000'', TTY = ''626'', ProdCode = ''U1806'' where KeyID in (''[batchID]'',''[batchID]-data3'') and GL = ''2860000'''),
    ('SQL-M41', 411, 'insert into TransX (KeyID,Yr,Period,Co,GL,TP,PC,BusCat,TTY,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt3) (select KeyID + ''-data3'',Yr,Period,Co,GL,TP,PC,BusCat,TTY,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Yr <> [Yr] and SUBSTRING(GL,1,1) = ''4'' and Flex1 is NULL)'),
