    ('SQL-M41', 413, 'insert into TransX (KeyID,Yr,Period,Co,GL,TP,PC,BusCat,TTY,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt5,Amt7) (select KeyID + ''-data3'',Yr,Period,Co,GL,TP,PC,BusCat,TTY,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Yr <> [Yr] and GL < ''4010000'' and Flex1 is NULL)'),
    ('SQL-M41', 414, 'insert into TransX (KeyID,Yr,Period,Co,GL,TP,PC,BusCat,TTY,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt6,Amt8) (select KeyID + ''-data3'',Yr,Period,Co,GL,TP,PC,BusCat,TTY,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Yr = [Yr] and GL <  ''4010000'' and Flex1 is NULL)'),
    ('SQL-W15', 504, 'Insert into IR17_Other_Canada (Co,Crcy,Co_Crcy,YearPeriod,GL,GL_Desc,PC,PC_Desc,Program,CC,CC_Desc,CCCat,CCCat_Desc,TP,Source,Incl_Excl,ACD,Portfolio_PC,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select Co,Crcy,Flex1,YearPeriod,GL,GLDesc,PC,PCdesc,Flex3,CC,CCdesc,CCCat,Flex5,TP,''R67'',Flex4,''A'',Flex9,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
