    ('SQL-M25', 101, 'Update TransX set Co = ''JE'', GL = ''JE'', Gldesc = substring(Flex8,1,50), SubProd = ''OS JE'', Flex5 = ''99 OS JE'',  TTY = '''', TP = '''', BusCat = '''', Amt2 = 0 where KeyID = ''[batchID]'' and not Division is NULL and SubProd is NULL'),
