    ('SQL-M25', 301, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat,SubProd, round(sum(Amt1),2) as Amt1, FSitem, Flex1, ''missing'' as Flex2, Flex5, Flex9 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, TTY, TP, BusCat, SubProd, FSitem, Flex1, Flex5, Flex9)'),
