    ('SQL-M25', 400, 'update x set Co = y.Field1, SubProd = ''G23'' from TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Co'' and y.Descr = x.Co where x.KeyID = ''[batchID]'' and x.Flex9 > ''1'''),
    ('SQL-S38', 212, 'update TransX set Flex3 = ''Budget/Outlook'' from TransX where KeyID = ''[batchID]'' and Flex3 is NULL'),
    ('SQL-M25', 402, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, Flex5, Flex9) (Select KeyID, Co, GL, TTY, TP, BusCat, ''G23'' as SubProd, -Amt1, FSitem, Flex1, Flex2, Flex3, Flex4, ''09 Bulk & DAH'' as Flex5, Flex9 from TransX where KeyID = ''[batchID]'' and Flex9 in (''2'',''3''))'),
