    ('SQL-G93', 211, 'insert into TransX (KeyID, GL, Crcy,CC,Contract,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, GL, Crcy, CC, Contract, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,round(sum(coalesce(Amt3,0)),2) as Amt3,round(sum(coalesce(Amt4,0)),2) as Amt4, '''' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, GL, Crcy,CC,Contract)'),
    ('SQL-G93', 212, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G93', 221, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID + ''-data2'',GL,Crcy,''2006'' as Co,CC,Contract,Amt1,Amt2,Amt3,Amt4 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G93', 301, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2006'' as Co,''1CBA000012'' as CC,''1CBA000010'' as Contract,-Amt1,-Amt2,-Amt3,-Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000010'')'),
    ('SQL-G93', 302, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2006'' as Co,''1CBA000012'' as CC,''1CBA000011'' as Contract,-Amt1,-Amt2,-Amt3,-Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000011'')'),
    ('SQL-G93', 303, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2006'' as Co,''1CBA000012'' as CC,''1CBA000010'' as Contract,-Amt1,-Amt2,-Amt3,-Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000012'' and Contract = ''1CBA000010'')'),
    ('SQL-G93', 304, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2006'' as Co,''1CBA000012'' as CC,''1CBA000011'' as Contract,-Amt1,-Amt2,-Amt3,-Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000012'' and Contract = ''1CBA000011'')'),
    ('SQL-G93', 305, 'insert into TransX (KeyID, GL,Crcy,Amt1, Amt2, Amt3, Amt4,Co,PC,TP) (Select KeyID, ''1999901'' as GL, Crcy, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3,round(sum(Amt4),2) as Amt4, ''2006'' as Co,''1600000000'' as PC, ''2008'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)'),
    ('SQL-S60', 202, 'update TransX set Amt5 = ABS(round(Amt2-Amt1,2)), Amt6 = 100 from TransX where KeyID = ''[batchID]'''),
    ('SQL-M28', 202, 'update TransX set  BusCat = ''20'' where KeyID = ''[batchID]'' and BusCat like ''2%'''),
    ('SQL-R16', 302, 'insert into TransX (KeyID, Flex1,Flex2,Flex3,Flex5,Amt3,Amt4) select ''[batchID]'', Flex1, ''prorate'', Flex3, ''non-affiliate'', Amt3, Amt4 from (select Flex1, Flex3, round(sum(-Amt3),2) as Amt3, round(sum(-Amt4),2) as Amt4 from TransX where KeyID = ''[batchID]'' and Flex2 = ''prorate'' group by Flex1, Flex3) f2 where Amt3 <> 0 or Amt4 <> 0'),
    ('SQL-S22', 463, 'update CedingCoByQtr set Flex3 = replace(replace(replace(replace(replace(Flex3,''corporation'',''corp''),''insurance'',''ins''),''company'',''co''),''mutual'',''mut''),''casualty'',''cas'') where Yr = ''[Yr]'' and Per = ''[Mo]'' and Flex2 is NULL'),
    ('SQL-S22', 464, 'update CedingCoByQtr set Flex3 = replace(replace(replace(replace(Flex3,''méxico'',''mexico''),''new jersey'',''nj''),''florida'',''fl''),''texas'',''tx'') where Yr = ''[Yr]'' and Per = ''[Mo]'' and Flex2 is NULL'),
    ('SQL-S03', 201, 'delete from TransX where KeyID = ''[batchID]'' and amt2 = 0'),
    ('SQL-G93', 306, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2008'' as Co,''5USA000069'' as CC,''1CBA000010'' as Contract,Amt1,Amt3,Amt3,Amt3 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000010'')'),
    ('SQL-G93', 307, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2008'' as Co,''5USA000083'' as CC,''1CBA000011'' as Contract,Amt1,Amt3,Amt3,Amt3 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000011'')'),
    ('SQL-G93', 308, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2008'' as Co,''5USA000069'' as CC,''1CBA000010'' as Contract,Amt1,Amt3,Amt3,Amt3 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000012'' and Contract = ''1CBA000010'')'),
    ('SQL-G93', 309, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2008'' as Co,''5USA000083'' as CC,''1CBA000011'' as Contract,Amt1,Amt3,Amt3,Amt3 from TransX where KeyID = ''[batchID]'' and Co is NULL and CC = ''1CBA000012'' and Contract = ''1CBA000011'')'),
    ('SQL-R83', 504, 'insert into Misc_Tables (Table_ID,ID,Descr,Field1,Field2,Field3) (select ''R83 Comm Pct'',Flex1,Co,cast(Amt3 as varchar),''calc'',Flex4 from TransX where KeyID = ''[batchID]-data2'' and Flex2 = ''calc'')'),
    ('SQL-M19', 231, 'update TransX set Flex1 = substring(PC,1,6), Flex2 = (case when substring(PC,6,1) = ''C'' then ''Port Reins/Ceded'' else ''Port Ins/Gross'' end), Flex3 = (case when substring(GL,3,1) = ''5'' then ''GL Ins/Gross'' else ''GL Reins/Ceded'' end), Flex4 = (case when substring(GL,1,1) = ''1'' then ''Asset'' else ''Liab'' end) where KeyID = ''[batchID]'''),
    ('SQL-G26', 252, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL = m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID in (''[batchID]'',''[batchID]-data8'') and not GL in (''4419900'') and Assgnmt is NULL'),
    ('SQL-R83', 502, 'update TransX set Amt3 = (Case when Amt1 = 0 then 0 else round(Amt2*100/Amt1,2) end) where KeyID = ''[batchID]-data2'''),
    ('SQL-G81', 191, 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,UWYR,Amt1,Amt2,Amt3,Amt4,Flex3) (select KeyID,Ledger,Co,Crcy,GL,PC,UWYR,(case when Flex3 = ''00'' then Amt1 else 0 end),(case when Flex3 = ''10'' then Amt1 else 0 end),(case when Flex3 = ''30'' then Amt1 else 0 end),(case when Flex3 = ''60'' then Amt1 else 0 end),''pass1'' from TransX where KeyID = ''[batchID]'')'),
    ('SQL-R07', 202, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R07', 211, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R25', 207, 'insert into TransX (KeyID, Yr, Crcy, Co, GL, TP, PC, BusCat, Contract, UWYR, Amt1, Amt2, Flex1) (select KeyID, Yr, Crcy, Co, replace(GL,''89'',''00'') as GL, TP, PC, BusCat, Contract, UWYR, Amt1, Amt2, Flex1 from TransX where KeyID = ''[batchID]'' and TTY = ''824'')'),
    ('SQL-R25', 252, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '''' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''143%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 left join (Select Crcy,PC,GL,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''143%'' and Flex1 = ''FX'' and UWYR = ''AW'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)'),
    ('SQL-R25', 254, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, '''' as BusCat, '''' as Contract, ''AW'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, f2.Amt1, f2.Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''159%'' and Flex1 = ''FX'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 inner join (Select Crcy,PC,GL,round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF088'' and GL like ''219%'' and Flex1 = ''FX'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and substring(f1.GL,4,4) = substring(f2.GL,4,4) where f2.Amt1 <> 0 or f2.Amt2 <> 0)'),
    ('SQL-R25', 255, 'insert into TransX (KeyID,Yr,Co,Crcy,PC,TP,TPname,BusCat,Contract,UWYR,Flex1,GL,GLdesc,Amt1,Amt2) (Select f1.KeyID,f1.Yr,f1.Co,f1.Crcy,f1.PC,f1.TP,f1.TPname, ''31'' as BusCat, '''' as Contract, ''NoB'' as UWYR, ''FX'' as Flex1, f1.GL, f1.GLdesc, round(f1.Amt1 - coalesce(f2.Amt1,0),2) as Amt1, round(f1.Amt2 - coalesce(f2.Amt2,0),2) as Amt2 from (Select KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc, sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''159%'' and Flex1 = ''FX'' and UWYR <> ''AW'' group by KeyID,Yr,Co,Crcy,PC,TP,TPname,GL,GLdesc) f1 left join (Select Crcy,PC,GL,sum(Amt1) as Amt1, sum(Amt2) as Amt2 from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and GL like ''159%'' and Flex1 = ''FX'' and UWYR = ''AW'' group by Crcy,PC,GL,GLdesc) f2 on f1.Crcy = f2.Crcy and f1.PC = f2.PC and f1.GL = f2.GL where coalesce(f2.Amt1,0) <> f1.Amt1 or coalesce(f2.Amt2,0) <> f1.Amt2)'),
    ('SQL-R25', 271, 'update TransX set UWYR = ''NoB'' from TransX where KeyID = ''[batchID]'' and TP = ''FF001'' and not UWYR = ''AW'' and Flex1 = ''FX'''),
    ('SQL-S08', 514, 'delete from TransX where KeyID = ''[batchID]'' and Ledger = ''UG'' and Amt1 = Amt2'),
    ('SQL-M13', 418, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,Amt1,Amt2,Amt3) (select ''[batchID]-data9'',Co,GL,Crcy,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,Source union all select Co,GL,'''' as Crcy,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF where source = ''R65'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'''' as Crcy,Source,0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' and not GL like ''222%'' GROUP BY Co,GL,Crcy,Source) a GROUP BY Co,GL,Crcy) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-R07', 414, 'update TransX set Flex1 = ''14 Synd Paris'' from TransX where KeyID = ''[batchID]'' and Co = ''3030'' and TP = ''2002'' and Flex1 is NULL'),
    ('SQL-G65', 102, 'delete from TransX where KeyID = ''[batchID]'' and CC in (select Descr from Misc_Tables where Table_ID = ''Bonus Accrual'' and ID = ''Skip CC'')'),
    ('SQL-R61', 127, 'update TransX set Flex4 = ''Specialty'' where KeyID = ''[batchID]'' and Flex4 like ''Specialty%'''),
    ('SQL-G87', 212, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-R16', 221, 'update TransX set ReinName = f4.CEDANT_REINSURER_CODE from TransX f1 inner join (select f3.contract_no, f3.cedant_reinsurer_code from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] f3 inner join (select CONTRACT_NO, max(UW_YEAR) as UW_YEAR from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] group by COntract_no) f2 on f2.contract_no = f3.contract_no and f2.uw_year = f3.uw_year group by f3.contract_no, f3.cedant_reinsurer_code) f4 on f1.contract = f4.contract_no where KeyID = ''[batchID]'' and not f1.Contract in ('''',''UNKNOWN'') and not ReinName in (select z.CEDANT_REINSURER_CODE from [stm-dwhse-01].[ORION].dbo.[GFS_Dimensions] z where z.CONTRACT_NO = f1.Contract and z.UW_YEAR = f1.UWYR and z.LEGAL_ENTITY = f1.Co)'),
