    ('SQL-G32', 282, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''600'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Flex5, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''4600000'' and Assgnmt like ''% 805'')'),
    ('SQL-G66', 103, 'insert into TransX (KeyID,Co,Crcy,GL,CC,Amt1,Amt2,Amt3,Flex1) (select KeyID,Co,Crcy,''6011000'' as GL,CC, round(sum(coalesce(Amt1,0)),2), round(sum(coalesce(Amt2,0)),2), round(sum(coalesce(Amt3,0)),2),''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,Co,Crcy,CC)'),
