    ('SQL-G32', 284, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''1560000'' as GL, Crcy, PC,''620'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1806'' as ProdCode, Flex5, -Amt1, -Amt2 , -Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''4610000'' and Assgnmt like ''% 805'')'),
    ('SQL-G32', 285, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150000'' as GL, Crcy, PC,''607'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1804'' as ProdCode, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600000'')'),
