    ('SQL-G67', 102, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1) (select KeyID + ''-data2'',Ledger,Co,GL,TP,Amt1 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G67', 201, 'Insert into TransX (KeyID,Ledger,Co,TP,Amt1,Flex1) select KeyID,Ledger,Co,TP,round(sum(Amt1),2) as Amt1, ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' and (Ledger in (''UG'',''IF'') or (Ledger = ''US'' and not Co like ''200%'' and not Co like ''23%'')) group by KeyID,Ledger,Co,TP'),
    ('SQL-G67', 202, 'Insert into TransX (KeyID,TP,Amt1,Flex1) select KeyID,TP,round(sum(Amt1),2) as Amt1, ''pass2'' as Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' and Co like ''200%'' and not TP like ''200%'' group by KeyID,TP'),
    ('SQL-G67', 203, 'Insert into TransX (KeyID,TP,Amt1,Flex1) select KeyID,TP,round(sum(Amt1),2) as Amt1, ''pass3'' as Flex1 from TransX where KeyID = ''[batchID]'' and Ledger = ''US'' and Co like ''23%'' and not TP like ''23%'' group by KeyID,TP'),
    ('SQL-G67', 211, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select x.KeyID,x.Ledger,x.Co,x.GL,x.TP,round(-x.Amt1,2) as Amt1,''pass4'' as Flex1 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Ledger = y.Ledger and x.Co = y.Co and x.TP = y.TP where x.KeyID = ''[batchID]'' and y.Amt1 >= 0 and x.GL like ''28%'' and y.Flex1 = ''pass1'' and x.Flex1 is NULL'),
    ('SQL-G67', 212, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select x.KeyID,x.Ledger,x.Co,x.GL,x.TP,round(-x.Amt1,2) as Amt1,''pass4'' as Flex1 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Ledger = y.Ledger and x.Co = y.Co and x.TP = y.TP where x.KeyID = ''[batchID]'' and y.Amt1 < 0 and x.GL like ''19%'' and y.Flex1 = ''pass1'' and x.Flex1 is NULL'),
    ('SQL-G67', 213, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select x.KeyID,x.Ledger,x.Co,x.GL,x.TP,round(-x.Amt1,2) as Amt1,''pass4'' as Flex1 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.TP = y.TP where x.KeyID = ''[batchID]'' and y.Amt1 >= 0 and x.GL like ''28%'' and y.Flex1 = ''pass2'' and x.Flex1 is NULL and x.Ledger = ''US'' and x.Co like ''200%'''),
    ('SQL-G67', 214, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select x.KeyID,x.Ledger,x.Co,x.GL,x.TP,round(-x.Amt1,2) as Amt1,''pass4'' as Flex1 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.TP = y.TP where x.KeyID = ''[batchID]'' and y.Amt1 < 0 and x.GL like ''19%'' and y.Flex1 = ''pass2'' and x.Flex1 is NULL and x.Ledger = ''US'' and x.Co like ''200%'''),
    ('SQL-G67', 215, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select x.KeyID,x.Ledger,x.Co,x.GL,x.TP,round(-x.Amt1,2) as Amt1,''pass4'' as Flex1 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.TP = y.TP where x.KeyID = ''[batchID]'' and y.Amt1 >= 0 and x.GL like ''28%'' and y.Flex1 = ''pass3'' and x.Flex1 is NULL and x.Ledger = ''US'' and x.Co like ''23%'''),
    ('SQL-G67', 216, 'insert into TransX (KeyID,Ledger,Co,GL,TP,Amt1,Flex1) select x.KeyID,x.Ledger,x.Co,x.GL,x.TP,round(-x.Amt1,2) as Amt1,''pass4'' as Flex1 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.TP = y.TP where x.KeyID = ''[batchID]'' and y.Amt1 < 0 and x.GL like ''19%'' and y.Flex1 = ''pass3'' and x.Flex1 is NULL and x.Ledger = ''US'' and x.Co like ''23%'''),
    ('SQL-G62', 101, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 or Date2  >  ''[yyyy-mm-dd]'' or Flex3 <> ''ZE'')'),
    ('SQL-G62', 102, 'insert into TransX (KeyID, Co,Flex1,Flex2,Flex3,Date1,Date2,Crcy,GL,GLdesc,Amt1,PC,CC) (Select KeyID + ''-data2'', Co,Flex1,Flex2,Flex3,Date1,Date2,Crcy,GL,GLdesc,Amt1,PC,CC from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-G62', 103, 'insert into TransX (KeyID, Co,GL,Amt1,PC,CC) (Select KeyID, Co,''2520020'' as GL,-Amt1,'''' as PC,'''' as CC from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-G62', 104, 'update TransX set PC = c.DefaultPC from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'' and PC = '''''),
    ('SQL-G62', 105, 'insert into TransX (KeyID, Co,GL,Amt1,PC,CC,Txt,Flex6) (Select KeyID, Co,GL,round(sum(Amt1),2),PC,CC,''Corp Accrual'' as Txt,'''' as Flex6 from TransX where KeyID = ''[batchID]''  group by KeyID,Co,GL,PC,CC)'),
