    ('SQL-S21', 101, 'delete from TransX where KeyID like ''[batchID]%'' and Amt1 = 0'),
    ('SQL-S21', 131, 'insert into TransX (KeyID,Co,Flex3,Date2,Date1,GL,Amt1,Assgnmt,Txt,PC,TTY) (Select ''[batchID]'' as KeyID, Co,''QU'',''[yyyy-mm-dd]'',''[yyyy-mm-dd]'',''2850500'' as GL,round(sum(Amt1),2) as Amt1,''2850996'' as Assgnmt,''Balancing 2850996'' as Txt,PC,''991'' as TTY from TransX where (KeyID = ''[batchID]'' or KeyID = ''[batchID]-data3'') and GL = ''2850996'' group by Co, PC )'),
    ('SQL-S21', 132, 'insert into TransX (KeyID,Co,Flex3,Date2,Date1,GL,Amt1,Assgnmt,Txt,PC,TTY) (Select ''[batchID]'' as KeyID, Co,''QU'',''[yyyy-mm-dd]'',''[yyyy-mm-dd]'',''2585000'' as GL,round(sum(Amt1),2) as Amt1,''2599996'' as Assgnmt,''Balancing 2599996'' as Txt,PC,''991'' as TTY from TransX where (KeyID = ''[batchID]'' or KeyID = ''[batchID]-data3'') and GL = ''2599996'' group by Co, PC )'),
    ('SQL-S21', 133, 'insert into TransX (KeyID,Co,Flex3,Date2,Date1,GL,Amt1,Assgnmt,Txt,PC,TTY) (Select ''[batchID]'' as KeyID, Co,''QU'',''[yyyy-mm-dd]'',''[yyyy-mm-dd]'',''1935000'' as GL,round(sum(Amt1),2) as Amt1,''1935996'' as Assgnmt,''Balancing 1935996'' as Txt,PC,''991'' as TTY from TransX where (KeyID = ''[batchID]'' or KeyID = ''[batchID]-data3'') and GL = ''1935996'' group by Co, PC )'),
    ('SQL-S21', 134, 'insert into TransX (KeyID,Co,Flex3,Date2,Date1,GL,Amt1,Assgnmt,Txt,PC,TTY) (Select ''[batchID]'' as KeyID, Co,''QU'',''[yyyy-mm-dd]'',''[yyyy-mm-dd]'',''2850500'' as GL,round(sum(Amt1),2) as Amt1,''2850998'' as Assgnmt,''Balancing 2850998'' as Txt,PC,''990'' as TTY from TransX where (KeyID = ''[batchID]'' or KeyID = ''[batchID]-data3'') and GL = ''2850998'' group by Co, PC )'),
    ('SQL-S21', 135, 'insert into TransX (KeyID,Co,Flex3,Date2,Date1,GL,Amt1,Assgnmt,Txt,PC,TTY) (Select ''[batchID]'' as KeyID, Co,''QU'',''[yyyy-mm-dd]'',''[yyyy-mm-dd]'',''2585000'' as GL,round(sum(Amt1),2) as Amt1,''2599998'' as Assgnmt,''Balancing 2599998'' as Txt,PC,''990'' as TTY from TransX where (KeyID = ''[batchID]'' or KeyID = ''[batchID]-data3'') and GL = ''2599998'' group by Co, PC )'),
    ('SQL-S21', 136, 'insert into TransX (KeyID,Co,Flex3,Date2,Date1,GL,Amt1,Assgnmt,Txt,PC,TTY) (Select ''[batchID]'' as KeyID, Co,''QU'',''[yyyy-mm-dd]'',''[yyyy-mm-dd]'',''1935000'' as GL,round(sum(Amt1),2) as Amt1,''1935998'' as Assgnmt,''Balancing 1935998'' as Txt,PC,''990'' as TTY from TransX where (KeyID = ''[batchID]'' or KeyID = ''[batchID]-data3'') and GL = ''1935998'' group by Co, PC )'),
    ('SQL-S21', 137, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-S21', 138, 'insert into TransX (KeyID,Co,Flex3,Date2,Date1,GL,Amt1,Assgnmt,Txt,PC,TTY) (Select ''[batchID]'' as KeyID,Co,Flex3,Date2,Date1,Assgnmt as GL,round(-Amt1,2) as Amt1,Assgnmt,Txt,PC,TTY from TransX where KeyID = ''[batchID]'' and Txt like ''Balancing %'')'),
    ('SQL-S21', 102, 'delete from TransX where KeyID = ''[batchID]'' and Txt like (cast(GL as varchar) + '' - Translation Using %'')'),
    ('SQL-S21', 103, 'delete from TransX where KeyID = ''[batchID]'' and Txt like (cast(GL as varchar) + '' - Valuation on %'')'),
    ('SQL-S21', 104, 'delete from TransX where KeyID = ''[batchID]'' and not (substring(Txt,8,21) = '' - Translation Using '' or substring(Txt,8,16) = '' - Valuation on '')'),
    ('SQL-S21', 111, 'insert into TransX (KeyID,Co,Assgnmt,Flex3,Date2,Date1,Crcy,GL,Amt1,Txt,PC,TTY) (Select KeyID + ''-data2'', Co,Assgnmt,Flex3,Date2,Date1,Crcy,GL,Amt1,Txt,PC,TTY from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-R70', 227, 'update TransX set Flex1 = ''2008'', Flex2 = ''ORH ST 1000'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''1000'' and Contract like ''67612W%'' and Flex1 = '''''),
    ('SQL-M31', 122, 'insert into SAP_ledger_data_temp (co,fiscal_year,gl,doc_no,item_no,post_key,doc_amt,lc_amt,lc2_amt,ref1,ref2,ref3,assignment,txt,profit_centre,cost_centre,bus_cat,trans_type,uwyr,broker,trade_ptr,ptf,contract,prod_code,vendor,tax_code,period,ledger,posting_date,entry_date,doc_user,doc_type,doc_hdr_text,crcy,Flex1,Flex2,Flex3,gl_crcy,gl_doc_amt) (select x1.co,x1.fiscal_year,x1.gl,x1.doc_no,x1.item_no,x1.post_key,x1.doc_amt,x1.lc_amt,x1.lc2_amt,x1.ref1,x1.ref2,x1.ref3,x1.assignment,x1.txt,x1.profit_centre,x1.cost_centre,x1.bus_cat,x1.trans_type,x2.uwyr,x2.broker,x2.trade_ptr,x2.ptf,x2.contract,x2.prod_code,x2.vendor,x2.tax_code,x3.period,x3.ledger,x3.posting_date,x3.entry_date,x3.doc_user,x3.doc_type,x3.doc_hdr_text,x3.crcy,''[batchID]'' as Flex1,x2.Flex1 as Flex2,x1.Flex2 as Flex3,x2.gl_crcy,x2.gl_doc_amt from SAP_ledger_data_temp x1 inner join SAP_ledger_data_temp x2 on x1.flex3 = x2.flex3 and x1.co = x2.co and x1.doc_no = x2.doc_no and x1.item_no = x2.item_no and not x1.gl is null and not x2.flex1 is null inner join SAP_ledger_data_temp x3 on x1.flex3 = x3.flex3 and x1.co = x3.co and x1.doc_no = x3.doc_no and not x1.gl is null and not x3.doc_type is null where x1.flex3 = ''[batchID]'')'),
    ('SQL-M31', 231, 'insert into SAP_ledger_data_temp (co,fiscal_year,gl,doc_no,item_no,post_key,doc_amt,lc_amt,lc2_amt,ref1,ref2,ref3,assignment,txt,profit_centre,cost_centre,bus_cat,trans_type,uwyr,broker,trade_ptr,ptf,contract,prod_code,vendor,tax_code,period,ledger,posting_date,entry_date,doc_user,doc_type,doc_hdr_text,crcy,Flex1,Flex2,Flex3,gl_crcy,gl_doc_amt) (select co,fiscal_year,gl,doc_no,item_no + 1000 as item_no,post_key, -doc_amt,-lc_amt,-lc2_amt, ref1,ref2,ref3,assignment,txt,profit_centre,cost_centre,bus_cat,trans_type,uwyr,broker,trade_ptr,ptf,contract,prod_code,vendor,tax_code,period,ledger,posting_date,entry_date,doc_user,doc_type,doc_hdr_text,crcy,Flex1,Flex2,Flex3,gl_crcy,gl_doc_amt from SAP_ledger_data_temp where flex1 = ''[batchID]'' and (crcy <> gl_crcy or doc_amt <> gl_doc_amt))'),
    ('SQL-G38', 301, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, BusCat, PC, Contract, Txt, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, BusCat, PC, Contract, Txt, TP, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, BusCat, PC, Contract, Txt, TP)'),
    ('SQL-G38', 302, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G38', 303, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G38', 311, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, BusCat, PC, Contract, Txt, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, BusCat, PC, Contract, Txt, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
    ('SQL-G38', 312, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, BusCat, PC, Contract, Txt, TP, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, BusCat, PC, Contract, Txt, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL)'),
    ('SQL-G38', 313, 'delete from TransX where KeyID = ''[batchID]'' and PK = ''0'''),
    ('SQL-G38', 314, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G22', 401, 'insert into TransX (KeyID, Flex1,Qtr,Date1,Crcy,Flex2,Assgnmt,GL,PK,Amt1,Amt2,Amt3,Amt4,Txt,PC,CC,TTY,RefKey3,Flex9,Flex4,RefKey2) (Select ''[batchID]'' as KeyID, Flex1,Qtr,Date1,Crcy,substring(Assgnmt,1,7) + '' '' + substring(Flex2,1,8) as Flex2,Assgnmt,GL,(case when PK = ''40'' then ''50'' else ''40'' end) as PK,round(-Amt1,2),round(-Amt2,2),round(-Amt3,2),round(-Amt2,2) as Amt4,Txt,PC,CC,TTY,RefKey3,Flex1 as Flex9,substring(Assgnmt,1,7) as Flex4,GL as RefKey2 from TransX where KeyID = ''[batchID]-data2'' and GL = ''6210000'')'),
    ('SQL-M25', 742, 'update t set Flex4 = substring(t.Flex2,4,1) + '') '' + m.Name from TransX t inner join MapKeys m on substring(t.Flex2,1,4) = m.MapKey where KeyID = ''[batchID]'''),
    ('SQL-M25', 751, 'update x set Flex1 = y.OS_GL_Desc from TransX x inner join (Select OS_GL,min(OS_GL_Desc) as OS_GL_Desc from osAccountMap3 group by OS_GL) y on x.Fsitem = y.OS_GL where KeyID = ''[batchID]'''),
    ('SQL-M25', 761, 'update TransX set Flex2 = substring(Flex2,6,2) + '') '' + Flex3 where KeyID = ''[batchID]'''),
    ('SQL-M25', 762, 'update TransX set Flex1 = Fsitem + '' '' + Flex1 where KeyID = ''[batchID]'''),
    ('SQL-M25', 763, 'update TransX set Flex3 = GL + '' '' + GLdesc where KeyID = ''[batchID]'''),
    ('SQL-M25', 792, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G32', 301, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, ProdCode, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150001'' as GL, ''2880000 803'' as Assgnmt, Crcy, ''822'' as TTY, ''U1801'' as ProdCode, TP, '''' as BusCat, PC, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''2880000'')'),
    ('SQL-G32', 323, 'Update TransX set Co = ''9231''  where KeyID in (''[batchID]'',''[batchID]-data8'') and substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
    ('SQL-G32', 411, 'update TransX set Assgnmt = '''' where KeyID in (''[batchID]'',''[batchID]-data8'') and (select count(*) from TransX where KeyID = ''[batchID]-data3'') > 0'),
    ('SQL-G32', 412, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3, PK) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, -Amt1,- Amt2 ,- Amt3, ''0'' as PK from TransX where KeyID = ''[batchID]-data3'')'),
    ('SQL-G32', 413, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, Assgnmt, ProdCode, PTF, Amt1, Amt2, Amt3) (Select ''[batchID]-data3'' as KeyID, ''9999'' as Co, ''filler'' as GL, '''' as Crcy, '''' as PC, '''' as TTY, '''' as TP, '''' as  Assgnmt, '''' as ProdCode, '''' as PTF, 0 as Amt1, 0 as  Amt2 , 0 as  Amt3)'),
    ('SQL-G32', 418, 'update TransX set KeyID = ''[batchID]'' where KeyID = ''[batchID]-data8'''),
    ('SQL-G34', 402, 'update TransX set Txt = ''IFRS-17 Exp Reclass'', SubProd = ''G28'' from TransX where KeyID = ''[batchID]'''),
    ('SQL-R70', 237, 'update TransX set Flex1 = ''2006'', Flex2 = ''CAD HIC 2300'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2300'' and Contract like ''% 2006'' and Flex1 = '''''),
    ('SQL-R70', 246, 'update TransX set Flex1 = ''2006'', Flex2 = ''CAD HSC 2400'', Flex3 = '''' from TransX where KeyID = ''[batchID]'' and TP = ''2400'' and Contract like ''% 2006'' and Flex1 = '''''),
    ('SQL-G22', 411, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'' and t.GL like ''6%'''),
    ('SQL-R83', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-G32', 421, 'Update TransX set ProdCode =  ''U1806'' where KeyID = ''[batchID]'' and Co like ''9%'' and GL = ''1560000'''),
    ('SQL-G32', 431, 'update TransX set TTY = '''' from TransX where KeyID = ''[batchID]'' and GL in (''2853500'',''3870003'') and not ''[yyyy-mm-dd]'' = ''2022-01-31'''),
    ('SQL-W27', 202, 'update IR17_Trigger set Flag = ''Y'', insdt = CURRENT_TIMESTAMP where Pipelinename = ''P_PL_IFRS_SAP_AzureSQL_Pull'' and GroupID = (select Field1 from Misc_Tables where Table_ID = ''IR17'' and ID = ''Trigger'' and ''[BudAct]'' like Descr)'),
    ('SQL-M13', 436, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data7'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Canada where source = ''R68'' and YearPeriod = ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Canada x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod = ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and not GL_Grp in (''WP'',''COMM'',''WPx'',''COMMx'',''DAC'',''IBNR'',''UPR'') and substring(''[BudAct]'',1,7) = ''LG_CAD '')'),
    ('SQL-M13', 475, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6) (select ''[batchID]-data6'',Co,GL,Crcy,PC,CC,ACD,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(-Doc_QTD),2) as Doc_QTD,round(sum(-Doc_ITD),2) as Doc_ITD,round(sum(-LC_QTD),2) as LC_QTD,round(sum(-LC_ITD),2) as LC_ITD,round(sum(-LC2_QTD),2) as LC2_QTD,round(sum(-LC2_ITD),2) as LC2_ITD from IR17_Other_HudCAD where  source = ''R67'' GROUP BY Co,GL,Crcy,PC,CC,ACD,Source union all select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from IR17_Control_HudCAD where source = ''R63'' and (GL like ''6%'' or GL = ''4498000'') GROUP BY Co,GL,Crcy,PC,CC,ACD,Source) a GROUP BY Co,GL,Crcy,PC,CC,ACD) b where (abs(Doc_QTD) > 1 or abs(Doc_ITD) > 1 or abs(LC_QTD) > 1 or abs(LC_ITD) > 1 or abs(LC2_QTD) > 1 or abs(LC2_ITD) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-M13', 477, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6) (select ''[batchID]-data8'',Co,GL,Crcy,PC,CC,ACD,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(-Doc_QTD),2) as Doc_QTD,round(sum(-Doc_ITD),2) as Doc_ITD,round(sum(-LC_QTD),2) as LC_QTD,round(sum(-LC_ITD),2) as LC_ITD,round(sum(-LC2_QTD),2) as LC2_QTD,round(sum(-LC2_ITD),2) as LC2_ITD from IR17_Other_HudCAD where source = ''R69'' GROUP BY Co,GL,Crcy,PC,CC,ACD,Source union all select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from IR17_Control_HudCAD where source = ''R63'' and GL in (''nothing'') GROUP BY Co,GL,Crcy,PC,CC,ACD,Source) a GROUP BY Co,GL,Crcy,PC,CC,ACD) b where (abs(Doc_QTD) > 1 or abs(Doc_ITD) > 1 or abs(LC_QTD) > 1 or abs(LC_ITD) > 1 or abs(LC2_QTD) > 1 or abs(LC2_ITD) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-G13', 203, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G13', 204, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 '),
    ('SQL-G13', 221, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-G13', 222, 'update TransX set Txt = ''DAC HUD [yyyy-mm-dd]'', Flex1 = '''' from TransX where KeyID = ''[batchID]'''),
    ('SQL-G32', 236, 'Update TransX set PC = ''5500000000'' where KeyID in (''[batchID]'',''[batchID]-data8'') and Flex5 = ''Investment'''),
    ('SQL-R28', 217, 'update TransX set Amt2 = (case when GL < 4000000 or substring(GL,1,2) = ''42'' then round(0-Amt1,2) else Amt1 end) from TransX where KeyID = ''[batchID]'' and not (Co >= ''2001'' and Co <= ''2008'' and TP >= ''2001'' and TP <= ''2450'' and not TP = ''2210'')'),
    ('SQL-G92', 223, 'delete from TransX where KeyID = ''[batchID]'' and PK = ''1'''),
    ('SQL-R49', 527, 'update TransX set Flex5 = 44 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and substring(contract,1,7) = ''HCN CAF'''),
    ('SQL-R14', 204, 'delete from TransX where KeyID = ''[batchID]'' and Ledger = ''LG'' and not Co = ''2210'''),
    ('SQL-R49', 422, 'update TransX set Flex5 = 6 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and PC = ''6059000000'' and not len(TP) = 4  and not (substring(Contract,1,7) = ''FIRV ST'' or substring(Contract,1,3) =  ''FV-'') and tp <> ''2310'''),
    ('SQL-R49', 483, 'update TransX set Flex5 = 8 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2008'' and TP in (''2300'',''2400'',''2450'') and not substring(PC,1,1) = ''6'' '),
    ('SQL-G23', 444, 'update TransX set BusCat = ''20'' where KeyID = ''[batchID]''  and BusCat = '''' and GL like ''18%'''),
    ('SQL-W12', 505, 'Insert into IR17_LIC_Canada (Co,Contract,UWYR,Crcy,Co_Crcy,PC,TP,PC_Desc,Program,YearPeriod,GL_Grp,Doc_Amt,LC_Amt,LC2_Amt,Source,Incl_Excl,ACD,Flex1,Flex2,Flex3,Portfolio_PC) Select Co,Contract,UWYR,Crcy,Flex1,PC,TP,PCdesc,Flex3,YearPeriod,Flex2,Amt1,Amt2,Amt3,''R64'',Flex4,BusCat,Flex6,Flex7,Flex8,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W12', 507, 'Insert into IR17_LIC_Singapore (Co,Contract,UWYR,Crcy,Co_Crcy,PC,TP,PC_Desc,Program,YearPeriod,GL_Grp,Doc_Amt,LC_Amt,LC2_Amt,Source,Incl_Excl,ACD,Flex1,Flex2,Flex3,Portfolio_PC) Select Co,Contract,UWYR,Crcy,Flex1,PC,TP,PCdesc,Flex3,YearPeriod,Flex2,Amt1,Amt2,Amt3,''R64'',Flex4,BusCat,Flex6,Flex7,Flex8,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-SING'''),
    ('SQL-W12', 509, 'Insert into IR17_LIC_HudCAD (Co,Contract,UWYR,Crcy,Co_Crcy,PC,TP,PC_Desc,Program,YearPeriod,GL_Grp,Doc_Amt,LC_Amt,LC2_Amt,Source,Incl_Excl,ACD,Flex1,Flex2,Flex3,Portfolio_PC) Select Co,Contract,UWYR,Crcy,Flex1,PC,TP,PCdesc,Flex3,YearPeriod,Flex2,Amt1,Amt2,Amt3,''R64'',Flex4,BusCat,Flex6,Flex7,Flex8,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
    ('SQL-W14', 542, 'Insert into IR17_CF_HudCAD (Co,YearPeriod,GL,DocNbr,RowNbr,Crcy,Co_Crcy,Doc_Amt,LC_Amt,LC2_Amt,TP,TTY,UWYR,Contract,TransCode,TransID,AppliedToID,PaidByID,Group1,Group2,Group2_Desc,Group3,Group3_Desc,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC) Select Co,Yr*100+Period,GL,CC,CatCode,Crcy,Flex1,Amt1,Amt2,Amt3,TP,TTY,UWYR,Contract,TransCode,Assgnmt,Flex6,Flex7,Flex8,Flex2,Flex4,Flex3,Flex5,PC,PCdesc,Division,''R66'',Stat,BusCat,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
    ('SQL-W15', 502, 'Insert into IR17_Other (Co,Crcy,Co_Crcy,YearPeriod,GL,GL_Desc,PC,PC_Desc,Program,CC,CC_Desc,CCCat,CCCat_Desc,TP,Source,Incl_Excl,ACD,Portfolio_PC,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select Co,Crcy,Flex1,YearPeriod,GL,GLDesc,PC,PCdesc,Flex3,CC,CCdesc,CCCat,Flex5,TP,''R67'',Flex4,''A'',Flex9,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-ODY '''),
    ('SQL-M41', 422, 'insert into TransX (KeyID,Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt2,Amt4) (select KeyID,''pass2'' as Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and SUBSTRING(GL,1,1) = ''4'' and Flex1 is NULL)'),
    ('SQL-M41', 423, 'insert into TransX (KeyID,Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt5,Amt7) (select KeyID,''pass2'' as Flex1,UWYr,Crcy,Flex2,Division,Flex5,Flex8,Amt1,Amt2 from TransX where KeyID = ''[batchID]'' and Yr <> [Yr] and GL < ''4010000'' and Flex1 is NULL)'),
    ('SQL-R48', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-R48', 111, 'insert into TransX (KeyID, Co, GL, PC, BusCat, RiskTerr,ReinLoc,Amt1) (select ''[batchID]-data2'', Co, GL, PC, BusCat, RiskTerr,ReinLoc,Amt1  from TransX  where KeyID = ''[batchID]'' and Amt1 <>0)'),
    ('SQL-G71', 238, 'Update TransX set TP = ''F0046'' where KeyID = ''[batchID]'' and GL = ''1998900'' and Contract = ''5USA000096'''),
    ('SQL-R49', 113, 'delete from TransX where KeyID = ''[batchID]'' and substring(GL,1,5) in (''19999'',''28999'',''28980'',''28989'',''19989'')'),
    ('SQL-M28', 302, 'delete from TransX where KeyID = ''[batchID]'' and Flex2 is NULL'),
    ('SQL-G32', 252, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL = m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID in (''[batchID]'',''[batchID]-data8'') and not GL in (''4419900'') and Assgnmt is NULL'),
    ('SQL-M28', 431, 'update TransX set Flex5 = ''01 IFRS-4''  where KeyID = ''[batchID]'' and Co < ''5990'' and Flex5 = '''''),
    ('SQL-S43', 540, 'update TransX set PC = ''1402000317'', Contract = ''35188'', TP = ''3030'', Co = ''2008'', BusCat = ''21'', CC = '''', TTY = '''' from TransX where KeyID = ''[batchID]'''),
    ('SQL-R48', 142, 'update TransX set Flex6 = ''Reinsurance(ceded)'', BusCatDesc = ''Ceded'', Amt1 = -Amt1, Flex9 = ''Proportional'' where KeyID = ''[batchID]'' and BusCat >= ''30'''),
    ('SQL-R48', 202, 'Update TransX set Flex5 = r.Descr, Flex4 = r.Region from TransX t inner join ReinLocs r on t.ReinLoc = r.ReinLoc where KeyID = ''[batchID]'' and coalesce(Flex5,'''') = '''''),
    ('SQL-M28', 203, 'update TransX set  BusCat = ''30'' where KeyID = ''[batchID]'' and BusCat like ''3%'''),
    ('SQL-M28', 231, 'update TransX set SubProd = ''TX'' where KeyID = ''[batchID]'' and SubProd = '''' and Co like ''9%'''),
