    ('SQL-M28', 301, 'insert into TransX (KeyID, Co, GL, TTY, TP, BusCat, SubProd, Amt1, Flex2, Flex5) (Select KeyID, Co, GL, TTY, TP, BusCat,SubProd, round(sum(Amt1),2) as Amt1, ''missing'' as Flex2, Flex5 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, TTY, TP, BusCat, SubProd, Flex5)'),
    ('SQL-G28', 112, 'delete from TransX where KeyID = ''[batchID]''  and Zone = ''3'''),
    ('SQL-G32', 302, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, ProdCode, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150001'' as GL, ''2880000 803'' as Assgnmt, Crcy, ''824'' as TTY, ''U1801'' as ProdCode, TP, '''' as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''2880000'')'),
    ('SQL-G28', 102, 'delete from TransX where KeyID = ''[batchID]'' and Zone = ''3'' and PTF in (''U3455'',''U3460'')'),
    ('SQL-G28', 103, 'update TransX set Amt1 = coalesce(Amt1,0), Amt2 = coalesce(Amt2,0), Amt3 = coalesce(Amt3,0) where KeyID = ''[batchID]'''),
    ('SQL-G28', 104, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 and Amt2 = 0 and Amt3 = 0)'),
    ('SQL-G43', 252, 'update TransX set Flex1 = cast(ABS(Amt1) as varchar(255)), Flex2 = cast(ABS(Amt2) as varchar(255)), Flex3 = cast(ABS(Amt3) as varchar(255)) from TransX where KeyID = ''[batchID]'''),
    ('SQL-G43', 253, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-G43', 302, 'update TransX set TP = '''' where KeyID = ''[batchID]'' and GL = ''3610000'''),
    ('SQL-G28', 165, 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Flex3,Flex4,Flex1,Flex2,Location) (select ''[batchID]-data4'' as KeyID, Co,Crcy,GL,PC,CC,Amt1 * (100-Rate2) * Rate3,Amt2 * (100-Rate2) * Rate3,Amt3 * (100-Rate2) * Rate3,CCcat, ''N'' as Deferrable_Flag, ''N'' as Attributable_Flag, Flex1, Flex2,Location from TransX where KeyID = ''[batchID]-data3'' and Rate1 < Rate2)'),
    ('SQL-M13', 434, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data5'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Canada where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Canada where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_CAD '')'),
    ('SQL-G28', 151, 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Rate1,Rate2,Rate3,Flex1,Flex2,Location) (select ''[batchID]-data3'' as KeyID, t.Co,t.Crcy,t.GL,t.PC,t.CC,t.Amt1,t.Amt2,t.Amt3,c.Cat_Override as CCcat, c.Deferrable * 100 as Rate1, c.Attributable * 100 as Rate2, c.Amt1 as Rate3, c.Co as Flex1, c.Portfolio_Nbr, c.Portfolio_PC as Flex2 from TransX t inner join IR17_CC c on t.CC = c.CC and t.GL = c.GL and c.Typ = ''CC_PC_GL'' where KeyID = ''[batchID]'' and Zone in (''1'',''2''))'),
    ('SQL-G28', 251, 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,Amt1,Amt2,Amt3) (select ''[batchID]'' as KeyID, Flex1 as Co,Crcy,Flex5 as GL,Location as PC,Flex6 as PTF,round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]-data4'' group by Flex1,Crcy,Flex5,Location,Flex6)'),
    ('SQL-G28', 311, 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,Amt1,Amt2,Amt3,Txt) (select KeyID, Co,Crcy,GL,PC,PTF,round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, ''Exp reclass [yyyy-mm-dd]'' as Txt from TransX where KeyID = ''[batchID]'' group by KeyID, Co,Crcy,GL,PC,PTF)'),
    ('SQL-G28', 315, 'delete from TransX where KeyID = ''[batchID]'' and Txt is NULL'),
    ('SQL-G28', 319, 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,Amt1,Amt2,Amt3,Txt) (select KeyID, Co,Crcy,''2851017'' as GL,''7URCAANTP0'' as PC,'''' as PTF,round(-sum(Amt1),2) as Amt1, round(sum(-Amt2),2) as Amt2, round(sum(-Amt3),2) as Amt3, ''Exp reclass [yyyy-mm-dd]'' as Txt from TransX where KeyID = ''[batchID]'' group by KeyID, Co,Crcy)'),
    ('SQL-G28', 371, 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt, Amt1, Amt2, Amt3,PK) (Select KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL group by KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt)'),
    ('SQL-G28', 262, 'update TransX set Amt7 = (select round(sum(Amt3),2) from TransX where KeyID = ''[batchID]-data6'' and  Zone = ''5'') where KeyID = ''[batchID]-data5'' and GL = ''5600000'''),
    ('SQL-G32', 222, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''5600052'' as GL, ''2880000 803'' as Assgnmt, Crcy, '''' as TTY, TP, '''' as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''2880000'')'),
    ('SQL-R48', 105, 'delete from TransX where KeyID = ''[batchID]'' and substring(''[GL]'',1,3) = ''non'' and TP like ''F%'''),
    ('SQL-G32', 243, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and not GL in (''2853500'',''2851017'')'),
    ('SQL-G32', 253, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL like m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID in (''[batchID]'',''[batchID]-data8'')and not GL in (''4419900'') and Assgnmt is NULL'),
    ('SQL-G21', 101, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-G21', 121, 'insert into TransX (KeyID,Co, GL, Amt1,CC,Contract) (Select KeyID + ''-data2'', Co, GL, Amt1,CC,Contract from TransX where KeyID = ''[batchID]'' )'),
    ('SQL-R48', 143, 'update TransX set Flex9 = ''Non-proportional'' where KeyID = ''[batchID]'' and BusCat in (''22'',''23'',''32'',''33'')'),
    ('SQL-G28', 131, 'insert into TransX (KeyID, Zone, Co, GL, Crcy, PC, CC, PTF, SubProd, Amt1, Amt2, Amt3) (Select ''[batchID]-data2'' as KeyID, Zone, Co, GL, Crcy, PC, CC, PTF, SubProd, Amt1, Amt2, Amt3 from TransX where KeyID = ''[batchID]'')'),
    ('SQL-M25', 532, 'update TransX set Flex5 = ''05 Other''  where KeyID = ''[batchID]'' and Flex5 = ''02 RI'' and GL in (''2310003'',''4398014'')'),
    ('SQL-R48', 210, 'Update TransX set Flex4 = ''United States'', Flex5 = ''United States'' where KeyID = ''[batchID]'' and (PC like ''%ORB%'' OR PC in (''2202EU0725'',''2202EU0STM''))'),
    ('SQL-R19', 103, 'insert into TransX (KeyID, Co, GL, PC, TP, TTY, Amt1, Amt2, Amt3, Amt4, Flex6) (select KeyID, Co, GL, PC, TP, TTY, ROUND(SUM(COALESCE(Amt1,0)),2) as Amt1, ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt3,0)),2) as Amt3, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, ''pass1'' as Flex6  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, PC,TP, TTY)'),
    ('SQL-G28', 116, 'delete from TransX where KeyID = ''[batchID]''  and Zone in (''4'',''5'')'),
    ('SQL-G28', 121, 'insert into TransX (KeyID, Zone, Co, GL, Crcy, PC, CC, PTF, SubProd, Amt1, Amt2, Amt3,Flex1) (Select KeyID, Zone, Co, GL, Crcy, PC, CC, PTF, SubProd, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, '''' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Zone, Co, GL, Crcy, PC, CC, PTF, SubProd)'),
    ('SQL-G28', 122, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-R48', 263, 'Update x set Flex7 = m.field2 from TransX x inner join Misc_Tables m on m.Field1 = x.Flex7 and m.Table_ID = ''IR17'' and m.ID = ''PC'' and m.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-M41', 416, 'delete from TransX where KeyID = ''[batchID]-data3'' and Flex1 is NULL'),
    ('SQL-G26', 201, 'update TransX set  BusCat = ''20'' where KeyID = ''[batchID]'' and (BusCat like ''2%'' or BusCat = ''10'')'),
    ('SQL-W15', 506, 'Insert into IR17_Other_Singapore (Co,Crcy,Co_Crcy,YearPeriod,GL,GL_Desc,PC,PC_Desc,Program,CC,CC_Desc,CCCat,CCCat_Desc,TP,Source,Incl_Excl,ACD,Portfolio_PC,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select Co,Crcy,Flex1,YearPeriod,GL,GLDesc,PC,PCdesc,Flex3,CC,CCdesc,CCCat,Flex5,TP,''R67'',Flex4,''A'',Flex9,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-SING'''),
    ('SQL-W15', 507, 'Delete from IR17_Other_HudCAD where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R67'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-M18', 542, 'update TransX set Flex3 = ''FX P&L'' where KeyID = ''[batchID]'' and substring(GL,1,4) in (''4397'',''4398'') and coalesce(Flex3,'''') = '''''),
