    ('SQL-G46', 256, 'update TransX set SubProd = ''TX'' where KeyID = ''[batchID]'' and substring(''[version]'',6,2) = ''17'''),
    ('SQL-S05', 501, 'update TransX set Amt1 = round(0-Amt1,2), Flex1 = ''pass1'' from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-R49', 472, 'update TransX set Flex5 = 28 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2008'' and TP = ''3030'' and Contract in (''2376'',''9403'',''OACN9353'',''OACN16600'')'),
    ('SQL-R49', 517, 'update TransX set Flex5 = 43 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2008'' and TP = ''3030'' and Contract in (''35188'')'),
    ('SQL-R49', 473, 'update TransX set Flex5 = 28 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''3030'' and TP = ''2008'' and PC = ''3991061405'' and not BusCat = ''20'''),
    ('SQL-R49', 474, 'update TransX set Flex5 = 28 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and Contract like ''SYND ST%'''),
    ('SQL-R49', 519, 'update TransX set Flex5 = 43 from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co = ''2999'' and Contract like ''SYN ST%'''),
    ('SQL-G25', 211, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'') then '''' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' and substring(x.TTY,1,1) = ''9'' then '''' else x.TTY end) and m.Field6 = ''1'' and not x.TTY = ''815'' where KeyID = ''[batchID]'')'),
    ('SQL-G92', 304, 'insert into TransX (KeyID, GL, Crcy,Amt1,Amt2,Amt3,Amt4,Co,PC,TP) (Select KeyID, ''2899901'' as GL, ''SGD'' as Crcy, round(sum(-Amt1),2) as Amt1, round(sum(-Amt3),2) as Amt2, round(sum(-Amt3),2) as Amt3, round(sum(-Amt1),2) as Amt4, ''2008'' as Co,''1400000000'' as PC, ''2005'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)'),
    ('SQL-W21', 401, 'update gfsdb[version].CorpAcct_Apps.dbo.IR17_Trigger set Flag = ''Y'', insdt = CURRENT_TIMESTAMP  where Pipelinename = ''P_PL_IFRS_SAP_AzureSQL_Pull'' and GroupID = (select Field1 from Misc_Tables where Table_ID = ''IR17'' and ID = ''Trigger'' and ''[BudAct]'' like Descr)'),
    ('SQL-W21', 201, '[ReplaceConnString][LockDownConnString]'),
    ('SQL-W21', 411, '[ReplaceConnString][OriginalConnString]'),
    ('SQL-G92', 303, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,''SGD'' as Crcy,''2008'' as Co,''5USA000080'' as CC,''2SFA310005'' as Contract,Amt1 as Amt1, Amt3 as Amt2, Amt3 as Amt3, Amt1 as Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL)'),
    ('SQL-G30', 232, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TP, ProdCode, Amt1, Amt2, Amt3,Flex2) (Select KeyID, Co, GL, Crcy, PC, TP, ProdCode, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3,'''' as Flex2 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, PC, TP, ProdCode)'),
