    ('SQL-R49', 382, 'update TransX set Flex5 = ''200'', Flex6 = ''interim/fh balances - needs further review'' where KeyID = ''[batchID]'' and Flex5 is NULL and substring(GL,1,5) in (''28510'',''35925'')'),
