    ('SQL-W14', 201, 'Update x set x.Flex8 = y.Field1, x.Flex2 = y.Field2, x.Flex3 = y.Field3 from TransX x inner join Misc_Tables y on replace(replace(substring(GL,1,3),''231'',''131''),''148'',''221'') = y.ID and TransCode = y.Descr and y.Table_ID = ''W13 GL''  where KeyID = ''[batchID]'' and not coalesce(TransCode,'''') = '''''),
