    ('SQL-G91', 104, 'Update TransX set Txt = ''Ki Exec Reimb @[Yr]/[Mo] from '' + Contract + '' '' + GL, Amt1 = round(-Amt1,2) where KeyID = ''[batchID]'' and CC = ''5USA000092'''),
    ('SQL-G91', 201, 'Update TransX set Txt = ''Ki Exec Reimb @[Yr]/[Mo] from '' + CC + '' '' + GL, Contract = CC, CC = ''5USA000092'', ProdCode = ''CHGBACK'', Amt1 = round(-Amt1,2) where KeyID = ''[batchID]'' and not CC = ''5USA000092'''),
    ('SQL-G91', 202, 'Update x set x.GL = y.Field1 from TransX x inner join Misc_Tables y on x.GL = y.Descr where KeyID = ''[batchID]'' and Table_ID = ''Reimburse'' and ID = ''GL'''),
    ('SQL-G91', 211, 'insert into TransX (KeyID,GL,CC,Txt,Contract,ProdCode,Amt1,Flex1) (select KeyID,GL,CC,Txt,Contract,ProdCode,round(sum(Amt1),2) as Amt1,''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID,GL,CC,Txt,Contract,ProdCode)'),
    ('SQL-G91', 212, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 or FLex1 is NULL)'),
    ('SQL-G91', 224, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-G91', 301, 'Update x set x.GLdesc = y.Descr from TransX x inner join COA y on x.GL = y.GL where KeyID like ''[batchID]%'''),
    ('SQL-G91', 302, 'Update TransX set PK = (case when Amt1 > 0 then ''40'' else ''50'' end) where KeyID = ''[batchID]'''),
    ('SQL-W14', 232, 'Update x set x.Flex5 = y.Descr from TransX x inner join Misc_Tables y on Flex3 = y.ID and y.Table_ID = ''W13 Grp3''  where KeyID = ''[batchID]'' and not Flex3 = '''''),
    ('SQL-M13', 456, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data7'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Singapore where source = ''R68'' and YearPeriod = ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Singapore x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod = ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and not GL_Grp in (''WP'',''COMM'',''WPx'',''COMMx'',''DAC'',''IBNR'',''UPR'') and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-M13', 458, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,Amt1,Amt2,Amt3) (select ''[batchID]-data9'',Co,GL,Crcy,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,Source union all select Co,GL,'''' as Crcy,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R65'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'''' as Crcy,Source,0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' and not GL like ''222%'' GROUP BY Co,GL,Crcy,Source) a GROUP BY Co,GL,Crcy) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-M13', 459, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data10'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,'''' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R66'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'''' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source union all select Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,PC,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-G29', 463, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''2851017'' as GL, Crcy, ''990'' as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, '''' as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and GL like ''6%'' and not GL like ''682%'' and not GL = ''6915002'' and not substring(CC,4,1) in (''I'',''E''))'),
    ('SQL-M13', 460, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data11'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Singapore where source = ''R64'' and YearPeriod > ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Singapore x left join IR17_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join IR17_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD ) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) AND NOT GL_Grp IN (''DAC'',''UPR'') and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-M13', 461, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt1) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_ITD),2) from IR17_Control_Singapore where YearPeriod = ''[Yr][Mo]'' and substring(''[BudAct]'',1,7) = ''LS-SING'' group by Co,GL,ACD)'),
    ('SQL-M13', 462, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_QTD),2) from IR17_Control_Singapore where YearPeriod <= ''[Yr][Mo]'' and GL < ''4000000'' and substring(''[BudAct]'',1,7) = ''LS-SING'' group by Co,GL,ACD)'),
    ('SQL-M13', 463, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC2_QTD),2) from IR17_Control_Singapore where YearPeriod <= ''[Yr][Mo]'' and YearPeriod >= ''[Yr]01'' and GL >= ''4000000'' and substring(''[BudAct]'',1,7) = ''LS-SING'' group by Co,GL,ACD)'),
    ('SQL-G32', 244, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and m.Field1 = '''' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL and not GL in (''2853500'',''2851017'')'),
    ('SQL-G32', 261, 'Update TransX set TTY = ''900'' where KeyID = ''[batchID]'' and GL = ''1099917'''),
    ('SQL-M13', 471, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,PC,BusCat,Amt3) (select ''[batchID]-data2'',Co,GL,PC,ACD,LC_Amt from (select Co,GL,PC,ACD, round(sum(LC_Amt),2) as LC_Amt from (select Co,GL,PC,ACD,Source,round(sum(-LC_Amt),2) as LC_Amt from IR17_CF_HudCAD where source = ''M12'' and YearPeriod = ''201012'' GROUP BY Co,GL,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,PC,ACD,Source,round(sum(LC_QTD),2) as LC_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod = ''201012'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'' or GL like ''148%'' or GL like ''23%'') and not GL like ''2822%'' GROUP BY Co,GL,PC,ACD,Source) a GROUP BY Co,GL,PC,ACD) b where abs(LC_Amt) > 1 and substring(''[BudAct]'',1,7) = ''LG-HUDC'')'),
    ('SQL-M13', 472, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data3'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_HudCAD where  source = ''R64'' and YearPeriod > ''202112'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_HudCAD x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''202112'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-M13', 473, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt3) (select ''[batchID]-data4'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt, round(sum(LC_Amt),2) as LC_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt, round(sum(-LC_Amt),2) as LC_Amt from IR17_CF_HudCAD where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt, round(sum(LC_QTD),2) as LC_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG-CAD '')'),
    ('SQL-M13', 474, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data5'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-M13', 476, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data7'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_HudCAD where source = ''R68'' and YearPeriod = ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_HudCAD x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod = ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and not GL_Grp in (''WP'',''COMM'',''WPx'',''COMMx'',''DAC'',''IBNR'',''UPR'') and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-G32', 287, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, BusCat, Assgnmt, ProdCode, Flex5, Amt1, Amt2, Amt3) (Select KeyID, Co, ''2150001'' as GL, Crcy, PC,''803'' as TTY, TP, BusCat, coalesce(Assgnmt,''''), ''U1801'' as ProdCode, Flex5, Amt1, Amt2 , Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''5600052'' and Assgnmt like ''% 805'')'),
    ('SQL-G32', 313, 'update TransX set  TTY = ''607'' where KeyID = ''[batchID]''  and not ''[yyyy-mm-dd]'' = ''2022-01-31'' and TTY = '''' and GL in (''2150000'')'),
    ('SQL-G32', 433, 'update TransX set ProdCode = ''U1892'', PTF = ''U3650'' from TransX where KeyID = ''[batchID]'' and GL = ''4600000'' and coalesce(ProdCode,'''') = '''''),
    ('SQL-M13', 478, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,Amt1,Amt2,Amt3) (select ''[batchID]-data9'',Co,GL,Crcy,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,Source union all select Co,GL,'''' as Crcy,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R65'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'''' as Crcy,Source,0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' and not GL like ''222%'' GROUP BY Co,GL,Crcy,Source) a GROUP BY Co,GL,Crcy) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-M13', 479, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data10'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,'''' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R66'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,'''' as Crcy,ACD,Source, 0 as Doc_Amt, 0 as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201012'' and YearPeriod <= ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source union all select Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_HudCAD where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,(CASE WHEN (Co = ''2002'' AND GL = ''2310001'' AND PC = ''2202FR0347'') THEN ''2310000'' ELSE GL END) as GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_HudCAD where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,PC,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-M25', 717, 'update t set FSitem = OS_GL, Flex1 = OS_GL_Desc from TransX t inner join osAccountMap3 c on t.GL >= c.GL_From and t.GL <= c.GL_Thru and t.Co >= c.Co_From and t.Co <= c.Co_Thru and c.TTY = ''990'' and substring(t.GL,4,3) = ''999'' and c.BC_From = '''' and (t.TP = c.TP_From or (t.TP = ''ODY'' and c.TP_From = ''O'') or (t.TP = ''FFH'' and c.TP_From = ''F'')) where KeyID = ''[batchID]'' and FSitem is NULL'),
    ('SQL-W11', 507, 'Delete from IR17_Control_HudCAD where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R63'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-G32', 197, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, GL, Assgnmt, Crcy, ''806'' as TTY, TP, BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and Zone = ''4'' and GL like ''231%'' and TTY = ''809'')'),
    ('SQL-G32', 224, 'delete from TransX where KeyID = ''[batchID]'''),
    ('SQL-G28', 106, 'insert into TransX (KeyID, Co, GL, Crcy, PC, PTF, SubProd, Amt1, Amt2, Amt3) (Select ''[batchID]-data7'' as KeyID, Co, GL, Crcy, PC, PTF, SubProd, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and Zone = ''6''  and not PTF = ''U3460'' and not SubProd = ''TPA'' group by Co, GL, Crcy, PC, PTF, SubProd)'),
    ('SQL-G28', 152, 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Rate1,Rate2,Rate3,Flex1,Flex2,Location) (select ''[batchID]-data3'' as KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,substring(CC,4,1) as CCcat, 0 as Rate1, 100 as Rate2, 1 as Rate3, ''5990'' as Flex1, ''1'' as Location, ''7URCAANTP0'' as Flex2 from TransX where KeyID = ''[batchID]'' and Zone in (''1'',''2'') and substring(CC,4,1) in (''I'',''E''))'),
    ('SQL-G28', 161, 'insert into TransX (KeyID, Co,Crcy,GL,PC,CC,Amt1,Amt2,Amt3,CCcat,Flex3,Flex4,Flex1,Flex2,Location) (select ''[batchID]-data4'' as KeyID, Co,Crcy,GL,PC,CC,Amt1 * Rate1 * Rate3,Amt2 * Rate1 * Rate3,Amt3 * Rate1 * Rate3,CCcat, ''Y'' as Deferrable_Flag, ''Y'' as Attributable_Flag, Flex1, Flex2,Location from TransX where KeyID = ''[batchID]-data3'' and Rate1 <= Rate2)'),
    ('SQL-G28', 201, 'Update TransX set Flex5 = ''5600000'' from TransX where KeyID = ''[batchID]-data4'' and Flex3 = ''Y'' and Flex4 = ''Y'' and CCcat in (''U'',''S'',''A'',''I'',''E'')'),
    ('SQL-G28', 202, 'Update TransX set Flex5 = ''5600062'' from TransX where KeyID = ''[batchID]-data4'' and Flex4 = ''Y'' and CCcat in (''C'',''H'')'),
    ('SQL-R49', 116, 'delete from TransX where KeyID = ''[batchID]'' and GL > ''8000000'' and Co = ''2999'''),
    ('SQL-R49', 117, 'delete from TransX where KeyID = ''[batchID]'' and (substring(GL,1,5) in (''11448'',''11449'',''11456'',''11457'',''11478'',''11455'') or GL = ''1145403'') and Ledger = ''US'''),
    ('SQL-R49', 121, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R49', 122, 'update TransX set PCdesc = p.Descr, Hierarchy = p.Hierarchy from TransX t inner join PCTRS p on t.PC = p.PCTR where KeyID = ''[batchID]'''),
    ('SQL-R49', 123, 'update TransX set TPname = p.Name from TransX t inner join TPs p on t.TP = p.TP where KeyID = ''[batchID]'''),
    ('SQL-R49', 131, 'update TransX set Flex3 = ''(2) Elim'' from TransX where KeyID = ''[batchID]'' and Co in (''1999'',''2999'',''3999'')'),
    ('SQL-R49', 132, 'update TransX set Flex3 = ''(1) Co2Co'' from TransX where KeyID = ''[batchID]'' and Flex3 is NULL'),
    ('SQL-R49', 133, 'update TransX set Flex2 = ''Co'' + Co + '' Tp'' + TP from TransX where KeyID = ''[batchID]'''),
    ('SQL-R49', 134, 'update TransX set Flex1 = Descr, Flex4 = Field1 from TransX t inner join Misc_Tables m on t.GL = m.ID where KeyID = ''[batchID]'' and Table_ID = ''GL Grp 4'''),
    ('SQL-R49', 135, 'update TransX set Flex1 = Descr, Flex4 = Field1 from TransX t inner join Misc_Tables m on substring(t.GL,1,2) = m.ID where KeyID = ''[batchID]'' and Table_ID = ''GL Grp 4'''),
    ('SQL-G28', 203, 'Update TransX set Flex5 = ''5620000'' from TransX where KeyID = ''[batchID]-data4'' and Flex4 = ''N'''),
    ('SQL-G28', 204, 'Update TransX set Flex5 = ''5600001'' from TransX where KeyID = ''[batchID]-data4'' and Flex3 = ''N'' and Flex4 = ''Y'' and CCcat in (''U'',''S'',''A'',''I'',''E'')'),
    ('SQL-G28', 211, 'Update t set Flex6 = m.UD3 from TransX t inner join osAccountMap3 m on t.GL >= m.GL_From and t.GL <= m.GL_Thru and m.Co_Thru = ''9999'' and m.TTY = '''' and m.TP_From = '''' and m.BC_From = '''' where KeyID = ''[batchID]-data4'''),
    ('SQL-G28', 212, 'Update TransX set Flex6 = ''U3451'' from TransX where KeyID = ''[batchID]-data4'' and GL = ''6420000'''),
    ('SQL-R49', 108, 'insert into TransX (KeyID, YearPeriod, Ledger, Co, GL, TP, BusCat, Contract, PC, TTY, Amt2,Amt4,Amt5,Flex6) (select KeyID, YearPeriod, Ledger, Co, GL, TP, BusCat, Contract, PC, TTY, round(sum(Amt2),2) as Amt2, round(sum(Amt4),2) as Amt4, round(sum(Amt5),2) as Amt5,'''' as Flex6 from TransX where KeyID = ''[batchID]'' group by KeyID, YearPeriod, Ledger, Co, GL, TP, BusCat, Contract, PC, TTY)'),
    ('SQL-W11', 508, 'Insert into IR17_Control_HudCAD (YearPeriod,Co,GL,Crcy,Co_Crcy,PC,PC_Desc,CC,CC_Desc,TP,ACD,Source,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select YearPeriod,Co,GL,Crcy,Flex1,PC,PCdesc,CC,CCdesc,TP,BusCat,''R63'',Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
    ('SQL-G12', 244, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, Amt1, PK) (Select KeyID, YearPeriod, Yr, Period, Co, GL, Crcy, '''' as TP, PC, CC, BusCat, Contract, UWYR, TTY, TransCode, ProdCode, AccYr, ReinName, ReinLoc, Stat, CatCode, Broker, RiskTerr, PTF, round(-Amt1,2) as Amt1,''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''50'' and substring(GL,4,2) <> ''89'' and TP <> '''')'),
    ('SQL-R49', 647, 'update TransX set Flex5 = ''134'', Flex6 = ''Co 2999 1320000'' where KeyID = ''[batchID]'' and Co = ''2999'' and GL = ''1320000'' and Flex5 is NULL'),
    ('SQL-R49', 648, 'update TransX set Flex5 = ''135'', Flex6 = ''Co 2999 Equity & Building'' where KeyID = ''[batchID]'' and Co = ''2999'' and (GL like ''3%'' or GL like ''119%'') and Flex5 is NULL'),
    ('SQL-G28', 264, 'update TransX set Amt7 = Amt7 - (select round(sum(Amt3),2) from TransX where KeyID = ''[batchID]'' and GL = ''5600000'') where KeyID = ''[batchID]-data5'' and GL = ''5600000'''),
    ('SQL-G28', 373, 'insert into TransX (KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co,Crcy,GL,PC,PTF,ProdCode,TTY,Txt, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'')'),
    ('SQL-M41', 425, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-G92', 201, 'delete from TransX where KeyID = ''[batchID]'' and (Amt1 = 0 or Amt2 = 0 or Amt3 = 0 or Amt4 = 0)'),
    ('SQL-G92', 212, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL'),
    ('SQL-G92', 301, 'insert into TransX (KeyID,GL,Crcy,Co,CC,Contract,Amt1,Amt2,Amt3,Amt4) (select KeyID,GL,Crcy,''2005'' as Co,''2SFA310006'' as CC,''2SFA310005'' as Contract,-Amt1,-Amt2,-Amt3,-Amt4 from TransX where KeyID = ''[batchID]'' and Co is NULL)'),
    ('SQL-G92', 302, 'insert into TransX (KeyID, GL, Crcy,Amt1, Amt2, Amt3, Amt4,Co,PC,TP) (Select KeyID, ''1999901'' as GL, Crcy, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2,  round(sum(Amt3),2) as Amt3,round(sum(Amt4),2) as Amt4, ''2005'' as Co,''2310000000'' as PC, ''2008'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)'),
    ('SQL-G92', 307, 'delete from TransX where KeyID = ''[batchID]'' and Co is NULL'),
    ('SQL-G92', 308, 'delete from TransX where KeyID = ''[batchID]'' and Co = ''2008'' and Amt1 = 0'),
    ('SQL-G92', 309, 'delete from TransX where KeyID = ''[batchID]'' and Co = ''2005'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G92', 401, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP, Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, (case when Amt4 > 0 then Amt4 else 0 end) as Amt4, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and Co = ''2005'')'),
    ('SQL-G92', 403, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL and Co = ''2005'''),
    ('SQL-G92', 404, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0'),
    ('SQL-G92', 411, 'update TransX set PK = ''40'' where KeyID = ''[batchID]'' and Co =''2008'' and Amt1 > 0'),
    ('SQL-G92', 412, 'update TransX set PK = ''50'' where KeyID = ''[batchID]'' and Co =''2008'' and Amt1 < 0'),
    ('SQL-G92', 451, 'update TransX set GL = ''6115012'' where KeyID = ''[batchID]'' and Co = ''2008'' and GL in (''6115005'',''6115010'',''6115011'')'),
    ('SQL-G92', 452, 'update TransX set GL = ''6115013'' where KeyID = ''[batchID]'' and Co = ''2008'' and GL in (''6110000'',''6110004'')'),
    ('SQL-G92', 453, 'update TransX set GL = ''6116000'' where KeyID = ''[batchID]'' and Co = ''2008'' and GL in (''6115002'',''6115003'')'),
    ('SQL-G92', 454, 'update TransX set GL = ''6314000'' where KeyID = ''[batchID]'' and Co = ''2008'' and GL in (''6314005'')'),
    ('SQL-R34', 103, 'insert into TransX (KeyID, Co, GL, PC, TP, Amt1, Amt2, Amt3, Amt4, Flex6) (select KeyID, Co, GL, PC, TP, ROUND(SUM(COALESCE(Amt1,0)),2) as Amt1, ROUND(SUM(COALESCE(Amt2,0)),2) as Amt2, ROUND(SUM(COALESCE(Amt3,0)),2) as Amt3, ROUND(SUM(COALESCE(Amt4,0)),2) as Amt4, ''pass1'' as Flex6  from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, PC,TP)'),
    ('SQL-R34', 104, 'delete from TransX where KeyID = ''[batchID]'' and Flex6 is NULL'),
    ('SQL-R34', 110, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-R34', 111, 'update TransX set TPname = c.Name from TransX t inner join TPs c on t.TP = c.TP where KeyID = ''[batchID]'''),
    ('SQL-R34', 112, 'update TransX set Hierarchy = p.Division from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''Rpt'' inner join ElimSelect e on e.FromVal = p.Division and e.ElimID = ''Co:'' + m.Field1 where KeyID = ''[batchID]'' and t.Hierarchy is NULL'),
    ('SQL-R34', 113, 'update TransX set Hierarchy = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''Rpt'' inner join ElimSelect e on e.FromVal = p.Region and e.ElimID = ''Co:'' + m.Field1 where KeyID = ''[batchID]'' and t.Hierarchy is NULL'),
    ('SQL-R34', 114, 'update TransX set Hierarchy = p.Location from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''Rpt'' inner join ElimSelect e on e.FromVal = p.Location and e.ElimID = ''Co:'' + m.Field1 where KeyID = ''[batchID]'' and t.Hierarchy is NULL'),
    ('SQL-R34', 115, 'update TransX set Hierarchy = p.Zone from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''Rpt'' inner join ElimSelect e on e.FromVal = p.Zone and e.ElimID = ''Co:'' + m.Field1 where KeyID = ''[batchID]'' and t.Hierarchy is NULL'),
    ('SQL-R34', 116, 'update TransX set Hierarchy = p.Hierarchy from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''Rpt'' inner join ElimSelect e on e.FromVal = p.Hierarchy and e.ElimID = ''Co:'' + m.Field1 where KeyID = ''[batchID]'' and t.Hierarchy is NULL'),
    ('SQL-R34', 121, 'update TransX set Hierarchy = p.Division from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Division like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 122, 'update TransX set Hierarchy = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Region like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 123, 'update TransX set Hierarchy = p.Location from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Location like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 124, 'update TransX set Hierarchy = p.Zone from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Zone like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 125, 'update TransX set Hierarchy = p.Hierarchy from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and p.Hierarchy like m.Field2 and m.Field2 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 131, 'update TransX set Hierarchy = p.Division from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Division like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 132, 'update TransX set Hierarchy = p.Region from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Region like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 133, 'update TransX set Hierarchy = p.Location from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Location like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 134, 'update TransX set Hierarchy = p.Zone from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Zone like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 135, 'update TransX set Hierarchy = p.Hierarchy from TransX t inner join PCTRS p on t.PC = p.PCTR inner join Misc_Tables m on m.Descr = ''All Divisions'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and t.Co = m.Field2 and p.Hierarchy like m.Field3 and m.Field3 <> '''' where KeyID = ''[batchID]'''),
    ('SQL-R34', 141, 'update TransX set Flex1 = m.Field1 from TransX t inner join Misc_Tables m on m.Field2 = t.Co and (t.Hierarchy like m.Field3 or m.Field3 = '''') where KeyID = ''[batchID]'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect1'' and m.Descr = ''All Divisions'''),
    ('SQL-R34', 142, 'update TransX set Flex1 = m.Field1 from TransX t inner join Misc_Tables m on m.Field2 = t.Hierarchy or m.Field2 = '''' where KeyID = ''[batchID]'' and m.Table_ID = ''Flux'' and m.ID = ''TabSelect2'' and m.Descr = ''All Divisions'' and Flex1 is NULL'),
    ('SQL-R34', 143, 'update TransX set Flex1 = Co where KeyID = ''[batchID]'' and ''All Divisions'' like ''% by Co'''),
    ('SQL-R34', 145, 'update TransX set Flex2 = m.Descr from TransX t inner join Misc_Tables m on t.GL >= m.Field1 and t.GL <= m.Field2 where KeyID = ''[batchID]'' and m.Table_ID = ''Flux'' and m.ID = ''GLgrp'''),
