    ('SQL-W13', 456, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and (Co in (''2003'',''2004'',''2006'',''4110'') or Co like ''22%'') and not Co + '' '' + Contract + '' '' + UWYR in (Select Co + '' '' + Contract + '' '' + UWYR from IR17_Contracts where (Co in (''2003'',''2004'',''2006'',''4110'') or Co like ''22%'')) ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
