    ('SQL-W13', 218, 'Update TransX set Flex2 = ''01-PW'' where KeyID = ''[batchID]'' and Flex2 = '''' and substring(GL,1,2) in (''13'',''23'')'),
    ('SQL-W13', 219, 'Update TransX set Flex2 = ''02-CLM'' where KeyID = ''[batchID]'' and Flex2 = '''' and substring(GL,1,2) in (''14'',''22'',''28'')'),
    ('SQL-W13', 232, 'Update x set x.Flex5 = y.Descr from TransX x inner join Misc_Tables y on Flex3 = y.ID and y.Table_ID = ''W13 Grp3''  where KeyID = ''[batchID]'' and not Flex3 = '''''),
    ('SQL-W13', 233, 'Update TransX set TP = (case when substring(FSitem,1,2) = ''00'' then substring(FSitem,3,4) else Fsitem end) where KeyID = ''[batchID]'''),
    ('SQL-W13', 234, 'Update TransX set Amt1 = -Amt1, Amt2 = -Amt2, Amt3 = -Amt3 where KeyID = ''[batchID]'' and PK = ''H'''),
    ('SQL-W13', 301, 'Update x set Flex7 = y.Assgnmt from TransX x inner join TransX y on x.Co = y.Co and x.Assgnmt = y.Flex6 and x.Contract = y.Contract and x.UWYR = y.UWYR where x.KeyID = ''[batchID]'''),
    ('SQL-W13', 302, 'Update x set Flex6 = ''self flip'', Flex7 = ''self flip'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''' and x.TTY = ''806'' and y.Flex6 = '''' and y.Flex7 = '''' and y.TTY = ''806'' and ((x.GL like ''131%'' and y.GL like ''221%'') or (x.GL like ''221%'' and y.GL like ''131%'')) and x.Assgnmt like ''%$%'''),
    ('SQL-W13', 303, 'Update x set Flex6 = ''self 806'', Flex7 = ''self 806'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 and substring(x.GL,1,3) = substring(y.GL,1,3) and x.Flex6 = y.Flex6 and x.Flex7 = y.Flex7 and x.TTY = y.TTY where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''' and x.TTY = ''806'' and abs(cast(x.CatCode as int)-cast(y.CatCode as int))<3'),
    ('SQL-W13', 304, 'Update x set Flex6 = ''self'', Flex7 = ''self'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 and substring(x.GL,1,3) = substring(y.GL,1,3) and x.Flex6 = y.Flex6 and x.Flex7 = y.Flex7 where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''' and abs(cast(x.CatCode as int)-cast(y.CatCode as int))<3'),
    ('SQL-W13', 311, 'Update TransX set Stat = (case when substring(GL,6,2) in (''94'',''95'',''96'',''97'',''98'') then ''E'' else ''I'' end) from TransX where KeyID = ''[batchID]'''),
    ('SQL-W13', 312, 'Update TransX set Stat = ''E'' from TransX where KeyID = ''[batchID]'' and TTY in (''990'',''991'')'),
    ('SQL-W13', 313, 'Update TransX set Stat = ''X'' where KeyID = ''[batchID]'' and len(TP) = 4'),
    ('SQL-W13', 314, 'Update TransX set Stat = ''X'' where KeyID = ''[batchID]'' and Co in (''2999'',''3999'')'),
    ('SQL-W13', 321, 'Update x set Amt4 = y.DocBal, Amt5 = y.LCBal, Amt6 = y.LC2Bal from TransX x inner join (select Co,substring(GL,1,3) as GL,CC,TTY,UWYR,Contract,TransCode,sum(Amt1) as DocBal,sum(Amt2) as LCBal,sum(Amt3) as LC2Bal from TransX where KeyID = ''[batchID]'' and Flex6 = '''' and Flex7 = '''' and Stat = ''I'' group by Co,substring(GL,1,3),CC,TTY,UWYR,Contract,TransCode) y on x.Co = y.Co and substring(x.GL,1,3) = y.GL and x.CC = y.CC and x.TTY = y.TTY and x.UWYR = y.UWYR and x.Contract = y.Contract and x.TransCode = y.TransCode where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''' and x.Stat = ''I'''),
    ('SQL-W13', 322, 'Update TransX set Flex6 = ''self TP'', Flex7 = ''self TP'' where KeyID = ''[batchID]'' and Flex6 = '''' and Flex7 = '''' and Stat = ''I'' and coalesce(Amt4,0) = 0 and coalesce(Amt5,0) = 0 and coalesce(Amt6,0) = 0'),
    ('SQL-W13', 331, 'update TransX set Flex1 = c.Crcy from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'''),
    ('SQL-W13', 341, 'Update x set x.PCdesc = y.Descr, x.Division = y.Program from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]'''),
    ('SQL-W13', 342, 'Update TransX set BusCat = (case when BusCat = ''10'' then ''D'' else ''A'' end) where KeyID = ''[batchID]'''),
    ('SQL-W13', 351, 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join pctrs p on x.PC = p.pctr inner join Misc_Tables m2 on m2.Field1 = p.Product and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-W13', 353, 'Update x set Flex9 = c.Portfolio_PC from TransX x inner join IR17_Contracts c on x.Contract = c.Contract and x.UWYR = c.UWYR and x.Co = c.Co where KeyID = ''[batchID]'' and not substring(x.Flex9,2,2) in (''UI'',''NL'',''EL'') and not x.Co = ''2999'''),
    ('SQL-W13', 403, 'Update TransX set Flex4 = ''Premiums'' where KeyID = ''[batchID]'' and GL = ''1310001'' and Flex4 = ''Cash'' and UWYR < ''2015'''),
    ('SQL-W13', 404, 'Update TransX set TP = ''2308'', Stat = ''X'' where KeyID = ''[batchID]'' and Contract = ''DAH'' and TP = '''''),
    ('SQL-W13', 405, 'Update TransX set Division = '''' where KeyID = ''[batchID]'' and Division is NULL'),
    ('SQL-W13', 421, 'Update x set Rate1 = c.Rate From TransX x inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-W13', 422, 'Update x set Amt1 = Amt3, Amt2 = round(Amt3/Rate1,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]'''),
    ('SQL-W13', 431, 'Update TransX set Flex9 = NULL where KeyID = ''[batchID]'' and PC = ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W13', 441, 'update TransX set PC = ''UNKNOWN'', Flex9 = ''7UISCANTP0'' where  GL = ''2820000'' and Co = ''2300'' and BusCat = ''A'' and PC = '''''),
    ('SQL-W13', 451, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2001'' and not ''2001 '' + Contract + '' '' + UWYR in (Select ''2001 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2001'') ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W13', 452, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2002'' and not ''2002 '' + Contract + '' '' + UWYR in (Select ''2002 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2002'') ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W13', 501, 'Delete from IR17_CF where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' and not coalesce(Flex2,'''') like ''%adj%'''),
