    ('SQL-W13', 521, 'Delete from IR17_LIC where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and GL_GRP = ''RIP'' and substring(''[BudAct]'',1,7) = ''IF-ODY '''),
    ('SQL-W13', 522, 'insert into IR17_LIC (Co,YearPeriod,Crcy,Co_Crcy,Doc_Amt,LC_Amt,LC2_Amt,TP,UWYR,Contract,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC,GL_Grp,Flex1,Flex2,Flex3) (select Co,YearPeriod,Crcy,Co_Crcy,round(-Doc_Amt,2) as Doc_Amt,round(-LC_Amt,2) as LC_Amt,round(-LC2_Amt,2) as LC2_Amt,TP,UWYR,Contract,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC, ''RIP'' as GL_Grp,Flex1,Flex2,Flex3 from IR17_CF where GL = ''1310001'' and Group2_Desc = ''Claims'' and YearPeriod in (Select distinct Yr*100 + Period from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
