    ('SQL-W13', 532, 'Insert into IR17_CF_Canada (Co,YearPeriod,GL,DocNbr,RowNbr,Crcy,Co_Crcy,Doc_Amt,LC_Amt,LC2_Amt,TP,TTY,UWYR,Contract,TransCode,TransID,AppliedToID,PaidByID,Group1,Group2,Group2_Desc,Group3,Group3_Desc,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC) Select Co,Yr*100+Period,GL,CC,CatCode,Crcy,Flex1,Amt1,Amt2,Amt3,TP,TTY,UWYR,Contract,TransCode,Assgnmt,Flex6,Flex7,Flex8,Flex2,Flex4,Flex3,Flex5,PC,PCdesc,Division,''R65'',Stat,BusCat,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W13', 541, 'Delete from IR17_LIC_Canada where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and GL_GRP = ''RIP'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W13', 542, 'insert into IR17_LIC_Canada (Co,YearPeriod,Crcy,Co_Crcy,Doc_Amt,LC_Amt,LC2_Amt,TP,UWYR,Contract,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC,GL_Grp,Flex1,Flex2,Flex3) (select Co,YearPeriod,Crcy,Co_Crcy,round(-Doc_Amt,2) as Doc_Amt,round(-LC_Amt,2) as LC_Amt,round(-LC2_Amt,2) as LC2_Amt,TP,UWYR,Contract,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC, ''RIP'' as GL_Grp,Flex1,Flex2,Flex3 from IR17_CF_Canada where GL = ''1310001'' and Group2_Desc = ''Claims'' and YearPeriod in (Select distinct Yr*100 + Period from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and substring(''[BudAct]'',1,7) = ''LG-CAD '')'),
