    ('SQL-W13', 571, 'Delete from IR17_CF_HudCAD where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R65'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' and not coalesce(Flex2,'''') like ''%adj%'''),
