    ('SQL-W14', 103, 'Update x set Crcy = y.Field1 From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Swap'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]'''),
    ('SQL-W14', 115, 'Update x set x.GL = y.GL from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Yr = y.Yr and x.Co = y.Co and x.CC = y.CC and y.GL = substring(''[BudAct]'',1,7) where x.KeyID = ''[batchID]'''),
    ('SQL-W14', 116, 'delete from TransX where KeyID = ''[batchID]''  and GL  = substring(''[BudAct]'',1,7)'),
    ('SQL-W14', 121, 'Update x set x.Crcy = y.Crcy, x.Period = y.Period from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Yr = y.Yr and x.Co = y.Co and x.CC = y.CC and x.Crcy = ''X'' and y.GL = ''X'' and x.Period is null and not y.Period is NULL and y.Ledger in (''IF'',''Z003'',''Z004'',''Z007'',''Z014'',''Z015'',''Z018'',''Z023'')  where x.KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-ODY '''),
    ('SQL-W14', 122, 'Update x set x.Crcy = y.Crcy, x.Period = y.Period from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Yr = y.Yr and x.Co = y.Co and x.CC = y.CC and x.Crcy = ''X'' and y.GL = ''X'' and x.Period is null and not y.Period is NULL and y.Ledger in (''LG'',''Z006'',''Z007'',''Z009'',''Z014'',''Z015'',''Z016'')  where x.KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W14', 123, 'Update x set x.Crcy = y.Crcy, x.Period = y.Period from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Yr = y.Yr and x.Co = y.Co and x.CC = y.CC and x.Crcy = ''X'' and y.GL = ''X'' and x.Period is null and not y.Period is NULL and y.Ledger in (''LS'',''Z006'',''Z008'',''Z015'',''Z016'')  where x.KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-SING'''),
    ('SQL-W14', 127, 'delete from TransX where KeyID = ''[batchID]''  and GL  = ''X'''),
    ('SQL-W14', 128, 'delete from TransX where KeyID = ''[batchID]''  and Crcy  = ''X'''),
    ('SQL-W14', 129, 'delete from TransX where KeyID = ''[batchID]''  and (GL like ''2822%'' or GL like ''222%'')'),
    ('SQL-W14', 131, 'Update x set x.Flex6 = y.Flex6 from TransX x inner join TransX y on x.KeyID = y.KeyID and x.Yr = y.Yr and x.CC = y.CC and x.CatCode = y.CatCode and not x.Period is null and y.Period is NULL  where x.KeyID = ''[batchID]'''),
    ('SQL-W14', 132, 'delete from TransX where KeyID = ''[batchID]''  and Period is NULL'),
    ('SQL-W14', 140, 'delete from TransX where KeyID = ''[batchID]''  and (Co > ''5000'' or Co in (''2101'',''2102'',''2103'',''2500'',''4025'',''4030''))'),
    ('SQL-W14', 141, 'Update TransX set Period = ''12'' where KeyID = ''[batchID]''  and Period = ''16'''),
    ('SQL-W14', 150, 'Update x set x.Amt1 = x.Amt1 * 100 from TransX x inner join Crcy y on x.Crcy = y.Crcy where x.KeyID = ''[batchID]'' and y.DecimalPlaces = 0'),
    ('SQL-W14', 151, 'Update TransX set Amt1 = Amt1 / 10 where KeyID = ''[batchID]'' and Crcy in (''BHD'',''JOD'',''KWD'',''TND'',''OMR'',''LYD'',''IQD'')'),
    ('SQL-W14', 161, 'Update TransX set Contract = Assgnmt  where KeyID = ''[batchID]'' and Yr < ''2022'' and Co like ''3%'''),
    ('SQL-W14', 171, 'Update TransX set contract = ''UNKNOWN'', UWYR = ''2010'' where KeyID = ''[batchID]'' and co like ''3%'' and UWYR < ''2011'' and UWYR <> '''''),
    ('SQL-W14', 172, 'Update TransX set contract = ''UNKNOWN'' where KeyID = ''[batchID]'' and co like ''3%'' and len(contract) = 8 and contract like ''20%'''),
    ('SQL-W14', 173, 'Update TransX set contract = ''UNKNOWN'' where KeyID = ''[batchID]'' and co like ''3%'' and contract in ('''',''US GAAP UW RESULT'')'),
    ('SQL-W14', 174, 'Update TransX set UWYR = ''1959'' where KeyID = ''[batchID]'' and co like ''3%'' and UWYR = '''''),
    ('SQL-W14', 175, 'Update TransX set UWYR = ''1958'' where KeyID = ''[batchID]'' and co like ''3%'' and UWYR = ''9999'''),
    ('SQL-W14', 181, 'Update t set Co = ''3030'', Amt2 = round(Amt2*r1.Rate/r2.Rate,2) from TransX t inner join Companies c on c.Co = t.Co inner join CrcyRates r1 on r1.Crcy = c.Crcy and r1.Typ = ''S'' and r1.EffDate = (select max(EffDate) from (select EffDate from CrcyRates where Typ = ''S'' and Crcy = ''GBP'' and EffDate <= ''[yyyy-mm-dd]'') a) inner join CrcyRates r2 on r2.Crcy = ''GBP'' and r2.Typ = ''S'' and r2.EffDate = r1.EffDate where t.KeyID = ''[batchID]'' and t.Co in (''3060'',''3100'')'),
    ('SQL-W14', 199, 'Update TransX set Flex8 = '''', Flex2 = '''', Flex3 = '''', Flex4 = '''', Flex5 = '''', Flex6 = coalesce(Flex6,''''), Flex7 = '''', Flex9 = '''', BusCat = ''C'' where KeyID = ''[batchID]'''),
    ('SQL-W14', 210, 'Update TransX set Flex2 = ''00-OPENBAL'' where KeyID = ''[batchID]'' and TTY = ''100'''),
