    ('SQL-W14', 213, 'Update TransX set Flex2 = ''09-FX'' where KeyID = ''[batchID]'' and (TTY like ''9%'' or substring(GL,6,2) in (''96'',''98''))'),
    ('SQL-W14', 214, 'Update TransX set Flex2 = ''01-PW'' where KeyID = ''[batchID]'' and Flex2 = '''' and TTY = ''801'''),
    ('SQL-W14', 215, 'Update TransX set Flex2 = ''04-ACQ'' where KeyID = ''[batchID]'' and Flex2 = '''' and TTY = ''802'''),
