    ('SQL-W14', 217, 'Update TransX set Flex2 = ''05-CASH'' where KeyID = ''[batchID]'' and Flex2 = '''' and TTY in (''804'',''807'',''808'',''809'')'),
    ('SQL-W14', 218, 'Update TransX set Flex2 = ''01-PW'' where KeyID = ''[batchID]'' and Flex2 = '''' and substring(GL,1,2) in (''13'',''23'')'),
    ('SQL-W14', 219, 'Update TransX set Flex2 = ''02-CLM'' where KeyID = ''[batchID]'' and Flex2 = '''' and substring(GL,1,2) in (''14'',''22'',''28'')'),
    ('SQL-W14', 220, 'Update TransX set Flex2 = ''05-CASH'' where KeyID = ''[batchID]'' and TTY in (''805'',''808'') and TransCode in (''T0008'',''T0014'',''T0048'')'),
    ('SQL-W14', 221, 'Update TransX set Flex2 = ''05-CASH'' where KeyID = ''[batchID]'' and TTY in (''805'',''811'',''812'') and TransCode = '''''),
    ('SQL-W14', 233, 'Update TransX set TP = (case when substring(FSitem,1,2) = ''00'' then substring(FSitem,3,4) else Fsitem end) where KeyID = ''[batchID]'''),
    ('SQL-W14', 234, 'Update TransX set Amt1 = -Amt1, Amt2 = -Amt2, Amt3 = -Amt3 where KeyID = ''[batchID]'' and PK = ''H'''),
    ('SQL-W14', 301, 'Update x set Flex7 = y.Assgnmt from TransX x inner join TransX y on x.Co = y.Co and x.Assgnmt = y.Flex6 and x.Contract = y.Contract and x.UWYR = y.UWYR where x.KeyID = ''[batchID]'''),
    ('SQL-W14', 302, 'Update x set Flex6 = ''self flip'', Flex7 = ''self flip'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''' and x.TTY = ''806'' and y.Flex6 = '''' and y.Flex7 = '''' and y.TTY = ''806'' and ((x.GL like ''231%'' and y.GL like ''148%'') or (x.GL like ''148%'' and y.GL like ''231%'')) and x.Assgnmt like ''%$%'''),
    ('SQL-W14', 303, 'Update x set Flex6 = ''self 806'', Flex7 = ''self 806'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 and substring(x.GL,1,3) = substring(y.GL,1,3) and x.Flex6 = y.Flex6 and x.Flex7 = y.Flex7 and x.TTY = y.TTY where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''' and x.TTY = ''806'' and abs(cast(x.CatCode as int)-cast(y.CatCode as int))<3'),
    ('SQL-W14', 304, 'Update x set Flex6 = ''self'', Flex7 = ''self'' from TransX x inner join TransX y on x.Co = y.Co and x.CC = y.CC and x.Assgnmt = y.Assgnmt and round(x.Amt3 + y.Amt3,2) = 0 and substring(x.GL,1,3) = substring(y.GL,1,3) and x.Flex6 = y.Flex6 and x.Flex7 = y.Flex7 where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''' and abs(cast(x.CatCode as int)-cast(y.CatCode as int))<3'),
    ('SQL-W14', 311, 'Update x set Amt4 = y.DocBal, Amt5 = y.LCBal, Amt6 = y.LC2Bal from TransX x inner join (select Co,substring(GL,1,3) as GL,CC,TTY,UWYR,Contract,TransCode,sum(Amt1) as DocBal,sum(Amt2) as LCBal,sum(Amt3) as LC2Bal from TransX where KeyID = ''[batchID]'' and Flex6 = '''' and Flex7 = '''' group by Co,substring(GL,1,3),CC,TTY,UWYR,Contract,TransCode) y on x.Co = y.Co and substring(x.GL,1,3) = y.GL and x.CC = y.CC and x.TTY = y.TTY and x.UWYR = y.UWYR and x.Contract = y.Contract and x.TransCode = y.TransCode where x.KeyID = ''[batchID]'' and x.Flex6 = '''' and x.Flex7 = '''''),
    ('SQL-W14', 312, 'Update TransX set Flex6 = ''self TP'', Flex7 = ''self TP'' where KeyID = ''[batchID]'' and Flex6 = '''' and Flex7 = '''' and coalesce(Amt4,0) = 0 and coalesce(Amt5,0) = 0 and coalesce(Amt6,0) = 0'),
    ('SQL-W14', 331, 'update TransX set Flex1 = c.Crcy from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'''),
    ('SQL-W14', 341, 'Update x set x.PCdesc = y.Descr, x.Division = y.Program from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]'''),
    ('SQL-W14', 351, 'Update TransX set Stat = (case when substring(GL,6,2) in (''94'',''95'',''96'',''97'',''98'') then ''E'' else ''I'' end) from TransX where KeyID = ''[batchID]'''),
    ('SQL-W14', 352, 'Update TransX set Stat = ''E'' from TransX where KeyID = ''[batchID]'' and TTY in (''990'',''991'')'),
    ('SQL-W14', 353, 'Update TransX set Stat = ''X'' where KeyID = ''[batchID]'' and len(TP) = 4'),
    ('SQL-W14', 354, 'Update TransX set Stat = ''X'' where KeyID = ''[batchID]'' and Co in (''2999'',''3999'')'),
    ('SQL-W14', 361, 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join pctrs p on x.PC = p.pctr inner join Misc_Tables m2 on m2.Field1 = p.Product and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-W14', 362, 'Update x set Flex9 = c.Portfolio_PC from TransX x inner join IR17_Contracts c on x.Contract = c.Contract and x.UWYR = c.UWYR and x.Co = c.Co where KeyID = ''[batchID]'' and not substring(x.Flex9,2,2) in (''UI'',''NL'',''EL'') and not x.Co = ''2999'''),
    ('SQL-W14', 403, 'Update TransX set Flex4 = ''AnO_Cash'', Flex2 = ''07-AnOCash'' where KeyID = ''[batchID]'' and Division = ''131'' and GL like ''231%'' and CC like ''79%'' and Flex4 = ''Cash'''),
    ('SQL-W14', 405, 'Update TransX set Division = '''' where KeyID = ''[batchID]'' and Division is NULL'),
    ('SQL-W14', 421, 'Update x set Rate1 = c.Rate From TransX x inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-W14', 422, 'Update x set Amt1 = Amt3, Amt2 = round(Amt3/Rate1,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]'''),
    ('SQL-W14', 431, 'Update TransX set Flex9 = NULL where KeyID = ''[batchID]'' and PC = ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W14', 451, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2001'' and not ''2001 '' + Contract + '' '' + UWYR in (Select ''2001 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2001'') ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W14', 452, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2002'' and not ''2002 '' + Contract + '' '' + UWYR in (Select ''2002 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2002'') ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W14', 453, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2005'' and not ''2005 '' + Contract + '' '' + UWYR in (Select ''2005 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2005'') ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W14', 454, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2007'' and not ''2007 '' + Contract + '' '' + UWYR in (Select ''2007 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2007'') ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W14', 455, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and Co = ''2008'' and not ''2008 '' + Contract + '' '' + UWYR in (Select ''2008 '' + Contract + '' '' + UWYR from IR17_Contracts where co = ''2008'') ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W14', 456, 'Insert into IR17_Contracts (Co,Contract,UWYR,YearPeriod,Portfolio_PC,Flex1) Select distinct Co,Contract,UWYR,min(YearPeriod),min(Flex9),min(PC) from (Select Co,Contract,UWYR,YearPeriod,Flex9,PC from (Select Co,Contract,UWYR,(Yr * 100 + Period) as YearPeriod,Flex9,PC from TransX where KeyID = ''[batchID]'' and (Co in (''2003'',''2004'',''2006'',''4110'') or Co like ''22%'') and not Co + '' '' + Contract + '' '' + UWYR in (Select Co + '' '' + Contract + '' '' + UWYR from IR17_Contracts where (Co in (''2003'',''2004'',''2006'',''4110'') or Co like ''22%'')) ) x where UWYR <> '''' and Contract <> '''' and Contract <> ''UNKNOWN'' and substring(''[BudAct]'',1,7) = ''IF-ODY '') y group by Co,Contract,UWYR'),
    ('SQL-W14', 500, '[ReplaceConnString][LockDownConnString]'),
    ('SQL-W14', 501, 'Delete from IR17_CF where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R66'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' and not coalesce(Flex2,'''') like ''%adj%'''),
    ('SQL-W14', 502, 'Insert into IR17_CF (Co,YearPeriod,GL,DocNbr,RowNbr,Crcy,Co_Crcy,Doc_Amt,LC_Amt,LC2_Amt,TP,TTY,UWYR,Contract,TransCode,TransID,AppliedToID,PaidByID,Group1,Group2,Group2_Desc,Group3,Group3_Desc,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC) Select Co,Yr*100+Period,GL,CC,CatCode,Crcy,Flex1,Amt1,Amt2,Amt3,TP,TTY,UWYR,Contract,TransCode,Assgnmt,Flex6,Flex7,Flex8,Flex2,Flex4,Flex3,Flex5,PC,PCdesc,Division,''R66'',Stat,BusCat,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-ODY '''),
    ('SQL-W14', 521, 'Delete from IR17_CF_Canada where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R66'' and substring(''[BudAct]'',1,7) = ''LG-CAD '' and not coalesce(Flex2,'''') like ''%adj%'''),
    ('SQL-W14', 522, 'Insert into IR17_CF_Canada (Co,YearPeriod,GL,DocNbr,RowNbr,Crcy,Co_Crcy,Doc_Amt,LC_Amt,LC2_Amt,TP,TTY,UWYR,Contract,TransCode,TransID,AppliedToID,PaidByID,Group1,Group2,Group2_Desc,Group3,Group3_Desc,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC) Select Co,Yr*100+Period,GL,CC,CatCode,Crcy,Flex1,Amt1,Amt2,Amt3,TP,TTY,UWYR,Contract,TransCode,Assgnmt,Flex6,Flex7,Flex8,Flex2,Flex4,Flex3,Flex5,PC,PCdesc,Division,''R66'',Stat,BusCat,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W14', 531, 'Delete from IR17_CF_Singapore where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R66'' and substring(''[BudAct]'',1,7) = ''IF-SING'' and not coalesce(Flex2,'''') like ''%adj%'''),
    ('SQL-W14', 532, 'Insert into IR17_CF_Singapore (Co,YearPeriod,GL,DocNbr,RowNbr,Crcy,Co_Crcy,Doc_Amt,LC_Amt,LC2_Amt,TP,TTY,UWYR,Contract,TransCode,TransID,AppliedToID,PaidByID,Group1,Group2,Group2_Desc,Group3,Group3_Desc,PC,PC_Desc,Program,Source,Incl_Excl,ACD,Portfolio_PC) Select Co,Yr*100+Period,GL,CC,CatCode,Crcy,Flex1,Amt1,Amt2,Amt3,TP,TTY,UWYR,Contract,TransCode,Assgnmt,Flex6,Flex7,Flex8,Flex2,Flex4,Flex3,Flex5,PC,PCdesc,Division,''R66'',Stat,BusCat,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-SING'''),
    ('SQL-W14', 541, 'Delete from IR17_CF_HudCAD where cast(Co as varchar(4)) +  cast(YearPeriod as varchar(6)) in (Select distinct cast(Co as varchar(4)) + cast(Yr*100+Period as varchar(6)) from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R66'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' and not coalesce(Flex2,'''') like ''%adj%'''),
    ('SQL-W14', 561, '[ReplaceConnString][OriginalConnString]'),
    ('SQL-W15', 101, 'delete from TransX where KeyID = ''[batchID]'' and Co in (''1010'',''1099'',''2101'',''2102'',''2103'',''2500'',''4025'',''4030'',''5990'',''5992'',''5993'',''5996'')'),
    ('SQL-W15', 103, 'Update x set Crcy = y.Field1 From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Swap'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]'''),
    ('SQL-W15', 104, 'insert into TransX (KeyID, YearPeriod, Crcy,Co, GL, BusCat, CC, PC, Amt1,Amt2,Amt3,Amt4,Amt5,Amt6,Flex1) (select KeyID, YearPeriod, Crcy,Co, GL, BusCat, CC, PC, round(sum(coalesce(Amt1,0)),2),round(sum(coalesce(Amt2,0)),2),round(sum(coalesce(Amt3,0)),2),round(sum(coalesce(Amt4,0)),2),round(sum(coalesce(Amt5,0)),2),round(sum(coalesce(Amt6,0)),2),''pass1'' from TransX where KeyID = ''[batchID]''  group by KeyID, YearPeriod, Crcy,Co, GL, BusCat, CC, PC)'),
    ('SQL-W15', 105, 'delete from TransX where KeyID = ''[batchID]'' and Flex1 is NULL'),
    ('SQL-W15', 108, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0 and Amt4 = 0 and Amt5 = 0 and Amt6 = 0'),
    ('SQL-W15', 111, 'update TransX set Amt2 = round(Amt2 + Amt1,2),Amt4 = round(Amt4 + Amt3,2),Amt6 = round(Amt6 + Amt5,2), CCcat = substring(CC,4,1), Flex1 = '''', Flex2 = substring(CC,4,1), Flex4 = ''I'' where KeyID = ''[batchID]'''),
    ('SQL-W15', 112, 'update TransX set Flex2 = ''CL'' where KeyID = ''[batchID]'' and CCCat in (''C'',''H'')'),
    ('SQL-W15', 113, 'update TransX set Flex2 = ''UW'' where KeyID = ''[batchID]'' and CCCat in (''U'',''S'',''A'')'),
    ('SQL-W15', 114, 'update TransX set Flex4 = ''E'' where KeyID = ''[batchID]'' and not CCCat in (''U'',''S'',''A'',''C'',''H'')'),
    ('SQL-W15', 211, 'update TransX set GLdesc = c.Name from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-W15', 212, 'update TransX set Flex1 = c.Crcy, Flex6 = c.Name from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'''),
    ('SQL-W15', 213, 'update TransX set PCdesc = p.Descr, Flex8 = p.Product, Flex3 = p.Program from TransX t inner join Pctrs p on t.PC = p.Pctr where KeyID = ''[batchID]'''),
    ('SQL-W15', 214, 'update TransX set CCdesc = c.Descr from TransX t inner join Cctrs c on t.CC = c.Cctr where KeyID = ''[batchID]'''),
    ('SQL-W15', 215, 'update TransX set Flex5 = c.Descr from TransX t inner join CCtrCats c on t.CCcat = c.Cat where KeyID = ''[batchID]'''),
    ('SQL-W15', 351, 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + ''AN'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex8 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-W15', 490, 'Update x set Amt1 = Amt5, Amt2 = Amt6, Amt3 = round(Amt5/c.Rate,2), Amt4 = round(Amt6/c.Rate,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-W15', 500, '[ReplaceConnString][LockDownConnString]'),
    ('SQL-W15', 501, 'Delete from IR17_Other where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R67'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-W15', 503, 'Delete from IR17_Other_Canada where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R67'' and substring(''[BudAct]'',1,7) = ''LG-CAD '' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-W15', 511, '[ReplaceConnString][OriginalConnString]'),
    ('SQL-W24', 101, 'delete from TransX where KeyID = ''[batchID]'' and Co in (''1010'',''1099'',''2101'',''2102'',''2103'',''2500'',''4025'',''4030'',''5990'',''5992'',''5993'',''5996'')'),
    ('SQL-W24', 103, 'Update x set Crcy = y.Field1 From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Swap'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]'''),
    ('SQL-W24', 111, 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and BusCat like ''3%'''),
    ('SQL-W24', 112, 'Update TransX set BusCat = ''D'' where KeyID = ''[batchID]'' and BusCat = ''10'''),
    ('SQL-W24', 113, 'Update TransX set BusCat = ''A'' where KeyID = ''[batchID]'' and BusCat like ''2%'''),
    ('SQL-W24', 114, 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''14'',''15'') and not BusCat in (''A'',''D'',''C'')'),
    ('SQL-W24', 115, 'Update TransX set BusCat = ''A'' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''20'',''21'',''18'') and not BusCat in (''A'',''D'',''C'')'),
    ('SQL-W24', 116, 'Update TransX set BusCat = ''C'' where KeyID = ''[batchID]'' and substring(GL,1,3) = ''287'' and not BusCat in (''A'',''D'',''C'')'),
    ('SQL-W24', 117, 'Update TransX set BusCat = ''A'' where KeyID = ''[batchID]'' and not BusCat in (''A'',''D'',''C'')'),
    ('SQL-W24', 151, 'Update TransX set UWYR = ''1959'' where KeyID = ''[batchID]'' and co like ''3%'' and UWYR = '''''),
    ('SQL-W24', 152, 'Update TransX set UWYR = ''1958'' where KeyID = ''[batchID]'' and co like ''3%'' and UWYR = ''9999'''),
    ('SQL-W24', 202, 'Update x set x.Flex2 = y.Field1 from TransX x inner join Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex2 is NULL'),
    ('SQL-W24', 203, 'Update x set x.Flex2 = y.Field1 from TransX x inner join Misc_Tables y on substring(GL,1,3) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' where KeyID = ''[batchID]'' and Flex2 is NULL'),
    ('SQL-W24', 204, 'Update TransX set Flex2 = Flex2 + ''x'' from TransX where KeyID = ''[batchID]'' and GL like ''%999%'''),
    ('SQL-W24', 221, 'insert into TransX (KeyID, Co,PC,TP,BusCat,Contract,UWYR,Crcy,YearPeriod,Flex5,Flex2,Amt1,Amt2,Amt3) (select KeyID, Co,PC,TP,BusCat,Contract,UWYR,Crcy,YearPeriod,''N/A'' as Flex5,Flex2,round(-sum(coalesce(Amt1,0)),2),round(sum(-coalesce(Amt2,0)),2),round(sum(-coalesce(Amt3,0)),2) from TransX where KeyID = ''[batchID]''  group by KeyID, Co,PC,TP,BusCat,Contract,UWYR,Crcy,YearPeriod,Flex2)'),
