    ('SQL-W24', 301, 'Update x set x.PCdesc = y.Descr, x.Flex3 = y.Program, x.Flex5 = y.Product, x.Division = y.Division, x.Region = y.Region, x.Location = y.Location, x.Zone = y.Zone, x.Hierarchy = y.Hierarchy from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]'''),
    ('SQL-W24', 302, 'Update x set x.Flex1 = y.Crcy from TransX x inner join Companies y on x.Co = y.Co where KeyID = ''[batchID]'''),
    ('SQL-W24', 311, 'Update TransX set Flex4 = (case when Flex2 like ''%x'' then ''E'' else ''I'' end) from TransX where KeyID = ''[batchID]'''),
