    ('SQL-W24', 321, 'Update TransX set Flex6 = Division, Flex7 = rtrim(Region + '' '' + Location) where KeyID = ''[batchID]'' and Division in (''US_INS_OPS'',''LATAMER'',''FIRV'') and Flex6 is NULL'),
    ('SQL-W24', 322, 'Update TransX set Flex6 = Region, Flex7 = rtrim(Location + '' '' + Zone) where KeyID = ''[batchID]'' and Region in (''LONBRANCH'',''EUROPE'',''ASIA'',''NEWLN'')'),
