    ('SQL-W24', 351, 'Update x set Flex9 = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N'' +(case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-W24', 352, 'Update TransX set Flex8 = Hierarchy where KeyID = ''[batchID]'''),
    ('SQL-W24', 401, 'Update TransX set Flex2 = ''RCR IF'' where KeyID = ''[batchID]'' and Flex2 = ''RCR'' and Co = ''2999'' and TP like ''F%'''),
    ('SQL-W24', 402, 'Update TransX set Flex2 = ''RCR IF'' where KeyID = ''[batchID]'' and Flex2 = ''RCR'' and Co = ''2999'' and TP = '''' and (Contract = '''' or Contract = ''RRP RECLASS'')'),
    ('SQL-W24', 403, 'Update TransX set Flex4 = ''I'' where KeyID = ''[batchID]'' and Flex2 = ''RCR IF'''),
    ('SQL-W24', 404, 'Update TransX set TP = ''2308'', Flex4 = ''X'' where KeyID = ''[batchID]'' and Contract = ''DAH'' and TP = '''''),
    ('SQL-W24', 491, 'Update x set Rate1 = c.Rate From TransX x inner join CrcyRates c on c.Crcy = x.Flex1 and c.Typ = ''S'' and c.EffDate = ''[yyyy-mm-dd]'' where x.KeyID = ''[batchID]'''),
    ('SQL-W24', 492, 'Update x set Amt1 = Amt3, Amt2 = round(Amt3/Rate1,2), Flex3 = x.Crcy, Crcy = ''USD'' From TransX x inner join Misc_Tables y on y.Table_ID = ''IR17'' and y.ID = ''Crcy Exp'' and y.Descr = x.Crcy where x.KeyID = ''[batchID]'''),
