    ('SQL-W24', 505, 'Delete from IR17_LIC_Singapore where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R68'' and substring(''[BudAct]'',1,7) = ''IF-SING'''),
    ('SQL-W24', 506, 'Insert into IR17_LIC_Singapore (Co,Contract,UWYR,Crcy,Co_Crcy,PC,TP,PC_Desc,Program,YearPeriod,GL_Grp,Doc_Amt,LC_Amt,LC2_Amt,Source,Incl_Excl,ACD,Flex1,Flex2,Flex3,Portfolio_PC) Select Co,Contract,UWYR,Crcy,Flex1,PC,TP,PCdesc,Flex3,YearPeriod,Flex2,Amt1,Amt2,Amt3,''R68'',Flex4,BusCat,Flex6,Flex7,Flex8,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-SING'''),
    ('SQL-W24', 507, 'Delete from IR17_LIC_HudCAD where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R68'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
    ('SQL-W24', 508, 'Insert into IR17_LIC_HudCAD (Co,Contract,UWYR,Crcy,Co_Crcy,PC,TP,PC_Desc,Program,YearPeriod,GL_Grp,Doc_Amt,LC_Amt,LC2_Amt,Source,Incl_Excl,ACD,Flex1,Flex2,Flex3,Portfolio_PC) Select Co,Contract,UWYR,Crcy,Flex1,PC,TP,PCdesc,Flex3,YearPeriod,Flex2,Amt1,Amt2,Amt3,''R68'',Flex4,BusCat,Flex6,Flex7,Flex8,Flex9 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'''),
