    ('SQL-W41', 121, 'insert into TransX (KeyID, Yr, Period, Co, GL, PC, CC, BusCat, Flex1, Amt1, Amt2, Amt3,Flex2) (Select KeyID, Yr, Period, Co, GL, PC, CC, BusCat, Flex1, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2 , round(sum(coalesce(Amt3,0)),2) as Amt3, '''' as Flex2 from TransX where KeyID = ''[batchID]'' group by KeyID, Yr, Period, Co, GL, PC, CC, BusCat, Flex1)'),
    ('SQL-W41', 122, 'delete from TransX where KeyID = ''[batchID]'' and Flex2 is NULL'),
    ('SQL-W41', 123, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-W41', 141, 'Update TransX set BusCat = '''' where KeyID = ''[batchID]'' and BusCat = ''XX'''),
    ('SQL-W41', 142, 'Update x set Crcy = c.Crcy From TransX x inner join Companies c on c.Co = x.Co where x.KeyID = ''[batchID]'''),
    ('SQL-W41', 143, 'Update TransX set PK = (case when Amt1 > 0 or Amt2 > 0 or Amt3 > 0 then ''40'' else ''50'' end) where KeyID = ''[batchID]'''),
    ('SQL-W41', 144, 'Update TransX set Date1 = EOMONTH(cast(period as varchar) + ''/01/'' + cast(yr as varchar),0), Date2 = format(SYSDATETIME(),''yyyy-MM-dd'') where KeyID = ''[batchID]'''),
    ('SQL-W41', 145, 'Update TransX set Ledger = ''[version]'' where KeyID = ''[batchID]'''),
    ('SQL-W41', 146, 'Update TransX set Ledger = ''0'' where KeyID = ''[batchID]'' and Ledger = ''P'''),
    ('SQL-W41', 151, 'with cte as (select YearPeriod,Qtr, row_number() over (partition by co,period,crcy order by GL,PC,CC) as row_nbr,dense_rank() over (partition by co order by period,crcy) + 1000000 as doc_nbr from TransX) update cte set Qtr = doc_nbr, YearPeriod = row_nbr'),
    ('SQL-W41', 201, '[ReplaceConnString][LockDownConnString]'),
    ('SQL-W41', 211, 'delete from SAP_ledger_data where fiscal_year = [Yr] and ledger = (case when ''[version]'' = ''P'' then ''0'' else ''[version]'' end)'),
    ('SQL-W41', 221, 'insert into SAP_ledger_data (Co,fiscal_year,period,gl,ledger,doc_no,item_no,posting_date,entry_date,doc_user,doc_type,doc_hdr_text,crcy,post_key,doc_amt,lc_amt,lc2_amt,ref1,ref2,ref3,assignment,txt,profit_centre,cost_centre,bus_cat,trans_type,uwyr,broker,trade_ptr,ptf,contract,prod_code,vendor,tax_code,flex1,flex2,flex3,gl_crcy,gl_doc_amt,risk_terr,reins_loc,cat_code,acc_yr,reinsurer,status_code,lc3_amt,sub_prod,flex4) (select Co,Yr,period,gl,ledger,Qtr as doc_no,YearPeriod as item_no,Date1 as posting_date,Date2 as entry_date,user as doc_user,''0'' as doc_type,''Budget Load'' as doc_hdr_text,crcy,PK,Amt1,Amt2,Amt3,'''','''','''','''',''Budget Load'' as txt,PC,CC,BusCat,'''','''','''','''','''','''','''','''','''',flex1,flex2,flex3,crcy,Amt1,'''','''','''','''','''','''',0 as lc3_amt,'''','''' from [FX_Recon].dbo.TransX where  KeyID = ''[batchID]'')'),
    ('SQL-W41', 231, '[ReplaceConnString][OriginalConnString]'),
    ('SQL-E08', 1065, 'update TransX set PC = ''4059000000'' from TransX where KeyID = ''[batchID]'' and not TP = ''2008'' and not PC like ''40401%'' and not PC in ( ''1002000000'',''1402000755'',''4050100250'',''4050100267'',''4050500003'',''4050500010'',''4050609161'',''4060100156'',''5000000000'') and not BusCat = 24 and (UWyr > ''2003'' or coalesce(UWyr,'''') = '''') and Flex2 = ''offset'''),
    ('SQL-R49', 444, 'update TransX set Flex5 = 12, Flex4 = ''z-Other'', Flex1 = GL + '' '' + GLdesc from TransX where KeyID = ''[batchID]'' and Flex5 is NULL and Co in (''1000'',''1999'',''2008'',''4100'') and (Contract = ''67612*102'' or Contract like ''67612W$%'')'),
    ('SQL-G24', 215, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = x.GL and m.Field1 = (case when substring(x.GL,1,3) in (''132'',''148'',''231'') then '''' else x.BusCat end) and m.Field2 = (case when substring(x.GL,6,1) = ''9'' and substring(x.TTY,1,1) = ''9'' then '''' else x.TTY end) and m.Field6 = ''1'' and not x.TTY = ''815'' where KeyID = ''[batchID]'')'),
    ('SQL-M12', 201, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0'),
    ('SQL-M12', 202, 'delete from TransX where KeyID = ''[batchID]'' and not substring(GL,6,2) in (''01'',''02'',''04'',''05'')'),
    ('SQL-M12', 203, 'update TransX set GL = ''9999999'' from TransX inner join Misc_Tables on substring(GL,1,5) = ID where KeyID = ''[batchID]'' and Table_ID = ''Tax GL'' and Descr = ''9999999'''),
    ('SQL-M12', 204, 'delete from TransX where KeyID = ''[batchID]'' and GL = ''9999999'''),
    ('SQL-M12', 205, 'update TransX set TP = '''', Contract = '''' from TransX where KeyID = ''[batchID]'' and substring(GL,1,5) <> ''35840'''),
    ('SQL-M12', 206, 'delete from TransX where KeyID = ''[batchID]'' and GL = ''3545502'''),
    ('SQL-M12', 207, 'update TransX set Fsitem = GL, Amt2 = 0 from TransX where KeyID = ''[batchID]'''),
    ('SQL-M12', 212, 'update TransX set Amt2 = -Amt1 where KeyID = ''[batchID]'' and substring(GL,6,2) in (''04'',''05'') and not Amt1 is NULL'),
    ('SQL-M12', 222, 'update TransX set Amt2 = -Amt1*0.21 from TransX where KeyID = ''[batchID]'' and substring(GL,6,2) in (''01'',''02'') and not Amt1 is NULL'),
    ('SQL-M12', 223, 'update TransX set FSitem = substring(GL,1,5) + ''04'' from TransX where KeyID = ''[batchID]'' and GL like ''%01'''),
    ('SQL-M12', 224, 'update TransX set FSitem = substring(GL,1,5) + ''05'' from TransX where KeyID = ''[batchID]'' and GL like ''%02'''),
    ('SQL-M12', 226, 'insert into TransX (KeyID, Co, GL, Fsitem, Amt1, Amt2, Flex6) (Select KeyID, Co, GL,FSitem, round(sum(Amt1),0) as Amt1, round(sum(Amt2),0) as Amt2, ''pass1'' from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, FSitem)'),
    ('SQL-M12', 227, 'delete from TransX where KeyID = ''[batchID]'' and Flex6 is NULL'),
    ('SQL-M12', 228, 'delete from TransX where KeyID = ''[batchID]'' and Amt1 = 0 and Amt2 = 0'),
    ('SQL-M12', 253, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-M12', 711, 'insert into TransX (KeyID,Yr,Flex1) (select ''[batchID]-data2'',Field1,Descr from Misc_Tables where Table_ID = ''Review Notes'' and ID = ''M12'')'),
    ('SQL-M13', 440, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data11'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Canada where source = ''R64'' and YearPeriod > ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Canada x left join IR17_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join IR17_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD ) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) AND NOT GL_Grp IN (''DAC'',''UPR'') and substring(''[BudAct]'',1,7) = ''LG_CAD '')'),
    ('SQL-M13', 441, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt1) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC_ITD),2) from IR17_Control_Canada where YearPeriod = ''[Yr][Mo]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '' group by Co,GL,ACD)'),
    ('SQL-M13', 442, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC_QTD),2) from IR17_Control_Canada where YearPeriod <= ''[Yr][Mo]'' and GL < ''4000000'' and substring(''[BudAct]'',1,7) = ''LG-CAD '' group by Co,GL,ACD)'),
    ('SQL-M13', 443, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC_QTD),2) from IR17_Control_Canada where YearPeriod <= ''[Yr][Mo]'' and YearPeriod >= ''[Yr]01'' and GL >= ''4000000'' and substring(''[BudAct]'',1,7) = ''LG-CAD '' group by Co,GL,ACD)'),
    ('SQL-M13', 451, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,PC,BusCat,Amt3) (select ''[batchID]-data2'',Co,GL,PC,ACD,LC2_Amt from (select Co,GL,PC,ACD, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,PC,ACD,Source,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''M12'' and YearPeriod = ''201012'' GROUP BY Co,GL,PC,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,PC,ACD,Source,round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod = ''201012'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'' or GL like ''148%'' or GL like ''23%'') and not GL like ''2822%'' GROUP BY Co,GL,PC,ACD,Source) a GROUP BY Co,GL,PC,ACD) b where abs(LC2_Amt) > 1 and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-M13', 452, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data3'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_Singapore where  source = ''R64'' and YearPeriod > ''202112'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_Singapore x left join [FX_Recon].dbo.Misc_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join [FX_Recon].dbo.Misc_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''202112'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-M13', 453, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt3) (select ''[batchID]-data4'',Co,GL,Crcy,ACD,Doc_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R65'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''131%'' or GL like ''22%'' or GL like ''282%'') and not GL like ''2822%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-M13', 454, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data5'',Co,GL,Crcy,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL,Crcy,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt, round(sum(LC2_Amt),2) as LC2_Amt from (select Co,GL,Crcy,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt, round(sum(-LC2_Amt),2) as LC2_Amt from IR17_CF_Singapore where source = ''R66'' and YearPeriod > ''201512'' GROUP BY Co,GL,Crcy,ACD,Source union all select (case when Co = ''3060'' or Co = ''3100'' then ''3030'' else Co end) as Co,GL,Crcy,ACD,Source,round(sum(Doc_QTD),2) as Doc_Amt,round(sum(LC_QTD),2) as LC_Amt, round(sum(LC2_QTD),2) as LC2_Amt from IR17_Control_Singapore where source = ''R63'' and YearPeriod > ''201512'' and (GL like ''148%'' or GL like ''23%'') and not GL like ''232%'' GROUP BY Co,GL,Crcy,ACD,Source) a GROUP BY Co,GL,Crcy,ACD) b where (abs(Doc_Amt) > 1 or abs(LC2_Amt) > 1) and substring(''[BudAct]'',1,7) = ''LS-SING'')'),
    ('SQL-S02', 201, 'declare @lvdBoYear date = DATEFROMPARTS(YEAR(GETDATE()), 1, 1); EXEC [CorpAcct_Apps].[dbo].[PROC_S02_FRS_Entries] @lvdBoYear'),
    ('SQL-S02', 202, 'delete from TransX where KeyID = ''[batchID]'' and amt1 = 0'),
    ('SQL-S02', 203, 'delete from TransX where KeyID = ''[batchID]'' and (GL < ''4019900'' or GL like ''533%'' or GL > ''5449901'')'),
    ('SQL-S02', 210, 'update TransX set Flex5 = Co where KeyID = ''[batchID]'''),
    ('SQL-S02', 213, 'update TransX set TPname = Contract from TransX where KeyID = ''[batchID]'' and Co = ''2008'''),
    ('SQL-S02', 302, 'update TransX set Flex4 = Contract, Flex5 = TP from TransX where KeyID = ''[batchID]'' and Co = ''2008'''),
    ('SQL-S02', 316, 'delete from TransX where KeyID = ''[batchID]'' and amt1 = 0'),
    ('SQL-M13', 480, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) (select ''[batchID]-data11'',Co,GL_Grp,Crcy,PC,ACD,Doc_Amt,LC_Amt,LC2_Amt from (select Co,GL_Grp,Crcy,PC,ACD,round(sum(Doc_Amt),2) as Doc_Amt,round(sum(LC_Amt),2) as LC_Amt,round(sum(LC2_Amt),2) as LC2_Amt from (select Co,(case when GL_Grp = ''RCR IF'' then ''RCR'' else GL_GRP end) as GL_Grp,Crcy,PC,ACD,Source,round(sum(-Doc_Amt),2) as Doc_Amt,round(sum(-LC_Amt),2) as LC_Amt,round(sum(-LC2_Amt),2) as LC2_Amt from IR17_LIC_HudCAD where source = ''R64'' and YearPeriod > ''201012'' GROUP BY Co,GL_Grp,Crcy,PC,ACD,Source union all select Co,(case when GL like ''%999%'' then coalesce(coalesce(y.Field1,z.Field1),GL) + ''x'' else  coalesce(coalesce(y.Field1,z.Field1),GL) end) as GL_Grp,Crcy,PC,ACD,Source,round(sum((case when GL < ''3000000'' then -Doc_QTD else Doc_QTD end)),2) as Doc_Amt,round(sum((case when GL < ''3000000'' then -LC_QTD else LC_QTD end)),2) as LC_Amt,round(sum((case when GL < ''3000000'' then -LC2_QTD else LC2_QTD end)),2) as LC2_Amt from IR17_Control_HudCAD x left join IR17_Tables y on substring(GL,1,4) = y.Descr and y.Table_ID = ''IR17'' and y.ID = ''LIC'' left join IR17_Tables z on substring(GL,1,3) = z.Descr and z.Table_ID = ''IR17'' and z.ID = ''LIC'' and y.Field1 is NULL where source = ''R63'' and YearPeriod > ''201012'' and (Substring(GL,1,2) in (''14'',''15'',''20'',''21'',''18'',''40'',''54'') or Substring(GL,1,3) in (''283'',''284'',''287'')) and not substring(GL,1,3) in (''148'',''149'',''208'',''209'',''182'') GROUP BY Co,y.Field1,z.Field1,Crcy,PC,ACD,Source,GL) a GROUP BY Co,GL_Grp,Crcy,PC,ACD ) b where (abs(Doc_Amt) > 1 or abs(LC_Amt) > 1 or abs(LC2_Amt) > 1) AND NOT GL_Grp IN (''DAC'',''UPR'') and substring(''[BudAct]'',1,7) = ''LG_HUDC'')'),
    ('SQL-M13', 481, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt1) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC_ITD),2) from IR17_Control_HudCAD where YearPeriod = ''[Yr][Mo]'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' group by Co,GL,ACD)'),
    ('SQL-M13', 482, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC_QTD),2) from IR17_Control_HudCAD where YearPeriod <= ''[Yr][Mo]'' and GL < ''4000000'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' group by Co,GL,ACD)'),
    ('SQL-M13', 483, 'Insert into [FX_Recon].dbo.TransX (KeyID, Co, GL, BusCat, Amt2) (Select ''[batchID]-data12'',Co,GL,ACD,round(sum(LC_QTD),2) from IR17_Control_HudCAD where YearPeriod <= ''[Yr][Mo]'' and YearPeriod >= ''[Yr]01'' and GL >= ''4000000'' and substring(''[BudAct]'',1,7) = ''LG-HUDC'' group by Co,GL,ACD)'),
    ('SQL-M13', 490, '[ReplaceConnString][OriginalConnString]'),
    ('SQL-M13', 492, 'Insert into TransX (KeyID, Co, GL, BusCat, Amt1,Amt2,Flex1) (Select KeyID, Co, GL, BusCat, round(sum(Coalesce(Amt1,0)),2) as Amt1, round(sum(Coalesce(Amt2,0)),2) as Amt2, ''pass2'' as Flex1 from TransX where KeyID = ''[batchID]-data12'' group by KeyID,Co,GL,BusCat)'),
