    ('SQL-M13', 565, 'insert into TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) values (''[batchID]-data4'',''x'',''x'',''x'',''x'',''x'',0,0,0)'),
    ('SQL-M13', 566, 'insert into TransX (KeyID,Co,GL,Crcy,PC,BusCat,Amt1,Amt2,Amt3) values (''[batchID]-data5'',''x'',''x'',''x'',''x'',''x'',0,0,0)'),
    ('SQL-M13', 567, 'insert into TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6)  values (''[batchID]-data6'',''x'',''x'',''x'',''x'',''x'',''x'',0,0,0,0,0,0)'),
