    ('SQL-M13', 569, 'insert into TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6)  values (''[batchID]-data8'',''x'',''x'',''x'',''x'',''x'',''x'',0,0,0,0,0,0)'),
    ('SQL-M13', 570, 'insert into TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6)  values (''[batchID]-data9'',''x'',''x'',''x'',''x'',''x'',''x'',0,0,0,0,0,0)'),
