    ('SQL-M13', 601, 'Update x set x.PCdesc = y.Product from TransX x inner join PCtrs y on x.PC = y.PCtr where x.KeyID = ''[batchID]'''),
    ('SQL-M13', 602, 'Update x set PCdesc = ''7'' + m1.field2 + m2.field2 + x.BusCat + ''N-P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.PCdesc and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-M13', 711, 'insert into TransX (KeyID,Yr,Flex1) (select ''[batchID]-data13'',Field1,Descr from Misc_Tables where Table_ID = ''Review Notes'' and ID = ''M13'')'),
    ('SQL-W11', 501, 'Delete from IR17_Control where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R63'' and substring(''[BudAct]'',1,7) = ''IF-ODY '' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-W11', 502, 'Insert into IR17_Control (YearPeriod,Co,GL,Crcy,Co_Crcy,PC,PC_Desc,CC,CC_Desc,TP,ACD,Source,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select YearPeriod,Co,GL,Crcy,Flex1,PC,PCdesc,CC,CCdesc,TP,BusCat,''R63'',Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-ODY '''),
    ('SQL-W11', 503, 'Delete from IR17_Control_Canada where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R63'' and substring(''[BudAct]'',1,7) = ''LG-CAD '' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-W11', 504, 'Insert into IR17_Control_Canada (YearPeriod,Co,GL,Crcy,Co_Crcy,PC,PC_Desc,CC,CC_Desc,TP,ACD,Source,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select YearPeriod,Co,GL,Crcy,Flex1,PC,PCdesc,CC,CCdesc,TP,BusCat,''R63'',Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''LG-CAD '''),
    ('SQL-W11', 505, 'Delete from IR17_Control_Singapore where YearPeriod in (Select distinct YearPeriod from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'') and Source = ''R63'' and substring(''[BudAct]'',1,7) = ''IF-SING'' and not coalesce(Flex2,'''') like ''%adj%'' '),
    ('SQL-W11', 506, 'Insert into IR17_Control_Singapore (YearPeriod,Co,GL,Crcy,Co_Crcy,PC,PC_Desc,CC,CC_Desc,TP,ACD,Source,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD) Select YearPeriod,Co,GL,Crcy,Flex1,PC,PCdesc,CC,CCdesc,TP,BusCat,''R63'',Amt1,Amt2,Amt3,Amt4,Amt5,Amt6 from [FX_Recon].dbo.TransX where KeyID = ''[batchID]'' and substring(''[BudAct]'',1,7) = ''IF-SING'''),
    ('SQL-R48', 351, 'update TransX set KeyID = ''[batchID]-data4'' where KeyID = ''[batchID]'' and GL in (''4019900'',''4019901'',''4119900'',''4119901'') and ''[GL]'' = ''non TP only'''),
    ('SQL-G32', 219, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''1099917'' as GL, substring(GL,1,3) + ''% 804'' as Assgnmt, Crcy, '''' as TTY, '''' as TP, '''' as BusCat, PC, Flex5, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and (substring(GL,1,3) in (''161'',''162'',''241'',''242'',''441'',''682'') or TTY = ''804'') and not GL in (''1610002'',''2421002'') group by KeyID,Co,Crcy,TP,PC,Flex5,substring(GL,1,3))'),
    ('SQL-T04', 101, 'insert into TransX (KeyID,CC,Flex1,CCdesc,Co,CCCat,Flex2,Flex3,Hierarchy,PC,Flex4,RefKey1,Contract,Flex5,Flex6,RefKey2,Flex7,Flex8,Flex9,PCdesc,Txt,Division,Region,Location,Zone) (select ''[batchID]'',CCtr,c.Name,c.Descr,c.Co,Cat,c.Typ,Func,p.Hierarchy,c.PCtr,c.ValidThru,BlockAct,ReplacementCC,c.UpdatedOn,c.UpdatedBy,ExpNode,c.Hierarchy,c.Dept,c.Person,c.Flex1,c.Flex2,p.Division,p.Region,p.Location,p.Zone from CCTRS c inner join Pctrs p on c.Pctr = p.Pctr inner join (Select Co from Companies where Co in (select co from Companies c inner join ElimSelect e on ((c.Co >= e.FromVal and c.Co <= e.ThruVal and e.Oper = ''BT'') or (c.Co = e.FromVal and e.Oper = ''EQ'')) and e.IncExcl = ''I'' inner join Misc_Tables m on m.Table_ID = ''CoSelect'' and (substring(m.Descr,1,4) = ''[CoSelect]'' or m.Descr = ''[CoSelect]'') and e.ElimID = ''Co:'' + m.ID) and not co in (select co from Companies c inner join ElimSelect e on ((c.Co >= e.FromVal and c.Co <= e.ThruVal and e.Oper = ''BT'') or (c.Co = e.FromVal and e.Oper = ''EQ'')) and e.IncExcl = ''E'' inner join Misc_Tables m on m.Table_ID = ''CoSelect'' and (substring(m.Descr,1,4) = ''[CoSelect]'' or m.Descr = ''[CoSelect]'') and e.ElimID = ''Co:'' + m.ID)) j on c.co = j.co)'),
    ('SQL-M28', 432, 'update TransX set Flex5 = ''02 G31 Rev''  where KeyID = ''[batchID]'' and SubProd = ''G23'' and Flex5 = '''''),
    ('SQL-M28', 433, 'update TransX set Flex5 = ''03 '' + SubProd  where KeyID = ''[batchID]'' and SubProd in (''RI'',''RI FX'') and Flex5 = '''''),
    ('SQL-M28', 434, 'update TransX set Flex5 = ''04 G32 Load''  where KeyID = ''[batchID]'' and SubProd = ''G26'' and Flex5 = '''''),
    ('SQL-M28', 435, 'update TransX set Flex5 = ''05 '' + SubProd  where KeyID = ''[batchID]'' and Flex5 = '''''),
    ('SQL-M28', 711, 'insert into TransX (KeyID,Yr,Flex1) (select ''[batchID]-data3'',Field1,Descr from Misc_Tables where Table_ID = ''Review Notes'' and ID = ''M25'')'),
    ('SQL-M28', 721, 'update TransX set  BusCat = '''' where KeyID = ''[batchID]'' and not substring(GL,1,1) in (''4'',''5'') and not substring(GL,1,3) in (''283'',''284'')'),
    ('SQL-M28', 722, 'update TransX set  BusCat = '''' where KeyID = ''[batchID]'' and substring(GL,1,2) in (''46'',''56'')'),
    ('SQL-M28', 731, 'update t set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID like ''[batchID]%'''),
    ('SQL-M28', 732, 'update t set Flex2 = m.MapKey from TransX t inner join MapKeyRanges m on t.GL >= m.FromGL and t.GL <= m.ThruGL and m.MapKey like ''M1-%'' and len(mapkey) > 5 and len(mapkey) < 8 where KeyID = ''[batchID]'''),
    ('SQL-M28', 733, 'update t set Flex3 = m.Name from TransX t inner join MapKeys m on t.Flex2 = m.MapKey where KeyID = ''[batchID]'''),
    ('SQL-M28', 742, 'update t set Flex4 = substring(t.Flex2,4,1) + '') '' + m.Name from TransX t inner join MapKeys m on substring(t.Flex2,1,4) = m.MapKey where KeyID = ''[batchID]'''),
    ('SQL-M28', 761, 'update TransX set Flex2 = substring(Flex2,6,2) + '') '' + Flex3 where KeyID = ''[batchID]'''),
    ('SQL-M28', 763, 'update TransX set Flex3 = GL + '' '' + GLdesc where KeyID = ''[batchID]'''),
    ('SQL-M28', 791, 'insert into TransX (KeyID, Co, TTY, TP, BusCat, SubProd, Amt1, Flex2, Flex3, Flex4, Flex5, PK) (Select KeyID, Co, TTY, TP, BusCat, SubProd, round(sum(Amt1),2) as Amt1, Flex2, Flex3, Flex4, Flex5, ''1'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID, Co, TTY, TP, BusCat, SubProd, Flex2, Flex3, Flex4, Flex5)'),
    ('SQL-M17', 536, 'update TransX set Flex4 = Flex4 + ''LRC Assumed'' where KeyID = ''[batchID]'' and substring(GL,1,3) in (''155'',''215'') and GL like ''%00'''),
    ('SQL-G24', 221, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, PTF, Flex5,Amt1, Amt2, Amt3) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, PTF, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC,PTF,Flex5)'),
    ('SQL-G24', 235, 'Update x set PC = ''7'' + m1.field2 + m2.field2 + (case when x.BusCat = ''20'' then ''A'' else ''C'' end) + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID = ''[batchID]'''),
    ('SQL-G24', 246, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and t.BusCat = m.Field1 and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL'),
    ('SQL-G24', 247, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,2) = m.Descr and m.Field1 = '''' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and Flex7 is NULL'),
    ('SQL-G26', 251, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Other'' and t.GL like m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID in (''[batchID]'',''[batchID]-data8'')'),
    ('SQL-G26', 436, 'update TransX set PTF = '''' from TransX where KeyID = ''[batchID]'' and PTF is NULL'),
    ('SQL-G26', 437, 'update TransX set ProdCode = '''' from TransX where KeyID = ''[batchID]'' and ProdCode is NULL'),
    ('SQL-G26', 441, 'insert into TransX (KeyID, Co, GL, Crcy, PC, TTY, TP, PTF, Assgnmt, ProdCode, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, TTY, TP, PTF, Assgnmt, ProdCode, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''0'' group by KeyID, Co, GL, Crcy, PC, TTY, TP, PTF, Assgnmt, ProdCode)'),
    ('SQL-M15', 101, 'delete from TransX where KeyID = ''[batchID]''  and ''[version]'' = ''B'' and GL > ''4000000'''),
