    ('SQL-E03', 1013, 'delete from TransX where KeyID = ''[batchID]'' and GL in (''1319900'',''2319900'') and Co = ''2999'' and PC = ''1000000000'' and TTY = ''806'' and Yr = ''2020'''),
    ('SQL-M11', 203, 'Update TransX set Flex2 = (case when TTY = ''806'' then ''yes'' else ''no'' end) where KeyID = ''[batchID]'''),
    ('SQL-M11', 204, 'Update x set x.Flex6 = y.Typ, x.Flex9 = y.Product, x.Hierarchy = y.Hierarchy from TransX x inner join PCtrs y on x.PC = y.PCtr where KeyID = ''[batchID]'''),
