    ('SQL-R03', 113, 'update TransX set Flex2 = ''2 QS'' from TransX where KeyID = ''[batchID]'' and TP = ''2008'''),
    ('SQL-T35', 102, 'Update t Set Division = f1.ID from TransX t inner join FX_Variant_Co f1 on t.Co >= f1.From_Co and t.Co <= f1.Thru_Co inner join FX_Variant f2 on f1.ID = f2.ID and f2.Descr like ''%Reval%'' and not f2.Descr like ''% LS %'' and not f2.Descr  like ''% LG %'''),
    ('SQL-T35', 103, 'Update t Set Region = f1.ID from TransX t inner join FX_Variant_Co f1 on t.Co >= f1.From_Co and t.Co <= f1.Thru_Co inner join FX_Variant f2 on f1.ID = f2.ID and f2.Descr like ''%Trans BS UW%'''),
    ('SQL-G91', 221, 'insert into TransX (KeyID,GL,PC,Txt,Contract,ProdCode,TP,Amt1) (select KeyID,''1998900'' as GL,''5200000000'' as PC,substring(Txt,1,len(Txt)-8),Contract,'''' as ProdCode,''F0118'' as TP,round(-sum(Amt1),2) as Amt1 from TransX where KeyID = ''[batchID]'' group by KeyID,substring(Txt,1,len(Txt)-8),Contract)'),
    ('SQL-G29', 511, 'Update t set GL = m.Field3, ProdCode = m.Field4, PTF = m.Field5, TransCode = m.Field6, Assgnmt = m.Descr + '' to '' + m.Field2 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''ODY TP'' and t.GL = m.Descr and (BusCat = m.Field6 or m.Field6 = '''') where t.KeyID = ''[batchID]'' and not GL in (''4419900'')'),
    ('SQL-T16', 101, 'insert into TransX (KeyID,Flex1,Flex2,Flex3,Flex4,Flex5,Flex6) (Select ''[batchID]'',PCgrp,Name,Parent,SortSeq,CreatedBy,convert(varchar,CreatedOn,101) as CreatedOn from PCgrps)'),
