    ('SQL-T18', 101, 'insert into TransX (KeyID,GL,GLdesc,FSitem,FSitemDesc,Yr,Flex1,Flex2,Flex3) (Select ''[batchID]'',Node_ID, Node_Name, Parent, Node_Owner, Sort_Key, Notes, CreatedBy, convert(varchar,CreatedOn,101) as CreatedOn from ccNodes)'),
    ('SQL-T18', 102, 'update TransX set Flex2 = substring(Flex2,11,99) from TransX where KeyID = ''[batchID]'' and substring(Flex2,1,10) = ''ODYSSEYRE\'''),
    ('SQL-T20', 101, 'insert into TransX (KeyID,Flex1,Flex2,Flex3,Flex4,Flex5,Flex6) (select ''[batchID]'',r.MapKey,Name,FromGL,ThruGL, SUBSTRING(r.MapKey,1,2) as Map, len(r.MapKey) - len(replace(r.MapKey,''-'','''')) as Lvl from MapkeyRanges r inner join MapKeys m on r.MapKey = m.MapKey)'),
    ('SQL-G23', 241, 'Update t set Flex1 = m.Field3, Flex2 = m.Field4, Flex3 = m.Field5, Flex4 = m.Field6 from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Rev Offset'' and m.Descr = ''any'' and m.Field1 = ''any'' and t.TTY = m.Field2 where t.KeyID = ''[batchID]'' and t.Flex1 is NULL and not ''[yyyy-mm-dd]'' = ''2022-01-31'''),
    ('SQL-G25', 210, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, m.Field3 as GL, Crcy, m.Field5 as TTY, substring(GL,1,3) + ''% '' + TTY as Assgnmt, TP, m.Field4 as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX x inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID like ''Rev Offset%'' and m.Descr = ''any'' and m.Field1 = ''any'' and m.Field2 = x.TTY and m.Field6 = ''1'' where KeyID = ''[batchID]'')'),
    ('SQL-G26', 202, 'update TransX set  BusCat = ''30'' where KeyID = ''[batchID]'' and BusCat like ''3%'''),
