    ('SQL-G26', 342, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3) (Select KeyID, Co, ''4398600'' as GL, Crcy, '''' as TTY, '''' as TP, ''5500000000'' as PC, '''' as ProdCode, '''' as PTF, '''' as Assgnmt, round(-sum(Amt1),2) as Amt1, round(-sum(Amt2),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID in (''[batchID]'',''[batchID]-data8'') group by KeyID, Co, Crcy)'),
    ('SQL-G26', 361, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, Amt1, Amt2, Amt3, PK) (Select KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''0'' as PK from TransX where KeyID in (''[batchID]'',''[batchID]-data8'') group by KeyID, Co, GL, Crcy, TTY, TP, PC, ProdCode, PTF, Assgnmt)'),
    ('SQL-G29', 411, 'update TransX set ProdCode = '''', PTF = '''' where KeyID = ''[batchID]'''),
    ('SQL-G29', 471, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, ProdCode, PTF, Flex5, Amt1, Amt2, Amt3,Flex6) (Select ''[batchID]'' as KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC, ProdCode, PTF, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3, ''pass1'' as Flex6 from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, Assgnmt, TP, BusCat, PC,ProdCode,PTF,Flex5)'),
    ('SQL-G29', 472, 'delete from TransX where KeyID = ''[batchID]'' and Flex6 is NULL'),
