    ('SQL-G32', 119, 'update TransX set TP = '''' from TransX where KeyID = ''[batchID]'' and not GL like ''441%'''),
    ('SQL-G32', 223, 'insert into TransX (KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt, Flex5, Amt1, Amt2, Amt3,Zone) (Select ''[batchID]-data2'' as KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC, ProdCode, PTF, Assgnmt, Flex5, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2 , round(sum(Amt3),2) as Amt3,Zone from TransX where KeyID = ''[batchID]'' group by KeyID, Co, GL, Crcy, TTY, TP, BusCat, PC,ProdCode,PTF,Assgnmt,Flex5,Zone)'),
    ('SQL-G32', 235, 'Update x set PC = ''7'' + m1.field2 + m2.field2 + (case when x.BusCat = ''20'' then ''A'' else ''C'' end) + ''N'' + (case when x.TP like ''F%'' then ''A'' else ''T'' end) + ''P0'' from TransX x inner join Misc_Tables m1 on m1.Field1 = x.Co and m1.Table_ID = ''IR17'' and m1.ID = ''PC'' and m1.Descr = ''Co'' inner join Misc_Tables m2 on m2.Field1 = x.Flex5 and m2.Table_ID = ''IR17'' and m2.ID = ''PC'' and m2.Descr = ''Product'' where KeyID in (''[batchID]'',''[batchID]-data8'')'),
    ('SQL-R49', 391, 'update TransX set Flex5 = ''131'', Flex6 = ''Dividend Payments'' where KeyID = ''[batchID]'' and GL = ''3620001'' and Flex5 is NULL'),
    ('SQL-R49', 101, 'update TransX set Contract = '''' where KeyID = ''[batchID]'' and Contract = ''YE EQU ROLL'''),
    ('SQL-G24', 245, 'Update t set TTY = m.Field5, Flex7 = ''done'' from TransX t inner join Misc_Tables m on m.Table_ID = ''IR17'' and m.ID = ''Flow'' and substring(t.GL,1,3) = m.Descr and (t.BusCat = m.Field1 or m.Field1 = '''') and (t.TTY = m.Field2 or m.Field2 = '''') where t.KeyID = ''[batchID]'' and Flex7 is NULL and not GL in (''2853500'',''2851017'') and not TTY = ''815'''),
    ('SQL-G31', 112, 'update TransX set Amt1 = coalesce(Amt1,0), Amt2 = coalesce(Amt2,0), Amt3 = coalesce(Amt3,0) where KeyID = ''[batchID]''  and (''[yyyy-mm-dd]'' <> ''2022-01-31''  or Co like ''9%'')'),
    ('SQL-S06', 202, 'delete from TransX where KeyID = ''[batchID]'' and GL in (''x1439900'',''x1439901'',''x2039900'',''x2039901'',''x5339900'',''x5339901'',''1819900'',''2879900'',''5519900'',''1819901'',''2879901'',''5519901'')'),
    ('SQL-S07', 202, 'delete from TransX where KeyID = ''[batchID]'' and GL in (''1439900'',''1439901'',''2039900'',''2039901'',''5339900'',''5339901'',''1819900'',''2879900'',''5519900'',''1819901'',''2879901'',''5519901'')'),
    ('SQL-S08', 202, 'delete from TransX where KeyID = ''[batchID]'' and GL in (''1439900x'',''1439901x'',''2039900x'',''2039901x'',''5339900x'',''5339901'',''1819900'',''2879900'',''5519900'',''1819901'',''2879901'',''5519901'')'),
    ('SQL-S39', 309, 'insert into TransX (KeyID, Yr, Period, Co, GL, BusCat, PC, CC, Amt1,flex1) (Select KeyID, Yr, Period, Co, GL, BusCat, ''3991061408'' as PC, ''3NS''+SUBSTRING(CC,4,1)+''101408'' as CC,ROUND(0-ROUND(Amt1/3,2)*2,2), ''pass1'' as flex1 from TransX where KeyID = ''[batchID]'' and PC = ''3991061407'')'),
    ('SQL-G28', 115, 'insert into TransX (KeyID, Zone, Co, GL, Crcy, PC, CC, PTF, SubProd, Amt1, Amt2, Amt3) (Select ''[batchID]-data6'' as KeyID, Zone, ''5990'' as Co, ''2150000'' as GL, ''USD'' as Crcy, ''7URCAANTP0'' as PC, '''' as CC, '''' as PTF, ''RI'' as SubProd, round(-sum(Amt3),2) as Amt1, round(-sum(Amt3),2) as Amt2 , round(-sum(Amt3),2) as Amt3 from TransX where KeyID = ''[batchID]'' and Zone in (''4'',''5'') group by Zone)'),
    ('SQL-P00', 1005, 'delete from TransX where KeyID = ''[batchID]'' and Co = ''2999'''),
