    ('SQL-P00', 1022, 'insert into TransX (KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat, Amt1, Amt3, TTY) (Select KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat, round(sum(Amt1),2) as Amt1, round(sum(Amt3),2) as Amt3, '''' as TTY from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Crcy, Co, GL, PC, Contract, TP, BusCat)'),
    ('SQL-P00', 1023, 'delete from TransX where KeyID = ''[batchID]'' and TTY is NULL'),
    ('SQL-M13', 415, 'insert into [FX_Recon].dbo.TransX (KeyID,Co,GL,Crcy,PC,CC,BusCat,Amt1,Amt2,Amt3,Amt4,Amt5,Amt6) (select ''[batchID]-data6'',Co,GL,Crcy,PC,CC,ACD,Doc_QTD,Doc_ITD,LC_QTD,LC_ITD,LC2_QTD,LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from (select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(-Doc_QTD),2) as Doc_QTD,round(sum(-Doc_ITD),2) as Doc_ITD,round(sum(-LC_QTD),2) as LC_QTD,round(sum(-LC_ITD),2) as LC_ITD,round(sum(-LC2_QTD),2) as LC2_QTD,round(sum(-LC2_ITD),2) as LC2_ITD from IR17_Other where  source = ''R67'' GROUP BY Co,GL,Crcy,PC,CC,ACD,Source union all select Co,GL,Crcy,PC,CC,ACD,Source,round(sum(Doc_QTD),2) as Doc_QTD,round(sum(Doc_ITD),2) as Doc_ITD,round(sum(LC_QTD),2) as LC_QTD,round(sum(LC_ITD),2) as LC_ITD,round(sum(LC2_QTD),2) as LC2_QTD,round(sum(LC2_ITD),2) as LC2_ITD from IR17_Control where source = ''R63'' and (GL like ''6%'' or GL = ''4498000'') GROUP BY Co,GL,Crcy,PC,CC,ACD,Source) a GROUP BY Co,GL,Crcy,PC,CC,ACD) b where (abs(Doc_QTD) > 1 or abs(Doc_ITD) > 1 or abs(LC_QTD) > 1 or abs(LC_ITD) > 1 or abs(LC2_QTD) > 1 or abs(LC2_ITD) > 1) and substring(''[BudAct]'',1,7) = ''IF-ODY '')'),
    ('SQL-R48', 190, 'Update TransX set RiskTerr = m.Field1 from TransX t inner join Misc_Tables m on t.Co like m.ID and t.RiskTerr like m.Descr and m.Table_ID = ''R48 Overrides'' where KeyID = ''[batchID]'''),
    ('SQL-S08', 505, 'update TransX set GL = substring(GL,1,3) + ''9901'' from TransX where KeyID = ''[batchID]'' and GL like ''%9900'' and substring(gl,1,3) <> ''533'''),
    ('SQL-S08', 545, 'delete from TransX where KeyID = ''[batchID]'' and contract = ''OACN16600'' and gl = ''5339901'''),
    ('SQL-M18', 198, 'insert into TransX (KeyID, Zone, Co, GL, BusCat,TP,PC,SubProd, Flex1, Amt1,Amt2,TTY) (Select KeyID, Zone, Co, GL, BusCat,TP,PC,SubProd, Flex1, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2, ''801'' as TTY from TransX where KeyID = ''[batchID]'' and Zone = ''6'' and GL like ''131%'')'),
    ('SQL-M18', 196, 'insert into TransX (KeyID, Zone, Co, GL, BusCat,TP,PC,SubProd, Flex1, Amt1,Amt2) (Select KeyID, Zone, Co, ''231 806'' as GL, BusCat,TP,PC,SubProd, Flex1, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2  from TransX where KeyID = ''[batchID]'' and Zone = ''6'' and GL like ''231%'')'),
    ('SQL-G43', 221, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, substring(GL,1,5) + ''03'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and (GL like ''11%'' or (GL >= ''3330000'' and GL < ''3600000'' and substring(GL,6,2) in (''04'',''05''))))'),
    ('SQL-G28', 215, 'Update TransX set Flex6 = ''U3250'' from TransX where KeyID = ''[batchID]-data4'' and Flex6 = ''U3330'' and GL in (''6913001'',''6913003'',''6913004'')'),
    ('SQL-G28', 271, 'update TransX set Amt7 = (select round(sum(Amt3),2) from TransX where KeyID = ''[batchID]-data6'' and Zone in (''3'',''4'')) where KeyID = ''[batchID]-data5'' and GL = ''5600001'''),
    ('SQL-G28', 374, 'delete from TransX where KeyID = ''[batchID]'' and (not PK in (''40'',''50'') or PK is NULL)'),
