    ('SQL-R50', 201, 'Insert into TransX (KeyID,Co,Flex1,Amt1) (select KeyID + ''-save'' as KeyID,t.Co as Co,m.ID as Flex1,round(sum(Amt1 * m.Field5),2) as Amt1 from TransX t inner join Misc_Tables m on m.Table_ID = ''Val GL offset'' and t.GL = m.Descr and t.BusCat like m.Field1 and t.TTY like m.Field2 and t.Co >= ''1000'' and t.Co < (case when m.Field6 = ''IFRS4'' then ''5990'' else ''6000'' end)  where KeyID = ''[batchID]'' and not m.Field6 = ''IFRS17'' group by t.KeyID,t.Co,m.ID)'),
