    ('SQL-S20', 302, 'Insert into TransX (KeyID,Ledger,Co,Crcy,GL,PC,TP,BusCat,SubProd,TTY,UWYR,Contract,ReinName,Amt1,Amt2,Amt3,Amt4,Txt,Assgnmt,RefKey1,RefKey2,PK,Flex3) (select ''[batchID]'' as KeyID,Ledger,Co,Crcy,RefKey2 as GL,PC,TP,BusCat,(case when substring(''[GL]'',3,2) = ''30'' then ''S20 FB'' else ''S20 FA'' end) as SubProd,(case when substring(''[GL]'',3,2) = ''30'' then ''990'' else ''991'' end) as TTY,UWYR,Contract,ReinName,0 as Amt1,(case when substring(''[GL]'',3,2) = ''10'' then -Amt4 else 0 end) as Amt2,(case when substring(''[GL]'',3,2) = ''10'' then -Amt5 else (case when substring(''[GL]'',3,2) = ''30'' then -Amt4 else 0 end) end) as Amt3,(case when substring(''[GL]'',3,2) = ''60'' then -Amt4 else 0 end) as Amt4,Txt,Assgnmt,RefKey1,RefKey2, (case when Amt4 > 0 then ''50'' else ''40'' end) as PK, ''FX calc [Yr]-[Mo]'' from TransX where KeyID = ''[batchID]-data2'')'),
    ('SQL-G77', 341, 'insert into TransX (KeyID, Co,GL, Crcy,PC, CC,Contract,ProdCode,TP,Amt1, Amt2, Amt3,PK) (Select KeyID, ''3030'' as Co, ''1999901'' as GL, Crcy, ''3990000000'' as PC, '''' as CC,'''' as Contract, '''' as ProdCode, ''4010'' as TP,round(sum(-Amt1),2) as Amt1, round(sum(-Amt2),2) as Amt2,  round(sum(-Amt3),2) as Amt3, '''' as PK from TransX where KeyID = ''[batchID]'' and Co = ''3030'' group by KeyID,Crcy)'),
