    ('SQL-G75', 402, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, (case when Amt4 < 0 then Amt4 else 0 end) as Amt4, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and Co = ''2008'')'),
