    ('SQL-R22', 306, 'insert into TransX (KeyID, Flex3,FSitem,FSitemDesc,Flex4,Flex5,Ledger,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2) (select KeyID + ''-data2'', ''6. Ending Balance'' as Flex3,FSitem,FSitemDesc,Flex4,Flex5,Ledger,Co,CCdesc,GL,GLdesc,TPname,BusCat,BusCatDesc,RefKey2,PC,Flex6,RefKey3,PCdesc,Amt1,Flex1,RefKey1,Hierarchy,Flex2 from TransX where KeyID = ''[batchID]'' and Flex3 = ''Balance Sheet'')'),
