    ('SQL-G75', 304, 'insert into TransX (KeyID, GL, Crcy,Amt1,Co,PC,TP) (Select KeyID, ''2899901'' as GL, ''USD'' as Crcy, round(sum(-Amt3),2) as Amt1, ''3030'' as Co,''3990000000'' as PC, ''3010'' as TP from TransX where KeyID = ''[batchID]'' and Co is NULL group by KeyID, Crcy)'),
    ('SQL-G75', 305, 'insert into TransX (KeyID, GL, Crcy,Amt1,Co,PC,TP) (Select KeyID, ''1999901'' as GL, Crcy, round(-Amt1,2) as Amt1, ''3010'' as Co, PC, ''3030'' as TP from TransX where KeyID = ''[batchID]'' and Co = ''3030'' and GL = ''2899901'')'),
    ('SQL-G75', 306, 'insert into TransX (KeyID, GL, Crcy,Amt1,Co,PC,TP) (Select KeyID, GL, Crcy, Amt1, ''3010'' as Co, PC, ''2008'' as TP from TransX where KeyID = ''[batchID]'' and Co = ''3030'' and GL = ''2899901'')'),
    ('SQL-G75', 307, 'delete from TransX where KeyID = ''[batchID]'' and Co is NULL'),
    ('SQL-G75', 308, 'delete from TransX where KeyID = ''[batchID]'' and Co in (''3010'',''3030'') and Amt1 = 0'),
    ('SQL-G75', 309, 'delete from TransX where KeyID = ''[batchID]'' and Co = ''2008'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-R06', 206, 'insert into TransX (KeyID,FSitem,FSitemDesc,GL,GLdesc,Co,Crcy,Amt1,Amt2,Flex1,Flex2,Flex3) (select ''[batchID]'',FSitem,FSitemDesc,GL,GLdesc,Co,Crcy,Amt1,-Amt2,''SAP adjs'' as Flex1,Flex2,Flex3 from TransX  where KeyID = ''[batchID]'' and Flex3 = ''I'' and (GL like ''4382%'' or GL in (''4397000'',''3572002'') or Flex2 like ''d13%'' or Flex2 like ''d24%''))'),
    ('SQL-G26', 223, 'delete from TransX where KeyID = ''[batchID]-data2'' and Amt1 = 0 and Amt2 = 0 and Amt3 = 0'),
    ('SQL-G26', 216, 'insert into TransX (KeyID, Co, GL, Assgnmt, Crcy, TTY, TP, BusCat, PC, Flex5,Amt1, Amt2, Amt3) (Select KeyID, Co, ''5600052'' as GL, ''2880000 803'' as Assgnmt, Crcy, '''' as TTY, TP, '''' as BusCat, PC, Flex5, round(-Amt1,2) as Amt1, round(-Amt2,2) as Amt2 , round(-Amt3,2) as Amt3 from TransX where KeyID = ''[batchID]'' and GL = ''2880000'')'),
    ('SQL-M16', 542, 'update TransX set Flex3 = ''FX P&L'' where KeyID = ''[batchID]'' and GL like ''4398%'' and coalesce(Flex3,'''') = '''''),
    ('SQL-M16', 543, 'update TransX set Flex3 = ''FH P&L'' where KeyID = ''[batchID]'' and (GL like ''4415%'' or GL in (''4418900'',''6828900'')) and coalesce(Flex3,'''') = '''''),
    ('SQL-S10c', 100, 'insert into TransX (KeyID, Ledger, Co, GL,TP, BusCat, TTY, Amt1, Amt2, Amt3, Amt4, Flex1) (Select KeyID, Ledger, Co, GL,TP, BusCat,TTY,round(sum(coalesce(Amt2,0) - coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, round(sum(coalesce(Amt4,0) - coalesce(Amt3,0)),2) as Amt3, round(sum(coalesce(Amt4,0)),2) as Amt4, ''pass2'' as Flex1 from TransX where KeyID = ''[batchID]'' and Flex1 is NULL group by KeyID, Ledger, Co, GL, TP,BusCat, TTY)'),
    ('SQL-S10c', 105, 'insert into TransX (KeyID, Ledger, Co, GL, TP, BusCat, TTY, Amt1, Amt2, Amt3, Amt4, Flex1) (Select KeyID, Ledger, Co, GL, TP, BusCat, TTY, round(sum(Amt1),2) as Amt1, round(sum(Amt2),2) as Amt2, round(sum(Amt3),2) as Amt3, round(sum(Amt4),2) as Amt4, ''pass3'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Co, GL, TP, BusCat, TTY)'),
    ('SQL-S10b', 101, 'insert into TransX (KeyID, Ledger, Co, GL,TP,BusCat,TTY, Amt1, Amt2,Amt3,Amt4,Flex1) (Select KeyID, Ledger, Co, GL, '''' as TP, '''' as BusCat, '''' as TTY, round(sum(coalesce(Amt1,0)),2) as Amt1, 0 as Amt2, round(sum(coalesce(Amt3,0)),2) as Amt3, 0 as Amt4, ''pass1'' as Flex1 from TransX where KeyID = ''[batchID]'' group by KeyID, Ledger, Co, GL)'),
    ('SQL-G63', 256, 'update TransX set RiskTerr = ''UNKN'' from TransX inner join [GFS].dbo.FSGValidation on GL = GLAccount where KeyID = ''[batchID]'' and RiskLocation = 1'),
