    ('SQL-G43', 211, 'update TransX set Amt1 = -coalesce(Amt1,0), Amt2 = -coalesce(Amt2,0), Amt3 = -coalesce(Amt3,0) from TransX where KeyID = ''[batchID]'''),
    ('SQL-G43', 224, 'insert into TransX (KeyID, YearPeriod, Yr, Period, Ledger, Co, GL, Crcy, TP, PC, Contract, TTY, PTF, Amt1, Amt2, Amt3, PK) (Select KeyID, YearPeriod, Yr, Period, Ledger, Co, ''3610000'' as GL, Crcy, TP, PC, Contract, TTY, PTF, -Amt1 as Amt1,-Amt2 as Amt2,  -Amt3 as Amt3,  ''0'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL and GL >= ''3600000'' and GL < ''3640000'' )'),
    ('SQL-G43', 228, 'update TransX set GL = substring(GL,1,5) + ''00'' from TransX where KeyID = ''[batchID]'' and GL like ''19%'''),
