    ('SQL-G46', 231, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3, Amt4, PK) (Select KeyID, Ledger, Co, GL,TP, Contract, round(sum(coalesce(Amt3,0)),0) as Amt3, round(sum(coalesce(Amt4,0)),0) as Amt4,  ''40'' as PK from TransX where KeyID = ''[batchID]'' and (Amt3 > 0 or Amt4 > 0) and PK is NULL group by KeyID, Ledger, Co, GL, TP, Contract)'),
    ('SQL-G46', 232, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3, Amt4, PK) (Select KeyID, Ledger, Co, GL,TP, Contract, round(sum(coalesce(Amt3,0)),0) as Amt3, round(sum(coalesce(Amt4,0)),0) as Amt4,  ''50'' as PK from TransX where KeyID = ''[batchID]'' and (Amt3 < 0 or Amt4 < 0) and PK is NULL group by KeyID, Ledger, Co, GL, TP, Contract)'),
