    ('SQL-G46', 241, 'update TransX set Flex5 = m.Descr from TransX inner join Misc_Tables m on substring(GL,1,5) = m.ID where KeyID = ''[batchID]'' and m.Table_ID = ''Tax GL'''),
    ('SQL-G46', 242, 'update TransX set Flex5 = ''1720005'' from TransX where KeyID = ''[batchID]'' and GL like ''34%'' and Flex5 is NULL'),
