    ('SQL-G46', 244, 'update TransX set Flex5 = ''1720013'' from TransX where KeyID = ''[batchID]'' and GL like ''35%'' and Flex5 is NULL'),
    ('SQL-G46', 245, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3,Amt4, PK,Flex6) (Select KeyID, Ledger, Co, Flex5 as GL,TP, Contract, Amt3, Amt4, PK,''3610001'' as Flex6 from TransX where KeyID = ''[batchID]'' and PK = ''50'' and not Flex5 is NULL and GL like ''%04'')'),
    ('SQL-G46', 246, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3,Amt4, PK,Flex6) (Select KeyID, Ledger, Co, Flex5 as GL,TP, Contract, Amt3, Amt4, PK,''3610001'' as Flex6 from TransX where KeyID = ''[batchID]'' and PK = ''40'' and not Flex5 is NULL and GL like ''%04'' and not coalesce(Flex6,'''') = ''3610001'')'),
    ('SQL-G46', 247, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3,Amt4, PK,Flex6) (Select KeyID, Ledger, Co, ''3610001'' as GL,TP, Contract, -Amt3 as Amt3, -Amt4 as Amt4, ''40'' as PK,''3610001'' as Flex6 from TransX where KeyID = ''[batchID]'' and PK = ''50'' and not Flex5 is NULL and GL like ''%04'' and not coalesce(Flex6,'''') = ''3610001'')'),
    ('SQL-G46', 248, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3,Amt4, PK,Flex6) (Select KeyID, Ledger, Co, ''3610001'' as GL,TP, Contract, -Amt3 as Amt3, -Amt4 as Amt4, ''50'' as PK,''3610001'' as Flex6 from TransX where KeyID = ''[batchID]'' and PK = ''40'' and not Flex5 is NULL and GL like ''%04'' and not coalesce(Flex6,'''') = ''3610001'')'),
    ('SQL-G46', 249, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3,Amt4, PK) (Select KeyID, Ledger, Co, Flex5 as GL,TP, Contract, -Amt3 as Amt3, -Amt4 as Amt4, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''50'' and not Flex5 is NULL and not coalesce(Flex6,'''') = ''3610001'')'),
    ('SQL-G46', 250, 'insert into TransX (KeyID, Ledger, Co, GL, TP, Contract, Amt3,Amt4, PK) (Select KeyID, Ledger, Co, Flex5 as GL,TP, Contract, -Amt3 as Amt3, -Amt4 as Amt4, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''40'' and not Flex5 is NULL and not coalesce(Flex6,'''') = ''3610001'')'),
    ('SQL-G46', 251, 'update TransX set Txt = ''Tax'', Flex6 = '''', Amt1 = Amt4, Amt2 = abs(Amt4), Amt3 = abs(Amt3), Amt4 = abs(Amt4) from TransX where KeyID = ''[batchID]'''),
    ('SQL-G46', 252, 'update TransX set TTY = ''704'' from TransX where KeyID = ''[batchID]'' and GL like ''172%'''),
    ('SQL-G46', 253, 'update TransX set GLdesc = c.Descr from TransX t inner join COA c on t.GL = c.GL where KeyID = ''[batchID]'''),
    ('SQL-G46', 254, 'update TransX set PC = c.DefaultPC from TransX t inner join Companies c on t.Co = c.Co where KeyID = ''[batchID]'''),
