    ('SQL-G47', 221, 'insert into TransX (KeyID, GL, PC, Amt1, TTY, BusCat) (Select KeyID,GL, PC, round(-sum(coalesce(Amt1,0)),2) as Amt1, '''' as TTY, '''' as BusCat from TransX where KeyID = ''[batchID]'' group by KeyID, GL, PC)'),
    ('SQL-G47', 222, 'delete from TransX where KeyID = ''[batchID]'' and (TTY is NULL or Amt1 = 0)'),
    ('SQL-G47', 231, 'insert into TransX (KeyID, GL, PC, Amt1, TTY, BusCat) (Select KeyID,substring(GL,1,3) + ''8901'' as GL, PC, -Amt1 as Amt1, '''' as TTY, ''30'' as BusCat from TransX where KeyID = ''[batchID]'')'),
    ('SQL-G47', 232, 'insert into TransX (KeyID, GL, PC, Amt1, TTY, BusCat) (Select KeyID,substring(Descr,1,3) + substring(GL,4,4) as GL, PC, -Amt1 as Amt1, Field2 asTTY, BusCat from TransX inner join Misc_Tables on substring(GL,1,3) = substring(ID,1,3) and BusCat = Field1 where KeyID = ''[batchID]'' and Table_ID = ''ElimGLmap5'')'),
    ('SQL-G47', 233, 'insert into TransX (KeyID, GL, PC, Amt1, TTY, BusCat) (Select KeyID, ''211'' + substring(GL,4,4) as GL, PC, Amt1, ''831'' as TTY, BusCat from TransX where KeyID = ''[batchID]'' and GL like ''401%'' and BusCat = '''')'),
    ('SQL-G47', 234, 'insert into TransX (KeyID, GL, PC, Amt1, TTY,BusCat) (Select KeyID, ''211'' + substring(GL,4,4) as GL, PC, -Amt1 as Amt1, ''832'' as TTY,BusCat from TransX where KeyID = ''[batchID]'' and GL like ''401%'' and BusCat = '''')'),
    ('SQL-G70', 320, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP, Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2,  round(sum(coalesce(Amt3,0)),2) as Amt3,round(sum(coalesce(Amt4,0)),2) as Amt4, ''1'' as PK  from TransX where KeyID = ''[batchID]'' and PK is NULL group by KeyID, Co, GL, Crcy, PC, CC, Contract, TP)'),
    ('SQL-G70', 401, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP, Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, (case when Amt4 > 0 then Amt4 else 0 end) as Amt4, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2006'')'),
    ('SQL-G70', 402, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP,Amt1, Amt2, Amt3, Amt4,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, (case when Amt4 < 0 then Amt4 else 0 end) as Amt4, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''2006'')'),
    ('SQL-G70', 403, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP, Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 > 0 then Amt1 else 0 end) as Amt1, (case when Amt2 > 0 then Amt2 else 0 end) as Amt2, (case when Amt3 > 0 then Amt3 else 0 end) as Amt3, ''40'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''3060'')'),
    ('SQL-G70', 404, 'insert into TransX (KeyID, Co, GL, Crcy, PC, CC, Contract, TP,Amt1, Amt2, Amt3,PK) (Select KeyID, Co, GL, Crcy, PC, CC, Contract, TP, (case when Amt1 < 0 then Amt1 else 0 end) as Amt1, (case when Amt2 < 0 then Amt2 else 0 end) as Amt2, (case when Amt3 < 0 then Amt3 else 0 end) as Amt3, ''50'' as PK from TransX where KeyID = ''[batchID]'' and PK = ''1'' and Co = ''3060'')'),
    ('SQL-G70', 405, 'delete from TransX where KeyID = ''[batchID]'' and PK is NULL or PK = ''1'''),
    ('SQL-G79', 410, 'insert into TransX (KeyID, Crcy, Co, GL, PC, CC, Txt, Contract, TP, ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, Crcy, Co, GL, PC, CC, Txt, Contract, TP, ProdCode, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, round(sum(coalesce(Amt3,0)),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' and PK is NULL group by KeyID, Crcy, Co, GL, PC, CC, Txt, Contract, TP, ProdCode)'),
    ('SQL-G89', 410, 'insert into TransX (KeyID, Crcy, Co, GL, PC, CC, Txt, Contract, TP, ProdCode,Amt1, Amt2, Amt3,PK) (Select KeyID, Crcy, Co, GL, PC, CC, Txt, Contract, TP, ProdCode, round(sum(coalesce(Amt1,0)),2) as Amt1, round(sum(coalesce(Amt2,0)),2) as Amt2, round(sum(coalesce(Amt3,0)),2) as Amt3, ''1'' as PK from TransX where KeyID = ''[batchID]'' group by KeyID,Crcy, Co, GL, PC, CC, Txt, Contract, TP, ProdCode)');
